// Hexagonal Architecture: Domain Layer (Inner Core)
// Zero dependencies on UI or Rendering libraries.

export interface Vec3 {
  x: number;
  y: number;
  z: number;
}

export interface Node {
  id: string;
  pos: Vec3;
  oldPos: Vec3; // For Verlet integration
  mass: number;
  friction: number;
  isFixed?: boolean;
  isHead?: boolean; // NEW: The only node that can eat

  // SUCTION MECHANICS
  isGripping?: boolean; // Read-only physics state
  gripSignal?: number;  // 0.0 to 1.0 (Controlled by Brain). High = Release Suction.

  // EDITOR METADATA (Preserves shape upon reloading)
  originalGridCoord?: { x: number; y: number; z: number }; 

  // Neural State
  activation?: number; // 0.0 to 1.0 (Visualization Glow)
  // Physics State
}

export interface Muscle {
  id: string;
  nodeA: string; // ID reference
  nodeB: string; // ID reference
  baseLength: number;
  stiffness: number;
  dnaIndex: number; // Maps to a Gene (Index in genome arrays)

  // Runtime Physics State
  currentLength?: number; 
  targetLength?: number; 

  // --- OSCILLATOR STATE (The Anti-Vibration Core) ---
  // The brain controls these parameters, not the length directly.
  phase: number;      // Current position in the sine wave (0 to 2PI)
  freq: number;       // How fast it pulses (Hz). Clamped to prevent jitter.
  amp: number;        // How much it expands (0.0 to 0.4). 
}

// Replaced simple Sine Gene with Neural Genome
export interface NeuralGenome {
  // GNN Weights: How much signal flows through each muscle (Synapse)
  synapseWeights: number[]; 
  // LSM Weights: The chaotic reservoir weights (simplified as a float array)
  reservoirWeights: number[];
  // Output Weights: Mapping the reservoir state to muscle contraction
  outputWeights: number[]; 
  // NEW: Predictive World Model Weights (Reservoir -> Predicted Sensory Input)
  predictionWeights: number[];
  // NEW: Grip Control Weights (Reservoir -> Node Suction Release)
  gripWeights: number[]; 
  // Biases for neurons
  biases: number[];

  // --- EVOLVABLE BRAIN DYNAMICS ---
  internalClockSpeed: number; // Multiplier (0.5 to 2.0). How fast the brain thinks relative to physics.
  waveFreq: number;           // Hz (0.5 to 3.0). Base frequency of the spinal generator.
  waveSpeed: number;          // Propagation speed of the wave along the body.
}

export interface FoodItem {
    id: string;
    pos: Vec3;
    energyValue: number;
    consumed: boolean;
}

export enum ShapeType {
  CUBE = 'CUBE', // Cartesian Lattice
  TETRAHEDRON = 'TETRAHEDRON', // Offset Lattice
  WORM = 'WORM', // Legacy
  HEX = 'HEX', // 3D Hexagonal Prism Layout
}

export interface Organism {
  id: string;
  shape: ShapeType; // NEW: Tracks the lattice type for the Architect
  nodes: Node[];
  muscles: Muscle[];
  // The Blueprint
  neuralGenome: NeuralGenome;
  // The Runtime Brain (Controller instance, not serialized usually, but here for simplicity)
  brain?: any; 

  // Stats
  fitness: number; // Total Score
  generation: number;

  // NEW: Posture Metrics
  initialVerticalSize: number; // BENCHMARK: Distance from Feet to Head at Spawn
  currentHeightScore: number; // Real-time score (0.0 to 1.0) for UI
  accumulatedPostureScore: number; // NEW: Running total of posture points
  bestHeightScore: number; // NEW: Track peak posture

  // NEW: Metabolism & Survival
  energy: number;          // 0 to 100
  maxEnergy: number;       
  hungerTime: number;      // Time since last meal (drives exponential decay)
  isAlive: boolean;
  foodEaten: number;
  visibleFood: FoodItem[]; // Each creature has its own reality/food track
}

export interface SimulationConfig {
  gravity: number;
  friction: number;
  groundDamping: number;
  timeStep: number;
  // NEW: Structural Integrity
  shapeMemoryStrength: number;

  // NEW: Real-time Physics Tweaks
  globalStiffness: number;     // Multiplier for bone rigidity (0.1 to 2.0)
  globalContractility: number; // Multiplier for muscle power (0.0 to 2.0)
}

// --- ARCHITECT TYPES ---
export type GridCoord = { x: number; y: number; z: number };

export interface Blueprint {
    cells: Map<string, boolean>; // Key "x,y,z"
    type: ShapeType;
}

import { GridCoord, ShapeType, Vec3 } from '../types';

export interface Neighbor {
    coord: GridCoord;
    distanceWeight: number; // 1.0 for standard, others for diagonals
}

export interface ILatticeStrategy {
    gridToWorld(coord: GridCoord, scale: number): Vec3;
    getNeighbors(coord: GridCoord): Neighbor[];
    getVerticalNeighbors(coord: GridCoord): Neighbor[];
}

export class CubeLatticeStrategy implements ILatticeStrategy {
    gridToWorld(coord: GridCoord, scale: number): Vec3 {
        // Simple Cartesian
        return {
            x: coord.x * scale,
            y: coord.y * scale + 0.5,
            z: coord.z * scale
        };
    }

    getNeighbors(coord: GridCoord): Neighbor[] {
        const offsets = [
            {x:1, y:0, z:0}, {x:-1, y:0, z:0},
            {x:0, y:1, z:0}, {x:0, y:-1, z:0},
            {x:0, y:0, z:1}, {x:0, y:0, z:-1}
        ];
        const diags = [
            {x:1, y:1, z:0}, {x:1, y:-1, z:0},
            {x:0, y:1, z:1}, {x:0, y:1, z:-1},
            {x:1, y:0, z:1}, {x:1, y:0, z:-1}
        ];

        const neighbors: Neighbor[] = [];

        offsets.forEach(o => {
            neighbors.push({
                coord: { x: coord.x + o.x, y: coord.y + o.y, z: coord.z + o.z },
                distanceWeight: 1.0
            });
        });

        diags.forEach(o => {
            neighbors.push({
                coord: { x: coord.x + o.x, y: coord.y + o.y, z: coord.z + o.z },
                distanceWeight: 1.0
            });
        });

        return neighbors;
    }

    getVerticalNeighbors(coord: GridCoord): Neighbor[] {
        return [
            { coord: { x: coord.x, y: coord.y + 1, z: coord.z }, distanceWeight: 1.0 },
            { coord: { x: coord.x, y: coord.y - 1, z: coord.z }, distanceWeight: 1.0 }
        ];
    }
}

export class HexLatticeStrategy implements ILatticeStrategy {
    gridToWorld(coord: GridCoord, scale: number): Vec3 {
        const size = scale * 0.6;
        const hexHeight = scale * 0.7;

        const q = coord.x;
        const r = coord.z;
        const yLevel = coord.y;

        const px = size * 1.5 * q;
        const pz = size * Math.sqrt(3) * (r + q/2);
        const py = 0.5 + yLevel * hexHeight;

        return { x: px, y: py, z: pz };
    }

    getNeighbors(coord: GridCoord): Neighbor[] {
        // Hexagonal Prisms have 6 horizontal neighbors + 2 vertical + diagonal ups/downs
        const hexDirs = [
            {dq: 1, dr: 0}, {dq: 1, dr: -1}, {dq: 0, dr: -1},
            {dq: -1, dr: 0}, {dq: -1, dr: 1}, {dq: 0, dr: 1}
        ];

        const neighbors: Neighbor[] = [];

        // 1. Planar Neighbors (Same Y)
        hexDirs.forEach(d => {
            neighbors.push({
                coord: { x: coord.x + d.dq, y: coord.y, z: coord.z + d.dr },
                distanceWeight: 1.0
            });
        });

        // 2. Vertical Neighbors
        neighbors.push({ coord: { x: coord.x, y: coord.y + 1, z: coord.z }, distanceWeight: 1.0 });
        neighbors.push({ coord: { x: coord.x, y: coord.y - 1, z: coord.z }, distanceWeight: 1.0 });

        // 3. Diagonal Up/Down (Structural Integrity)
        hexDirs.forEach(d => {
            neighbors.push({
                coord: { x: coord.x + d.dq, y: coord.y + 1, z: coord.z + d.dr },
                distanceWeight: 0.8
            });
             neighbors.push({
                coord: { x: coord.x + d.dq, y: coord.y - 1, z: coord.z + d.dr },
                distanceWeight: 0.8
            });
        });

        return neighbors;
    }

    getVerticalNeighbors(coord: GridCoord): Neighbor[] {
         return [
            { coord: { x: coord.x, y: coord.y + 1, z: coord.z }, distanceWeight: 1.0 },
            { coord: { x: coord.x, y: coord.y - 1, z: coord.z }, distanceWeight: 1.0 }
        ];
    }
}

export class TetraLatticeStrategy implements ILatticeStrategy {
    gridToWorld(coord: GridCoord, scale: number): Vec3 {
        let px = coord.x * scale;
        let pz = coord.z * scale;

        // Offset odd layers
        if (coord.y % 2 !== 0) {
            px += scale * 0.5;
            pz += scale * 0.5;
        }

        const py = coord.y * (scale * 0.82) + 0.5;

        return { x: px, y: py, z: pz };
    }

    getNeighbors(coord: GridCoord): Neighbor[] {
        const neighbors: Neighbor[] = [];

        // Connect to everyone in a 3x3x3 block except self
        for(let x=-1; x<=1; x++) {
            for(let y=-1; y<=1; y++) {
                for(let z=-1; z<=1; z++) {
                    if (x===0 && y===0 && z===0) continue;
                    neighbors.push({
                        coord: { x: coord.x + x, y: coord.y + y, z: coord.z + z },
                        distanceWeight: 1.0
                    });
                }
            }
        }
        return neighbors;
    }

    getVerticalNeighbors(coord: GridCoord): Neighbor[] {
        return [
            { coord: { x: coord.x, y: coord.y + 1, z: coord.z }, distanceWeight: 1.0 },
            { coord: { x: coord.x, y: coord.y - 1, z: coord.z }, distanceWeight: 1.0 }
        ];
    }
}

export class LatticeFactory {
    static getStrategy(type: ShapeType): ILatticeStrategy {
        switch (type) {
            case ShapeType.HEX: return new HexLatticeStrategy();
            case ShapeType.TETRAHEDRON: return new TetraLatticeStrategy();
            case ShapeType.CUBE: 
            default: return new CubeLatticeStrategy();
        }
    }
}

import { Organism } from '../types';

export interface IFitnessEvaluator {
    evaluate(organism: Organism, dt: number): void;
    finalize(organism: Organism): void;
    setWeights(foodWeight: number, heightWeight: number): void;
}

export class StandardFitnessEvaluator implements IFitnessEvaluator {
    private foodWeight: number = 20.0;
    private heightWeight: number = 100.0;

    setWeights(foodWeight: number, heightWeight: number) {
        this.foodWeight = foodWeight;
        this.heightWeight = heightWeight;
    }

    evaluate(organism: Organism, dt: number): void {
        let headY = 0;
        const head = organism.nodes.find(n => n.isHead);
        if (head) headY = head.pos.y;

        // --- STRUCTURAL POSTURE CALCULATION ---
        let currentMinY = Infinity;
        for(const n of organism.nodes) {
            if (n.pos.y < currentMinY) currentMinY = n.pos.y;
        }
        const currentSpan = Math.max(0, headY - currentMinY);

        let benchmark = organism.initialVerticalSize;
        if (typeof benchmark !== 'number' || isNaN(benchmark) || benchmark < 0.01) {
            benchmark = 0.5;
        }

        let liftRatio = currentSpan / benchmark;
        if (isNaN(liftRatio)) liftRatio = 0;

        // UI Score Update
        organism.currentHeightScore = Math.min(Math.max(0, liftRatio), 1.0);

        // ACCUMULATION (Only if Alive)
        if (organism.isAlive) {
            const rewardRate = Math.min(Math.max(0, liftRatio), 1.5);
            organism.accumulatedPostureScore += rewardRate * this.heightWeight * dt;
        }

        if (isNaN(organism.accumulatedPostureScore)) organism.accumulatedPostureScore = 0;

        // TOTAL FITNESS FORMULA
        organism.fitness = (organism.foodEaten * this.foodWeight) + organism.accumulatedPostureScore;
    }

    finalize(organism: Organism): void {
        this.evaluate(organism, 0);
    }
}

import { NeuralGenome } from '../types';

export class GeneticOperator {
    private mutationRate: number;

    constructor(mutationRate: number = 0.05) {
        this.mutationRate = mutationRate;
    }

    public createRandomGenome(numMuscles: number, numNodes: number, reservoirSize: number = 20): NeuralGenome {
        return {
            synapseWeights: this.randomArray(numMuscles * 2),
            reservoirWeights: this.randomArray(reservoirSize * reservoirSize),
            outputWeights: this.randomArray(numMuscles * reservoirSize),
            predictionWeights: this.randomArray(reservoirSize),
            gripWeights: this.randomArray(numNodes * reservoirSize),
            biases: this.randomArray(numNodes),
            // Default Evolvable Params
            internalClockSpeed: 1.0,
            waveFreq: 1.5,
            waveSpeed: 1.0
        };
    }

    public cloneGenome(source: NeuralGenome): NeuralGenome {
        return {
            synapseWeights: [...source.synapseWeights],
            reservoirWeights: [...source.reservoirWeights],
            outputWeights: [...source.outputWeights],
            predictionWeights: source.predictionWeights ? [...source.predictionWeights] : [],
            gripWeights: source.gripWeights ? [...source.gripWeights] : [],
            biases: [...source.biases],
            internalClockSpeed: source.internalClockSpeed ?? 1.0,
            waveFreq: source.waveFreq ?? 1.5,
            waveSpeed: source.waveSpeed ?? 1.0
        };
    }

    public mutateGenome(genome: NeuralGenome): void {
        const mutateArray = (arr: number[]) => {
            if (!arr) return;
            for(let i=0; i<arr.length; i++) {
                if (Math.random() < this.mutationRate) {
                    arr[i] += (Math.random() - 0.5) * 0.5;
                    if (arr[i] > 2) arr[i] = 2;
                    if (arr[i] < -2) arr[i] = -2;
                }
            }
        };

        mutateArray(genome.synapseWeights);
        mutateArray(genome.reservoirWeights);
        mutateArray(genome.outputWeights);
        mutateArray(genome.predictionWeights);
        mutateArray(genome.gripWeights);
        mutateArray(genome.biases);

        // Mutate Parameters
        if (Math.random() < this.mutationRate) {
            genome.internalClockSpeed += (Math.random() - 0.5) * 0.2;
            genome.internalClockSpeed = Math.max(0.5, Math.min(2.0, genome.internalClockSpeed));
        }
        if (Math.random() < this.mutationRate) {
            genome.waveFreq += (Math.random() - 0.5) * 0.5;
            genome.waveFreq = Math.max(0.2, Math.min(4.0, genome.waveFreq));
        }
        if (Math.random() < this.mutationRate) {
            genome.waveSpeed += (Math.random() - 0.5) * 0.2;
            genome.waveSpeed = Math.max(0.1, Math.min(3.0, genome.waveSpeed));
        }
    }

    private randomArray(size: number): number[] {
        return Array.from({ length: size }, () => (Math.random() * 1.0) - 0.5);
    }
}

import { ShapeType, Organism, Node, Muscle, NeuralGenome, GridCoord } from './types';
import { VectorOps } from './math';
import { LatticeFactory, ILatticeStrategy } from './lattice/LatticeStrategy';
import { GeneticOperator } from './genetics/GeneticOperator';

export class BlueprintService {
  private cells: Map<string, boolean> = new Map();
  private type: ShapeType = ShapeType.CUBE;
  private readonly GRID_SIZE = 10; 
  private geneticOperator: GeneticOperator;

  constructor() {
    this.geneticOperator = new GeneticOperator();
    this.clear();
  }

  public setType(t: ShapeType) {
    this.type = t;
  }

  public clear() {
    this.cells.clear();
  }

  public getCells(): GridCoord[] {
    const res: GridCoord[] = [];
    this.cells.forEach((val, key) => {
        if (val) {
            const [x, y, z] = key.split(',').map(Number);
            res.push({ x, y, z });
        }
    });
    return res;
  }

  public setCell(x: number, y: number, z: number, active: boolean) {
    const key = `${Math.round(x)},${Math.round(y)},${Math.round(z)}`;
    if (active) {
        this.cells.set(key, true);
    } else {
        this.cells.delete(key);
    }
  }

  public hasCell(x: number, y: number, z: number): boolean {
      return this.cells.has(`${x},${y},${z}`);
  }

  // --- HEURISTICS ---

  public generateSmallCritter() {
      this.clear();
      const rng = () => Math.random();
      const length = 4 + Math.floor(rng() * 3);
      const wideStance = rng() > 0.4;
      const legX = wideStance ? 2 : 1;

      for(let z=0; z<length; z++) this.setCell(0, 1, z, true);

      const headZ = length - 1;
      this.setCell(0, 2, headZ, true);
      if (rng() > 0.5) this.setCell(0, 3, headZ, true);

      const frontLegZ = Math.max(0, headZ - 1);
      const backLegZ = 0;

      const addLeg = (z: number) => {
          this.setCell(legX, 0, z, true);
          this.setCell(1, 1, z, true);
          if (legX === 2) this.setCell(1, 0, z, true);
      };

      addLeg(backLegZ);
      addLeg(frontLegZ);

      for(let z=1; z < length - 1; z++) {
           if (rng() > 0.6) this.setCell(1, 1, z, true);
      }
      this.applyMirrorX();
  }

  public generateLargeBeast() {
    this.clear();
    const rng = () => Math.random();
    const range = (min: number, max: number) => Math.floor(Math.random() * (max - min + 1)) + min;

    const bodyLength = range(5, 8);
    const bodyHeight = range(2, 4); 
    const zOffset = -Math.floor(bodyLength / 2);

    for (let z = 0; z < bodyLength; z++) {
        const absZ = z + zOffset;
        this.setCell(0, bodyHeight, absZ, true);
        if (rng() > 0.4) this.setCell(0, bodyHeight + 1, absZ, true);
        if (rng() > 0.4 && bodyHeight > 1) this.setCell(0, bodyHeight - 1, absZ, true);
    }

    const numLegPairs = range(2, 4); 
    const legSpacing = Math.floor(bodyLength / numLegPairs);

    for (let i = 0; i < numLegPairs; i++) {
        const zIndex = (i * legSpacing) + Math.floor(legSpacing/2);
        if (zIndex >= bodyLength) continue;

        const startZ = zIndex + zOffset;
        const startY = bodyHeight;
        const startX = 0;
        let cx = startX;
        let cy = startY;
        let cz = startZ;

        cx++;
        this.setCell(cx, cy, cz, true);

        let safety = 0;
        while (cy > 0 && safety++ < 10) {
            const moveDown = rng() > 0.3; 
            if (moveDown) cy--;
            else {
                if (rng() > 0.4) cx++; 
                else cz += (rng() > 0.5 ? 1 : -1); 
            }
            this.setCell(cx, cy, cz, true);
        }

        if (cy === 0) {
            this.setCell(cx + 1, 0, cz, true);
            this.setCell(cx - 1, 0, cz, true);
        }
    }

    const headZ = (bodyLength - 1) + zOffset + 1;
    this.setCell(0, bodyHeight + 1, headZ, true);
    this.setCell(0, bodyHeight, headZ, true);
    this.setCell(0, bodyHeight - 1, headZ, true);

    this.applyMirrorX();
  }

  public applyWorm(length: number) {
      let curr = { x: 0, y: 0, z: 0 };
      this.setCell(0, 0, 0, true);

      for(let i=0; i<length; i++) {
          const axis = Math.floor(Math.random() * 3);
          const dir = Math.random() > 0.5 ? 1 : -1;

          if (axis === 0) curr.x += dir;
          if (axis === 1) curr.y += dir;
          if (axis === 2) curr.z += dir;
          if (Math.abs(curr.x) > 4) curr.x -= dir;
          if (Math.abs(curr.y) > 4) curr.y -= dir;
          if (Math.abs(curr.z) > 4) curr.z -= dir;

          this.setCell(curr.x, curr.y, curr.z, true);
      }
  }

  public applyMirrorX() {
      const newCells = new Map<string, boolean>();
      this.cells.forEach((_, key) => {
          const [x, y, z] = key.split(',').map(Number);
          newCells.set(key, true);

          if (this.type === ShapeType.HEX) {
              const mq = -x;
              const mr = z + x; 
              newCells.set(`${mq},${y},${mr}`, true);
          } else {
             const mx = -x;
             newCells.set(`${mx},${y},${z}`, true);
          }
      });
      this.cells = newCells;
  }

  public applyFloorFill() {
      for(let x=-2; x<=2; x++) {
          for(let z=-2; z<=2; z++) {
              this.setCell(x, 0, z, true);
          }
      }
  }

  public importOrganism(org: Organism) {
      this.clear();
      this.type = org.shape || ShapeType.CUBE; 

      // If we have metadata, use it (Exact reconstruction)
      for (const node of org.nodes) {
          if (node.originalGridCoord) {
              this.setCell(node.originalGridCoord.x, node.originalGridCoord.y, node.originalGridCoord.z, true);
          }
      }

      // If metadata missing (Legacy), we'd need inverse strategy logic
      // For now, assume metadata exists or we just fail gracefully (empty grid)
  }

  // --- EXPORT TO PHYSICS WITH BRAIN GRAFTING ---

  public generateOrganism(id: string, source?: Organism): Organism {
      const strategy: ILatticeStrategy = LatticeFactory.getStrategy(this.type);

      const nodes: Node[] = [];
      const muscles: Muscle[] = [];
      const coordToNodeId = new Map<string, string>();
      const createdMuscles = new Set<string>();

      const activeCoords = this.getCells();
      if (activeCoords.length === 0) {
          this.setCell(0,0,0, true);
          this.setCell(0,1,0, true);
          activeCoords.push({x:0,y:0,z:0}, {x:0,y:1,z:0});
      }

      // --- HEIGHT NORMALIZATION ---
      // Ensure the creature sits on the floor regardless of editor position
      let minY = Infinity;
      activeCoords.forEach(c => { 
          const w = strategy.gridToWorld(c, 0.8);
          if(w.y < minY) minY = w.y; 
      });
      const heightOffset = -minY + 0.1; // Slight float

      const scale = 0.8; 
      const mass = 1.0; 
      const friction = 0.8;

      // 1. Generate Nodes
      activeCoords.forEach((c) => {
          const nodeId = `n_${c.x}_${c.y}_${c.z}`;
          coordToNodeId.set(`${c.x},${c.y},${c.z}`, nodeId);

          const worldPos = strategy.gridToWorld(c, scale);
          worldPos.y += heightOffset;

          nodes.push({
              id: nodeId,
              pos: worldPos,
              oldPos: VectorOps.copy(worldPos),
              mass,
              friction,
              originalGridCoord: { x: c.x, y: c.y, z: c.z }
          });
      });

      // 2. Identify Head
      let maxZ = -Infinity;
      nodes.forEach(n => { if (n.pos.z > maxZ) maxZ = n.pos.z; });
      const candidatesZ = nodes.filter(n => Math.abs(n.pos.z - maxZ) < 0.1);
      let maxY = -Infinity;
      candidatesZ.forEach(n => { if (n.pos.y > maxY) maxY = n.pos.y; });
      let headNode = candidatesZ.find(n => Math.abs(n.pos.y - maxY) < 0.1);

      if (headNode) {
          // @ts-ignore
          headNode.isHead = true;
      }

      // 3. Benchmark Size
      let structureMinY = Infinity;
      let structureHeadY = headNode ? headNode.pos.y : 0;
      nodes.forEach(n => { if (n.pos.y < structureMinY) structureMinY = n.pos.y; });
      const initialVerticalSize = Math.max(0.1, structureHeadY - structureMinY);

      // 4. Connect Muscles using Strategy
      const addMuscle = (n1: string, n2: string, stiffness: number = 0.8) => {
          const k = [n1, n2].sort().join('-');
          if (createdMuscles.has(k)) return;

          const node1 = nodes.find(n => n.id === n1);
          const node2 = nodes.find(n => n.id === n2);
          if (!node1 || !node2) return;

          const dist = VectorOps.distance(node1.pos, node2.pos);
          muscles.push({
              id: `m_${k}`,
              nodeA: n1,
              nodeB: n2,
              baseLength: dist,
              stiffness: stiffness, 
              dnaIndex: muscles.length,
              phase: Math.random() * Math.PI * 2,
              freq: 1.0,
              amp: 0.0
          });
          createdMuscles.add(k);
      };

      activeCoords.forEach(c => {
          const myId = coordToNodeId.get(`${c.x},${c.y},${c.z}`);
          if (!myId) return;

          const neighbors = strategy.getNeighbors(c);
          neighbors.forEach(n => {
              const targetKey = `${n.coord.x},${n.coord.y},${n.coord.z}`;
              const targetId = coordToNodeId.get(targetKey);
              if (targetId) {
                  addMuscle(myId, targetId, n.distanceWeight);
              }
          });
      });

      // 5. Genome Init & Grafting
      const reservoirSize = 20;
      let genome = this.geneticOperator.createRandomGenome(muscles.length, nodes.length, reservoirSize);

      // GRAFTING: Preserve brain if shape is similar
      if (source && source.neuralGenome) {
          const oldGenome = source.neuralGenome;
          const oldMuscles = source.muscles;
          const oldNodes = source.nodes;

          // Copy parameters
          genome = this.geneticOperator.cloneGenome(oldGenome);

          // Resize Arrays if needed (Topology change)
          // Simple heuristics: If array lengths mismatch, we lose some data, but we try to keep what lines up.
          // Ideally, we map by ID, but IDs might change if generated differently.
          // Since we map by index in muscle list, topology changes ruin the brain mostly.
          // BUT, if we are just tweaking (adding a leg), the start of the list might align.

          // Reset weights array to new size, filling with old data where possible
          const resizeWeights = (target: number[], source: number[]) => {
              for(let i=0; i<target.length; i++) {
                  if (i < source.length) target[i] = source[i];
              }
          };

          const newSyn = this.geneticOperator.createRandomGenome(muscles.length, nodes.length).synapseWeights;
          resizeWeights(newSyn, oldGenome.synapseWeights);
          genome.synapseWeights = newSyn;

          // ... (Can implement more complex grafting here)
      }

      return {
          id,
          shape: this.type,
          nodes,
          muscles,
          neuralGenome: genome,
          fitness: source ? source.fitness : 0,
          generation: source ? source.generation : 1,
          energy: 100,
          maxEnergy: 100,
          hungerTime: 0,
          isAlive: true,
          foodEaten: 0,
          visibleFood: [],
          initialVerticalSize: initialVerticalSize, 
          currentHeightScore: 1.0, 
          accumulatedPostureScore: 0,
          bestHeightScore: 0
      };
  }
}

import { Node, Muscle, Organism, SimulationConfig } from './types';
import { VectorOps } from './math';
import { BrainController } from './neural/BrainController';

export class BioPhysicsEngine {
  private config: SimulationConfig;
  private readonly MAX_VELOCITY = 12.0; 

  // SOLVER SETTINGS
  private readonly RELAXATION_FACTOR = 0.25; 
  private readonly ITERATIONS = 6; 

  // DAMPING SETTINGS
  private readonly BASE_MUSCLE_DAMPING = 0.08; 
  private readonly ADAPTIVE_DAMPING_FACTOR = 0.12; 
  private readonly ROTATIONAL_DRAG = 0.92; 

  // AIR RESISTANCE
  private readonly DRAG_COEFFICIENT = 0.08; 

  // --- SOLIDITY CONSTANTS ---
  private readonly NODE_RADIUS = 0.1; 
  private readonly HARD_CONTACT_LIMIT = 0.22; 

  constructor(config: Partial<SimulationConfig> = {}) {
    this.config = {
      gravity: -60.0, 
      friction: 0.98, // Global air friction
      groundDamping: 0.8, // Increased ground damping (less bounce = more grip)
      timeStep: 0.016,
      shapeMemoryStrength: 0.85, 
      globalStiffness: 0.8, // Updated Default: 80% stiffness
      globalContractility: 1.5, // Updated Default: 150% muscle power
      ...config
    };
  }

  public setConfig(config: Partial<SimulationConfig>) {
      this.config = { ...this.config, ...config };
  }

  // fastMode: If true, runs lower fidelity physics for rapid evolutionary calculation
  public updateOrganism(organism: Organism, totalTime: number, fastMode: boolean = false): void {

    // 1. PHYSICS INTEGRATION
    // Note: Brain update is now handled externally by EvolutionService

    // Handle Ragdoll state
    if (!organism.isAlive) {
        organism.muscles.forEach(m => {
            m.stiffness = 0.05; // Very loose
            m.amp = 0; // Stop oscillating
            m.targetLength = m.baseLength;
        });
        // Release all grips if dead
        organism.nodes.forEach(n => {
            n.gripSignal = 1.0; 
            n.isGripping = false;
        });
    }

    // ADAPTIVE SUBSTEPS
    const subSteps = fastMode ? 4 : 12; 
    const subDt = this.config.timeStep / subSteps;
    const gravityVec = { x: 0, y: this.config.gravity * subDt * subDt, z: 0 };

    for(let s=0; s < subSteps; s++) {
        this.integrate(organism, subDt, gravityVec);
        if (!fastMode) this.applyRotationalDrag(organism); 

        // ITERATIVE SOLVER
        // In Fast Mode, we reduce iterations slightly
        const loops = fastMode ? 4 : this.ITERATIONS;

        for (let i = 0; i < loops; i++) {
            this.resolveMuscles(organism);

            // CRITICAL OPTIMIZATION:
            // Self-Collision is O(N^2). We disable it during rapid evolution.
            if (!fastMode) {
                this.resolveSelfCollisions(organism); 
            }
        }

        this.resolveFloor(organism);
    }
  }

  private applyRotationalDrag(organism: Organism): void {
      let cx = 0, cz = 0;
      let count = 0;
      for (const n of organism.nodes) {
          cx += n.pos.x;
          cz += n.pos.z;
          count++;
      }
      if (count === 0) return;
      cx /= count;
      cz /= count;

      let angularMomentum = 0;
      let momentOfInertia = 0;

      for (const n of organism.nodes) {
          const rx = n.pos.x - cx;
          const rz = n.pos.z - cz;

          const vx = n.pos.x - n.oldPos.x;
          const vz = n.pos.z - n.oldPos.z;

          const orbitalComponent = rx * vz - rz * vx;

          angularMomentum += orbitalComponent;
          momentOfInertia += rx * rx + rz * rz;
      }

      if (momentOfInertia < 0.001) return;

      const angularVel = angularMomentum / momentOfInertia;

      for (const n of organism.nodes) {
          const rx = n.pos.x - cx;
          const rz = n.pos.z - cz;

          const dampX = -angularVel * rz * this.ROTATIONAL_DRAG;
          const dampZ =  angularVel * rx * this.ROTATIONAL_DRAG;

          n.oldPos.x += dampX;
          n.oldPos.z += dampZ;
      }
  }

  private integrate(organism: Organism, dt: number, gravityVec: {x:number, y:number, z:number}): void {
    const { friction } = this.config;
    const maxStepDist = this.MAX_VELOCITY * dt;
    const maxStepSq = maxStepDist * maxStepDist;

    for (const node of organism.nodes) {
      if (node.isFixed) continue;

      let velX = node.pos.x - node.oldPos.x;
      let velY = node.pos.y - node.oldPos.y;
      let velZ = node.pos.z - node.oldPos.z;

      // 1. QUADRATIC DRAG
      const vSq = velX*velX + velY*velY + velZ*velZ;
      if (vSq > 0.000001) {
          const vLen = Math.sqrt(vSq);
          const dragFactor = 1.0 / (1.0 + this.DRAG_COEFFICIENT * vLen);

          velX *= dragFactor;
          velY *= dragFactor;
          velZ *= dragFactor;
      }

      // 2. Base Friction (Air)
      velX *= friction;
      velY *= friction;
      velZ *= friction;

      // 3. Hard Cap (Safety Terminator)
      const distSq = velX*velX + velY*velY + velZ*velZ;
      if (distSq > maxStepSq) {
          const scale = maxStepDist / Math.sqrt(distSq);
          velX *= scale;
          velY *= scale;
          velZ *= scale;
      }

      node.oldPos = VectorOps.copy(node.pos);

      node.pos.x += velX + gravityVec.x;
      node.pos.y += velY + gravityVec.y;
      node.pos.z += velZ + gravityVec.z;
    }
  }

  private resolveMuscles(organism: Organism): void {
    const GROUND_TOLERANCE = 0.02;
    const ANCHOR_MULTIPLIER = 0.1; 
    const MEMORY_STRENGTH = this.config.shapeMemoryStrength || 0.8;
    const GLOBAL_STIFFNESS = this.config.globalStiffness; 

    for (const muscle of organism.muscles) {
        const n1 = organism.nodes.find(n => n.id === muscle.nodeA);
        const n2 = organism.nodes.find(n => n.id === muscle.nodeB);

        if (!n1 || !n2) continue;

        const dx = n2.pos.x - n1.pos.x;
        const dy = n2.pos.y - n1.pos.y;
        const dz = n2.pos.z - n1.pos.z;
        const dist = Math.sqrt(dx*dx + dy*dy + dz*dz);

        if (dist < 0.0001) continue; 

        // 1. ACTIVE MUSCLE COMPONENT (The Brain's Desire)
        let activeTarget = muscle.targetLength || muscle.baseLength;
        // Safety limit to prevent implosion
        if (activeTarget < this.HARD_CONTACT_LIMIT) activeTarget = this.HARD_CONTACT_LIMIT;

        // Active stiffness is softer than structural memory
        // SCALED BY GLOBAL STIFFNESS
        let stiffness = muscle.stiffness * 0.8 * GLOBAL_STIFFNESS; 

        const activeDiff = dist - activeTarget;

        // 2. PASSIVE MEMORY COMPONENT (The Exoskeleton)
        // This force resists deviation from the Blueprint.

        // Calculate Deformation Percentage
        const deviation = Math.abs(dist - muscle.baseLength);
        const strain = deviation / muscle.baseLength;

        // NON-LINEAR RESTORING FORCE:
        const strainBoost = 1.0 + (strain * 4.0); 

        // SCALED BY GLOBAL STIFFNESS
        const currentMemoryStrength = organism.isAlive 
            ? MEMORY_STRENGTH * strainBoost * GLOBAL_STIFFNESS
            : MEMORY_STRENGTH * 0.1 * GLOBAL_STIFFNESS;

        const baseDiff = dist - muscle.baseLength;

        // --- DUAL FORCE BLENDING ---
        const activeCorrection = activeDiff * stiffness;
        const memoryCorrection = baseDiff * currentMemoryStrength;

        // Sum the corrections. 
        let totalCorrection = activeCorrection + memoryCorrection;

        // Apply Relaxation Factor (Iterative Solver Stability)
        totalCorrection *= this.RELAXATION_FACTOR;

        // --- DAMPING (Higher damping reduces twitch) ---
        const vx1 = n1.pos.x - n1.oldPos.x;
        const vy1 = n1.pos.y - n1.oldPos.y;
        const vz1 = n1.pos.z - n1.oldPos.z;
        const vx2 = n2.pos.x - n2.oldPos.x;
        const vy2 = n2.pos.y - n2.oldPos.y;
        const vz2 = n2.pos.z - n2.oldPos.z;

        const rvx = vx2 - vx1;
        const rvy = vy2 - vy1;
        const rvz = vz2 - vz1;

        const nx = dx / dist;
        const ny = dy / dist;
        const nz = dz / dist;

        const relVelSq = rvx*rvx + rvy*rvy + rvz*rvz;
        const relVel = Math.sqrt(relVelSq);

        const dynamicDamping = this.BASE_MUSCLE_DAMPING + (relVel * this.ADAPTIVE_DAMPING_FACTOR);

        const vRelProj = rvx * nx + rvy * ny + rvz * nz;
        totalCorrection += vRelProj * dynamicDamping;

        // --- MOMENTUM PRESERVATION ---
        // If a node is gripping, it acts like infinite mass (Fixed)
        let im1 = (n1.isFixed || n1.isGripping) ? 0 : 1 / n1.mass;
        let im2 = (n2.isFixed || n2.isGripping) ? 0 : 1 / n2.mass;

        if (n1.pos.y <= GROUND_TOLERANCE) im1 *= ANCHOR_MULTIPLIER;
        if (n2.pos.y <= GROUND_TOLERANCE) im2 *= ANCHOR_MULTIPLIER;

        const totalInvMass = im1 + im2;
        if (totalInvMass === 0) continue;

        const w1 = im1 / totalInvMass;
        const w2 = im2 / totalInvMass;

        const offsetX = nx * totalCorrection;
        const offsetY = ny * totalCorrection;
        const offsetZ = nz * totalCorrection;

        if (!n1.isFixed && !n1.isGripping) {
            n1.pos.x += offsetX * w1;
            n1.pos.y += offsetY * w1;
            n1.pos.z += offsetZ * w1;
        }

        if (!n2.isFixed && !n2.isGripping) {
            n2.pos.x -= offsetX * w2;
            n2.pos.y -= offsetY * w2;
            n2.pos.z -= offsetZ * w2;
        }
    }
  }

  private resolveSelfCollisions(organism: Organism): void {
      const nodes = organism.nodes;
      const count = nodes.length;

      const minDistance = this.HARD_CONTACT_LIMIT; 
      const minDistanceSq = minDistance * minDistance;

      for (let i = 0; i < count; i++) {
          for (let j = i + 1; j < count; j++) {
              const n1 = nodes[i];
              const n2 = nodes[j];

              const dx = n1.pos.x - n2.pos.x;
              const dy = n1.pos.y - n2.pos.y;
              const dz = n1.pos.z - n2.pos.z;
              const distSq = dx*dx + dy*dy + dz*dz;

              if (distSq < minDistanceSq && distSq > 0.000001) {
                  const dist = Math.sqrt(distSq);
                  const overlap = minDistance - dist;

                  // Soft repulsion (Relaxed)
                  const fx = (dx / dist) * overlap * 0.2; // Gentle push
                  const fy = (dy / dist) * overlap * 0.2;
                  const fz = (dz / dist) * overlap * 0.2;

                  if (!n1.isFixed) { 
                      n1.pos.x += fx; 
                      n1.pos.y += fy; 
                      n1.pos.z += fz; 
                  }
                  if (!n2.isFixed) { 
                      n2.pos.x -= fx; 
                      n2.pos.y -= fy; 
                      n2.pos.z -= fz; 
                  }
              }
          }
      }
  }

  private resolveFloor(organism: Organism): void {
    const RADIUS = this.NODE_RADIUS;
    const SUCTION_THRESHOLD = 0.5; // If release signal is < 0.5, we stick.

    for (const node of organism.nodes) {
      // 1. Check Floor Contact
      if (node.pos.y < RADIUS) {

        node.pos.y = RADIUS;

        // 2. SUCTION LOGIC (The "Active Grip" Upgrade)
        // Default (undefined) gripSignal is 0.0 -> Meaning "Full Grip" by default.
        // The brain must output > 0.5 to RELEASE the grip.
        const releaseSignal = node.gripSignal || 0;

        if (releaseSignal < SUCTION_THRESHOLD) {
            // --- GRIP ACTIVE ---
            node.isGripping = true;

            // Anchor in place (Stop X/Z movement)
            // We set current pos to previous pos to kill velocity in Verlet.
            node.pos.x = node.oldPos.x;
            node.pos.z = node.oldPos.z;
        } else {
            // --- GRIP RELEASED (Sliding) ---
            node.isGripping = false;

            const vx = node.pos.x - node.oldPos.x;
            const vz = node.pos.z - node.oldPos.z;

            // Apply standard dynamic friction when sliding
            const frictionCoeff = 0.85; // Slippery when release is held
            node.oldPos.x = node.pos.x - vx * frictionCoeff;
            node.oldPos.z = node.pos.z - vz * frictionCoeff;
        }
      } else {
          // Not touching ground
          node.isGripping = false;
      }
    }
  }
}

import { Organism, Node } from '../types';
import { NeuralNode } from './NeuralNode';
import { CentralPatternGenerator } from './CentralPatternGenerator';
import { VectorOps } from '../math';

export class BrainController {
  private neuralNodes: Map<string, NeuralNode> = new Map();
  private cpg: CentralPatternGenerator;
  private organism: Organism;
  private isInitialized = false;

  // Simulation Time Tracker
  private internalTime = 0;

  // Spinal Wave Props
  private headNodeId: string | null = null;
  private muscleRestDistances: Map<string, number> = new Map();

  // Decision Timer
  private decisionTimer = 0;
  private readonly DECISION_INTERVAL_BASE = 0.08; 

  // --- LEARNING MEMORY ---
  private previousEnergy: number = 0;
  private previousDistanceToFood: number = Infinity;
  private readonly VISION_RADIUS = 4.0;
  private readonly HEBBIAN_RATE = 0.15; // Learning Rate

  constructor(organism: Organism) {
    this.organism = organism;
    this.cpg = new CentralPatternGenerator(20);
    this.previousEnergy = organism.energy;

    organism.nodes.forEach(node => {
      this.neuralNodes.set(node.id, new NeuralNode(node));
    });

    if (organism.neuralGenome) {
        this.cpg.initialize(organism.neuralGenome.reservoirWeights);
    }
  }

  private initializeNervousSystem() {
      if (this.organism.nodes.length === 0) return;

      // Identify Head (The one tagged isHead, or fallback to highest Z)
      let headNode = this.organism.nodes.find(n => n.isHead);
      if (!headNode) {
          headNode = this.organism.nodes[0];
          for(const n of this.organism.nodes) {
              if (n.pos.z > headNode.pos.z) headNode = n;
          }
          // @ts-ignore
          headNode.isHead = true; 
      }
      this.headNodeId = headNode.id;

      this.organism.muscles.forEach(m => {
          const nA = this.organism.nodes.find(n => n.id === m.nodeA);
          const nB = this.organism.nodes.find(n => n.id === m.nodeB);
          if (nA && nB) {
              const midX = (nA.pos.x + nB.pos.x) / 2;
              const midY = (nA.pos.y + nB.pos.y) / 2;
              const midZ = (nA.pos.z + nB.pos.z) / 2;

              const dist = VectorOps.distance(
                  headNode!.pos, 
                  { x: midX, y: midY, z: midZ }
              );
              this.muscleRestDistances.set(m.id, dist);
          }
      });

      this.organism.muscles.forEach(m => {
          m.targetLength = m.baseLength;
          m.phase = Math.random() * Math.PI * 2; 
          m.freq = 1.0; 
          m.amp = 0.0;
      });

      this.isInitialized = true;
  }

  public update(dt: number, powerScale: number = 1.0): void {
    const genome = this.organism.neuralGenome;
    if (!genome) return;

    // EVOLVABLE TIME DILATION:
    // Some brains run faster than others.
    // Default 1.0. Range 0.5 to 2.0.
    const brainDt = dt * (genome.internalClockSpeed || 1.0);

    if (!this.isInitialized) {
        this.initializeNervousSystem();
    }

    this.internalTime += brainDt;

    this.decisionTimer += brainDt;
    if (this.decisionTimer >= this.DECISION_INTERVAL_BASE) {
        this.think(brainDt);
        // SELF-REWARD MECHANISM: Learn from eating + movement + balance
        this.learn();
        this.decisionTimer = 0;
    }

    // --- SPINAL WAVE (Motor Control) ---
    // EVOLVABLE WAVE DYNAMICS
    const WAVE_FREQ = genome.waveFreq || 1.5; 
    const WAVE_SPEED = genome.waveSpeed || 1.0; 

    const FORCED_AMP = 0.15; 
    const MAX_DEFORMATION = 0.3; // Hard Clamp: Muscles can only expand/contract 30%

    this.organism.muscles.forEach(m => {
        m.phase += m.freq * brainDt * (Math.PI * 2);
        if (m.phase > Math.PI * 2) m.phase -= Math.PI * 2;
        const brainSignal = Math.sin(m.phase) * m.amp;

        const dist = this.muscleRestDistances.get(m.id) || 0;
        const nerveLag = dist * WAVE_SPEED;
        const spinalSignal = Math.sin(this.internalTime * WAVE_FREQ * Math.PI * 2 - nerveLag) * FORCED_AMP;

        let totalSignal = (spinalSignal + brainSignal) * powerScale;

        // SIGNAL CLAMPING: Prevent extreme distortion command
        if (totalSignal > MAX_DEFORMATION) totalSignal = MAX_DEFORMATION;
        if (totalSignal < -MAX_DEFORMATION) totalSignal = -MAX_DEFORMATION;

        const desiredLength = m.baseLength * (1 + totalSignal);

        // MUSCLE INERTIA: Slow down the reaction to prevent twitching
        // Lower value = smoother, heavier feel.
        const reactionSpeed = 0.05; 

        if (!m.targetLength) m.targetLength = m.baseLength;
        m.targetLength += (desiredLength - m.targetLength) * reactionSpeed;
        m.currentLength = m.targetLength;
    });
  }

  private think(dt: number): void {
    const genome = this.organism.neuralGenome;

    // 1. GATHER PROPRIOCEPTION (Internal Body Sense)
    let globalSensoryInput = 0;
    this.neuralNodes.forEach(nn => {
        nn.sense(dt); 
        globalSensoryInput += nn.inputSum; 
    });

    // 2. VISION WITH GATED ATTENTION
    const head = this.organism.nodes.find(n => n.isHead);
    if (head) {
        // --- UPGRADE 4: GATED ATTENTION ---
        // If falling/unstable, ignore food to focus on balance.
        // Stability is 0 when y < 0.2, ramps up to 1.0 at y > 1.2
        const stability = Math.min(1.0, Math.max(0, (head.pos.y - 0.2))); 

        // Find nearest food
        let nearestDist = Infinity;
        let targetVec = { x: 0, y: 0, z: 0 };
        let foundFood = false;

        for (const food of this.organism.visibleFood) {
            if (food.consumed) continue;

            const dx = food.pos.x - head.pos.x;
            const dy = food.pos.y - head.pos.y;
            const dz = food.pos.z - head.pos.z;
            const distSq = dx*dx + dy*dy + dz*dz;

            if (distSq < this.VISION_RADIUS * this.VISION_RADIUS) {
                if (distSq < nearestDist) {
                    nearestDist = distSq;
                    targetVec = { x: dx, y: dy, z: dz };
                    foundFood = true;
                }
            }
        }

        // Update dist for learning step
        this.previousDistanceToFood = foundFood ? Math.sqrt(nearestDist) : Infinity;

        if (foundFood && stability > 0.1) {
            const dist = Math.sqrt(nearestDist);
            const headNeural = this.neuralNodes.get(head.id);
            if (headNeural) {
                // Scale signal by stability. Dizzy creatures can't focus.
                const signalStrength = Math.max(0, 1.0 - (dist / this.VISION_RADIUS)) * stability;

                headNeural.inputSum += (targetVec.x / dist) * signalStrength * 3.0; 
                headNeural.inputSum += (targetVec.y / dist) * signalStrength * 3.0; 
                headNeural.inputSum += (targetVec.z / dist) * signalStrength * 3.0; 

                globalSensoryInput += signalStrength * 2.0;
            }
        }
    }

    globalSensoryInput /= (this.neuralNodes.size || 1);

    // 3. SYNAPTIC PROPAGATION (The "Thinking")
    this.organism.muscles.forEach((muscle, i) => {
        const nnA = this.neuralNodes.get(muscle.nodeA);
        const nnB = this.neuralNodes.get(muscle.nodeB);
        if (nnA && nnB) {
            const w = genome.synapseWeights[i % genome.synapseWeights.length];
            // Bidirectional flow
            nnB.inputSum += nnA.activation * w;
            nnA.inputSum += nnB.activation * w;
        }
    });

    this.neuralNodes.forEach(nn => nn.updateActivation());

    // 4. RESERVOIR COMPUTING & PREDICTIVE CODING
    this.cpg.tick(globalSensoryInput);

    // --- PREDICTIVE CODING (Velocity) ---
    if (genome.predictionWeights) {
        // ... (Existing prediction logic)
    }

    // 5. MOTOR OUTPUT (Muscles)
    this.organism.muscles.forEach((muscle, i) => {
        const rawAmp = this.cpg.getSignal(i, genome.outputWeights); 
        const rawFreq = this.cpg.getSignal(i + 1, genome.outputWeights); 

        const targetAmp = Math.abs(rawAmp) * 0.3; 
        const minFreq = 0.5;
        const maxFreq = 3.0; 
        const targetFreq = minFreq + ((rawFreq + 1) / 2) * (maxFreq - minFreq);

        const lerpRate = 0.1; 
        muscle.amp += (targetAmp - muscle.amp) * lerpRate;
        muscle.freq += (targetFreq - muscle.freq) * lerpRate;
    });

    // 6. SUCTION OUTPUT (Nodes)
    // The brain now controls the grip of each foot individually.
    if (genome.gripWeights && genome.gripWeights.length > 0) {
        this.organism.nodes.forEach((node, i) => {
            // Get signal from reservoir for this specific node
            const rawSignal = this.cpg.getSignal(i, genome.gripWeights);
            // Convert tanh (-1 to 1) to 0.0 to 1.0
            const normalized = (rawSignal + 1) / 2;

            // Smooth it out to prevent flickering grip
            const oldGrip = node.gripSignal || 0;
            node.gripSignal = oldGrip + (normalized - oldGrip) * 0.2;
        });
    } else {
        // Fallback for old genomes: Always try to release slightly, but mostly stick
        this.organism.nodes.forEach(n => n.gripSignal = 0.2); 
    }
  }

  // --- SELF-REWARDING MECHANISM (Hebbian Learning) ---
  private learn(): void {
      const genome = this.organism.neuralGenome;
      let learningSignal = 0;

      // 1. METABOLIC REWARD (Eating)
      const currentEnergy = this.organism.energy;
      const energyDelta = currentEnergy - this.previousEnergy;
      if (energyDelta > 0.5) learningSignal += 1.0;
      this.previousEnergy = currentEnergy;


      const currentDist = this.previousDistanceToFood; 

      // --- UPGRADE 2: VESTIBULAR PAIN ---
      const head = this.organism.nodes.find(n => n.isHead);
      if (head) {
          if (head.pos.y < 0.2) {
              // Pain! Punish active connections.
              learningSignal -= 0.5; 
          }
      }

      // APPLY LEARNING
      if (Math.abs(learningSignal) > 0.1) {
          this.organism.muscles.forEach((muscle, i) => {
            const nnA = this.neuralNodes.get(muscle.nodeA);
            const nnB = this.neuralNodes.get(muscle.nodeB);

            if (nnA && nnB) {
                const wIdx = i % genome.synapseWeights.length;
                const coActivity = nnA.activation * nnB.activation;

                if (coActivity > 0.1) {
                    // Hebbian (Signal > 0) or Anti-Hebbian (Signal < 0)
                    genome.synapseWeights[wIdx] += this.HEBBIAN_RATE * learningSignal * coActivity;

                    // Clamp
                    if (genome.synapseWeights[wIdx] > 3.0) genome.synapseWeights[wIdx] = 3.0;
                    if (genome.synapseWeights[wIdx] < -3.0) genome.synapseWeights[wIdx] = -3.0;
                }
            }
          });
      }
  }
}

import { Organism, ShapeType, Node, Muscle, NeuralGenome } from './types';
import { VectorOps } from './math';
import { GeneticOperator } from './genetics/GeneticOperator';

export class ShapeFactory {

  static create(type: ShapeType, id: string): Organism {
    let nodes: Node[] = [];
    let muscles: Muscle[] = [];

    switch (type) {
      case ShapeType.CUBE:
        ({ nodes, muscles } = this.createCube());
        break;
      case ShapeType.WORM:
        ({ nodes, muscles } = this.createWorm(4));
        break;
      case ShapeType.TETRAHEDRON:
      default:
        ({ nodes, muscles } = this.createTetrahedron());
        break;
    }

    // Initialize Neural Genome
    const operator = new GeneticOperator();
    const genome = operator.createRandomGenome(muscles.length, nodes.length);

    muscles.forEach((m, i) => m.dnaIndex = i);

    // Identify Head (Furthest Forward, then Highest Up)
    let maxZ = -Infinity;
    nodes.forEach(n => { if (n.pos.z > maxZ) maxZ = n.pos.z; });

    let candidates: Node[] = [];
    nodes.forEach(n => {
        if (Math.abs(n.pos.z - maxZ) < 0.1) candidates.push(n);
    });

    let headNode: Node | null = null;
    let maxY = -Infinity;
    candidates.forEach(n => {
        if (n.pos.y > maxY) {
            maxY = n.pos.y;
            headNode = n;
        }
    });

    if (headNode) {
        // @ts-ignore
        headNode.isHead = true;
    }

    // Calculate Benchmark Size
    let minY = Infinity;
    let headY = headNode ? headNode.pos.y : 0;
    nodes.forEach(n => { if (n.pos.y < minY) minY = n.pos.y; });
    const initialVerticalSize = Math.max(0.1, headY - minY);

    return {
      id,
      shape: type, // Store shape type for editor consistency
      nodes,
      muscles,
      neuralGenome: genome,
      fitness: 0,
      generation: 1,
      // Metabolism Defaults
      energy: 100,
      maxEnergy: 100,
      hungerTime: 0,
      isAlive: true,
      foodEaten: 0,
      visibleFood: [],
      // Posture Defaults
      initialVerticalSize: initialVerticalSize,
      currentHeightScore: 1.0, // Start perfect
      accumulatedPostureScore: 0,
      bestHeightScore: 0
    };
  }

  private static createTetrahedron() {
    const f = 0.95; // High friction for grip
    const m = 4.0;  // Heavy mass

    const nodes: Node[] = [
      { id: 'n1', pos: { x: 0, y: 0, z: 1 }, oldPos: { x: 0, y: 0, z: 1 }, mass: m, friction: f },
      { id: 'n2', pos: { x: 1, y: 0, z: -0.7 }, oldPos: { x: 1, y: 0, z: -0.7 }, mass: m, friction: f },
      { id: 'n3', pos: { x: -1, y: 0, z: -0.7 }, oldPos: { x: -1, y: 0, z: -0.7 }, mass: m, friction: f },
      { id: 'n4', pos: { x: 0, y: 1.5, z: 0 }, oldPos: { x: 0, y: 1.5, z: 0 }, mass: m, friction: f },
    ];
    const muscles = this.connectAll(nodes);
    return { nodes, muscles };
  }

  private static createCube() {
    const nodes: Node[] = [];
    const size = 1.0;
    const startY = 0.5;
    const f = 0.95; 
    const m = 4.0; 

    for(let x=0; x<=1; x++) {
      for(let y=0; y<=1; y++) {
        for(let z=0; z<=1; z++) {
          const px = (x - 0.5) * size;
          const py = startY + y * size;
          const pz = (z - 0.5) * size;
          nodes.push({
            id: `n${x}${y}${z}`,
            pos: { x: px, y: py, z: pz },
            oldPos: { x: px, y: py, z: pz },
            mass: m, 
            friction: f
          });
        }
      }
    }
    const muscles = this.connectDistanceThreshold(nodes, size * 1.8);
    return { nodes, muscles };
  }

  private static createWorm(segments: number) {
    const nodes: Node[] = [];
    const size = 1.0;
    const bellyFriction = 0.5; // Belly slides a bit
    const footFriction = 0.98; // Feet grip hard
    const m = 4.0; 

    for (let i = 0; i < segments; i++) {
        const offset = i * size;
        nodes.push(
            { id: `n${i}_a`, pos: { x: -0.5, y: 0, z: offset }, oldPos: { x: -0.5, y: 0, z: offset }, mass: m, friction: footFriction },
            { id: `n${i}_b`, pos: { x: 0.5, y: 0, z: offset }, oldPos: { x: 0.5, y: 0, z: offset }, mass: m, friction: footFriction },
            { id: `n${i}_top`, pos: { x: 0, y: 1, z: offset + 0.5 }, oldPos: { x: 0, y: 1, z: offset + 0.5 }, mass: m, friction: bellyFriction }
        );
    }
    return { nodes, muscles: this.connectDistanceThreshold(nodes, size * 1.5) };
  }

  private static connectAll(nodes: Node[]): Muscle[] {
    const muscles: Muscle[] = [];
    let mCount = 0;
    for (let i = 0; i < nodes.length; i++) {
      for (let j = i + 1; j < nodes.length; j++) {
        const dist = VectorOps.distance(nodes[i].pos, nodes[j].pos);
        muscles.push({
          id: `m${mCount++}`,
          nodeA: nodes[i].id,
          nodeB: nodes[j].id,
          baseLength: dist,
          stiffness: 1.0, // Maximum stiffness for bones
          dnaIndex: 0,
          // Init Oscillator
          phase: Math.random() * Math.PI * 2,
          freq: 1.0,
          amp: 0.0
        });
      }
    }
    return muscles;
  }

    private static connectDistanceThreshold(nodes: Node[], threshold: number): Muscle[] {
      const muscles: Muscle[] = [];
      let mCount = 0;
      for (let i = 0; i < nodes.length; i++) {
        for (let j = i + 1; j < nodes.length; j++) {
          const dist = VectorOps.distance(nodes[i].pos, nodes[j].pos);
          if (dist <= threshold) {
            muscles.push({
              id: `m${mCount++}`,
              nodeA: nodes[i].id,
              nodeB: nodes[j].id,
              baseLength: dist,
              stiffness: 1.0,
              dnaIndex: 0,
              // Init Oscillator
              phase: Math.random() * Math.PI * 2,
              freq: 1.0,
              amp: 0.0
            });
          }
        }
      }
      return muscles;
    }
}

import { BioPhysicsEngine } from '../domain/BioPhysicsEngine';
import { Organism, ShapeType, NeuralGenome, FoodItem, Node } from '../domain/types';
import { ShapeFactory } from '../domain/ShapeFactory';
import { VectorOps } from '../domain/math';
import { GeneticOperator } from '../domain/genetics/GeneticOperator';
import { IFitnessEvaluator, StandardFitnessEvaluator } from '../domain/fitness/FitnessEvaluator';
import { BrainController } from '../domain/neural/BrainController';

export class EvolutionService {
  public population: Organism[] = [];
  public currentGeneration = 1;
  public simulationTime = 0;

  private engine: BioPhysicsEngine;
  private geneticOperator: GeneticOperator;
  private fitnessEvaluator: IFitnessEvaluator;

  private populationSize = 20;
  private template: Organism | null = null; 

  // METABOLISM CONSTANTS
  private readonly START_ENERGY = 100;
  private readonly BASE_DECAY = 4.0; 
  private readonly HUNGER_ACCEL = 1.15; 
  private readonly FOOD_ENERGY = 30;

  // FEEDING MECHANICS
  public readonly MAGNET_RADIUS = 1.5; 
  private readonly MAGNET_FORCE = 0.8;  
  private readonly EAT_RADIUS = 0.8;    

  // SCARCITY CONTROLS (Tweakable via UI)
  public foodSpawnCount = 50;
  public foodSpawnRadius = 3.5;

  // OBSERVER PATTERN
  private updateListeners: ((pop: Organism[], time: number) => void)[] = [];
  private genCompleteListeners: ((best: Organism, gen: number) => void)[] = [];
  private newGenListeners: ((pop: Organism[]) => void)[] = [];

  constructor() {
    this.engine = new BioPhysicsEngine();
    this.geneticOperator = new GeneticOperator(0.05); // 5% mutation rate
    this.fitnessEvaluator = new StandardFitnessEvaluator();
  }

  public setGlobalStiffness(val: number) {
      this.engine.setConfig({ globalStiffness: val });
  }

  public setGlobalContractility(val: number) {
      this.engine.setConfig({ globalContractility: val });
  }

  // --- CONFIGURATION SETTERS ---
  public set foodWeight(val: number) {
      this.fitnessEvaluator.setWeights(val, (this.fitnessEvaluator as any).heightWeight);
  }
  public get foodWeight(): number { return (this.fitnessEvaluator as any).foodWeight; }

  public set heightWeight(val: number) {
       this.fitnessEvaluator.setWeights((this.fitnessEvaluator as any).foodWeight, val);
  }
  public get heightWeight(): number { return (this.fitnessEvaluator as any).heightWeight; }

  // --- REAL-TIME UPDATES ---

  public updateFoodDistribution(): void {
      this.population.forEach(org => {
          org.visibleFood = this.generateFoodTrack(org);
      });
  }

  // --- INITIALIZATION ---

  public initializePopulation(shape: ShapeType): void {
    this.template = ShapeFactory.create(shape, 'template');
    this.spawnGenerationFromTemplate(true);
  }

  public setTemplateAndReset(organism: Organism, startGeneration: number = 1): void {
      const safeJson = JSON.stringify(organism, (key, value) => {
          if (key === 'brain') return undefined;
          return value;
      });
      this.template = JSON.parse(safeJson);

      this.currentGeneration = startGeneration;
      this.spawnGenerationFromTemplate(false); 
  }

  private spawnGenerationFromTemplate(resetGen: boolean): void {
      if (!this.template) return;

      this.population = [];
      if (resetGen) this.currentGeneration = 1;
      this.simulationTime = 0;

      for (let i = 0; i < this.populationSize; i++) {
          const child = this.createOrganismFromTemplate(this.template, `gen${this.currentGeneration}_${i}`);

          if (i > 0) {
              this.geneticOperator.mutateGenome(child.neuralGenome);
          }

          child.visibleFood = this.generateFoodTrack(child);
          this.fitnessEvaluator.evaluate(child, 0.016);

          this.population.push(child);
      }

      this.notifyNewGeneration(this.population);
  }

  private generateFoodTrack(organism: Organism): FoodItem[] {
      const food: FoodItem[] = [];
      const numFood = this.foodSpawnCount; 

      let centerX = 0;
      let centerZ = 0;

      let head = organism.nodes.find(n => n.isHead);
      if (!head && organism.nodes.length > 0) head = organism.nodes[0];

      if (head) {
          centerX = head.pos.x;
          centerZ = head.pos.z;
      }

      const spread = this.foodSpawnRadius; 

      for(let i=0; i<numFood; i++) {
          const theta = Math.random() * Math.PI * 2;
          const radius = 1.0 + Math.random() * spread; 
          const x = centerX + Math.cos(theta) * radius;
          const z = centerZ + Math.sin(theta) * radius;
          const y = 1.0 + Math.random() * 2.5;

          food.push({
              id: `f_${i}`,
              pos: { x, y, z },
              energyValue: this.FOOD_ENERGY,
              consumed: false
          });
      }
      return food;
  }

  // --- SERIALIZATION ---

  public getBestOrganism(): Organism | null {
      if (this.population.length === 0) return null;
      const sorted = [...this.population].sort((a, b) => b.fitness - a.fitness);
      const best = sorted[0];

      const safeJson = JSON.stringify(best, (key, value) => {
          if (key === 'brain') return undefined;
          return value;
      });
      const cleanCopy = JSON.parse(safeJson);
      cleanCopy.generation = this.currentGeneration;

      return cleanCopy;
  }

  public getLeader(): Organism | null {
      if (this.population.length === 0) return null;

      let bestAlive: Organism | null = null;
      let maxZAlive = -Infinity;

      let bestDead: Organism | null = null;
      let maxZDead = -Infinity;

      for (const org of this.population) {
          let cz = 0;
          for(const n of org.nodes) cz += n.pos.z;
          cz /= org.nodes.length;

          if (org.isAlive) {
              if (cz > maxZAlive) { maxZAlive = cz; bestAlive = org; }
          } else {
              if (cz > maxZDead) { maxZDead = cz; bestDead = org; }
          }
      }

      return bestAlive || bestDead || this.population[0];
  }

  // --- LOOP ---

  public step(dt: number): void {
    this.simulationTime += dt;
    this.updatePhysics(dt, false);
    this.updateMetabolism(dt);

    if (Math.floor(this.simulationTime * 100) % 100 === 0) {
        this.applySocialLearning();
    }

    const allDead = !this.population.some(org => org.isAlive);
    if (allDead) {
        this.evolve();
    }

    this.notifyUpdate(this.population, this.simulationTime);
  }

  private applySocialLearning() {
      const sorted = [...this.population].sort((a, b) => b.fitness - a.fitness);
      if (sorted.length < 2) return;

      const leader = sorted[0];
      const bottomHalfStart = Math.floor(sorted.length / 2);

      for(let i=bottomHalfStart; i<sorted.length; i++) {
          const learner = sorted[i];
          if (!learner.isAlive) continue;

          const learningRate = 0.05; 
          const lg = learner.neuralGenome;
          const bg = leader.neuralGenome;

          for(let k=0; k<lg.synapseWeights.length; k++) {
              if (bg.synapseWeights[k] !== undefined) {
                  lg.synapseWeights[k] += (bg.synapseWeights[k] - lg.synapseWeights[k]) * learningRate;
              }
          }
      }
  }

  public async computeGenerationAsync(
    maxSafetyTime: number, 
    shouldStop: () => boolean, 
    onProgress?: (pct: number) => void
  ): Promise<void> {
      const dt = 0.016; 
      const BATCH_DURATION = 0.012; 
      let allDead = false;

      while (!allDead && this.simulationTime < maxSafetyTime) {
          if (shouldStop()) throw new Error("Evolution Aborted");

          let batchTime = 0;
          while (batchTime < BATCH_DURATION && !allDead && this.simulationTime < maxSafetyTime) {
              this.simulationTime += dt;
              batchTime += dt; 

              this.updatePhysics(dt, true);
              this.updateMetabolism(dt); 

              if (Math.abs(this.simulationTime % 1.0) < dt) {
                  this.applySocialLearning();
              }

              allDead = !this.population.some(org => org.isAlive);
          }

          const deadCount = this.population.filter(o => !o.isAlive).length;
          const pct = deadCount / this.populationSize;

          if (onProgress) onProgress(pct);
          await new Promise(resolve => setTimeout(resolve, 0));
      }

      this.finalizeFitness();
  }

  private updatePhysics(dt: number, fastMode: boolean): void {
    this.population.forEach(org => {
      // ORCHESTRATION: Update Brain THEN Physics
      // This decouples the brain from the engine
      if (org.isAlive) {
         if (!org.brain) {
             org.brain = new BrainController(org);
         }
         // Configurable muscle power is passed here from engine config via service
         const contractility = (this.engine as any).config.globalContractility;
         org.brain.update(dt, contractility);
      }

      this.engine.updateOrganism(org, this.simulationTime, fastMode);
    });
  }

  private updateMetabolism(dt: number): void {
      this.population.forEach(org => {
          // 1. Calculate Fitness
          this.fitnessEvaluator.evaluate(org, dt);

          if (!org.isAlive) return;

          org.hungerTime += dt;
          const hungerMultiplier = Math.pow(this.HUNGER_ACCEL, org.hungerTime);
          const loss = this.BASE_DECAY * hungerMultiplier * dt;
          org.energy -= loss;

          if (org.energy <= 0) {
              org.energy = 0;
              org.isAlive = false;
              return; 
          }

          let head = org.nodes.find(n => n.isHead);
          if (!head && org.nodes.length > 0) {
              let highest = org.nodes[0];
              for(const n of org.nodes) {
                  if (n.pos.y > highest.pos.y) highest = n;
              }
              head = highest;
              // @ts-ignore
              head.isHead = true; 
          }

          if (head) {
            for (const food of org.visibleFood) {
                if (food.consumed) continue;

                const dist = VectorOps.distance(head.pos, food.pos);

                if (dist < this.MAGNET_RADIUS) {
                    const pull = VectorOps.sub(head.pos, food.pos);
                    const strength = 1.0 - (dist / this.MAGNET_RADIUS);
                    const force = this.MAGNET_FORCE * (1.0 + strength);

                    food.pos.x += pull.x * force * 0.1;
                    food.pos.y += pull.y * force * 0.1;
                    food.pos.z += pull.z * force * 0.1;

                    const newDist = VectorOps.distance(head.pos, food.pos);

                    if (newDist < this.EAT_RADIUS) {
                        food.consumed = true;
                        org.energy += food.energyValue;
                        if (org.energy > org.maxEnergy) org.energy = org.maxEnergy;
                        org.hungerTime = 0;
                        org.foodEaten++;
                    }
                }
            }
          }
      });
  }

  private finalizeFitness() {
      this.population.forEach(org => this.fitnessEvaluator.finalize(org));
  }

  public evolve(): void {
    if (!this.template) return;

    this.finalizeFitness(); 

    // 1. Selection
    this.population.sort((a, b) => b.fitness - a.fitness);
    const survivorsCount = Math.floor(this.populationSize * 0.25);
    const survivors = this.population.slice(0, survivorsCount);
    const bestOrganism = survivors[0];

    this.notifyGenComplete(bestOrganism, this.currentGeneration);

    // 2. Reproduction
    this.currentGeneration++;
    const nextGen: Organism[] = [];

    // Elitism
    const champion = this.createOrganismFromTemplate(this.template, `gen${this.currentGeneration}_champ`);
    champion.neuralGenome = this.geneticOperator.cloneGenome(bestOrganism.neuralGenome);
    champion.visibleFood = this.generateFoodTrack(champion);
    this.fitnessEvaluator.evaluate(champion, 0.016);
    nextGen.push(champion);

    // Fill
    while (nextGen.length < this.populationSize) {
      const parent = survivors[Math.floor(Math.random() * survivors.length)];
      const child = this.createOrganismFromTemplate(this.template, `gen${this.currentGeneration}_${nextGen.length}`);
      child.neuralGenome = this.geneticOperator.cloneGenome(parent.neuralGenome);
      this.geneticOperator.mutateGenome(child.neuralGenome);
      child.visibleFood = this.generateFoodTrack(child);
      this.fitnessEvaluator.evaluate(child, 0.016);
      nextGen.push(child);
    }

    this.population = nextGen;
    this.simulationTime = 0;

    this.notifyNewGeneration(this.population);
  }

  // --- HELPERS ---

  private createOrganismFromTemplate(template: Organism, newId: string): Organism {
      const safeJson = JSON.stringify(template, (key, value) => {
          if (key === 'brain') return undefined;
          return value;
      });
      const clone: Organism = JSON.parse(safeJson);

      clone.id = newId;
      clone.fitness = 0;
      clone.brain = undefined; 

      clone.nodes.forEach(n => {
          n.oldPos = { x: n.pos.x, y: n.pos.y, z: n.pos.z };
          n.activation = 0;
      });

      clone.energy = this.START_ENERGY;
      clone.maxEnergy = this.START_ENERGY;
      clone.hungerTime = 0;
      clone.isAlive = true;
      clone.foodEaten = 0;
      clone.visibleFood = []; 

      clone.bestHeightScore = 0;
      clone.currentHeightScore = 1.0; 
      clone.accumulatedPostureScore = 0; 

      if (typeof template.initialVerticalSize === 'number') {
           clone.initialVerticalSize = template.initialVerticalSize;
      } else {
           const head = clone.nodes.find(n => n.isHead);
           let minY = Infinity;
           clone.nodes.forEach(n => { if (n.pos.y < minY) minY = n.pos.y; });
           const hY = head ? head.pos.y : 1.0;
           clone.initialVerticalSize = Math.max(0.1, hY - minY);
      }

      return clone;
  }

  // --- OBSERVER PATTERN ---

  public subscribe(type: 'update', cb: (pop: Organism[], time: number) => void): () => void;
  public subscribe(type: 'genComplete', cb: (best: Organism, gen: number) => void): () => void;
  public subscribe(type: 'newGen', cb: (pop: Organism[]) => void): () => void;
  public subscribe(type: string, cb: any): () => void {
      if (type === 'update') {
          this.updateListeners.push(cb);
          return () => this.updateListeners = this.updateListeners.filter(l => l !== cb);
      }
      if (type === 'genComplete') {
          this.genCompleteListeners.push(cb);
          return () => this.genCompleteListeners = this.genCompleteListeners.filter(l => l !== cb);
      }
      if (type === 'newGen') {
          this.newGenListeners.push(cb);
          return () => this.newGenListeners = this.newGenListeners.filter(l => l !== cb);
      }
      return () => {};
  }

  // Backward compatibility alias for useEvolutionLoop
  public onUpdate(cb: (pop: Organism[], time: number) => void) { this.subscribe('update', cb); }
  public onGenComplete(cb: (best: Organism, gen: number) => void) { this.subscribe('genComplete', cb); }
  public onNewGeneration(cb: (pop: Organism[]) => void) { this.subscribe('newGen', cb); }

  private notifyUpdate(pop: Organism[], time: number) { this.updateListeners.forEach(l => l(pop, time)); }
  private notifyGenComplete(best: Organism, gen: number) { this.genCompleteListeners.forEach(l => l(best, gen)); }
  private notifyNewGeneration(pop: Organism[]) { this.newGenListeners.forEach(l => l(pop)); }
}

import { useEffect, useRef, useState, useCallback } from 'react';
import { EvolutionService } from './EvolutionService';
import { ShapeType, Organism } from '../domain/types';

export function useEvolutionLoop() {
  const serviceRef = useRef<EvolutionService>(new EvolutionService());
  const requestRef = useRef<number>(0);

  // Ref for synchronous access inside tight loops
  const isAutoEvolvingRef = useRef(false);

  const [population, setPopulation] = useState<Organism[]>([]);
  const [generation, setGeneration] = useState(1);
  const [currentShape, setCurrentShape] = useState<ShapeType>(ShapeType.TETRAHEDRON);
  const [isRunning, setIsRunning] = useState(false);
  const [isAutoEvolving, setIsAutoEvolvingState] = useState(false);

  const [isProcessing, setIsProcessing] = useState(false);
  const [progress, setProgress] = useState(0);

  // New Physics State (Updated Defaults)
  const [globalStiffness, setGlobalStiffnessState] = useState(0.8);
  const [globalContractility, setGlobalContractilityState] = useState(1.5);

  // Fitness Weights Configuration (Updated Defaults)
  const [foodWeight, setFoodWeightState] = useState(20.0);
  const [heightWeight, setHeightWeightState] = useState(100.0);

  // Scarcity Controls
  const [foodSpawnCount, setFoodSpawnCountState] = useState(50);
  const [foodSpawnRadius, setFoodSpawnRadiusState] = useState(3.5);

  // NEW: Live Stats for Dashboard
  const [currentStats, setCurrentStats] = useState({
      fitness: 0,
      foodEaten: 0,
      height: 0
  });

  // Initialize
  useEffect(() => {
    const service = serviceRef.current;

    // Wire up listeners
    let lastUpdate = 0;

    // Using subscription pattern
    const unsubUpdate = service.subscribe('update', (pop, time) => {
        // Throttled UI update (15 FPS is enough for text stats)
        if (time - lastUpdate > 0.06) {
            lastUpdate = time;

            const leader = service.getLeader();

            if (leader) {
                setCurrentStats({
                    fitness: leader.fitness,
                    foodEaten: leader.foodEaten,
                    height: leader.currentHeightScore || 0
                });
            }
        }
    });

    const unsubGen = service.subscribe('genComplete', (best, gen) => {
        setGeneration(gen);
    });

    const unsubNewGen = service.subscribe('newGen', (newPop) => {
        setPopulation([...newPop]);
    });

    service.initializePopulation(currentShape);
    setPopulation([...service.population]); // Initial sync

    return () => {
        cancelAnimationFrame(requestRef.current!);
        unsubUpdate();
        unsubGen();
        unsubNewGen();
    };
  }, []);

  const reset = useCallback((shape: ShapeType) => {
    setIsRunning(false);

    // Stop Auto
    isAutoEvolvingRef.current = false;
    setIsAutoEvolvingState(false);

    setIsProcessing(false);
    setCurrentShape(shape);
    serviceRef.current.initializePopulation(shape);
    setPopulation([...serviceRef.current.population]);
    setGeneration(1);
    setCurrentStats({ fitness: 0, foodEaten: 0, height: 1.0 }); // Start at 100% implicitly
  }, []);

  const spawnCustom = useCallback((organism: Organism) => {
      setIsRunning(false);
      isAutoEvolvingRef.current = false;
      setIsAutoEvolvingState(false);
      setIsProcessing(false);

      serviceRef.current.setTemplateAndReset(organism);
      setPopulation([...serviceRef.current.population]);
      setGeneration(1);
      setCurrentStats({ fitness: 0, foodEaten: 0, height: 1.0 });
      setCurrentShape(ShapeType.WORM); 
  }, []);

  const evolve = useCallback(() => {
    serviceRef.current.evolve();
    setPopulation([...serviceRef.current.population]); // Update React view
    setGeneration(serviceRef.current.currentGeneration);
  }, []);

  // --- PHYSICS CONTROL HANDLERS ---
  const setGlobalStiffness = useCallback((val: number) => {
      setGlobalStiffnessState(val);
      serviceRef.current.setGlobalStiffness(val);
  }, []);

  const setGlobalContractility = useCallback((val: number) => {
      setGlobalContractilityState(val);
      serviceRef.current.setGlobalContractility(val);
  }, []);

  // --- FITNESS WEIGHT HANDLERS ---
  const setFoodWeight = useCallback((val: number) => {
      setFoodWeightState(val);
      serviceRef.current.foodWeight = val;
  }, []);

  const setHeightWeight = useCallback((val: number) => {
      setHeightWeightState(val);
      serviceRef.current.heightWeight = val;
  }, []);

  // --- SCARCITY HANDLERS ---
  const setFoodSpawnCount = useCallback((val: number) => {
      setFoodSpawnCountState(val);
      serviceRef.current.foodSpawnCount = val;
      serviceRef.current.updateFoodDistribution(); // Real-time update
  }, []);

  const setFoodSpawnRadius = useCallback((val: number) => {
      setFoodSpawnRadiusState(val);
      serviceRef.current.foodSpawnRadius = val;
      serviceRef.current.updateFoodDistribution(); // Real-time update
  }, []);


  // --- DATA IO ---

  const saveCreature = useCallback(() => {
    const best = serviceRef.current.getBestOrganism();
    if (!best) return;

    const json = JSON.stringify(best, null, 2);
    const blob = new Blob([json], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `creature_gen${best.generation}_${Date.now()}.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  }, []);

  const loadCreature = useCallback((file: File, onLoaded?: (org: Organism) => void) => {
      const reader = new FileReader();
      reader.onload = (e) => {
          try {
              const json = e.target?.result as string;
              const organism = JSON.parse(json) as Organism;

              if (!organism.nodes || !organism.muscles || !organism.neuralGenome) {
                  alert("Invalid Creature File");
                  return;
              }

              // Stop everything
              setIsRunning(false);
              isAutoEvolvingRef.current = false;
              setIsAutoEvolvingState(false);
              setIsProcessing(false);

              // Inject
              const startGen = organism.generation || 1;
              serviceRef.current.setTemplateAndReset(organism, startGen);

              setPopulation([...serviceRef.current.population]);
              setGeneration(startGen);
              setCurrentStats({ fitness: 0, foodEaten: 0, height: 0 });

              // Notify App
              if (onLoaded) onLoaded(organism);

          } catch (err) {
              console.error(err);
              alert("Failed to load creature file.");
          }
      };
      reader.readAsText(file);
  }, []);


  // --- AUTO EVOLUTION ---

  const runAutoEvolution = useCallback(async () => {
      if (isProcessing) return; // Prevent double entry

      setIsProcessing(true);

      try {
          // 1. Compute Generation Async (Yielding to UI)
          // We pass a callback that checks our Ref. If ref is false, service throws error.
          await serviceRef.current.computeGenerationAsync(
              10.0, 
              () => !isAutoEvolvingRef.current, // Stop Signal
              (pct) => setProgress(pct)
          );

          // 2. Evolve (Only if we finished successfully)
          evolve();

          // 3. Reset for next round
          setProgress(0);
          setIsProcessing(false);

      } catch (e) {
          // If we aborted (or other error), we catch it here.
          console.log("Evolution Stopped or Aborted");
          setIsProcessing(false);
          // Do NOT evolve. We stay on the current generation.
      }
  }, [isProcessing, evolve]);

  const toggleAutoEvolve = useCallback(() => {
      const newState = !isAutoEvolvingRef.current;
      isAutoEvolvingRef.current = newState;
      setIsAutoEvolvingState(newState);

      // If turning ON, ensure regular run is off (optional, but cleaner)
      if (newState) setIsRunning(false);
  }, []);

  const loop = useCallback(() => {
    // If neither running nor auto, stop loop
    if (!isRunning && !isAutoEvolving) return;

    if (isAutoEvolving) {
        if (!isProcessing) {
            runAutoEvolution();
        }
    } else {
        // NORMAL MODE: 60 FPS Physics
        if (isRunning) {
            serviceRef.current.step(0.016);
        }
    }

    requestRef.current = requestAnimationFrame(loop);
  }, [isRunning, isAutoEvolving, isProcessing, runAutoEvolution]);

  useEffect(() => {
    if (isRunning || isAutoEvolving) {
      requestRef.current = requestAnimationFrame(loop);
    } else {
      cancelAnimationFrame(requestRef.current!);
    }
    return () => cancelAnimationFrame(requestRef.current!);
  }, [isRunning, isAutoEvolving, loop]);

  return {
    population,
    generation,
    currentStats, // NEW
    isRunning,
    isAutoEvolving,
    isProcessing, 
    progress,    
    currentShape,
    // Physics State
    globalStiffness,
    globalContractility,
    setGlobalStiffness,
    setGlobalContractility,
    // Fitness State
    foodWeight,
    heightWeight,
    setFoodWeight,
    setHeightWeight,
    // Scarcity
    foodSpawnCount,
    setFoodSpawnCount,
    foodSpawnRadius,
    setFoodSpawnRadius,
    // Actions
    setIsRunning,
    toggleAutoEvolve, 
    reset,
    evolve,
    spawnCustom,
    saveCreature,
    loadCreature
  };
}

import { Node, Muscle, Organism, SimulationConfig } from './types';
import { BrainController } from './neural/BrainController';

export class BioPhysicsEngine {
  private config: SimulationConfig;
  private readonly MAX_VELOCITY = 12.0; 

  // SOLVER SETTINGS
  private readonly RELAXATION_FACTOR = 0.25; 
  private readonly ITERATIONS = 6; 

  // DAMPING SETTINGS
  private readonly BASE_MUSCLE_DAMPING = 0.08; 
  private readonly ADAPTIVE_DAMPING_FACTOR = 0.12; 
  private readonly ROTATIONAL_DRAG = 0.92; 

  // AIR RESISTANCE
  private readonly DRAG_COEFFICIENT = 0.08; 

  // --- SOLIDITY CONSTANTS ---
  private readonly NODE_RADIUS = 0.1; 
  private readonly HARD_CONTACT_LIMIT = 0.22; 

  constructor(config: Partial<SimulationConfig> = {}) {
    this.config = {
      gravity: -60.0, 
      friction: 0.98, // Global air friction
      groundDamping: 0.8, // Increased ground damping (less bounce = more grip)
      timeStep: 0.016,
      shapeMemoryStrength: 0.85, 
      globalStiffness: 0.8, // Updated Default: 80% stiffness
      globalContractility: 1.5, // Updated Default: 150% muscle power
      ...config
    };
  }

  public setConfig(config: Partial<SimulationConfig>) {
      this.config = { ...this.config, ...config };
  }

  // fastMode: If true, runs lower fidelity physics for rapid evolutionary calculation
  public updateOrganism(organism: Organism, totalTime: number, fastMode: boolean = false): void {

    // 1. PHYSICS INTEGRATION
    // Note: Brain update is now handled externally by EvolutionService

    // Handle Ragdoll state
    if (!organism.isAlive) {
        organism.muscles.forEach(m => {
            m.stiffness = 0.05; // Very loose
            m.amp = 0; // Stop oscillating
            m.targetLength = m.baseLength;
        });
        // Release all grips if dead
        organism.nodes.forEach(n => {
            n.gripSignal = 1.0; 
            n.isGripping = false;
        });
    }

    // ADAPTIVE SUBSTEPS
    const subSteps = fastMode ? 4 : 12; 
    const subDt = this.config.timeStep / subSteps;
    const gravityVec = { x: 0, y: this.config.gravity * subDt * subDt, z: 0 };

    for(let s=0; s < subSteps; s++) {
        this.integrate(organism, subDt, gravityVec);
        if (!fastMode) this.applyRotationalDrag(organism); 

        // ITERATIVE SOLVER
        // In Fast Mode, we reduce iterations slightly
        const loops = fastMode ? 4 : this.ITERATIONS;

        for (let i = 0; i < loops; i++) {
            this.resolveMuscles(organism);

            // CRITICAL OPTIMIZATION:
            // Self-Collision is O(N^2). We disable it during rapid evolution.
            if (!fastMode) {
                this.resolveSelfCollisions(organism); 
            }
        }

        this.resolveFloor(organism);
    }
  }

  private applyRotationalDrag(organism: Organism): void {
      let cx = 0, cz = 0;
      let count = 0;
      for (const n of organism.nodes) {
          cx += n.pos.x;
          cz += n.pos.z;
          count++;
      }
      if (count === 0) return;
      cx /= count;
      cz /= count;

      let angularMomentum = 0;
      let momentOfInertia = 0;

      for (const n of organism.nodes) {
          const rx = n.pos.x - cx;
          const rz = n.pos.z - cz;

          const vx = n.pos.x - n.oldPos.x;
          const vz = n.pos.z - n.oldPos.z;

          const orbitalComponent = rx * vz - rz * vx;

          angularMomentum += orbitalComponent;
          momentOfInertia += rx * rx + rz * rz;
      }

      if (momentOfInertia < 0.001) return;

      const angularVel = angularMomentum / momentOfInertia;

      for (const n of organism.nodes) {
          const rx = n.pos.x - cx;
          const rz = n.pos.z - cz;

          const dampX = -angularVel * rz * this.ROTATIONAL_DRAG;
          const dampZ =  angularVel * rx * this.ROTATIONAL_DRAG;

          n.oldPos.x += dampX;
          n.oldPos.z += dampZ;
      }
  }

  private integrate(organism: Organism, dt: number, gravityVec: {x:number, y:number, z:number}): void {
    const { friction } = this.config;
    const maxStepDist = this.MAX_VELOCITY * dt;
    const maxStepSq = maxStepDist * maxStepDist;

    for (const node of organism.nodes) {
      if (node.isFixed) continue;

      let velX = node.pos.x - node.oldPos.x;
      let velY = node.pos.y - node.oldPos.y;
      let velZ = node.pos.z - node.oldPos.z;

      // 1. QUADRATIC DRAG
      const vSq = velX*velX + velY*velY + velZ*velZ;
      if (vSq > 0.000001) {
          const vLen = Math.sqrt(vSq);
          const dragFactor = 1.0 / (1.0 + this.DRAG_COEFFICIENT * vLen);

          velX *= dragFactor;
          velY *= dragFactor;
          velZ *= dragFactor;
      }

      // 2. Base Friction (Air)
      velX *= friction;
      velY *= friction;
      velZ *= friction;

      // 3. Hard Cap (Safety Terminator)
      const distSq = velX*velX + velY*velY + velZ*velZ;
      if (distSq > maxStepSq) {
          const scale = maxStepDist / Math.sqrt(distSq);
          velX *= scale;
          velY *= scale;
          velZ *= scale;
      }

      // GC OPTIMIZATION: Update oldPos in place instead of creating new object
      node.oldPos.x = node.pos.x;
      node.oldPos.y = node.pos.y;
      node.oldPos.z = node.pos.z;

      node.pos.x += velX + gravityVec.x;
      node.pos.y += velY + gravityVec.y;
      node.pos.z += velZ + gravityVec.z;
    }
  }

  private resolveMuscles(organism: Organism): void {
    const GROUND_TOLERANCE = 0.02;
    const ANCHOR_MULTIPLIER = 0.1; 
    const MEMORY_STRENGTH = this.config.shapeMemoryStrength || 0.8;
    const GLOBAL_STIFFNESS = this.config.globalStiffness; 

    for (const muscle of organism.muscles) {
        const n1 = organism.nodes.find(n => n.id === muscle.nodeA);
        const n2 = organism.nodes.find(n => n.id === muscle.nodeB);

        if (!n1 || !n2) continue;

        const dx = n2.pos.x - n1.pos.x;
        const dy = n2.pos.y - n1.pos.y;
        const dz = n2.pos.z - n1.pos.z;
        const dist = Math.sqrt(dx*dx + dy*dy + dz*dz);

        if (dist < 0.0001) continue; 

        // 1. ACTIVE MUSCLE COMPONENT
        let activeTarget = muscle.targetLength || muscle.baseLength;
        if (activeTarget < this.HARD_CONTACT_LIMIT) activeTarget = this.HARD_CONTACT_LIMIT;

        let stiffness = muscle.stiffness * 0.8 * GLOBAL_STIFFNESS; 

        const activeDiff = dist - activeTarget;

        // 2. PASSIVE MEMORY COMPONENT
        const deviation = Math.abs(dist - muscle.baseLength);
        const strain = deviation / muscle.baseLength;
        const strainBoost = 1.0 + (strain * 4.0); 

        const currentMemoryStrength = organism.isAlive 
            ? MEMORY_STRENGTH * strainBoost * GLOBAL_STIFFNESS
            : MEMORY_STRENGTH * 0.1 * GLOBAL_STIFFNESS;

        const baseDiff = dist - muscle.baseLength;

        // --- DUAL FORCE BLENDING ---
        const activeCorrection = activeDiff * stiffness;
        const memoryCorrection = baseDiff * currentMemoryStrength;
        let totalCorrection = (activeCorrection + memoryCorrection) * this.RELAXATION_FACTOR;

        // --- DAMPING ---
        const vx1 = n1.pos.x - n1.oldPos.x;
        const vy1 = n1.pos.y - n1.oldPos.y;
        const vz1 = n1.pos.z - n1.oldPos.z;
        const vx2 = n2.pos.x - n2.oldPos.x;
        const vy2 = n2.pos.y - n2.oldPos.y;
        const vz2 = n2.pos.z - n2.oldPos.z;

        const rvx = vx2 - vx1;
        const rvy = vy2 - vy1;
        const rvz = vz2 - vz1;

        const nx = dx / dist;
        const ny = dy / dist;
        const nz = dz / dist;

        const relVel = Math.sqrt(rvx*rvx + rvy*rvy + rvz*rvz);
        const dynamicDamping = this.BASE_MUSCLE_DAMPING + (relVel * this.ADAPTIVE_DAMPING_FACTOR);
        const vRelProj = rvx * nx + rvy * ny + rvz * nz;

        totalCorrection += vRelProj * dynamicDamping;

        // --- MOMENTUM PRESERVATION ---
        let im1 = (n1.isFixed || n1.isGripping) ? 0 : 1 / n1.mass;
        let im2 = (n2.isFixed || n2.isGripping) ? 0 : 1 / n2.mass;

        if (n1.pos.y <= GROUND_TOLERANCE) im1 *= ANCHOR_MULTIPLIER;
        if (n2.pos.y <= GROUND_TOLERANCE) im2 *= ANCHOR_MULTIPLIER;

        const totalInvMass = im1 + im2;
        if (totalInvMass === 0) continue;

        const w1 = im1 / totalInvMass;
        const w2 = im2 / totalInvMass;

        const offsetX = nx * totalCorrection;
        const offsetY = ny * totalCorrection;
        const offsetZ = nz * totalCorrection;

        if (!n1.isFixed && !n1.isGripping) {
            n1.pos.x += offsetX * w1;
            n1.pos.y += offsetY * w1;
            n1.pos.z += offsetZ * w1;
        }

        if (!n2.isFixed && !n2.isGripping) {
            n2.pos.x -= offsetX * w2;
            n2.pos.y -= offsetY * w2;
            n2.pos.z -= offsetZ * w2;
        }
    }
  }

  private resolveSelfCollisions(organism: Organism): void {
      const nodes = organism.nodes;
      const count = nodes.length;
      const minDistance = this.HARD_CONTACT_LIMIT; 
      const minDistanceSq = minDistance * minDistance;

      for (let i = 0; i < count; i++) {
          for (let j = i + 1; j < count; j++) {
              const n1 = nodes[i];
              const n2 = nodes[j];

              const dx = n1.pos.x - n2.pos.x;
              const dy = n1.pos.y - n2.pos.y;
              const dz = n1.pos.z - n2.pos.z;
              const distSq = dx*dx + dy*dy + dz*dz;

              if (distSq < minDistanceSq && distSq > 0.000001) {
                  const dist = Math.sqrt(distSq);
                  const overlap = minDistance - dist;

                  const fx = (dx / dist) * overlap * 0.2;
                  const fy = (dy / dist) * overlap * 0.2;
                  const fz = (dz / dist) * overlap * 0.2;

                  if (!n1.isFixed) { n1.pos.x += fx; n1.pos.y += fy; n1.pos.z += fz; }
                  if (!n2.isFixed) { n2.pos.x -= fx; n2.pos.y -= fy; n2.pos.z -= fz; }
              }
          }
      }
  }

  private resolveFloor(organism: Organism): void {
    const RADIUS = this.NODE_RADIUS;
    const SUCTION_THRESHOLD = 0.5; 

    for (const node of organism.nodes) {
      if (node.pos.y < RADIUS) {
        node.pos.y = RADIUS;
        const releaseSignal = node.gripSignal || 0;

        if (releaseSignal < SUCTION_THRESHOLD) {
            node.isGripping = true;
            node.pos.x = node.oldPos.x;
            node.pos.z = node.oldPos.z;
        } else {
            node.isGripping = false;
            const vx = node.pos.x - node.oldPos.x;
            const vz = node.pos.z - node.oldPos.z;
            const frictionCoeff = 0.85; 
            node.oldPos.x = node.pos.x - vx * frictionCoeff;
            node.oldPos.z = node.pos.z - vz * frictionCoeff;
        }
      } else {
          node.isGripping = false;
      }
    }
  }
}

import React, { useRef, useMemo, MutableRefObject } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { Organism } from '../../domain/types';

interface CreatureViewProps {
  organism: Organism;
  leaderRef: MutableRefObject<Organism | null>;
  showBestOnly: boolean;
}

// SHARED SCRATCHPAD VECTORS (Optimization)
// Reusing these prevents creating hundreds of Vector3 objects per frame
const _v1 = new THREE.Vector3();
const _v2 = new THREE.Vector3();
const _vMid = new THREE.Vector3();

export const CreatureView: React.FC<CreatureViewProps> = ({ organism, leaderRef, showBestOnly }) => {
  const groupRef = useRef<THREE.Group>(null);
  const nodeRefs = useRef<THREE.Mesh[]>([]);
  const muscleRefs = useRef<THREE.Mesh[]>([]);
  const visionRef = useRef<THREE.Mesh>(null);
  const magnetRef = useRef<THREE.Mesh>(null);

  const nodeGeo = useMemo(() => new THREE.SphereGeometry(0.08, 8, 8), []); // Reduced polys
  const muscleGeo = useMemo(() => new THREE.CylinderGeometry(0.03, 0.03, 1, 5), []); // Reduced polys
  const visionGeo = useMemo(() => new THREE.SphereGeometry(1, 16, 16), []); 

  const MAGNET_RADIUS = 1.5; 
  const magnetGeo = useMemo(() => new THREE.RingGeometry(MAGNET_RADIUS - 0.05, MAGNET_RADIUS, 32), []);

  const colorRed = useMemo(() => new THREE.Color(0xff3333), []);
  const colorBlue = useMemo(() => new THREE.Color(0x3333ff), []);
  const colorWhite = useMemo(() => new THREE.Color(0xffffff), []);
  const colorYellow = useMemo(() => new THREE.Color(0xffff00), []); 
  const colorHead = useMemo(() => new THREE.Color(0x1a1a1a), []); 
  const colorDead = useMemo(() => new THREE.Color(0x52525b), []); 
  const colorGrip = useMemo(() => new THREE.Color(0x22c55e), []); 

  const visionMat = useMemo(() => new THREE.MeshBasicMaterial({ 
      color: 0x00ffff, 
      transparent: true, 
      opacity: 0.05, 
      wireframe: true 
  }), []);

  const magnetMat = useMemo(() => new THREE.MeshBasicMaterial({
      color: 0xffff00,
      transparent: true,
      opacity: 0.3,
      side: THREE.DoubleSide
  }), []);

  useFrame((state) => {
    if (!groupRef.current) return;

    if (showBestOnly) {
        const isLeader = leaderRef.current?.id === organism.id;
        groupRef.current.visible = isLeader;
    } else {
        groupRef.current.visible = true;
    }

    if (!groupRef.current.visible) return;

    let headPos: THREE.Vector3 | null = null;

    // 1. Sync Nodes
    organism.nodes.forEach((node, i) => {
      const mesh = nodeRefs.current[i];
      if (mesh) {
        mesh.position.set(node.pos.x, node.pos.y, node.pos.z);

        const mat = mesh.material as THREE.MeshStandardMaterial;

        if (!organism.isAlive) {
            mat.color.copy(colorDead);
            mat.opacity = 1;
            mat.transparent = false;
        } else if (node.isHead) {
            headPos = mesh.position; 
            mat.color.copy(colorHead);
            mat.opacity = 1;
        } else {
            if (node.isGripping) {
                mat.color.copy(colorGrip);
            } else {
                const activation = node.activation || 0;
                // Reuse _v1 as color lerp target would be complex, but color.lerp is safe
                // cloning colorWhite is lightweight compared to Vector3
                mat.color.copy(colorWhite).lerp(colorYellow, activation);
            }
            mat.opacity = 1;
        }
      }
    });

    // 2. Sync Vision
    if (headPos && organism.isAlive) {
        if (visionRef.current) {
            visionRef.current.position.copy(headPos);
            const pulse = 4.0 + Math.sin(state.clock.elapsedTime * 4) * 0.2; 
            visionRef.current.scale.setScalar(pulse);
            visionRef.current.visible = true;
        }
        if (magnetRef.current) {
            magnetRef.current.position.copy(headPos);
            magnetRef.current.rotation.x = -Math.PI / 2;
            magnetRef.current.visible = true;
        }
    } else {
        if (visionRef.current) visionRef.current.visible = false;
        if (magnetRef.current) magnetRef.current.visible = false;
    }

    // 3. Sync Muscles (GC OPTIMIZED)
    organism.muscles.forEach((muscle, i) => {
      const mesh = muscleRefs.current[i];
      if (mesh) {
        const nA = organism.nodes.find(n => n.id === muscle.nodeA);
        const nB = organism.nodes.find(n => n.id === muscle.nodeB);

        if (nA && nB) {
          // UPDATE: Use shared vectors instead of `new Vector3`
          _v1.set(nA.pos.x, nA.pos.y, nA.pos.z);
          _v2.set(nB.pos.x, nB.pos.y, nB.pos.z);

          _vMid.copy(_v1).add(_v2).multiplyScalar(0.5);

          mesh.position.copy(_vMid);
          mesh.lookAt(_v2);
          mesh.rotateX(Math.PI / 2); 

          const currentLen = _v1.distanceTo(_v2);
          mesh.scale.set(1, currentLen, 1);

          const mat = mesh.material as THREE.MeshStandardMaterial;

          if (!organism.isAlive) {
             mat.color.copy(colorDead);
          } else {
            const target = muscle.targetLength || muscle.baseLength;
            const ratio = target / muscle.baseLength;

            if (ratio < 0.98) {
              mat.color.copy(colorWhite).lerp(colorRed, Math.min(1, (1 - ratio) * 5));
            } else if (ratio > 1.02) {
              mat.color.copy(colorWhite).lerp(colorBlue, Math.min(1, (ratio - 1) * 5));
            } else {
              mat.color.copy(colorWhite);
            }
          }
        }
      }
    });
  });

  return (
    <group ref={groupRef}>
      <mesh ref={visionRef} geometry={visionGeo} material={visionMat} />
      <mesh ref={magnetRef} geometry={magnetGeo} material={magnetMat} />

      {organism.nodes.map((node, i) => (
        <mesh
          key={node.id}
          ref={(el) => { if(el) nodeRefs.current[i] = el; }}
          geometry={nodeGeo}
        >
          <meshStandardMaterial color="white" />
        </mesh>
      ))}

      {organism.muscles.map((muscle, i) => (
        <mesh
          key={muscle.id}
          ref={(el) => { if(el) muscleRefs.current[i] = el; }}
          geometry={muscleGeo}
        >
           <meshStandardMaterial color="white" />
        </mesh>
      ))}
    </group>
  );
};

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { useThree } from '@react-three/fiber';
import { GridCoord, ShapeType } from '../../domain/types';
import * as THREE from 'three';

// Helper to convert axial to pixel (for rendering hexes)
const hexToPixel = (q: number, r: number, size: number = 0.5) => {
    const x = size * 1.5 * q;
    const z = size * Math.sqrt(3) * (r + q/2);
    return { x, z };
};

// Neighbor directions for Hexagons (Axial)
const HEX_NEIGHBORS = [
    {q: 1, r: 0}, {q: 1, r: -1}, {q: 0, r: -1},
    {q: -1, r: 0}, {q: -1, r: 1}, {q: 0, r: 1}
];

export const BlueprintViewUpdated: React.FC<{
    cells: GridCoord[]; 
    onCellClick: (x: number, y: number, z: number, isRight: boolean) => void;
    currentType: ShapeType;
}> = ({ cells, onCellClick, currentType }) => {

  const { camera, raycaster, pointer, scene } = useThree();
  const [hoverCoord, setHoverCoord] = useState<GridCoord | null>(null);

  // INSTANCING REFS
  const meshRef = useRef<THREE.InstancedMesh>(null);
  const tempMat = useMemo(() => new THREE.Matrix4(), []);

  const boxGeo = useMemo(() => new THREE.BoxGeometry(0.8, 0.8, 0.8), []);
  const hexGeo = useMemo(() => new THREE.CylinderGeometry(0.45, 0.45, 0.5, 6), []);
  const hexRotation = useMemo(() => new THREE.Euler(0, Math.PI/6, 0), []);
  const hexQuaternion = useMemo(() => new THREE.Quaternion().setFromEuler(hexRotation), []);

  const material = useMemo(() => new THREE.MeshStandardMaterial({ color: '#3b82f6', roughness: 0.3 }), []);
  const materialHex = useMemo(() => new THREE.MeshStandardMaterial({ color: '#8b5cf6', roughness: 0.3 }), []);

  const hoverMaterial = useMemo(() => new THREE.MeshStandardMaterial({ color: '#facc15', transparent: true, opacity: 0.5 }), []);

  // UPDATE INSTANCES
  useEffect(() => {
      if (!meshRef.current) return;

      meshRef.current.count = cells.length;

      cells.forEach((c, i) => {
          tempMat.identity();
          if (currentType === ShapeType.HEX) {
             const {x, z} = hexToPixel(c.x, c.z, 0.6);
             const hexHeight = 0.5;
             const yPos = c.y * hexHeight + (hexHeight/2);
             tempMat.makeRotationFromQuaternion(hexQuaternion);
             tempMat.setPosition(x, yPos, z);
          } else {
             tempMat.setPosition(c.x, c.y, c.z);
          }
          meshRef.current!.setMatrixAt(i, tempMat);
      });
      meshRef.current.instanceMatrix.needsUpdate = true;

  }, [cells, currentType, tempMat, hexQuaternion]);


  const handlePointerMove = (e: any) => {
      raycaster.setFromCamera(pointer, camera);
      const intersects = raycaster.intersectObjects(scene.children, true);

      let hitPoint: THREE.Vector3 | null = null;
      let hitNormal: THREE.Vector3 | null = null;
      let hitObject: THREE.Object3D | null = null;
      let hitInstanceId: number | undefined = undefined;

      for (const hit of intersects) {
          if (hit.object === meshRef.current || hit.object.name === 'base_plane') {
              hitPoint = hit.point;
              hitNormal = hit.face?.normal || new THREE.Vector3(0,1,0);
              hitObject = hit.object;
              hitInstanceId = hit.instanceId;
              break;
          }
      }

      if (hitPoint) {
          // CASE 1: HOVERING EXISTING VOXEL (Add to side)
          if (hitObject === meshRef.current && hitInstanceId !== undefined) {
             const c = cells[hitInstanceId];
             if (!c) return;

             if (currentType === ShapeType.HEX) {
                  // --- HEX LOGIC ---
                  // Calculate local position relative to the hex center
                  // We need to re-calculate the hex world position to find relative hit
                  const {x: cx, z: cz} = hexToPixel(c.x, c.z, 0.6);
                  const hexHeight = 0.5;
                  const cy = c.y * hexHeight + (hexHeight/2);

                  const relY = hitPoint.y - cy;

                  // Top/Bottom
                  if (relY > 0.23) {
                      setHoverCoord({ x: c.x, y: c.y + 1, z: c.z });
                      return;
                  }
                  if (relY < -0.23) {
                       setHoverCoord({ x: c.x, y: c.y - 1, z: c.z });
                       return;
                  }

                  // Side Neighbors
                  let bestNeigh = null;
                  let minD = Infinity;

                  HEX_NEIGHBORS.forEach(n => {
                       const pos = hexToPixel(c.x + n.q, c.z + n.r, 0.6);
                       const dx = pos.x - hitPoint!.x;
                       const dz = pos.z - hitPoint!.z;
                       const d = dx*dx + dz*dz;
                       if (d < minD) {
                           minD = d;
                           bestNeigh = n;
                       }
                  });

                  if (bestNeigh) {
                      setHoverCoord({ x: c.x + bestNeigh.q, y: c.y, z: c.z + bestNeigh.r });
                  }
             } else {
                 // --- CUBE LOGIC ---
                 const nx = hitNormal!.x;
                 const ny = hitNormal!.y;
                 const nz = hitNormal!.z;

                 // Since we are instanced, we assume standard grid alignment
                 // We can just add normal to the grid coord
                 setHoverCoord({
                     x: c.x + Math.round(nx),
                     y: c.y + Math.round(ny),
                     z: c.z + Math.round(nz)
                 });
             }
          } 
          // CASE 2: HOVERING FLOOR
          else if (hitObject?.name === 'base_plane') {
             if (currentType === ShapeType.HEX) {
                  const size = 0.6;
                  const q = (2./3 * hitPoint.x) / size;
                  const r = (-1./3 * hitPoint.x + Math.sqrt(3)/3 * hitPoint.z) / size;

                  let rx = Math.round(q);
                  let rz = Math.round(r);
                  let ry = Math.round(-q-r);

                  const x_diff = Math.abs(rx - q);
                  const y_diff = Math.abs(ry - (-q-r));
                  const z_diff = Math.abs(rz - r);

                  if (x_diff > y_diff && x_diff > z_diff) {
                      rx = -ry-rz;
                  } else {
                      rz = -rx-ry;
                  }
                  setHoverCoord({ x: rx, y: 0, z: rz });
             } else {
                 setHoverCoord({
                     x: Math.round(hitPoint.x),
                     y: 0,
                     z: Math.round(hitPoint.z)
                 });
             }
          }
      } else {
          setHoverCoord(null);
      }
  };

  const handleClick = (e: any) => {
      e.stopPropagation();
      // Right Click: Remove
      if (e.button === 2) {
         if (e.object === meshRef.current && e.instanceId !== undefined) {
             const c = cells[e.instanceId];
             if(c) onCellClick(c.x, c.y, c.z, true);
         }
         return;
      }
      // Left Click: Add
      if (hoverCoord) {
          onCellClick(hoverCoord.x, hoverCoord.y, hoverCoord.z, false);
      }
  };

  return (
    <group 
        onPointerMove={handlePointerMove} 
        onClick={handleClick}
        onContextMenu={handleClick}
    >
      <ambientLight intensity={0.8} />
      <directionalLight position={[5, 10, 5]} intensity={1.5} />

      <instancedMesh 
          ref={meshRef} 
          args={[undefined, undefined, 2000]} // Capacity 2000
          onPointerMove={handlePointerMove}
      >
          {currentType === ShapeType.HEX 
            ? <cylinderGeometry args={[0.45, 0.45, 0.5, 6]} /> 
            : <boxGeometry args={[0.8, 0.8, 0.8]} />
          }
          {currentType === ShapeType.HEX 
            ? <primitive object={materialHex} attach="material" />
            : <primitive object={material} attach="material" />
          }
      </instancedMesh>

      {hoverCoord && (
         <group>
             {currentType === ShapeType.HEX ? (
                 <mesh 
                    position={[
                        hexToPixel(hoverCoord.x, hoverCoord.z, 0.6).x, 
                        hoverCoord.y * 0.5 + 0.25, 
                        hexToPixel(hoverCoord.x, hoverCoord.z, 0.6).z
                    ]} 
                    geometry={hexGeo} 
                    material={hoverMaterial}
                    rotation={[0, Math.PI/6, 0]}
                 />
             ) : (
                 <mesh position={[hoverCoord.x, hoverCoord.y, hoverCoord.z]} geometry={boxGeo} material={hoverMaterial} />
             )}
         </group>
      )}

      <mesh rotation={[-Math.PI / 2, 0, 0]} position={[0, -0.5, 0]} name="base_plane" visible={false}>
          <planeGeometry args={[60, 60]} />
      </mesh>

      {currentType === ShapeType.HEX ? (
           <gridHelper args={[30, 30, 0x444444, 0x111111]} position={[0, -2.5, 0]} />
      ) : (
           <gridHelper args={[30, 30, 0x444444, 0x222222]} position={[0, -2.5, 0]} />
      )}

    </group>
  );
};

// Hexagonal Architecture: Domain Layer (Inner Core)
// Zero dependencies on UI or Rendering libraries.

export interface Vec3 {
  x: number;
  y: number;
  z: number;
}

export interface Node {
  id: string;
  pos: Vec3;
  oldPos: Vec3; // For Verlet integration
  mass: number;
  friction: number;
  isFixed?: boolean;
  isHead?: boolean; // NEW: The only node that can eat

  // SUCTION MECHANICS
  isGripping?: boolean; // Read-only physics state
  gripSignal?: number;  // 0.0 to 1.0 (Controlled by Brain). High = Release Suction.

  // EDITOR METADATA (Preserves shape upon reloading)
  originalGridCoord?: { x: number; y: number; z: number }; 

  // Neural State
  activation?: number; // 0.0 to 1.0 (Visualization Glow)
  // Physics State
}

export interface Muscle {
  id: string;
  nodeA: string; // ID reference
  nodeB: string; // ID reference
  baseLength: number;
  stiffness: number;
  dnaIndex: number; // Maps to a Gene (Index in genome arrays)

  // Runtime Physics State
  currentLength?: number; 
  targetLength?: number; 

  // --- RUNTIME OPTIMIZATION (O(1) Access) ---
  nodeRefA?: Node;
  nodeRefB?: Node;

  // --- OSCILLATOR STATE (The Anti-Vibration Core) ---
  // The brain controls these parameters, not the length directly.
  phase: number;      // Current position in the sine wave (0 to 2PI)
  freq: number;       // How fast it pulses (Hz). Clamped to prevent jitter.
  amp: number;        // How much it expands (0.0 to 0.4). 
}

// Replaced simple Sine Gene with Neural Genome
export interface NeuralGenome {
  // GNN Weights: How much signal flows through each muscle (Synapse)
  synapseWeights: number[]; 
  // LSM Weights: The chaotic reservoir weights (simplified as a float array)
  reservoirWeights: number[];
  // Output Weights: Mapping the reservoir state to muscle contraction
  outputWeights: number[]; 
  // NEW: Predictive World Model Weights (Reservoir -> Predicted Sensory Input)
  predictionWeights: number[];
  // NEW: Grip Control Weights (Reservoir -> Node Suction Release)
  gripWeights: number[]; 
  // Biases for neurons
  biases: number[];

  // --- EVOLVABLE BRAIN DYNAMICS ---
  internalClockSpeed: number; // Multiplier (0.5 to 2.0). How fast the brain thinks relative to physics.
  waveFreq: number;           // Hz (0.5 to 3.0). Base frequency of the spinal generator.
  waveSpeed: number;          // Propagation speed of the wave along the body.
}

export interface FoodItem {
    id: string;
    pos: Vec3;
    energyValue: number;
    consumed: boolean;
}

export enum ShapeType {
  CUBE = 'CUBE', // Cartesian Lattice
  TETRAHEDRON = 'TETRAHEDRON', // Offset Lattice
  WORM = 'WORM', // Legacy
  HEX = 'HEX', // 3D Hexagonal Prism Layout
}

export interface Organism {
  id: string;
  shape: ShapeType; // NEW: Tracks the lattice type for the Architect
  nodes: Node[];
  muscles: Muscle[];
  // The Blueprint
  neuralGenome: NeuralGenome;
  // The Runtime Brain (Controller instance, not serialized usually, but here for simplicity)
  brain?: any; 

  // Stats
  fitness: number; // Total Score
  generation: number;

  // NEW: Posture Metrics
  initialVerticalSize: number; // BENCHMARK: Distance from Feet to Head at Spawn
  currentHeightScore: number; // Real-time score (0.0 to 1.0) for UI
  accumulatedPostureScore: number; // NEW: Running total of posture points
  bestHeightScore: number; // NEW: Track peak posture

  // NEW: Metabolism & Survival
  energy: number;          // 0 to 100
  maxEnergy: number;       
  hungerTime: number;      // Time since last meal (drives exponential decay)
  isAlive: boolean;
  foodEaten: number;
  visibleFood: FoodItem[]; // Each creature has its own reality/food track
}

export interface SimulationConfig {
  gravity: number;
  friction: number;
  groundDamping: number;
  timeStep: number;
  // NEW: Structural Integrity
  shapeMemoryStrength: number;

  // NEW: Real-time Physics Tweaks
  globalStiffness: number;     // Multiplier for bone rigidity (0.1 to 2.0)
  globalContractility: number; // Multiplier for muscle power (0.0 to 2.0)
}

// --- ARCHITECT TYPES ---
export type GridCoord = { x: number; y: number; z: number };

export interface Blueprint {
    cells: Map<string, boolean>; // Key "x,y,z"
    type: ShapeType;
}

import { Node, Muscle, Organism, SimulationConfig } from './types';
import { BrainController } from './neural/BrainController';

export class BioPhysicsEngine {
  private config: SimulationConfig;
  private readonly MAX_VELOCITY = 12.0; 

  // SOLVER SETTINGS
  private readonly RELAXATION_FACTOR = 0.25; 
  private readonly ITERATIONS = 6; 

  // DAMPING SETTINGS
  private readonly BASE_MUSCLE_DAMPING = 0.08; 
  private readonly ADAPTIVE_DAMPING_FACTOR = 0.12; 
  private readonly ROTATIONAL_DRAG = 0.92; 

  // AIR RESISTANCE
  private readonly DRAG_COEFFICIENT = 0.08; 

  // --- SOLIDITY CONSTANTS ---
  private readonly NODE_RADIUS = 0.1; 
  private readonly HARD_CONTACT_LIMIT = 0.22; 

  constructor(config: Partial<SimulationConfig> = {}) {
    this.config = {
      gravity: -60.0, 
      friction: 0.98, // Global air friction
      groundDamping: 0.8, // Increased ground damping (less bounce = more grip)
      timeStep: 0.016,
      shapeMemoryStrength: 0.85, 
      globalStiffness: 0.8, // Updated Default: 80% stiffness
      globalContractility: 1.5, // Updated Default: 150% muscle power
      ...config
    };
  }

  public setConfig(config: Partial<SimulationConfig>) {
      this.config = { ...this.config, ...config };
  }

  // fastMode: If true, runs lower fidelity physics for rapid evolutionary calculation
  public updateOrganism(organism: Organism, totalTime: number, fastMode: boolean = false): void {

    // 1. PHYSICS INTEGRATION
    // Note: Brain update is now handled externally by EvolutionService

    // Handle Ragdoll state
    if (!organism.isAlive) {
        organism.muscles.forEach(m => {
            m.stiffness = 0.05; // Very loose
            m.amp = 0; // Stop oscillating
            m.targetLength = m.baseLength;
        });
        // Release all grips if dead
        organism.nodes.forEach(n => {
            n.gripSignal = 1.0; 
            n.isGripping = false;
        });
    }

    // ADAPTIVE SUBSTEPS
    const subSteps = fastMode ? 4 : 12; 
    const subDt = this.config.timeStep / subSteps;
    const gravityVec = { x: 0, y: this.config.gravity * subDt * subDt, z: 0 };

    for(let s=0; s < subSteps; s++) {
        this.integrate(organism, subDt, gravityVec);
        if (!fastMode) this.applyRotationalDrag(organism); 

        // ITERATIVE SOLVER
        // In Fast Mode, we reduce iterations slightly
        const loops = fastMode ? 4 : this.ITERATIONS;

        for (let i = 0; i < loops; i++) {
            this.resolveMuscles(organism);

            // CRITICAL OPTIMIZATION:
            // Self-Collision is O(N^2). We disable it during rapid evolution.
            if (!fastMode) {
                this.resolveSelfCollisions(organism); 
            }
        }

        this.resolveFloor(organism);
    }
  }

  private applyRotationalDrag(organism: Organism): void {
      let cx = 0, cz = 0;
      let count = 0;
      for (const n of organism.nodes) {
          cx += n.pos.x;
          cz += n.pos.z;
          count++;
      }
      if (count === 0) return;
      cx /= count;
      cz /= count;

      let angularMomentum = 0;
      let momentOfInertia = 0;

      for (const n of organism.nodes) {
          const rx = n.pos.x - cx;
          const rz = n.pos.z - cz;

          const vx = n.pos.x - n.oldPos.x;
          const vz = n.pos.z - n.oldPos.z;

          const orbitalComponent = rx * vz - rz * vx;

          angularMomentum += orbitalComponent;
          momentOfInertia += rx * rx + rz * rz;
      }

      if (momentOfInertia < 0.001) return;

      const angularVel = angularMomentum / momentOfInertia;

      for (const n of organism.nodes) {
          const rx = n.pos.x - cx;
          const rz = n.pos.z - cz;

          const dampX = -angularVel * rz * this.ROTATIONAL_DRAG;
          const dampZ =  angularVel * rx * this.ROTATIONAL_DRAG;

          n.oldPos.x += dampX;
          n.oldPos.z += dampZ;
      }
  }

  private integrate(organism: Organism, dt: number, gravityVec: {x:number, y:number, z:number}): void {
    const { friction } = this.config;
    const maxStepDist = this.MAX_VELOCITY * dt;
    const maxStepSq = maxStepDist * maxStepDist;

    for (const node of organism.nodes) {
      if (node.isFixed) continue;

      let velX = node.pos.x - node.oldPos.x;
      let velY = node.pos.y - node.oldPos.y;
      let velZ = node.pos.z - node.oldPos.z;

      // 1. QUADRATIC DRAG
      const vSq = velX*velX + velY*velY + velZ*velZ;
      if (vSq > 0.000001) {
          const vLen = Math.sqrt(vSq);
          const dragFactor = 1.0 / (1.0 + this.DRAG_COEFFICIENT * vLen);

          velX *= dragFactor;
          velY *= dragFactor;
          velZ *= dragFactor;
      }

      // 2. Base Friction (Air)
      velX *= friction;
      velY *= friction;
      velZ *= friction;

      // 3. Hard Cap (Safety Terminator)
      const distSq = velX*velX + velY*velY + velZ*velZ;
      if (distSq > maxStepSq) {
          const scale = maxStepDist / Math.sqrt(distSq);
          velX *= scale;
          velY *= scale;
          velZ *= scale;
      }

      // GC OPTIMIZATION: Update oldPos in place instead of creating new object
      node.oldPos.x = node.pos.x;
      node.oldPos.y = node.pos.y;
      node.oldPos.z = node.pos.z;

      node.pos.x += velX + gravityVec.x;
      node.pos.y += velY + gravityVec.y;
      node.pos.z += velZ + gravityVec.z;
    }
  }

  private resolveMuscles(organism: Organism): void {
    const GROUND_TOLERANCE = 0.02;
    const ANCHOR_MULTIPLIER = 0.1; 
    const MEMORY_STRENGTH = this.config.shapeMemoryStrength || 0.8;
    const GLOBAL_STIFFNESS = this.config.globalStiffness; 

    // CACHE REFERENCES (Lazy Load)
    // If we haven't linked the muscles to nodes yet, do it once.
    // This removes the O(N) Array.find lookup from the inner loop.
    if (!organism.muscles[0]?.nodeRefA) {
         const nodeMap = new Map<string, Node>();
         for (const n of organism.nodes) nodeMap.set(n.id, n);
         for (const m of organism.muscles) {
             m.nodeRefA = nodeMap.get(m.nodeA);
             m.nodeRefB = nodeMap.get(m.nodeB);
         }
    }

    for (const muscle of organism.muscles) {
        // O(1) Access
        const n1 = muscle.nodeRefA;
        const n2 = muscle.nodeRefB;

        if (!n1 || !n2) continue;

        const dx = n2.pos.x - n1.pos.x;
        const dy = n2.pos.y - n1.pos.y;
        const dz = n2.pos.z - n1.pos.z;
        const dist = Math.sqrt(dx*dx + dy*dy + dz*dz);

        if (dist < 0.0001) continue; 

        // 1. ACTIVE MUSCLE COMPONENT
        let activeTarget = muscle.targetLength || muscle.baseLength;
        if (activeTarget < this.HARD_CONTACT_LIMIT) activeTarget = this.HARD_CONTACT_LIMIT;

        let stiffness = muscle.stiffness * 0.8 * GLOBAL_STIFFNESS; 

        const activeDiff = dist - activeTarget;

        // 2. PASSIVE MEMORY COMPONENT
        const deviation = Math.abs(dist - muscle.baseLength);
        const strain = deviation / muscle.baseLength;
        const strainBoost = 1.0 + (strain * 4.0); 

        const currentMemoryStrength = organism.isAlive 
            ? MEMORY_STRENGTH * strainBoost * GLOBAL_STIFFNESS
            : MEMORY_STRENGTH * 0.1 * GLOBAL_STIFFNESS;

        const baseDiff = dist - muscle.baseLength;

        // --- DUAL FORCE BLENDING ---
        const activeCorrection = activeDiff * stiffness;
        const memoryCorrection = baseDiff * currentMemoryStrength;
        let totalCorrection = (activeCorrection + memoryCorrection) * this.RELAXATION_FACTOR;

        // --- DAMPING ---
        const vx1 = n1.pos.x - n1.oldPos.x;
        const vy1 = n1.pos.y - n1.oldPos.y;
        const vz1 = n1.pos.z - n1.oldPos.z;
        const vx2 = n2.pos.x - n2.oldPos.x;
        const vy2 = n2.pos.y - n2.oldPos.y;
        const vz2 = n2.pos.z - n2.oldPos.z;

        const rvx = vx2 - vx1;
        const rvy = vy2 - vy1;
        const rvz = vz2 - vz1;

        const nx = dx / dist;
        const ny = dy / dist;
        const nz = dz / dist;

        const relVel = Math.sqrt(rvx*rvx + rvy*rvy + rvz*rvz);
        const dynamicDamping = this.BASE_MUSCLE_DAMPING + (relVel * this.ADAPTIVE_DAMPING_FACTOR);
        const vRelProj = rvx * nx + rvy * ny + rvz * nz;

        totalCorrection += vRelProj * dynamicDamping;

        // --- MOMENTUM PRESERVATION ---
        let im1 = (n1.isFixed || n1.isGripping) ? 0 : 1 / n1.mass;
        let im2 = (n2.isFixed || n2.isGripping) ? 0 : 1 / n2.mass;

        if (n1.pos.y <= GROUND_TOLERANCE) im1 *= ANCHOR_MULTIPLIER;
        if (n2.pos.y <= GROUND_TOLERANCE) im2 *= ANCHOR_MULTIPLIER;

        const totalInvMass = im1 + im2;
        if (totalInvMass === 0) continue;

        const w1 = im1 / totalInvMass;
        const w2 = im2 / totalInvMass;

        const offsetX = nx * totalCorrection;
        const offsetY = ny * totalCorrection;
        const offsetZ = nz * totalCorrection;

        if (!n1.isFixed && !n1.isGripping) {
            n1.pos.x += offsetX * w1;
            n1.pos.y += offsetY * w1;
            n1.pos.z += offsetZ * w1;
        }

        if (!n2.isFixed && !n2.isGripping) {
            n2.pos.x -= offsetX * w2;
            n2.pos.y -= offsetY * w2;
            n2.pos.z -= offsetZ * w2;
        }
    }
  }

  private resolveSelfCollisions(organism: Organism): void {
      const nodes = organism.nodes;
      const count = nodes.length;
      const minDistance = this.HARD_CONTACT_LIMIT; 
      const minDistanceSq = minDistance * minDistance;

      for (let i = 0; i < count; i++) {
          for (let j = i + 1; j < count; j++) {
              const n1 = nodes[i];
              const n2 = nodes[j];

              const dx = n1.pos.x - n2.pos.x;
              const dy = n1.pos.y - n2.pos.y;
              const dz = n1.pos.z - n2.pos.z;
              const distSq = dx*dx + dy*dy + dz*dz;

              if (distSq < minDistanceSq && distSq > 0.000001) {
                  const dist = Math.sqrt(distSq);
                  const overlap = minDistance - dist;

                  const fx = (dx / dist) * overlap * 0.2;
                  const fy = (dy / dist) * overlap * 0.2;
                  const fz = (dz / dist) * overlap * 0.2;

                  if (!n1.isFixed) { n1.pos.x += fx; n1.pos.y += fy; n1.pos.z += fz; }
                  if (!n2.isFixed) { n2.pos.x -= fx; n2.pos.y -= fy; n2.pos.z -= fz; }
              }
          }
      }
  }

  private resolveFloor(organism: Organism): void {
    const RADIUS = this.NODE_RADIUS;
    const SUCTION_THRESHOLD = 0.5; 

    for (const node of organism.nodes) {
      if (node.pos.y < RADIUS) {
        node.pos.y = RADIUS;
        const releaseSignal = node.gripSignal || 0;

        if (releaseSignal < SUCTION_THRESHOLD) {
            node.isGripping = true;
            node.pos.x = node.oldPos.x;
            node.pos.z = node.oldPos.z;
        } else {
            node.isGripping = false;
            const vx = node.pos.x - node.oldPos.x;
            const vz = node.pos.z - node.oldPos.z;
            const frictionCoeff = 0.85; 
            node.oldPos.x = node.pos.x - vx * frictionCoeff;
            node.oldPos.z = node.pos.z - vz * frictionCoeff;
        }
      } else {
          node.isGripping = false;
      }
    }
  }
}

import React, { useRef, useMemo, MutableRefObject } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { Organism, Node } from '../../domain/types';

interface CreatureViewProps {
  organism: Organism;
  leaderRef: MutableRefObject<Organism | null>;
  showBestOnly: boolean;
}

// SHARED SCRATCHPAD VECTORS (Optimization)
// Reusing these prevents creating hundreds of Vector3 objects per frame
const _v1 = new THREE.Vector3();
const _v2 = new THREE.Vector3();
const _vMid = new THREE.Vector3();

export const CreatureView: React.FC<CreatureViewProps> = ({ organism, leaderRef, showBestOnly }) => {
  const groupRef = useRef<THREE.Group>(null);
  const nodeRefs = useRef<THREE.Mesh[]>([]);
  const muscleRefs = useRef<THREE.Mesh[]>([]);
  const visionRef = useRef<THREE.Mesh>(null);
  const magnetRef = useRef<THREE.Mesh>(null);

  const nodeGeo = useMemo(() => new THREE.SphereGeometry(0.08, 8, 8), []); // Reduced polys
  const muscleGeo = useMemo(() => new THREE.CylinderGeometry(0.03, 0.03, 1, 5), []); // Reduced polys
  const visionGeo = useMemo(() => new THREE.SphereGeometry(1, 16, 16), []); 

  const MAGNET_RADIUS = 1.5; 
  const magnetGeo = useMemo(() => new THREE.RingGeometry(MAGNET_RADIUS - 0.05, MAGNET_RADIUS, 32), []);

  const colorRed = useMemo(() => new THREE.Color(0xff3333), []);
  const colorBlue = useMemo(() => new THREE.Color(0x3333ff), []);
  const colorWhite = useMemo(() => new THREE.Color(0xffffff), []);
  const colorYellow = useMemo(() => new THREE.Color(0xffff00), []); 
  const colorHead = useMemo(() => new THREE.Color(0x1a1a1a), []); 
  const colorDead = useMemo(() => new THREE.Color(0x52525b), []); 
  const colorGrip = useMemo(() => new THREE.Color(0x22c55e), []); 

  const visionMat = useMemo(() => new THREE.MeshBasicMaterial({ 
      color: 0x00ffff, 
      transparent: true, 
      opacity: 0.05, 
      wireframe: true 
  }), []);

  const magnetMat = useMemo(() => new THREE.MeshBasicMaterial({
      color: 0xffff00,
      transparent: true,
      opacity: 0.3,
      side: THREE.DoubleSide
  }), []);

  // OPTIMIZATION: Create O(1) lookup map for visual linking
  const nodeMap = useMemo(() => {
      const map = new Map<string, Node>();
      for (const n of organism.nodes) map.set(n.id, n);
      return map;
  }, [organism.nodes]);

  useFrame((state) => {
    if (!groupRef.current) return;

    if (showBestOnly) {
        const isLeader = leaderRef.current?.id === organism.id;
        groupRef.current.visible = isLeader;
    } else {
        groupRef.current.visible = true;
    }

    if (!groupRef.current.visible) return;

    let headPos: THREE.Vector3 | null = null;

    // 1. Sync Nodes
    organism.nodes.forEach((node, i) => {
      const mesh = nodeRefs.current[i];
      if (mesh) {
        mesh.position.set(node.pos.x, node.pos.y, node.pos.z);

        const mat = mesh.material as THREE.MeshStandardMaterial;

        if (!organism.isAlive) {
            mat.color.copy(colorDead);
            mat.opacity = 1;
            mat.transparent = false;
        } else if (node.isHead) {
            headPos = mesh.position; 
            mat.color.copy(colorHead);
            mat.opacity = 1;
        } else {
            if (node.isGripping) {
                mat.color.copy(colorGrip);
            } else {
                const activation = node.activation || 0;
                mat.color.copy(colorWhite).lerp(colorYellow, activation);
            }
            mat.opacity = 1;
        }
      }
    });

    // 2. Sync Vision
    if (headPos && organism.isAlive) {
        if (visionRef.current) {
            visionRef.current.position.copy(headPos);
            const pulse = 4.0 + Math.sin(state.clock.elapsedTime * 4) * 0.2; 
            visionRef.current.scale.setScalar(pulse);
            visionRef.current.visible = true;
        }
        if (magnetRef.current) {
            magnetRef.current.position.copy(headPos);
            magnetRef.current.rotation.x = -Math.PI / 2;
            magnetRef.current.visible = true;
        }
    } else {
        if (visionRef.current) visionRef.current.visible = false;
        if (magnetRef.current) magnetRef.current.visible = false;
    }

    // 3. Sync Muscles (OPTIMIZED LOOKUP)
    organism.muscles.forEach((muscle, i) => {
      const mesh = muscleRefs.current[i];
      if (mesh) {
        // Use Map lookup (O(1)) instead of Array.find (O(N))
        // Or use runtime refs if available from Physics pass, but View should be safe independently.
        const nA = nodeMap.get(muscle.nodeA);
        const nB = nodeMap.get(muscle.nodeB);

        if (nA && nB) {
          // UPDATE: Use shared vectors instead of `new Vector3`
          _v1.set(nA.pos.x, nA.pos.y, nA.pos.z);
          _v2.set(nB.pos.x, nB.pos.y, nB.pos.z);

          _vMid.copy(_v1).add(_v2).multiplyScalar(0.5);

          mesh.position.copy(_vMid);
          mesh.lookAt(_v2);
          mesh.rotateX(Math.PI / 2); 

          const currentLen = _v1.distanceTo(_v2);
          mesh.scale.set(1, currentLen, 1);

          const mat = mesh.material as THREE.MeshStandardMaterial;

          if (!organism.isAlive) {
             mat.color.copy(colorDead);
          } else {
            const target = muscle.targetLength || muscle.baseLength;
            const ratio = target / muscle.baseLength;

            if (ratio < 0.98) {
              mat.color.copy(colorWhite).lerp(colorRed, Math.min(1, (1 - ratio) * 5));
            } else if (ratio > 1.02) {
              mat.color.copy(colorWhite).lerp(colorBlue, Math.min(1, (ratio - 1) * 5));
            } else {
              mat.color.copy(colorWhite);
            }
          }
        }
      }
    });
  });

  return (
    <group ref={groupRef}>
      <mesh ref={visionRef} geometry={visionGeo} material={visionMat} />
      <mesh ref={magnetRef} geometry={magnetGeo} material={magnetMat} />

      {organism.nodes.map((node, i) => (
        <mesh
          key={node.id}
          ref={(el) => { if(el) nodeRefs.current[i] = el; }}
          geometry={nodeGeo}
        >
          <meshStandardMaterial color="white" />
        </mesh>
      ))}

      {organism.muscles.map((muscle, i) => (
        <mesh
          key={muscle.id}
          ref={(el) => { if(el) muscleRefs.current[i] = el; }}
          geometry={muscleGeo}
        >
           <meshStandardMaterial color="white" />
        </mesh>
      ))}
    </group>
  );
};

import { BioPhysicsEngine } from '../domain/BioPhysicsEngine';
import { Organism, ShapeType, NeuralGenome, FoodItem, Node, Muscle } from '../domain/types';
import { ShapeFactory } from '../domain/ShapeFactory';
import { VectorOps } from '../domain/math';
import { GeneticOperator } from '../domain/genetics/GeneticOperator';
import { IFitnessEvaluator, StandardFitnessEvaluator } from '../domain/fitness/FitnessEvaluator';
import { BrainController } from '../domain/neural/BrainController';

export class EvolutionService {
  public population: Organism[] = [];
  public currentGeneration = 1;
  public simulationTime = 0;

  private engine: BioPhysicsEngine;
  private geneticOperator: GeneticOperator;
  private fitnessEvaluator: IFitnessEvaluator;

  private populationSize = 20;
  private template: Organism | null = null; 

  // METABOLISM CONSTANTS
  private readonly START_ENERGY = 100;
  private readonly BASE_DECAY = 4.0; 
  private readonly HUNGER_ACCEL = 1.15; 
  private readonly FOOD_ENERGY = 30;

  // FEEDING MECHANICS
  public readonly MAGNET_RADIUS = 1.5; 
  private readonly MAGNET_FORCE = 0.8;  
  private readonly EAT_RADIUS = 0.8;    

  // SCARCITY CONTROLS (Tweakable via UI)
  public foodSpawnCount = 50;
  public foodSpawnRadius = 3.5;

  // OBSERVER PATTERN
  private updateListeners: ((pop: Organism[], time: number) => void)[] = [];
  private genCompleteListeners: ((best: Organism, gen: number) => void)[] = [];
  private newGenListeners: ((pop: Organism[]) => void)[] = [];

  constructor() {
    this.engine = new BioPhysicsEngine();
    this.geneticOperator = new GeneticOperator(0.05); // 5% mutation rate
    this.fitnessEvaluator = new StandardFitnessEvaluator();
  }

  public setGlobalStiffness(val: number) {
      this.engine.setConfig({ globalStiffness: val });
  }

  public setGlobalContractility(val: number) {
      this.engine.setConfig({ globalContractility: val });
  }

  // --- CONFIGURATION SETTERS ---
  public set foodWeight(val: number) {
      this.fitnessEvaluator.setWeights(val, (this.fitnessEvaluator as any).heightWeight);
  }
  public get foodWeight(): number { return (this.fitnessEvaluator as any).foodWeight; }

  public set heightWeight(val: number) {
       this.fitnessEvaluator.setWeights((this.fitnessEvaluator as any).foodWeight, val);
  }
  public get heightWeight(): number { return (this.fitnessEvaluator as any).heightWeight; }

  // --- REAL-TIME UPDATES ---

  public updateFoodDistribution(): void {
      this.population.forEach(org => {
          org.visibleFood = this.generateFoodTrack(org);
      });
  }

  // --- INITIALIZATION ---

  public initializePopulation(shape: ShapeType): void {
    this.template = ShapeFactory.create(shape, 'template');
    this.spawnGenerationFromTemplate(true);
  }

  public setTemplateAndReset(organism: Organism, startGeneration: number = 1): void {
      // Deep copy for the master template to ensure it's clean
      const safeJson = JSON.stringify(organism, (key, value) => {
          if (key === 'brain') return undefined;
          // Clear physics runtime caches on the template
          if (key === 'nodeRefA' || key === 'nodeRefB') return undefined;
          return value;
      });
      this.template = JSON.parse(safeJson);

      this.currentGeneration = startGeneration;
      this.spawnGenerationFromTemplate(false); 
  }

  private spawnGenerationFromTemplate(resetGen: boolean): void {
      if (!this.template) return;

      this.population = [];
      if (resetGen) this.currentGeneration = 1;
      this.simulationTime = 0;

      for (let i = 0; i < this.populationSize; i++) {
          const child = this.createOrganismFromTemplate(this.template, `gen${this.currentGeneration}_${i}`);

          if (i > 0) {
              this.geneticOperator.mutateGenome(child.neuralGenome);
          }

          child.visibleFood = this.generateFoodTrack(child);
          this.fitnessEvaluator.evaluate(child, 0.016);

          this.population.push(child);
      }

      this.notifyNewGeneration(this.population);
  }

  private generateFoodTrack(organism: Organism): FoodItem[] {
      const food: FoodItem[] = [];
      const numFood = this.foodSpawnCount; 

      let centerX = 0;
      let centerZ = 0;

      let head = organism.nodes.find(n => n.isHead);
      if (!head && organism.nodes.length > 0) head = organism.nodes[0];

      if (head) {
          centerX = head.pos.x;
          centerZ = head.pos.z;
      }

      const spread = this.foodSpawnRadius; 

      for(let i=0; i<numFood; i++) {
          const theta = Math.random() * Math.PI * 2;
          const radius = 1.0 + Math.random() * spread; 
          const x = centerX + Math.cos(theta) * radius;
          const z = centerZ + Math.sin(theta) * radius;
          const y = 1.0 + Math.random() * 2.5;

          food.push({
              id: `f_${i}`,
              pos: { x, y, z },
              energyValue: this.FOOD_ENERGY,
              consumed: false
          });
      }
      return food;
  }

  // --- SERIALIZATION ---

  public getBestOrganism(): Organism | null {
      if (this.population.length === 0) return null;
      const sorted = [...this.population].sort((a, b) => b.fitness - a.fitness);
      const best = sorted[0];

      const safeJson = JSON.stringify(best, (key, value) => {
          if (key === 'brain') return undefined;
          if (key === 'nodeRefA' || key === 'nodeRefB') return undefined;
          return value;
      });
      const cleanCopy = JSON.parse(safeJson);
      cleanCopy.generation = this.currentGeneration;

      return cleanCopy;
  }

  public getLeader(): Organism | null {
      if (this.population.length === 0) return null;

      let bestAlive: Organism | null = null;
      let maxZAlive = -Infinity;

      let bestDead: Organism | null = null;
      let maxZDead = -Infinity;

      for (const org of this.population) {
          let cz = 0;
          for(const n of org.nodes) cz += n.pos.z;
          cz /= org.nodes.length;

          if (org.isAlive) {
              if (cz > maxZAlive) { maxZAlive = cz; bestAlive = org; }
          } else {
              if (cz > maxZDead) { maxZDead = cz; bestDead = org; }
          }
      }

      return bestAlive || bestDead || this.population[0];
  }

  // --- LOOP ---

  public step(dt: number): void {
    this.simulationTime += dt;
    this.updatePhysics(dt, false);
    this.updateMetabolism(dt);

    if (Math.floor(this.simulationTime * 100) % 100 === 0) {
        this.applySocialLearning();
    }

    const allDead = !this.population.some(org => org.isAlive);
    if (allDead) {
        this.evolve();
    }

    this.notifyUpdate(this.population, this.simulationTime);
  }

  private applySocialLearning() {
      const sorted = [...this.population].sort((a, b) => b.fitness - a.fitness);
      if (sorted.length < 2) return;

      const leader = sorted[0];
      const bottomHalfStart = Math.floor(sorted.length / 2);

      for(let i=bottomHalfStart; i<sorted.length; i++) {
          const learner = sorted[i];
          if (!learner.isAlive) continue;

          const learningRate = 0.05; 
          const lg = learner.neuralGenome;
          const bg = leader.neuralGenome;

          for(let k=0; k<lg.synapseWeights.length; k++) {
              if (bg.synapseWeights[k] !== undefined) {
                  lg.synapseWeights[k] += (bg.synapseWeights[k] - lg.synapseWeights[k]) * learningRate;
              }
          }
      }
  }

  public async computeGenerationAsync(
    maxSafetyTime: number, 
    shouldStop: () => boolean, 
    onProgress?: (pct: number) => void
  ): Promise<void> {
      const dt = 0.016; 
      const BATCH_DURATION = 0.012; 
      let allDead = false;

      while (!allDead && this.simulationTime < maxSafetyTime) {
          if (shouldStop()) throw new Error("Evolution Aborted");

          let batchTime = 0;
          while (batchTime < BATCH_DURATION && !allDead && this.simulationTime < maxSafetyTime) {
              this.simulationTime += dt;
              batchTime += dt; 

              this.updatePhysics(dt, true);
              this.updateMetabolism(dt); 

              if (Math.abs(this.simulationTime % 1.0) < dt) {
                  this.applySocialLearning();
              }

              allDead = !this.population.some(org => org.isAlive);
          }

          const deadCount = this.population.filter(o => !o.isAlive).length;
          const pct = deadCount / this.populationSize;

          if (onProgress) onProgress(pct);
          await new Promise(resolve => setTimeout(resolve, 0));
      }

      this.finalizeFitness();
  }

  private updatePhysics(dt: number, fastMode: boolean): void {
    this.population.forEach(org => {
      // ORCHESTRATION: Update Brain THEN Physics
      // This decouples the brain from the engine
      if (org.isAlive) {
         if (!org.brain) {
             org.brain = new BrainController(org);
         }
         // Configurable muscle power is passed here from engine config via service
         const contractility = (this.engine as any).config.globalContractility;
         org.brain.update(dt, contractility);
      }

      this.engine.updateOrganism(org, this.simulationTime, fastMode);
    });
  }

  private updateMetabolism(dt: number): void {
      this.population.forEach(org => {
          // 1. Calculate Fitness
          this.fitnessEvaluator.evaluate(org, dt);

          if (!org.isAlive) return;

          org.hungerTime += dt;
          const hungerMultiplier = Math.pow(this.HUNGER_ACCEL, org.hungerTime);
          const loss = this.BASE_DECAY * hungerMultiplier * dt;
          org.energy -= loss;

          if (org.energy <= 0) {
              org.energy = 0;
              org.isAlive = false;
              return; 
          }

          let head = org.nodes.find(n => n.isHead);
          if (!head && org.nodes.length > 0) {
              let highest = org.nodes[0];
              for(const n of org.nodes) {
                  if (n.pos.y > highest.pos.y) highest = n;
              }
              head = highest;
              // @ts-ignore
              head.isHead = true; 
          }

          if (head) {
            for (const food of org.visibleFood) {
                if (food.consumed) continue;

                const dist = VectorOps.distance(head.pos, food.pos);

                if (dist < this.MAGNET_RADIUS) {
                    const pull = VectorOps.sub(head.pos, food.pos);
                    const strength = 1.0 - (dist / this.MAGNET_RADIUS);
                    const force = this.MAGNET_FORCE * (1.0 + strength);

                    food.pos.x += pull.x * force * 0.1;
                    food.pos.y += pull.y * force * 0.1;
                    food.pos.z += pull.z * force * 0.1;

                    const newDist = VectorOps.distance(head.pos, food.pos);

                    if (newDist < this.EAT_RADIUS) {
                        food.consumed = true;
                        org.energy += food.energyValue;
                        if (org.energy > org.maxEnergy) org.energy = org.maxEnergy;
                        org.hungerTime = 0;
                        org.foodEaten++;
                    }
                }
            }
          }
      });
  }

  private finalizeFitness() {
      this.population.forEach(org => this.fitnessEvaluator.finalize(org));
  }

  public evolve(): void {
    if (!this.template) return;

    this.finalizeFitness(); 

    // 1. Selection
    this.population.sort((a, b) => b.fitness - a.fitness);
    const survivorsCount = Math.floor(this.populationSize * 0.25);
    const survivors = this.population.slice(0, survivorsCount);
    const bestOrganism = survivors[0];

    this.notifyGenComplete(bestOrganism, this.currentGeneration);

    // 2. Reproduction
    this.currentGeneration++;
    const nextGen: Organism[] = [];

    // Elitism
    const champion = this.createOrganismFromTemplate(this.template, `gen${this.currentGeneration}_champ`);
    champion.neuralGenome = this.geneticOperator.cloneGenome(bestOrganism.neuralGenome);
    champion.visibleFood = this.generateFoodTrack(champion);
    this.fitnessEvaluator.evaluate(champion, 0.016);
    nextGen.push(champion);

    // Fill
    while (nextGen.length < this.populationSize) {
      const parent = survivors[Math.floor(Math.random() * survivors.length)];
      const child = this.createOrganismFromTemplate(this.template, `gen${this.currentGeneration}_${nextGen.length}`);
      child.neuralGenome = this.geneticOperator.cloneGenome(parent.neuralGenome);
      this.geneticOperator.mutateGenome(child.neuralGenome);
      child.visibleFood = this.generateFoodTrack(child);
      this.fitnessEvaluator.evaluate(child, 0.016);
      nextGen.push(child);
    }

    this.population = nextGen;
    this.simulationTime = 0;

    this.notifyNewGeneration(this.population);
  }

  // --- OPTIMIZATION: MANUAL COPYING ---
  // Replaces JSON.parse(JSON.stringify) for simulation cloning.
  // This is significantly faster and doesn't produce garbage strings.
  private createOrganismFromTemplate(template: Organism, newId: string): Organism {
      // 1. Clone Nodes
      const newNodes: Node[] = template.nodes.map(n => ({
          ...n,
          pos: { ...n.pos },
          oldPos: { ...n.pos }, // Reset momentum
          activation: 0,
          gripSignal: 0,
          isGripping: false
      }));

      // 2. Clone Muscles
      const newMuscles: Muscle[] = template.muscles.map(m => ({
          ...m,
          currentLength: undefined,
          targetLength: undefined,
          phase: Math.random() * Math.PI * 2, // Randomize start phase
          // IMPORTANT: Clear runtime refs so the engine rebuilds them correctly for the new nodes
          nodeRefA: undefined,
          nodeRefB: undefined
      }));

      // 3. Clone Genome (The Operator handles deep array copy)
      const newGenome = this.geneticOperator.cloneGenome(template.neuralGenome);

      // 4. Construct
      const clone: Organism = {
          id: newId,
          shape: template.shape,
          nodes: newNodes,
          muscles: newMuscles,
          neuralGenome: newGenome,
          fitness: 0,
          generation: 1,
          brain: undefined,

          energy: this.START_ENERGY,
          maxEnergy: this.START_ENERGY,
          hungerTime: 0,
          isAlive: true,
          foodEaten: 0,
          visibleFood: [],

          initialVerticalSize: template.initialVerticalSize || 1.0,
          currentHeightScore: 1.0,
          accumulatedPostureScore: 0,
          bestHeightScore: 0
      };

      // Recalculate Initial Size if needed (defensive)
      if (!clone.initialVerticalSize) {
           const head = clone.nodes.find(n => n.isHead);
           let minY = Infinity;
           clone.nodes.forEach(n => { if (n.pos.y < minY) minY = n.pos.y; });
           const hY = head ? head.pos.y : 1.0;
           clone.initialVerticalSize = Math.max(0.1, hY - minY);
      }

      return clone;
  }

  // --- OBSERVER PATTERN ---

  public subscribe(type: 'update', cb: (pop: Organism[], time: number) => void): () => void;
  public subscribe(type: 'genComplete', cb: (best: Organism, gen: number) => void): () => void;
  public subscribe(type: 'newGen', cb: (pop: Organism[]) => void): () => void;
  public subscribe(type: string, cb: any): () => void {
      if (type === 'update') {
          this.updateListeners.push(cb);
          return () => this.updateListeners = this.updateListeners.filter(l => l !== cb);
      }
      if (type === 'genComplete') {
          this.genCompleteListeners.push(cb);
          return () => this.genCompleteListeners = this.genCompleteListeners.filter(l => l !== cb);
      }
      if (type === 'newGen') {
          this.newGenListeners.push(cb);
          return () => this.newGenListeners = this.newGenListeners.filter(l => l !== cb);
      }
      return () => {};
  }

  public onUpdate(cb: (pop: Organism[], time: number) => void) { this.subscribe('update', cb); }
  public onGenComplete(cb: (best: Organism, gen: number) => void) { this.subscribe('genComplete', cb); }
  public onNewGeneration(cb: (pop: Organism[]) => void) { this.subscribe('newGen', cb); }

  private notifyUpdate(pop: Organism[], time: number) { this.updateListeners.forEach(l => l(pop, time)); }
  private notifyGenComplete(best: Organism, gen: number) { this.genCompleteListeners.forEach(l => l(best, gen)); }
  private notifyNewGeneration(pop: Organism[]) { this.newGenListeners.forEach(l => l(pop)); }
}

export class CentralPatternGenerator {
  private size: number = 20; 
  private weights: number[]; 

  // DOUBLE BUFFERING (Optimization)
  // We flip between A and B to avoid creating new arrays every tick
  private bufferA: Float32Array;
  private bufferB: Float32Array;
  private usingBufferA: boolean = true;

  constructor(size: number = 20) {
    this.size = size;
    this.bufferA = new Float32Array(size);
    this.bufferB = new Float32Array(size);
    this.weights = [];
  }

  public initialize(weights: number[]): void {
    this.weights = weights;
    if (this.weights.length < this.size * this.size) {
        const missing = (this.size * this.size) - this.weights.length;
        for(let i=0; i<missing; i++) this.weights.push(Math.random() - 0.5);
    }
  }

  public tick(sensoryInput: number): void {
    // 1. Select Buffers (Read from current, Write to next)
    const currentNeurons = this.usingBufferA ? this.bufferA : this.bufferB;
    const nextNeurons = this.usingBufferA ? this.bufferB : this.bufferA;

    const leak = 0.2; // 20% new info, 80% memory. Makes the brain "slower" and smoother.

    // 2. Update State
    for (let i = 0; i < this.size; i++) {
      let sum = 0;
      const rowOffset = i * this.size;

      // Internal Recurrence (Matrix Multiplication)
      for (let j = 0; j < this.size; j++) {
        const w = this.weights[rowOffset + j] || 0;
        sum += currentNeurons[j] * w;
      }

      // Sensory Input
      sum += sensoryInput * 0.5;

      // Activation with Inertia (Leaky Integrator)
      const targetActivation = Math.tanh(sum);

      // Smooth transition: New = Old * (1-leak) + Target * leak
      nextNeurons[i] = currentNeurons[i] * (1 - leak) + targetActivation * leak;
    }

    // 3. Swap Buffer Flag
    this.usingBufferA = !this.usingBufferA;
  }

  public getSignal(muscleIndex: number, outputWeights: number[]): number {
    const neurons = this.usingBufferA ? this.bufferA : this.bufferB;

    let sum = 0;
    const offset = (muscleIndex * this.size) % outputWeights.length;

    for (let i = 0; i < this.size; i++) {
        const wIdx = (offset + i) % outputWeights.length;
        sum += neurons[i] * outputWeights[wIdx];
    }

    return Math.tanh(sum); 
  }
}

import { Organism, Node } from '../types';
import { NeuralNode } from './NeuralNode';
import { CentralPatternGenerator } from './CentralPatternGenerator';
import { VectorOps } from '../math';

// Optimization Structure
interface Synapse {
    nodeA: NeuralNode;
    nodeB: NeuralNode;
    weightIndex: number;
}

export class BrainController {
  private neuralNodes: Map<string, NeuralNode> = new Map();
  private cpg: CentralPatternGenerator;
  private organism: Organism;
  private isInitialized = false;

  // OPTIMIZATION: Flattened array for O(1) iteration
  private synapses: Synapse[] = []; 

  // Simulation Time Tracker
  private internalTime = 0;

  // Spinal Wave Props
  private muscleRestDistances: Float32Array; // Flattened distance cache

  // Decision Timer
  private decisionTimer = 0;
  private readonly DECISION_INTERVAL_BASE = 0.08; 

  // --- LEARNING MEMORY ---
  private previousEnergy: number = 0;
  private previousDistanceToFood: number = Infinity;
  private readonly VISION_RADIUS = 4.0;
  private readonly HEBBIAN_RATE = 0.15; // Learning Rate

  constructor(organism: Organism) {
    this.organism = organism;
    this.cpg = new CentralPatternGenerator(20);
    this.previousEnergy = organism.energy;

    // Initialize Neural Nodes
    organism.nodes.forEach(node => {
      this.neuralNodes.set(node.id, new NeuralNode(node));
    });

    // Init Empty Cache
    this.muscleRestDistances = new Float32Array(organism.muscles.length);

    if (organism.neuralGenome) {
        this.cpg.initialize(organism.neuralGenome.reservoirWeights);
    }
  }

  private initializeNervousSystem() {
      if (this.organism.nodes.length === 0) return;

      // Identify Head
      let headNode = this.organism.nodes.find(n => n.isHead);
      if (!headNode) {
          headNode = this.organism.nodes[0];
          // @ts-ignore
          headNode.isHead = true; 
      }

      // 1. Build Distance Cache
      this.organism.muscles.forEach((m, i) => {
          const nA = this.organism.nodes.find(n => n.id === m.nodeA);
          const nB = this.organism.nodes.find(n => n.id === m.nodeB);
          if (nA && nB) {
              const midX = (nA.pos.x + nB.pos.x) / 2;
              const midY = (nA.pos.y + nB.pos.y) / 2;
              const midZ = (nA.pos.z + nB.pos.z) / 2;

              const dist = VectorOps.distance(
                  headNode!.pos, 
                  { x: midX, y: midY, z: midZ }
              );
              this.muscleRestDistances[i] = dist;
          }
      });

      // 2. Build Synapse Cache (Optimization)
      // We pre-calculate connections so we don't query the Map every frame
      this.synapses = [];
      const weightCount = this.organism.neuralGenome?.synapseWeights.length || 1;

      this.organism.muscles.forEach((muscle, i) => {
          const nnA = this.neuralNodes.get(muscle.nodeA);
          const nnB = this.neuralNodes.get(muscle.nodeB);
          if (nnA && nnB) {
              this.synapses.push({
                  nodeA: nnA,
                  nodeB: nnB,
                  weightIndex: i % weightCount
              });
          }
      });

      // 3. Reset Muscle Oscillators
      this.organism.muscles.forEach(m => {
          m.targetLength = m.baseLength;
          m.phase = Math.random() * Math.PI * 2; 
          m.freq = 1.0; 
          m.amp = 0.0;
      });

      this.isInitialized = true;
  }

  public update(dt: number, powerScale: number = 1.0): void {
    const genome = this.organism.neuralGenome;
    if (!genome) return;

    const brainDt = dt * (genome.internalClockSpeed || 1.0);

    if (!this.isInitialized) {
        this.initializeNervousSystem();
    }

    this.internalTime += brainDt;
    this.decisionTimer += brainDt;

    if (this.decisionTimer >= this.DECISION_INTERVAL_BASE) {
        this.think(brainDt);
        this.learn();
        this.decisionTimer = 0;
    }

    // --- SPINAL WAVE (Motor Control) ---
    const WAVE_FREQ = genome.waveFreq || 1.5; 
    const WAVE_SPEED = genome.waveSpeed || 1.0; 
    const FORCED_AMP = 0.15; 
    const MAX_DEFORMATION = 0.3; 
    const PI2 = Math.PI * 2;

    // Use loop index for cache access
    for(let i=0; i<this.organism.muscles.length; i++) {
        const m = this.organism.muscles[i];

        m.phase += m.freq * brainDt * PI2;
        if (m.phase > PI2) m.phase -= PI2;
        const brainSignal = Math.sin(m.phase) * m.amp;

        const dist = this.muscleRestDistances[i]; // Direct array access
        const nerveLag = dist * WAVE_SPEED;
        const spinalSignal = Math.sin(this.internalTime * WAVE_FREQ * PI2 - nerveLag) * FORCED_AMP;

        let totalSignal = (spinalSignal + brainSignal) * powerScale;

        // Clamp
        if (totalSignal > MAX_DEFORMATION) totalSignal = MAX_DEFORMATION;
        if (totalSignal < -MAX_DEFORMATION) totalSignal = -MAX_DEFORMATION;

        const desiredLength = m.baseLength * (1 + totalSignal);

        // Inertia
        m.targetLength = m.targetLength || m.baseLength;
        m.targetLength += (desiredLength - m.targetLength) * 0.05;
        m.currentLength = m.targetLength;
    }
  }

  private think(dt: number): void {
    const genome = this.organism.neuralGenome;

    // 1. GATHER PROPRIOCEPTION
    let globalSensoryInput = 0;
    for (const nn of this.neuralNodes.values()) {
        nn.sense(dt);
        globalSensoryInput += nn.inputSum;
    }

    // 2. VISION WITH GATED ATTENTION
    const head = this.organism.nodes.find(n => n.isHead);
    if (head) {
        // Optimized Vision Logic ...
        const stability = Math.min(1.0, Math.max(0, (head.pos.y - 0.2))); 
        let nearestDistSq = Infinity;
        let tX=0, tY=0, tZ=0;
        let foundFood = false;

        const vRadSq = this.VISION_RADIUS * this.VISION_RADIUS;

        for (const food of this.organism.visibleFood) {
            if (food.consumed) continue;

            const dx = food.pos.x - head.pos.x;
            const dy = food.pos.y - head.pos.y;
            const dz = food.pos.z - head.pos.z;
            const distSq = dx*dx + dy*dy + dz*dz;

            if (distSq < vRadSq) {
                if (distSq < nearestDistSq) {
                    nearestDistSq = distSq;
                    tX = dx; tY = dy; tZ = dz;
                    foundFood = true;
                }
            }
        }

        this.previousDistanceToFood = foundFood ? Math.sqrt(nearestDistSq) : Infinity;

        if (foundFood && stability > 0.1) {
            const dist = Math.sqrt(nearestDistSq);
            const headNeural = this.neuralNodes.get(head.id);
            if (headNeural) {
                const signalStrength = Math.max(0, 1.0 - (dist / this.VISION_RADIUS)) * stability;
                headNeural.inputSum += (tX / dist) * signalStrength * 3.0; 
                headNeural.inputSum += (tY / dist) * signalStrength * 3.0; 
                headNeural.inputSum += (tZ / dist) * signalStrength * 3.0; 
                globalSensoryInput += signalStrength * 2.0;
            }
        }
    }

    globalSensoryInput /= (this.neuralNodes.size || 1);

    // 3. SYNAPTIC PROPAGATION (OPTIMIZED)
    // We iterate the pre-compiled array instead of Map.get() inside a loop
    for(let i=0; i<this.synapses.length; i++) {
        const s = this.synapses[i];
        const w = genome.synapseWeights[s.weightIndex];
        s.nodeB.inputSum += s.nodeA.activation * w;
        s.nodeA.inputSum += s.nodeB.activation * w;
    }

    for (const nn of this.neuralNodes.values()) {
        nn.updateActivation();
    }

    // 4. RESERVOIR COMPUTING
    this.cpg.tick(globalSensoryInput);

    // 5. MOTOR OUTPUT
    const mus = this.organism.muscles;
    const len = mus.length;
    for(let i=0; i<len; i++) {
        const muscle = mus[i];
        const rawAmp = this.cpg.getSignal(i, genome.outputWeights); 
        const rawFreq = this.cpg.getSignal(i + 1, genome.outputWeights); 

        const targetAmp = Math.abs(rawAmp) * 0.3; 
        const targetFreq = 0.5 + ((rawFreq + 1) / 2) * 2.5; // range 0.5 to 3.0

        muscle.amp += (targetAmp - muscle.amp) * 0.1;
        muscle.freq += (targetFreq - muscle.freq) * 0.1;
    }

    // 6. SUCTION OUTPUT
    if (genome.gripWeights && genome.gripWeights.length > 0) {
        const nodes = this.organism.nodes;
        for(let i=0; i<nodes.length; i++) {
            const rawSignal = this.cpg.getSignal(i, genome.gripWeights);
            const normalized = (rawSignal + 1) / 2;
            const node = nodes[i];
            const oldGrip = node.gripSignal || 0;
            node.gripSignal = oldGrip + (normalized - oldGrip) * 0.2;
        }
    }
  }

  private learn(): void {
      const genome = this.organism.neuralGenome;
      let learningSignal = 0;

      // 1. METABOLIC REWARD
      const currentEnergy = this.organism.energy;
      const energyDelta = currentEnergy - this.previousEnergy;
      if (energyDelta > 0.5) learningSignal += 1.0;
      this.previousEnergy = currentEnergy;

      // 2. VESTIBULAR PAIN
      const head = this.organism.nodes.find(n => n.isHead);
      if (head && head.pos.y < 0.2) {
          learningSignal -= 0.5; 
      }

      // APPLY LEARNING (OPTIMIZED)
      if (Math.abs(learningSignal) > 0.1) {
          for(let i=0; i<this.synapses.length; i++) {
              const s = this.synapses[i];
              const coActivity = s.nodeA.activation * s.nodeB.activation;

              if (coActivity > 0.1) {
                  let w = genome.synapseWeights[s.weightIndex];
                  w += this.HEBBIAN_RATE * learningSignal * coActivity;

                  // Clamp (Inline check is faster than Math.max/min)
                  if (w > 3.0) w = 3.0;
                  else if (w < -3.0) w = -3.0;

                  genome.synapseWeights[s.weightIndex] = w;
              }
          }
      }
  }
}

import { BioPhysicsEngine } from '../domain/BioPhysicsEngine';
import { Organism, ShapeType, NeuralGenome, FoodItem, Node, Muscle } from '../domain/types';
import { ShapeFactory } from '../domain/ShapeFactory';
import { VectorOps } from '../domain/math';
import { GeneticOperator } from '../domain/genetics/GeneticOperator';
import { IFitnessEvaluator, StandardFitnessEvaluator } from '../domain/fitness/FitnessEvaluator';
import { BrainController } from '../domain/neural/BrainController';

export class EvolutionService {
  public population: Organism[] = [];
  public currentGeneration = 1;
  public simulationTime = 0;

  private engine: BioPhysicsEngine;
  private geneticOperator: GeneticOperator;
  private fitnessEvaluator: IFitnessEvaluator;

  private populationSize = 20;
  private template: Organism | null = null; 

  private readonly START_ENERGY = 100;
  private readonly BASE_DECAY = 4.0; 
  private readonly HUNGER_ACCEL = 1.15; 
  private readonly FOOD_ENERGY = 30;

  public readonly MAGNET_RADIUS = 1.5; 
  private readonly MAGNET_FORCE = 0.8;  
  private readonly EAT_RADIUS = 0.8;    

  public foodSpawnCount = 50;
  public foodSpawnRadius = 3.5;

  private updateListeners: ((pop: Organism[], time: number) => void)[] = [];
  private genCompleteListeners: ((best: Organism, gen: number) => void)[] = [];
  private newGenListeners: ((pop: Organism[]) => void)[] = [];

  constructor() {
    this.engine = new BioPhysicsEngine();
    this.geneticOperator = new GeneticOperator(0.05); // 5% mutation rate
    this.fitnessEvaluator = new StandardFitnessEvaluator();
  }

  public setGlobalStiffness(val: number) {
      this.engine.setConfig({ globalStiffness: val });
  }

  public setGlobalContractility(val: number) {
      this.engine.setConfig({ globalContractility: val });
  }

  public set foodWeight(val: number) {
      this.fitnessEvaluator.setWeights(val, (this.fitnessEvaluator as any).heightWeight);
  }
  public get foodWeight(): number { return (this.fitnessEvaluator as any).foodWeight; }

  public set heightWeight(val: number) {
       this.fitnessEvaluator.setWeights((this.fitnessEvaluator as any).foodWeight, val);
  }
  public get heightWeight(): number { return (this.fitnessEvaluator as any).heightWeight; }

  public updateFoodDistribution(): void {
      this.population.forEach(org => {
          org.visibleFood = this.generateFoodTrack(org);
      });
  }

  public initializePopulation(shape: ShapeType): void {
    this.template = ShapeFactory.create(shape, 'template');
    this.spawnGenerationFromTemplate(true);
  }

  public setTemplateAndReset(organism: Organism, startGeneration: number = 1): void {
      // Deep copy for the master template to ensure it's clean
      const safeJson = JSON.stringify(organism, (key, value) => {
          if (key === 'brain') return undefined;
          if (key === 'nodeRefA' || key === 'nodeRefB') return undefined;
          return value;
      });
      this.template = JSON.parse(safeJson);

      this.currentGeneration = startGeneration;
      this.spawnGenerationFromTemplate(false); 
  }

  private spawnGenerationFromTemplate(resetGen: boolean): void {
      if (!this.template) return;

      this.population = [];
      if (resetGen) this.currentGeneration = 1;
      this.simulationTime = 0;

      for (let i = 0; i < this.populationSize; i++) {
          const child = this.createOrganismFromTemplate(this.template, `gen${this.currentGeneration}_${i}`);

          if (i > 0) {
              this.geneticOperator.mutateGenome(child.neuralGenome);
          }

          child.visibleFood = this.generateFoodTrack(child);
          this.fitnessEvaluator.evaluate(child, 0.016);

          this.population.push(child);
      }

      this.notifyNewGeneration(this.population);
  }

  private generateFoodTrack(organism: Organism): FoodItem[] {
      const food: FoodItem[] = [];
      const numFood = this.foodSpawnCount; 

      let centerX = 0;
      let centerZ = 0;

      let head = organism.nodes.find(n => n.isHead);
      if (!head && organism.nodes.length > 0) head = organism.nodes[0];

      if (head) {
          centerX = head.pos.x;
          centerZ = head.pos.z;
      }

      const spread = this.foodSpawnRadius; 

      for(let i=0; i<numFood; i++) {
          const theta = Math.random() * Math.PI * 2;
          const radius = 1.0 + Math.random() * spread; 
          const x = centerX + Math.cos(theta) * radius;
          const z = centerZ + Math.sin(theta) * radius;
          const y = 1.0 + Math.random() * 2.5;

          food.push({
              id: `f_${i}`,
              pos: { x, y, z },
              energyValue: this.FOOD_ENERGY,
              consumed: false
          });
      }
      return food;
  }

  public getBestOrganism(): Organism | null {
      if (this.population.length === 0) return null;
      const sorted = [...this.population].sort((a, b) => b.fitness - a.fitness);
      const best = sorted[0];

      const safeJson = JSON.stringify(best, (key, value) => {
          if (key === 'brain') return undefined;
          if (key === 'nodeRefA' || key === 'nodeRefB') return undefined;
          return value;
      });
      const cleanCopy = JSON.parse(safeJson);
      cleanCopy.generation = this.currentGeneration;

      return cleanCopy;
  }

  public getLeader(): Organism | null {
      if (this.population.length === 0) return null;

      let bestAlive: Organism | null = null;
      let maxZAlive = -Infinity;

      let bestDead: Organism | null = null;
      let maxZDead = -Infinity;

      for (const org of this.population) {
          let cz = 0;
          for(const n of org.nodes) cz += n.pos.z;
          cz /= org.nodes.length;

          if (org.isAlive) {
              if (cz > maxZAlive) { maxZAlive = cz; bestAlive = org; }
          } else {
              if (cz > maxZDead) { maxZDead = cz; bestDead = org; }
          }
      }

      return bestAlive || bestDead || this.population[0];
  }

  public step(dt: number): void {
    this.simulationTime += dt;
    this.updatePhysics(dt, false);
    this.updateMetabolism(dt);

    if (Math.floor(this.simulationTime * 100) % 100 === 0) {
        this.applySocialLearning();
    }

    const allDead = !this.population.some(org => org.isAlive);
    if (allDead) {
        this.evolve();
    }

    this.notifyUpdate(this.population, this.simulationTime);
  }

  private applySocialLearning() {
      const sorted = [...this.population].sort((a, b) => b.fitness - a.fitness);
      if (sorted.length < 2) return;

      const leader = sorted[0];
      const bottomHalfStart = Math.floor(sorted.length / 2);

      for(let i=bottomHalfStart; i<sorted.length; i++) {
          const learner = sorted[i];
          if (!learner.isAlive) continue;

          const learningRate = 0.05; 
          const lg = learner.neuralGenome;
          const bg = leader.neuralGenome;

          for(let k=0; k<lg.synapseWeights.length; k++) {
              if (bg.synapseWeights[k] !== undefined) {
                  lg.synapseWeights[k] += (bg.synapseWeights[k] - lg.synapseWeights[k]) * learningRate;
              }
          }
      }
  }

  public async computeGenerationAsync(
    maxSafetyTime: number, 
    shouldStop: () => boolean, 
    onProgress?: (pct: number) => void
  ): Promise<void> {
      const dt = 0.016; 
      const BATCH_DURATION = 0.012; 
      let allDead = false;

      while (!allDead && this.simulationTime < maxSafetyTime) {
          if (shouldStop()) throw new Error("Evolution Aborted");

          let batchTime = 0;
          while (batchTime < BATCH_DURATION && !allDead && this.simulationTime < maxSafetyTime) {
              this.simulationTime += dt;
              batchTime += dt; 

              this.updatePhysics(dt, true);
              this.updateMetabolism(dt); 

              if (Math.abs(this.simulationTime % 1.0) < dt) {
                  this.applySocialLearning();
              }

              allDead = !this.population.some(org => org.isAlive);
          }

          const deadCount = this.population.filter(o => !o.isAlive).length;
          const pct = deadCount / this.populationSize;

          if (onProgress) onProgress(pct);
          await new Promise(resolve => setTimeout(resolve, 0));
      }

      this.finalizeFitness();
  }

  private updatePhysics(dt: number, fastMode: boolean): void {
    this.population.forEach(org => {
      // ORCHESTRATION: Update Brain THEN Physics
      if (org.isAlive) {
         if (!org.brain) {
             org.brain = new BrainController(org);
         }
         const contractility = (this.engine as any).config.globalContractility;
         org.brain.update(dt, contractility);
      }

      this.engine.updateOrganism(org, this.simulationTime, fastMode);
    });
  }

  private updateMetabolism(dt: number): void {
      this.population.forEach(org => {
          // 1. Calculate Fitness
          this.fitnessEvaluator.evaluate(org, dt);

          if (!org.isAlive) return;

          org.hungerTime += dt;
          const hungerMultiplier = Math.pow(this.HUNGER_ACCEL, org.hungerTime);
          const loss = this.BASE_DECAY * hungerMultiplier * dt;
          org.energy -= loss;

          if (org.energy <= 0) {
              org.energy = 0;
              org.isAlive = false;
              return; 
          }

          let head = org.nodes.find(n => n.isHead);
          if (!head && org.nodes.length > 0) {
              // Fallback logic for finding head if node ref lost
              let highest = org.nodes[0];
              for(const n of org.nodes) {
                  if (n.pos.y > highest.pos.y) highest = n;
              }
              head = highest;
              // @ts-ignore
              head.isHead = true; 
          }

          if (head) {
            for (const food of org.visibleFood) {
                if (food.consumed) continue;

                // INLINED MATH (Optimized)
                // Avoid VectorOps.distance and VectorOps.sub object creation
                const dx = head.pos.x - food.pos.x;
                const dy = head.pos.y - food.pos.y;
                const dz = head.pos.z - food.pos.z;
                const distSq = dx*dx + dy*dy + dz*dz;

                // Fast reject check (Squared)
                if (distSq < this.MAGNET_RADIUS * this.MAGNET_RADIUS) {
                    const dist = Math.sqrt(distSq);

                    // Pull Force
                    const strength = 1.0 - (dist / this.MAGNET_RADIUS);
                    const force = this.MAGNET_FORCE * (1.0 + strength);

                    // Apply directly (Pull vector is -diff vector)
                    // pull = head - food. so dx = head.x - food.x
                    food.pos.x += dx * force * 0.1;
                    food.pos.y += dy * force * 0.1;
                    food.pos.z += dz * force * 0.1;

                    // Recheck Distance (Cheap approximation: assume it moved closer)
                    // But to be exact for eating:
                    const ndx = head.pos.x - food.pos.x;
                    const ndy = head.pos.y - food.pos.y;
                    const ndz = head.pos.z - food.pos.z;
                    const nDistSq = ndx*ndx + ndy*ndy + ndz*ndz;

                    if (nDistSq < this.EAT_RADIUS * this.EAT_RADIUS) {
                        food.consumed = true;
                        org.energy += food.energyValue;
                        if (org.energy > org.maxEnergy) org.energy = org.maxEnergy;
                        org.hungerTime = 0;
                        org.foodEaten++;
                    }
                }
            }
          }
      });
  }

  private finalizeFitness() {
      this.population.forEach(org => this.fitnessEvaluator.finalize(org));
  }

  public evolve(): void {
    if (!this.template) return;

    this.finalizeFitness(); 

    // 1. Selection
    this.population.sort((a, b) => b.fitness - a.fitness);
    const survivorsCount = Math.floor(this.populationSize * 0.25);
    const survivors = this.population.slice(0, survivorsCount);
    const bestOrganism = survivors[0];

    this.notifyGenComplete(bestOrganism, this.currentGeneration);

    // 2. Reproduction
    this.currentGeneration++;
    const nextGen: Organism[] = [];

    // Elitism
    const champion = this.createOrganismFromTemplate(this.template, `gen${this.currentGeneration}_champ`);
    champion.neuralGenome = this.geneticOperator.cloneGenome(bestOrganism.neuralGenome);
    champion.visibleFood = this.generateFoodTrack(champion);
    this.fitnessEvaluator.evaluate(champion, 0.016);
    nextGen.push(champion);

    // Fill
    while (nextGen.length < this.populationSize) {
      const parent = survivors[Math.floor(Math.random() * survivors.length)];
      const child = this.createOrganismFromTemplate(this.template, `gen${this.currentGeneration}_${nextGen.length}`);
      child.neuralGenome = this.geneticOperator.cloneGenome(parent.neuralGenome);
      this.geneticOperator.mutateGenome(child.neuralGenome);
      child.visibleFood = this.generateFoodTrack(child);
      this.fitnessEvaluator.evaluate(child, 0.016);
      nextGen.push(child);
    }

    this.population = nextGen;
    this.simulationTime = 0;

    this.notifyNewGeneration(this.population);
  }

  private createOrganismFromTemplate(template: Organism, newId: string): Organism {
      // 1. Clone Nodes
      const newNodes: Node[] = template.nodes.map(n => ({
          ...n,
          pos: { ...n.pos },
          oldPos: { ...n.pos }, 
          activation: 0,
          gripSignal: 0,
          isGripping: false
      }));

      // 2. Clone Muscles
      const newMuscles: Muscle[] = template.muscles.map(m => ({
          ...m,
          currentLength: undefined,
          targetLength: undefined,
          phase: Math.random() * Math.PI * 2,
          nodeRefA: undefined,
          nodeRefB: undefined
      }));

      // 3. Clone Genome 
      const newGenome = this.geneticOperator.cloneGenome(template.neuralGenome);

      // 4. Construct
      const clone: Organism = {
          id: newId,
          shape: template.shape,
          nodes: newNodes,
          muscles: newMuscles,
          neuralGenome: newGenome,
          fitness: 0,
          generation: 1,
          brain: undefined,

          energy: this.START_ENERGY,
          maxEnergy: this.START_ENERGY,
          hungerTime: 0,
          isAlive: true,
          foodEaten: 0,
          visibleFood: [],

          initialVerticalSize: template.initialVerticalSize || 1.0,
          currentHeightScore: 1.0,
          accumulatedPostureScore: 0,
          bestHeightScore: 0
      };

      if (!clone.initialVerticalSize) {
           const head = clone.nodes.find(n => n.isHead);
           let minY = Infinity;
           clone.nodes.forEach(n => { if (n.pos.y < minY) minY = n.pos.y; });
           const hY = head ? head.pos.y : 1.0;
           clone.initialVerticalSize = Math.max(0.1, hY - minY);
      }

      return clone;
  }

  public subscribe(type: 'update', cb: (pop: Organism[], time: number) => void): () => void;
  public subscribe(type: 'genComplete', cb: (best: Organism, gen: number) => void): () => void;
  public subscribe(type: 'newGen', cb: (pop: Organism[]) => void): () => void;
  public subscribe(type: string, cb: any): () => void {
      if (type === 'update') {
          this.updateListeners.push(cb);
          return () => this.updateListeners = this.updateListeners.filter(l => l !== cb);
      }
      if (type === 'genComplete') {
          this.genCompleteListeners.push(cb);
          return () => this.genCompleteListeners = this.genCompleteListeners.filter(l => l !== cb);
      }
      if (type === 'newGen') {
          this.newGenListeners.push(cb);
          return () => this.newGenListeners = this.newGenListeners.filter(l => l !== cb);
      }
      return () => {};
  }

  public onUpdate(cb: (pop: Organism[], time: number) => void) { this.subscribe('update', cb); }
  public onGenComplete(cb: (best: Organism, gen: number) => void) { this.subscribe('genComplete', cb); }
  public onNewGeneration(cb: (pop: Organism[]) => void) { this.subscribe('newGen', cb); }

  private notifyUpdate(pop: Organism[], time: number) { this.updateListeners.forEach(l => l(pop, time)); }
  private notifyGenComplete(best: Organism, gen: number) { this.genCompleteListeners.forEach(l => l(best, gen)); }
  private notifyNewGeneration(pop: Organism[]) { this.newGenListeners.forEach(l => l(pop)); }
}

// Hexagonal Architecture: Domain Layer (Inner Core)
// Zero dependencies on UI or Rendering libraries.

export interface Vec3 {
  x: number;
  y: number;
  z: number;
}

export interface Node {
  id: string;
  pos: Vec3;
  oldPos: Vec3; // For Verlet integration
  mass: number;
  friction: number;
  isFixed?: boolean;
  isHead?: boolean; // NEW: The only node that can eat

  // SUCTION MECHANICS
  isGripping?: boolean; // Read-only physics state
  gripSignal?: number;  // 0.0 to 1.0 (Controlled by Brain). High = Release Suction.

  // EDITOR METADATA (Preserves shape upon reloading)
  originalGridCoord?: { x: number; y: number; z: number }; 

  // Neural State
  activation?: number; // 0.0 to 1.0 (Visualization Glow)
  // Physics State
}

export interface Muscle {
  id: string;
  nodeA: string; // ID reference
  nodeB: string; // ID reference
  baseLength: number;
  stiffness: number;
  dnaIndex: number; // Maps to a Gene (Index in genome arrays)

  // Runtime Physics State
  currentLength?: number; 
  targetLength?: number; 

  // --- RUNTIME OPTIMIZATION (O(1) Access) ---
  nodeRefA?: Node;
  nodeRefB?: Node;

  // --- OSCILLATOR STATE (The Anti-Vibration Core) ---
  // The brain controls these parameters, not the length directly.
  phase: number;      // Current position in the sine wave (0 to 2PI)
  freq: number;       // How fast it pulses (Hz). Clamped to prevent jitter.
  amp: number;        // How much it expands (0.0 to 0.4). 
}

// Replaced simple Sine Gene with Neural Genome
export interface NeuralGenome {
  // GNN Weights: How much signal flows through each muscle (Synapse)
  synapseWeights: number[]; 
  // LSM Weights: The chaotic reservoir weights (simplified as a float array)
  reservoirWeights: number[];
  // Output Weights: Mapping the reservoir state to muscle contraction
  outputWeights: number[]; 
  // NEW: Predictive World Model Weights (Reservoir -> Predicted Sensory Input)
  predictionWeights: number[];
  // NEW: Grip Control Weights (Reservoir -> Node Suction Release)
  gripWeights: number[]; 
  // Biases for neurons
  biases: number[];

  // --- EVOLVABLE BRAIN DYNAMICS ---
  internalClockSpeed: number; // Multiplier (0.5 to 2.0). How fast the brain thinks relative to physics.
  waveFreq: number;           // Hz (0.5 to 3.0). Base frequency of the spinal generator.
  waveSpeed: number;          // Propagation speed of the wave along the body.
}

export interface FoodItem {
    id: string;
    pos: Vec3;
    energyValue: number;
    consumed: boolean;
}

export enum ShapeType {
  CUBE = 'CUBE', // Cartesian Lattice
  TETRAHEDRON = 'TETRAHEDRON', // Offset Lattice
  WORM = 'WORM', // Legacy
  HEX = 'HEX', // 3D Hexagonal Prism Layout
}

export interface Organism {
  id: string;
  shape: ShapeType; // NEW: Tracks the lattice type for the Architect
  nodes: Node[];
  muscles: Muscle[];
  // The Blueprint
  neuralGenome: NeuralGenome;
  // The Runtime Brain (Controller instance, not serialized usually, but here for simplicity)
  brain?: any; 

  // Stats
  fitness: number; // Total Score
  generation: number;

  // NEW: Distance Metrics (Replacing Posture)
  initialHeadPos: Vec3; // BENCHMARK: Where the head started
  distanceTraveled: number; // Real-time distance from start

  // NEW: Metabolism & Survival
  energy: number;          // 0 to 100
  maxEnergy: number;       
  hungerTime: number;      // Time since last meal (drives exponential decay)
  isAlive: boolean;
  foodEaten: number;
  visibleFood: FoodItem[]; // Each creature has its own reality/food track
}

export interface SimulationConfig {
  gravity: number;
  friction: number;
  groundDamping: number;
  timeStep: number;
  // NEW: Structural Integrity
  shapeMemoryStrength: number;

  // NEW: Real-time Physics Tweaks
  globalStiffness: number;     // Multiplier for bone rigidity (0.1 to 2.0)
  globalContractility: number; // Multiplier for muscle power (0.0 to 2.0)
}

// --- ARCHITECT TYPES ---
export type GridCoord = { x: number; y: number; z: number };

export interface Blueprint {
    cells: Map<string, boolean>; // Key "x,y,z"
    type: ShapeType;
}

import { Node, Muscle, Organism, SimulationConfig } from './types';
import { BrainController } from './neural/BrainController';

export class BioPhysicsEngine {
  private config: SimulationConfig;
  private readonly MAX_VELOCITY = 12.0; 

  // SOLVER SETTINGS
  private readonly RELAXATION_FACTOR = 0.25; 
  private readonly ITERATIONS = 6; 

  // DAMPING SETTINGS
  private readonly BASE_MUSCLE_DAMPING = 0.08; 
  private readonly ADAPTIVE_DAMPING_FACTOR = 0.12; 
  private readonly ROTATIONAL_DRAG = 0.92; 

  // AIR RESISTANCE
  private readonly DRAG_COEFFICIENT = 0.08; 

  // --- SOLIDITY CONSTANTS ---
  private readonly NODE_RADIUS = 0.1; 
  private readonly HARD_CONTACT_LIMIT = 0.22; 

  constructor(config: Partial<SimulationConfig> = {}) {
    this.config = {
      gravity: -60.0, 
      friction: 0.98, // Global air friction
      groundDamping: 0.8, // Increased ground damping (less bounce = more grip)
      timeStep: 0.016,
      shapeMemoryStrength: 0.85, 
      globalStiffness: 0.8, // Updated Default: 80% stiffness
      globalContractility: 1.5, // Updated Default: 150% muscle power
      ...config
    };
  }

  public setConfig(config: Partial<SimulationConfig>) {
      this.config = { ...this.config, ...config };
  }

  // fastMode: If true, runs lower fidelity physics for rapid evolutionary calculation
  public updateOrganism(organism: Organism, totalTime: number, fastMode: boolean = false): void {

    // 1. PHYSICS INTEGRATION
    // Note: Brain update is now handled externally by EvolutionService

    // Handle Ragdoll state
    if (!organism.isAlive) {
        organism.muscles.forEach(m => {
            m.stiffness = 0.05; // Very loose
            m.amp = 0; // Stop oscillating
            m.targetLength = m.baseLength;
        });
        // Release all grips if dead
        organism.nodes.forEach(n => {
            n.gripSignal = 1.0; 
            n.isGripping = false;
        });
    }

    // ADAPTIVE SUBSTEPS
    const subSteps = fastMode ? 4 : 12; 
    const subDt = this.config.timeStep / subSteps;
    const gravityVec = { x: 0, y: this.config.gravity * subDt * subDt, z: 0 };

    for(let s=0; s < subSteps; s++) {
        this.integrate(organism, subDt, gravityVec);
        if (!fastMode) this.applyRotationalDrag(organism); 

        // ITERATIVE SOLVER
        // In Fast Mode, we reduce iterations slightly
        const loops = fastMode ? 4 : this.ITERATIONS;

        for (let i = 0; i < loops; i++) {
            this.resolveMuscles(organism);

            // CRITICAL OPTIMIZATION:
            // Self-Collision is O(N^2). We disable it during rapid evolution.
            if (!fastMode) {
                this.resolveSelfCollisions(organism); 
            }
        }

        this.resolveFloor(organism);
    }
  }

  private applyRotationalDrag(organism: Organism): void {
      let cx = 0, cz = 0;
      let count = 0;
      for (const n of organism.nodes) {
          cx += n.pos.x;
          cz += n.pos.z;
          count++;
      }
      if (count === 0) return;
      cx /= count;
      cz /= count;

      let angularMomentum = 0;
      let momentOfInertia = 0;

      for (const n of organism.nodes) {
          const rx = n.pos.x - cx;
          const rz = n.pos.z - cz;

          const vx = n.pos.x - n.oldPos.x;
          const vz = n.pos.z - n.oldPos.z;

          const orbitalComponent = rx * vz - rz * vx;

          angularMomentum += orbitalComponent;
          momentOfInertia += rx * rx + rz * rz;
      }

      if (momentOfInertia < 0.001) return;

      const angularVel = angularMomentum / momentOfInertia;

      for (const n of organism.nodes) {
          const rx = n.pos.x - cx;
          const rz = n.pos.z - cz;

          const dampX = -angularVel * rz * this.ROTATIONAL_DRAG;
          const dampZ =  angularVel * rx * this.ROTATIONAL_DRAG;

          n.oldPos.x += dampX;
          n.oldPos.z += dampZ;
      }
  }

  private integrate(organism: Organism, dt: number, gravityVec: {x:number, y:number, z:number}): void {
    const { friction } = this.config;
    const maxStepDist = this.MAX_VELOCITY * dt;
    const maxStepSq = maxStepDist * maxStepDist;

    for (const node of organism.nodes) {
      if (node.isFixed) continue;

      let velX = node.pos.x - node.oldPos.x;
      let velY = node.pos.y - node.oldPos.y;
      let velZ = node.pos.z - node.oldPos.z;

      // 1. QUADRATIC DRAG
      const vSq = velX*velX + velY*velY + velZ*velZ;
      if (vSq > 0.000001) {
          const vLen = Math.sqrt(vSq);
          const dragFactor = 1.0 / (1.0 + this.DRAG_COEFFICIENT * vLen);

          velX *= dragFactor;
          velY *= dragFactor;
          velZ *= dragFactor;
      }

      // 2. Base Friction (Air)
      velX *= friction;
      velY *= friction;
      velZ *= friction;

      // 3. Hard Cap (Safety Terminator)
      const distSq = velX*velX + velY*velY + velZ*velZ;
      if (distSq > maxStepSq) {
          const scale = maxStepDist / Math.sqrt(distSq);
          velX *= scale;
          velY *= scale;
          velZ *= scale;
      }

      // GC OPTIMIZATION: Update oldPos in place instead of creating new object
      node.oldPos.x = node.pos.x;
      node.oldPos.y = node.pos.y;
      node.oldPos.z = node.pos.z;

      node.pos.x += velX + gravityVec.x;
      node.pos.y += velY + gravityVec.y;
      node.pos.z += velZ + gravityVec.z;
    }
  }

  private resolveMuscles(organism: Organism): void {
    const GROUND_TOLERANCE = 0.02;
    const ANCHOR_MULTIPLIER = 0.1; 
    const MEMORY_STRENGTH = this.config.shapeMemoryStrength || 0.8;
    const GLOBAL_STIFFNESS = this.config.globalStiffness; 

    // CACHE REFERENCES (Lazy Load)
    if (!organism.muscles[0]?.nodeRefA) {
         const nodeMap = new Map<string, Node>();
         for (const n of organism.nodes) nodeMap.set(n.id, n);
         for (const m of organism.muscles) {
             m.nodeRefA = nodeMap.get(m.nodeA);
             m.nodeRefB = nodeMap.get(m.nodeB);
         }
    }

    for (const muscle of organism.muscles) {
        // O(1) Access
        const n1 = muscle.nodeRefA;
        const n2 = muscle.nodeRefB;

        if (!n1 || !n2) continue;

        const dx = n2.pos.x - n1.pos.x;
        const dy = n2.pos.y - n1.pos.y;
        const dz = n2.pos.z - n1.pos.z;
        const dist = Math.sqrt(dx*dx + dy*dy + dz*dz);

        if (dist < 0.0001) continue; 

        // 1. ACTIVE MUSCLE COMPONENT
        let activeTarget = muscle.targetLength || muscle.baseLength;
        if (activeTarget < this.HARD_CONTACT_LIMIT) activeTarget = this.HARD_CONTACT_LIMIT;

        let stiffness = muscle.stiffness * 0.8 * GLOBAL_STIFFNESS; 

        const activeDiff = dist - activeTarget;

        // 2. PASSIVE MEMORY COMPONENT
        const deviation = Math.abs(dist - muscle.baseLength);
        const strain = deviation / muscle.baseLength;
        const strainBoost = 1.0 + (strain * 4.0); 

        const currentMemoryStrength = organism.isAlive 
            ? MEMORY_STRENGTH * strainBoost * GLOBAL_STIFFNESS
            : MEMORY_STRENGTH * 0.1 * GLOBAL_STIFFNESS;

        const baseDiff = dist - muscle.baseLength;

        // --- DUAL FORCE BLENDING ---
        const activeCorrection = activeDiff * stiffness;
        const memoryCorrection = baseDiff * currentMemoryStrength;
        let totalCorrection = (activeCorrection + memoryCorrection) * this.RELAXATION_FACTOR;

        // --- DAMPING ---
        const vx1 = n1.pos.x - n1.oldPos.x;
        const vy1 = n1.pos.y - n1.oldPos.y;
        const vz1 = n1.pos.z - n1.oldPos.z;
        const vx2 = n2.pos.x - n2.oldPos.x;
        const vy2 = n2.pos.y - n2.oldPos.y;
        const vz2 = n2.pos.z - n2.oldPos.z;

        const rvx = vx2 - vx1;
        const rvy = vy2 - vy1;
        const rvz = vz2 - vz1;

        const nx = dx / dist;
        const ny = dy / dist;
        const nz = dz / dist;

        const relVel = Math.sqrt(rvx*rvx + rvy*rvy + rvz*rvz);
        const dynamicDamping = this.BASE_MUSCLE_DAMPING + (relVel * this.ADAPTIVE_DAMPING_FACTOR);
        const vRelProj = rvx * nx + rvy * ny + rvz * nz;

        totalCorrection += vRelProj * dynamicDamping;

        // --- MOMENTUM PRESERVATION ---
        let im1 = (n1.isFixed || n1.isGripping) ? 0 : 1 / n1.mass;
        let im2 = (n2.isFixed || n2.isGripping) ? 0 : 1 / n2.mass;

        if (n1.pos.y <= GROUND_TOLERANCE) im1 *= ANCHOR_MULTIPLIER;
        if (n2.pos.y <= GROUND_TOLERANCE) im2 *= ANCHOR_MULTIPLIER;

        const totalInvMass = im1 + im2;
        if (totalInvMass === 0) continue;

        const w1 = im1 / totalInvMass;
        const w2 = im2 / totalInvMass;

        const offsetX = nx * totalCorrection;
        const offsetY = ny * totalCorrection;
        const offsetZ = nz * totalCorrection;

        if (!n1.isFixed && !n1.isGripping) {
            n1.pos.x += offsetX * w1;
            n1.pos.y += offsetY * w1;
            n1.pos.z += offsetZ * w1;
        }

        if (!n2.isFixed && !n2.isGripping) {
            n2.pos.x -= offsetX * w2;
            n2.pos.y -= offsetY * w2;
            n2.pos.z -= offsetZ * w2;
        }
    }
  }

  private resolveSelfCollisions(organism: Organism): void {
      const nodes = organism.nodes;
      const count = nodes.length;
      const minDistance = this.HARD_CONTACT_LIMIT; 
      const minDistanceSq = minDistance * minDistance;

      for (let i = 0; i < count; i++) {
          for (let j = i + 1; j < count; j++) {
              const n1 = nodes[i];
              const n2 = nodes[j];

              const dx = n1.pos.x - n2.pos.x;
              const dy = n1.pos.y - n2.pos.y;
              const dz = n1.pos.z - n2.pos.z;
              const distSq = dx*dx + dy*dy + dz*dz;

              if (distSq < minDistanceSq && distSq > 0.000001) {
                  const dist = Math.sqrt(distSq);
                  const overlap = minDistance - dist;

                  const fx = (dx / dist) * overlap * 0.2;
                  const fy = (dy / dist) * overlap * 0.2;
                  const fz = (dz / dist) * overlap * 0.2;

                  if (!n1.isFixed) { n1.pos.x += fx; n1.pos.y += fy; n1.pos.z += fz; }
                  if (!n2.isFixed) { n2.pos.x -= fx; n2.pos.y -= fy; n2.pos.z -= fz; }
              }
          }
      }
  }

  private resolveFloor(organism: Organism): void {
    const RADIUS = this.NODE_RADIUS;

    for (const node of organism.nodes) {
      if (node.pos.y < RADIUS) {
        node.pos.y = RADIUS;

        // STANDARD FRICTION (Replaces Sticky Suction)
        const vx = node.pos.x - node.oldPos.x;
        const vz = node.pos.z - node.oldPos.z;
        const frictionCoeff = 0.85; 

        node.oldPos.x = node.pos.x - vx * frictionCoeff;
        node.oldPos.z = node.pos.z - vz * frictionCoeff;

        node.isGripping = false; // Never stick
      } else {
          node.isGripping = false;
      }
    }
  }
}

import { Organism, ShapeType, Node, Muscle, NeuralGenome } from './types';
import { VectorOps } from './math';
import { GeneticOperator } from './genetics/GeneticOperator';

export class ShapeFactory {

  static create(type: ShapeType, id: string): Organism {
    let nodes: Node[] = [];
    let muscles: Muscle[] = [];

    switch (type) {
      case ShapeType.CUBE:
        ({ nodes, muscles } = this.createCube());
        break;
      case ShapeType.WORM:
        ({ nodes, muscles } = this.createWorm(4));
        break;
      case ShapeType.TETRAHEDRON:
      default:
        ({ nodes, muscles } = this.createTetrahedron());
        break;
    }

    // Initialize Neural Genome
    const operator = new GeneticOperator();
    const genome = operator.createRandomGenome(muscles.length, nodes.length);

    muscles.forEach((m, i) => m.dnaIndex = i);

    // Identify Head (Furthest Forward, then Highest Up)
    let maxZ = -Infinity;
    nodes.forEach(n => { if (n.pos.z > maxZ) maxZ = n.pos.z; });

    let candidates: Node[] = [];
    nodes.forEach(n => {
        if (Math.abs(n.pos.z - maxZ) < 0.1) candidates.push(n);
    });

    let headNode: Node | null = null;
    let maxY = -Infinity;
    candidates.forEach(n => {
        if (n.pos.y > maxY) {
            maxY = n.pos.y;
            headNode = n;
        }
    });

    if (headNode) {
        // @ts-ignore
        headNode.isHead = true;
    }

    const initialHeadPos = headNode ? { ...headNode.pos } : { x: 0, y: 0, z: 0 };

    return {
      id,
      shape: type, // Store shape type for editor consistency
      nodes,
      muscles,
      neuralGenome: genome,
      fitness: 0,
      generation: 1,
      // Metabolism Defaults
      energy: 100,
      maxEnergy: 100,
      hungerTime: 0,
      isAlive: true,
      foodEaten: 0,
      visibleFood: [],
      // Distance Metrics (Replaces Posture)
      initialHeadPos,
      distanceTraveled: 0
    };
  }

  private static createTetrahedron() {
    const f = 0.95; // High friction for grip
    const m = 4.0;  // Heavy mass

    const nodes: Node[] = [
      { id: 'n1', pos: { x: 0, y: 0, z: 1 }, oldPos: { x: 0, y: 0, z: 1 }, mass: m, friction: f },
      { id: 'n2', pos: { x: 1, y: 0, z: -0.7 }, oldPos: { x: 1, y: 0, z: -0.7 }, mass: m, friction: f },
      { id: 'n3', pos: { x: -1, y: 0, z: -0.7 }, oldPos: { x: -1, y: 0, z: -0.7 }, mass: m, friction: f },
      { id: 'n4', pos: { x: 0, y: 1.5, z: 0 }, oldPos: { x: 0, y: 1.5, z: 0 }, mass: m, friction: f },
    ];
    const muscles = this.connectAll(nodes);
    return { nodes, muscles };
  }

  private static createCube() {
    const nodes: Node[] = [];
    const size = 1.0;
    const startY = 0.5;
    const f = 0.95; 
    const m = 4.0; 

    for(let x=0; x<=1; x++) {
      for(let y=0; y<=1; y++) {
        for(let z=0; z<=1; z++) {
          const px = (x - 0.5) * size;
          const py = startY + y * size;
          const pz = (z - 0.5) * size;
          nodes.push({
            id: `n${x}${y}${z}`,
            pos: { x: px, y: py, z: pz },
            oldPos: { x: px, y: py, z: pz },
            mass: m, 
            friction: f
          });
        }
      }
    }
    const muscles = this.connectDistanceThreshold(nodes, size * 1.8);
    return { nodes, muscles };
  }

  private static createWorm(segments: number) {
    const nodes: Node[] = [];
    const size = 1.0;
    const bellyFriction = 0.5; // Belly slides a bit
    const footFriction = 0.98; // Feet grip hard
    const m = 4.0; 

    for (let i = 0; i < segments; i++) {
        const offset = i * size;
        nodes.push(
            { id: `n${i}_a`, pos: { x: -0.5, y: 0, z: offset }, oldPos: { x: -0.5, y: 0, z: offset }, mass: m, friction: footFriction },
            { id: `n${i}_b`, pos: { x: 0.5, y: 0, z: offset }, oldPos: { x: 0.5, y: 0, z: offset }, mass: m, friction: footFriction },
            { id: `n${i}_top`, pos: { x: 0, y: 1, z: offset + 0.5 }, oldPos: { x: 0, y: 1, z: offset + 0.5 }, mass: m, friction: bellyFriction }
        );
    }
    return { nodes, muscles: this.connectDistanceThreshold(nodes, size * 1.5) };
  }

  private static connectAll(nodes: Node[]): Muscle[] {
    const muscles: Muscle[] = [];
    let mCount = 0;
    for (let i = 0; i < nodes.length; i++) {
      for (let j = i + 1; j < nodes.length; j++) {
        const dist = VectorOps.distance(nodes[i].pos, nodes[j].pos);
        muscles.push({
          id: `m${mCount++}`,
          nodeA: nodes[i].id,
          nodeB: nodes[j].id,
          baseLength: dist,
          stiffness: 1.0, // Maximum stiffness for bones
          dnaIndex: 0,
          // Init Oscillator
          phase: Math.random() * Math.PI * 2,
          freq: 1.0,
          amp: 0.0
        });
      }
    }
    return muscles;
  }

    private static connectDistanceThreshold(nodes: Node[], threshold: number): Muscle[] {
      const muscles: Muscle[] = [];
      let mCount = 0;
      for (let i = 0; i < nodes.length; i++) {
        for (let j = i + 1; j < nodes.length; j++) {
          const dist = VectorOps.distance(nodes[i].pos, nodes[j].pos);
          if (dist <= threshold) {
            muscles.push({
              id: `m${mCount++}`,
              nodeA: nodes[i].id,
              nodeB: nodes[j].id,
              baseLength: dist,
              stiffness: 1.0,
              dnaIndex: 0,
              // Init Oscillator
              phase: Math.random() * Math.PI * 2,
              freq: 1.0,
              amp: 0.0
            });
          }
        }
      }
      return muscles;
    }
}

import { Organism } from '../types';

export interface IFitnessEvaluator {
    evaluate(organism: Organism, dt: number): void;
    finalize(organism: Organism): void;
    setWeights(foodWeight: number, distanceWeight: number): void;
}

export class StandardFitnessEvaluator implements IFitnessEvaluator {
    private foodWeight: number = 20.0;
    private distanceWeight: number = 20.0;

    setWeights(foodWeight: number, distanceWeight: number) {
        this.foodWeight = foodWeight;
        this.distanceWeight = distanceWeight;
    }

    evaluate(organism: Organism, dt: number): void {
        // Distance Logic (Displacement from initial start point)
        const head = organism.nodes.find(n => n.isHead);
        if (!head) return;

        // Use XZ plane distance (Planar travel)
        const start = organism.initialHeadPos;
        const dx = head.pos.x - start.x;
        const dz = head.pos.z - start.z;
        const dist = Math.sqrt(dx*dx + dz*dz);

        organism.distanceTraveled = dist;

        // Fitness = Distance * Weight + Food
        // We evaluate this every frame so real-time fitness is visible
        organism.fitness = (organism.foodEaten * this.foodWeight) + (dist * this.distanceWeight);
    }

    finalize(organism: Organism): void {
        this.evaluate(organism, 0);
    }
}

import { BioPhysicsEngine } from '../domain/BioPhysicsEngine';
import { Organism, ShapeType, NeuralGenome, FoodItem, Node, Muscle } from '../domain/types';
import { ShapeFactory } from '../domain/ShapeFactory';
import { VectorOps } from '../domain/math';
import { GeneticOperator } from '../domain/genetics/GeneticOperator';
import { IFitnessEvaluator, StandardFitnessEvaluator } from '../domain/fitness/FitnessEvaluator';
import { BrainController } from '../domain/neural/BrainController';

export class EvolutionService {
  public population: Organism[] = [];
  public currentGeneration = 1;
  public simulationTime = 0;

  private engine: BioPhysicsEngine;
  private geneticOperator: GeneticOperator;
  private fitnessEvaluator: IFitnessEvaluator;

  private populationSize = 20;
  private template: Organism | null = null; 

  private readonly START_ENERGY = 100;
  private readonly BASE_DECAY = 4.0; 
  private readonly HUNGER_ACCEL = 1.15; 
  private readonly FOOD_ENERGY = 30;

  public readonly MAGNET_RADIUS = 1.5; 
  private readonly MAGNET_FORCE = 0.8;  
  private readonly EAT_RADIUS = 0.8;    

  public foodSpawnCount = 50;
  public foodSpawnRadius = 3.5;

  private updateListeners: ((pop: Organism[], time: number) => void)[] = [];
  private genCompleteListeners: ((best: Organism, gen: number) => void)[] = [];
  private newGenListeners: ((pop: Organism[]) => void)[] = [];

  constructor() {
    this.engine = new BioPhysicsEngine();
    this.geneticOperator = new GeneticOperator(0.05); // 5% mutation rate
    this.fitnessEvaluator = new StandardFitnessEvaluator();
  }

  public setGlobalStiffness(val: number) {
      this.engine.setConfig({ globalStiffness: val });
  }

  public setGlobalContractility(val: number) {
      this.engine.setConfig({ globalContractility: val });
  }

  public set foodWeight(val: number) {
      this.fitnessEvaluator.setWeights(val, (this.fitnessEvaluator as any).distanceWeight);
  }
  public get foodWeight(): number { return (this.fitnessEvaluator as any).foodWeight; }

  public set distanceWeight(val: number) {
       this.fitnessEvaluator.setWeights((this.fitnessEvaluator as any).foodWeight, val);
  }
  public get distanceWeight(): number { return (this.fitnessEvaluator as any).distanceWeight; }

  public updateFoodDistribution(): void {
      this.population.forEach(org => {
          org.visibleFood = this.generateFoodTrack(org);
      });
  }

  public initializePopulation(shape: ShapeType): void {
    this.template = ShapeFactory.create(shape, 'template');
    this.spawnGenerationFromTemplate(true);
  }

  public setTemplateAndReset(organism: Organism, startGeneration: number = 1): void {
      // Deep copy for the master template to ensure it's clean
      const safeJson = JSON.stringify(organism, (key, value) => {
          if (key === 'brain') return undefined;
          if (key === 'nodeRefA' || key === 'nodeRefB') return undefined;
          return value;
      });
      this.template = JSON.parse(safeJson);

      this.currentGeneration = startGeneration;
      this.spawnGenerationFromTemplate(false); 
  }

  private spawnGenerationFromTemplate(resetGen: boolean): void {
      if (!this.template) return;

      this.population = [];
      if (resetGen) this.currentGeneration = 1;
      this.simulationTime = 0;

      for (let i = 0; i < this.populationSize; i++) {
          const child = this.createOrganismFromTemplate(this.template, `gen${this.currentGeneration}_${i}`);

          if (i > 0) {
              this.geneticOperator.mutateGenome(child.neuralGenome);
          }

          child.visibleFood = this.generateFoodTrack(child);
          this.fitnessEvaluator.evaluate(child, 0.016);

          this.population.push(child);
      }

      this.notifyNewGeneration(this.population);
  }

  private generateFoodTrack(organism: Organism): FoodItem[] {
      const food: FoodItem[] = [];
      const numFood = this.foodSpawnCount; 

      let centerX = 0;
      let centerZ = 0;

      let head = organism.nodes.find(n => n.isHead);
      if (!head && organism.nodes.length > 0) head = organism.nodes[0];

      if (head) {
          centerX = head.pos.x;
          centerZ = head.pos.z;
      }

      const spread = this.foodSpawnRadius; 

      for(let i=0; i<numFood; i++) {
          const theta = Math.random() * Math.PI * 2;
          const radius = 1.0 + Math.random() * spread; 
          const x = centerX + Math.cos(theta) * radius;
          const z = centerZ + Math.sin(theta) * radius;
          const y = 1.0 + Math.random() * 2.5;

          food.push({
              id: `f_${i}`,
              pos: { x, y, z },
              energyValue: this.FOOD_ENERGY,
              consumed: false
          });
      }
      return food;
  }

  public getBestOrganism(): Organism | null {
      if (this.population.length === 0) return null;
      const sorted = [...this.population].sort((a, b) => b.fitness - a.fitness);
      const best = sorted[0];

      const safeJson = JSON.stringify(best, (key, value) => {
          if (key === 'brain') return undefined;
          if (key === 'nodeRefA' || key === 'nodeRefB') return undefined;
          return value;
      });
      const cleanCopy = JSON.parse(safeJson);
      cleanCopy.generation = this.currentGeneration;

      return cleanCopy;
  }

  public getLeader(): Organism | null {
      if (this.population.length === 0) return null;

      let bestAlive: Organism | null = null;
      let maxZAlive = -Infinity;

      let bestDead: Organism | null = null;
      let maxZDead = -Infinity;

      for (const org of this.population) {
          let cz = 0;
          for(const n of org.nodes) cz += n.pos.z;
          cz /= org.nodes.length;

          if (org.isAlive) {
              if (cz > maxZAlive) { maxZAlive = cz; bestAlive = org; }
          } else {
              if (cz > maxZDead) { maxZDead = cz; bestDead = org; }
          }
      }

      return bestAlive || bestDead || this.population[0];
  }

  public step(dt: number): void {
    this.simulationTime += dt;
    this.updatePhysics(dt, false);
    this.updateMetabolism(dt);

    if (Math.floor(this.simulationTime * 100) % 100 === 0) {
        this.applySocialLearning();
    }

    const allDead = !this.population.some(org => org.isAlive);
    if (allDead) {
        this.evolve();
    }

    this.notifyUpdate(this.population, this.simulationTime);
  }

  private applySocialLearning() {
      const sorted = [...this.population].sort((a, b) => b.fitness - a.fitness);
      if (sorted.length < 2) return;

      const leader = sorted[0];
      const bottomHalfStart = Math.floor(sorted.length / 2);

      for(let i=bottomHalfStart; i<sorted.length; i++) {
          const learner = sorted[i];
          if (!learner.isAlive) continue;

          const learningRate = 0.05; 
          const lg = learner.neuralGenome;
          const bg = leader.neuralGenome;

          for(let k=0; k<lg.synapseWeights.length; k++) {
              if (bg.synapseWeights[k] !== undefined) {
                  lg.synapseWeights[k] += (bg.synapseWeights[k] - lg.synapseWeights[k]) * learningRate;
              }
          }
      }
  }

  public async computeGenerationAsync(
    maxSafetyTime: number, 
    shouldStop: () => boolean, 
    onProgress?: (pct: number) => void
  ): Promise<void> {
      const dt = 0.016; 
      const BATCH_DURATION = 0.012; 
      let allDead = false;

      while (!allDead && this.simulationTime < maxSafetyTime) {
          if (shouldStop()) throw new Error("Evolution Aborted");

          let batchTime = 0;
          while (batchTime < BATCH_DURATION && !allDead && this.simulationTime < maxSafetyTime) {
              this.simulationTime += dt;
              batchTime += dt; 

              this.updatePhysics(dt, true);
              this.updateMetabolism(dt); 

              if (Math.abs(this.simulationTime % 1.0) < dt) {
                  this.applySocialLearning();
              }

              allDead = !this.population.some(org => org.isAlive);
          }

          const deadCount = this.population.filter(o => !o.isAlive).length;
          const pct = deadCount / this.populationSize;

          if (onProgress) onProgress(pct);
          await new Promise(resolve => setTimeout(resolve, 0));
      }

      this.finalizeFitness();
  }

  private updatePhysics(dt: number, fastMode: boolean): void {
    this.population.forEach(org => {
      // ORCHESTRATION: Update Brain THEN Physics
      if (org.isAlive) {
         if (!org.brain) {
             org.brain = new BrainController(org);
         }
         const contractility = (this.engine as any).config.globalContractility;
         org.brain.update(dt, contractility);
      }

      this.engine.updateOrganism(org, this.simulationTime, fastMode);
    });
  }

  private updateMetabolism(dt: number): void {
      this.population.forEach(org => {
          // 1. Calculate Fitness
          this.fitnessEvaluator.evaluate(org, dt);

          if (!org.isAlive) return;

          org.hungerTime += dt;
          const hungerMultiplier = Math.pow(this.HUNGER_ACCEL, org.hungerTime);
          const loss = this.BASE_DECAY * hungerMultiplier * dt;
          org.energy -= loss;

          if (org.energy <= 0) {
              org.energy = 0;
              org.isAlive = false;
              return; 
          }

          let head = org.nodes.find(n => n.isHead);
          if (!head && org.nodes.length > 0) {
              // Fallback logic for finding head if node ref lost
              let highest = org.nodes[0];
              for(const n of org.nodes) {
                  if (n.pos.y > highest.pos.y) highest = n;
              }
              head = highest;
              // @ts-ignore
              head.isHead = true; 
          }

          if (head) {
            for (const food of org.visibleFood) {
                if (food.consumed) continue;

                // INLINED MATH (Optimized)
                // Avoid VectorOps.distance and VectorOps.sub object creation
                const dx = head.pos.x - food.pos.x;
                const dy = head.pos.y - food.pos.y;
                const dz = head.pos.z - food.pos.z;
                const distSq = dx*dx + dy*dy + dz*dz;

                // Fast reject check (Squared)
                if (distSq < this.MAGNET_RADIUS * this.MAGNET_RADIUS) {
                    const dist = Math.sqrt(distSq);

                    // Pull Force
                    const strength = 1.0 - (dist / this.MAGNET_RADIUS);
                    const force = this.MAGNET_FORCE * (1.0 + strength);

                    // Apply directly (Pull vector is -diff vector)
                    // pull = head - food. so dx = head.x - food.x
                    food.pos.x += dx * force * 0.1;
                    food.pos.y += dy * force * 0.1;
                    food.pos.z += dz * force * 0.1;

                    // Recheck Distance (Cheap approximation: assume it moved closer)
                    // But to be exact for eating:
                    const ndx = head.pos.x - food.pos.x;
                    const ndy = head.pos.y - food.pos.y;
                    const ndz = head.pos.z - food.pos.z;
                    const nDistSq = ndx*ndx + ndy*ndy + ndz*ndz;

                    if (nDistSq < this.EAT_RADIUS * this.EAT_RADIUS) {
                        food.consumed = true;
                        org.energy += food.energyValue;
                        if (org.energy > org.maxEnergy) org.energy = org.maxEnergy;
                        org.hungerTime = 0;
                        org.foodEaten++;
                    }
                }
            }
          }
      });
  }

  private finalizeFitness() {
      this.population.forEach(org => this.fitnessEvaluator.finalize(org));
  }

  public evolve(): void {
    if (!this.template) return;

    this.finalizeFitness(); 

    // 1. Selection
    this.population.sort((a, b) => b.fitness - a.fitness);
    const survivorsCount = Math.floor(this.populationSize * 0.25);
    const survivors = this.population.slice(0, survivorsCount);
    const bestOrganism = survivors[0];

    this.notifyGenComplete(bestOrganism, this.currentGeneration);

    // 2. Reproduction
    this.currentGeneration++;
    const nextGen: Organism[] = [];

    // Elitism
    const champion = this.createOrganismFromTemplate(this.template, `gen${this.currentGeneration}_champ`);
    champion.neuralGenome = this.geneticOperator.cloneGenome(bestOrganism.neuralGenome);
    champion.visibleFood = this.generateFoodTrack(champion);
    this.fitnessEvaluator.evaluate(champion, 0.016);
    nextGen.push(champion);

    // Fill
    while (nextGen.length < this.populationSize) {
      const parent = survivors[Math.floor(Math.random() * survivors.length)];
      const child = this.createOrganismFromTemplate(this.template, `gen${this.currentGeneration}_${nextGen.length}`);
      child.neuralGenome = this.geneticOperator.cloneGenome(parent.neuralGenome);
      this.geneticOperator.mutateGenome(child.neuralGenome);
      child.visibleFood = this.generateFoodTrack(child);
      this.fitnessEvaluator.evaluate(child, 0.016);
      nextGen.push(child);
    }

    this.population = nextGen;
    this.simulationTime = 0;

    this.notifyNewGeneration(this.population);
  }

  private createOrganismFromTemplate(template: Organism, newId: string): Organism {
      // 1. Clone Nodes
      const newNodes: Node[] = template.nodes.map(n => ({
          ...n,
          pos: { ...n.pos },
          oldPos: { ...n.pos }, 
          activation: 0,
          gripSignal: 0,
          isGripping: false
      }));

      // 2. Clone Muscles
      const newMuscles: Muscle[] = template.muscles.map(m => ({
          ...m,
          currentLength: undefined,
          targetLength: undefined,
          phase: Math.random() * Math.PI * 2,
          nodeRefA: undefined,
          nodeRefB: undefined
      }));

      // 3. Clone Genome 
      const newGenome = this.geneticOperator.cloneGenome(template.neuralGenome);

      // 4. Construct
      const clone: Organism = {
          id: newId,
          shape: template.shape,
          nodes: newNodes,
          muscles: newMuscles,
          neuralGenome: newGenome,
          fitness: 0,
          generation: 1,
          brain: undefined,

          energy: this.START_ENERGY,
          maxEnergy: this.START_ENERGY,
          hungerTime: 0,
          isAlive: true,
          foodEaten: 0,
          visibleFood: [],

          // Distance Stats
          initialHeadPos: template.initialHeadPos ? { ...template.initialHeadPos } : {x:0,y:0,z:0},
          distanceTraveled: 0
      };

      // Safety check for starting pos if template was malformed
      if (!clone.initialHeadPos) {
           const head = clone.nodes.find(n => n.isHead);
           clone.initialHeadPos = head ? { ...head.pos } : { x: 0, y: 0, z: 0 };
      }

      return clone;
  }

  public subscribe(type: 'update', cb: (pop: Organism[], time: number) => void): () => void;
  public subscribe(type: 'genComplete', cb: (best: Organism, gen: number) => void): () => void;
  public subscribe(type: 'newGen', cb: (pop: Organism[]) => void): () => void;
  public subscribe(type: string, cb: any): () => void {
      if (type === 'update') {
          this.updateListeners.push(cb);
          return () => this.updateListeners = this.updateListeners.filter(l => l !== cb);
      }
      if (type === 'genComplete') {
          this.genCompleteListeners.push(cb);
          return () => this.genCompleteListeners = this.genCompleteListeners.filter(l => l !== cb);
      }
      if (type === 'newGen') {
          this.newGenListeners.push(cb);
          return () => this.newGenListeners = this.newGenListeners.filter(l => l !== cb);
      }
      return () => {};
  }

  public onUpdate(cb: (pop: Organism[], time: number) => void) { this.subscribe('update', cb); }
  public onGenComplete(cb: (best: Organism, gen: number) => void) { this.subscribe('genComplete', cb); }
  public onNewGeneration(cb: (pop: Organism[]) => void) { this.subscribe('newGen', cb); }

  private notifyUpdate(pop: Organism[], time: number) { this.updateListeners.forEach(l => l(pop, time)); }
  private notifyGenComplete(best: Organism, gen: number) { this.genCompleteListeners.forEach(l => l(best, gen)); }
  private notifyNewGeneration(pop: Organism[]) { this.newGenListeners.forEach(l => l(pop)); }
}

