import { useEffect, useRef, useState, useCallback } from 'react';
import { EvolutionService } from './EvolutionService';
import { ShapeType, Organism } from '../domain/types';

export function useEvolutionLoop() {
  const serviceRef = useRef<EvolutionService>(new EvolutionService());
  const requestRef = useRef<number>(0);

  // Ref for synchronous access inside tight loops
  const isAutoEvolvingRef = useRef(false);

  const [population, setPopulation] = useState<Organism[]>([]);
  const [generation, setGeneration] = useState(1);
  const [currentShape, setCurrentShape] = useState<ShapeType>(ShapeType.TETRAHEDRON);
  const [isRunning, setIsRunning] = useState(false);
  const [isAutoEvolving, setIsAutoEvolvingState] = useState(false);

  const [isProcessing, setIsProcessing] = useState(false);
  const [progress, setProgress] = useState(0);

  // New Physics State (Updated Defaults)
  const [globalStiffness, setGlobalStiffnessState] = useState(0.8);
  const [globalContractility, setGlobalContractilityState] = useState(1.5);

  // Fitness Weights Configuration (Updated Defaults)
  const [foodWeight, setFoodWeightState] = useState(20.0);
  const [distanceWeight, setDistanceWeightState] = useState(20.0);

  // Scarcity Controls
  const [foodSpawnCount, setFoodSpawnCountState] = useState(50);
  const [foodSpawnRadius, setFoodSpawnRadiusState] = useState(3.5);

  // NEW: Live Stats for Dashboard
  const [currentStats, setCurrentStats] = useState({
      fitness: 0,
      foodEaten: 0,
      distance: 0
  });

  // Initialize
  useEffect(() => {
    const service = serviceRef.current;

    // Wire up listeners
    let lastUpdate = 0;

    // Using subscription pattern
    const unsubUpdate = service.subscribe('update', (pop, time) => {
        // Throttled UI update (15 FPS is enough for text stats)
        if (time - lastUpdate > 0.06) {
            lastUpdate = time;

            const leader = service.getLeader();

            if (leader) {
                setCurrentStats({
                    fitness: leader.fitness,
                    foodEaten: leader.foodEaten,
                    distance: leader.distanceTraveled || 0
                });
            }
        }
    });

    const unsubGen = service.subscribe('genComplete', (best, gen) => {
        setGeneration(gen);
    });

    const unsubNewGen = service.subscribe('newGen', (newPop) => {
        setPopulation([...newPop]);
    });

    service.initializePopulation(currentShape);
    setPopulation([...service.population]); // Initial sync

    return () => {
        cancelAnimationFrame(requestRef.current!);
        unsubUpdate();
        unsubGen();
        unsubNewGen();
    };
  }, []);

  const reset = useCallback((shape: ShapeType) => {
    setIsRunning(false);

    // Stop Auto
    isAutoEvolvingRef.current = false;
    setIsAutoEvolvingState(false);

    setIsProcessing(false);
    setCurrentShape(shape);
    serviceRef.current.initializePopulation(shape);
    setPopulation([...serviceRef.current.population]);
    setGeneration(1);
    setCurrentStats({ fitness: 0, foodEaten: 0, distance: 0 });
  }, []);

  const spawnCustom = useCallback((organism: Organism) => {
      setIsRunning(false);
      isAutoEvolvingRef.current = false;
      setIsAutoEvolvingState(false);
      setIsProcessing(false);

      serviceRef.current.setTemplateAndReset(organism);
      setPopulation([...serviceRef.current.population]);
      setGeneration(1);
      setCurrentStats({ fitness: 0, foodEaten: 0, distance: 0 });
      setCurrentShape(ShapeType.WORM); 
  }, []);

  const evolve = useCallback(() => {
    serviceRef.current.evolve();
    setPopulation([...serviceRef.current.population]); // Update React view
    setGeneration(serviceRef.current.currentGeneration);
  }, []);

  // --- PHYSICS CONTROL HANDLERS ---
  const setGlobalStiffness = useCallback((val: number) => {
      setGlobalStiffnessState(val);
      serviceRef.current.setGlobalStiffness(val);
  }, []);

  const setGlobalContractility = useCallback((val: number) => {
      setGlobalContractilityState(val);
      serviceRef.current.setGlobalContractility(val);
  }, []);

  // --- FITNESS WEIGHT HANDLERS ---
  const setFoodWeight = useCallback((val: number) => {
      setFoodWeightState(val);
      serviceRef.current.foodWeight = val;
  }, []);

  const setDistanceWeight = useCallback((val: number) => {
      setDistanceWeightState(val);
      serviceRef.current.distanceWeight = val;
  }, []);

  // --- SCARCITY HANDLERS ---
  const setFoodSpawnCount = useCallback((val: number) => {
      setFoodSpawnCountState(val);
      serviceRef.current.foodSpawnCount = val;
      serviceRef.current.updateFoodDistribution(); // Real-time update
  }, []);

  const setFoodSpawnRadius = useCallback((val: number) => {
      setFoodSpawnRadiusState(val);
      serviceRef.current.foodSpawnRadius = val;
      serviceRef.current.updateFoodDistribution(); // Real-time update
  }, []);


  // --- DATA IO ---

  const saveCreature = useCallback(() => {
    const best = serviceRef.current.getBestOrganism();
    if (!best) return;

    const json = JSON.stringify(best, null, 2);
    const blob = new Blob([json], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `creature_gen${best.generation}_${Date.now()}.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  }, []);

  const loadCreature = useCallback((file: File, onLoaded?: (org: Organism) => void) => {
      const reader = new FileReader();
      reader.onload = (e) => {
          try {
              const json = e.target?.result as string;
              const organism = JSON.parse(json) as Organism;

              if (!organism.nodes || !organism.muscles || !organism.neuralGenome) {
                  alert("Invalid Creature File");
                  return;
              }

              // Stop everything
              setIsRunning(false);
              isAutoEvolvingRef.current = false;
              setIsAutoEvolvingState(false);
              setIsProcessing(false);

              // Inject
              const startGen = organism.generation || 1;
              serviceRef.current.setTemplateAndReset(organism, startGen);

              setPopulation([...serviceRef.current.population]);
              setGeneration(startGen);
              setCurrentStats({ fitness: 0, foodEaten: 0, distance: 0 });

              // Notify App
              if (onLoaded) onLoaded(organism);

          } catch (err) {
              console.error(err);
              alert("Failed to load creature file.");
          }
      };
      reader.readAsText(file);
  }, []);


  // --- AUTO EVOLUTION ---

  const runAutoEvolution = useCallback(async () => {
      if (isProcessing) return; // Prevent double entry

      setIsProcessing(true);

      try {
          // 1. Compute Generation Async (Yielding to UI)
          // We pass a callback that checks our Ref. If ref is false, service throws error.
          await serviceRef.current.computeGenerationAsync(
              10.0, 
              () => !isAutoEvolvingRef.current, // Stop Signal
              (pct) => setProgress(pct)
          );

          // 2. Evolve (Only if we finished successfully)
          evolve();

          // 3. Reset for next round
          setProgress(0);
          setIsProcessing(false);

      } catch (e) {
          // If we aborted (or other error), we catch it here.
          console.log("Evolution Stopped or Aborted");
          setIsProcessing(false);
          // Do NOT evolve. We stay on the current generation.
      }
  }, [isProcessing, evolve]);

  const toggleAutoEvolve = useCallback(() => {
      const newState = !isAutoEvolvingRef.current;
      isAutoEvolvingRef.current = newState;
      setIsAutoEvolvingState(newState);

      // If turning ON, ensure regular run is off (optional, but cleaner)
      if (newState) setIsRunning(false);
  }, []);

  const loop = useCallback(() => {
    // If neither running nor auto, stop loop
    if (!isRunning && !isAutoEvolving) return;

    if (isAutoEvolving) {
        if (!isProcessing) {
            runAutoEvolution();
        }
    } else {
        // NORMAL MODE: 60 FPS Physics
        if (isRunning) {
            serviceRef.current.step(0.016);
        }
    }

    requestRef.current = requestAnimationFrame(loop);
  }, [isRunning, isAutoEvolving, isProcessing, runAutoEvolution]);

  useEffect(() => {
    if (isRunning || isAutoEvolving) {
      requestRef.current = requestAnimationFrame(loop);
    } else {
      cancelAnimationFrame(requestRef.current!);
    }
    return () => cancelAnimationFrame(requestRef.current!);
  }, [isRunning, isAutoEvolving, loop]);

  return {
    population,
    generation,
    currentStats, // NEW
    isRunning,
    isAutoEvolving,
    isProcessing, 
    progress,    
    currentShape,
    // Physics State
    globalStiffness,
    globalContractility,
    setGlobalStiffness,
    setGlobalContractility,
    // Fitness State
    foodWeight,
    distanceWeight,
    setFoodWeight,
    setDistanceWeight,
    // Scarcity
    foodSpawnCount,
    setFoodSpawnCount,
    foodSpawnRadius,
    setFoodSpawnRadius,
    // Actions
    setIsRunning,
    toggleAutoEvolve, 
    reset,
    evolve,
    spawnCustom,
    saveCreature,
    loadCreature
  };
}

import React, { useState, useRef, useMemo } from 'react';
import { Canvas } from '@react-three/fiber';
import { OrbitControls, Grid, PerspectiveCamera } from '@react-three/drei';
import { LabScene } from './src/infrastructure/visuals/LabScene';
import { Dashboard } from './src/ui/Dashboard';
import { useEvolutionLoop } from './src/application/useEvolutionLoop';
import { BlueprintViewUpdated } from './src/infrastructure/visuals/BlueprintViewUpdated';
import { ArchitectControls } from './src/ui/ArchitectControls';
import { BlueprintService } from './src/domain/BlueprintService';
import { ShapeType, Organism } from './src/domain/types';

function App() {
  const {
    population,
    generation,
    currentStats,
    isRunning,
    isAutoEvolving,
    isProcessing,
    progress,
    currentShape,
    globalStiffness,
    globalContractility,
    setGlobalStiffness,
    setGlobalContractility,
    foodWeight,
    distanceWeight,
    setFoodWeight,
    setDistanceWeight,
    foodSpawnCount,
    setFoodSpawnCount,
    foodSpawnRadius,
    setFoodSpawnRadius,
    setIsRunning,
    toggleAutoEvolve, 
    reset,
    evolve,
    spawnCustom,
    saveCreature,
    loadCreature
  } = useEvolutionLoop();

  const [mode, setMode] = useState<'LAB' | 'ARCHITECT'>('LAB');
  const [showBestOnly, setShowBestOnly] = useState(false);

  // Architect State
  const blueprintService = useMemo(() => new BlueprintService(), []);
  const [blueprintCells, setBlueprintCells] = useState(blueprintService.getCells());
  const [archType, setArchType] = useState(ShapeType.CUBE);

  // TRACKING FOR EDITING
  const [editingOrganism, setEditingOrganism] = useState<Organism | undefined>(undefined);

  // --- HANDLERS ---

  const handleLoad = (file: File) => {
      loadCreature(file, (org) => {
          // Sync Architect State
          blueprintService.importOrganism(org);
          setBlueprintCells(blueprintService.getCells());
          setArchType(org.shape || ShapeType.CUBE);

          // Store for potential editing
          setEditingOrganism(org);
      });
  };

  const handleArchCellClick = (x: number, y: number, z: number, isRight: boolean) => {
      if (isRight) {
          blueprintService.setCell(x, y, z, false);
      } else {
          blueprintService.setCell(x, y, z, true);
      }
      setBlueprintCells(blueprintService.getCells());
  };

  const handleArchGenerate = (type: string) => {
      // If we generate a new random template, we clear the "editing" link
      // unless we want to merge? For now, assume fresh start.
      setEditingOrganism(undefined);

      if (type === 'small') blueprintService.generateSmallCritter();
      if (type === 'large') blueprintService.generateLargeBeast();
      if (type === 'procedural') blueprintService.generateLargeBeast(); 

      if (type === 'floor') blueprintService.applyFloorFill();
      if (type === 'worm') blueprintService.applyWorm(8);
      if (type === 'mirror') blueprintService.applyMirrorX();

      setBlueprintCells(blueprintService.getCells());
  };

  const handleArchType = (t: ShapeType) => {
      setArchType(t);
      blueprintService.setType(t);
      setBlueprintCells([...blueprintService.getCells()]);
  };

  const handleSpawn = () => {
      // Pass editingOrganism as source to preserve brain
      const organism = blueprintService.generateOrganism('custom_proto', editingOrganism);
      spawnCustom(organism);
      setMode('LAB');
  };

  const handleClear = () => {
      blueprintService.clear();
      setBlueprintCells([]);
      setEditingOrganism(undefined);
  };

  return (
    <div className="relative w-full h-full bg-slate-900">

      {/* MODE TOGGLE */}
      <div className="absolute top-4 right-1/2 translate-x-1/2 z-10 flex bg-slate-800 rounded-full p-1 border border-slate-700">
          <button 
            onClick={() => setMode('LAB')}
            className={`px-4 py-1 rounded-full text-xs font-bold transition-all ${mode === 'LAB' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-white'}`}
          >
              LAB
          </button>
          <button 
            onClick={() => setMode('ARCHITECT')}
            className={`px-4 py-1 rounded-full text-xs font-bold transition-all ${mode === 'ARCHITECT' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-white'}`}
          >
              ARCHITECT
          </button>
      </div>

      {mode === 'LAB' ? (
          <>
            <LabScene 
                population={population} 
                showBestOnly={showBestOnly}
            />
            <Dashboard 
                generation={generation}
                currentStats={currentStats}
                isRunning={isRunning}
                isAutoEvolving={isAutoEvolving}
                isProcessing={isProcessing}
                progress={progress}
                currentShape={currentShape}
                onReset={reset}
                onToggleRun={() => setIsRunning(!isRunning)}
                onToggleAutoEvolve={toggleAutoEvolve} 
                showBestOnly={showBestOnly}
                setShowBestOnly={setShowBestOnly}
                // New Controls
                globalStiffness={globalStiffness}
                setGlobalStiffness={setGlobalStiffness}
                globalContractility={globalContractility}
                setGlobalContractility={setGlobalContractility}
                // Fitness Controls
                foodWeight={foodWeight}
                setFoodWeight={setFoodWeight}
                distanceWeight={distanceWeight}
                setDistanceWeight={setDistanceWeight}
                // Scarcity Controls
                foodSpawnCount={foodSpawnCount}
                setFoodSpawnCount={setFoodSpawnCount}
                foodSpawnRadius={foodSpawnRadius}
                setFoodSpawnRadius={setFoodSpawnRadius}
                // IO
                onSave={saveCreature}
                onLoad={handleLoad}
            />
            {/* Instruction Toast */}
            {!isRunning && generation === 1 && !isAutoEvolving && (
                <div className="absolute bottom-10 left-1/2 -translate-x-1/2 bg-black/50 text-white px-4 py-2 rounded-full backdrop-blur text-sm pointer-events-none animate-pulse">
                    Press RESUME to start the simulation
                </div>
            )}
          </>
      ) : (
          <>
            {/* ARCHITECT 3D VIEW */}
            <div className="w-full h-full cursor-crosshair">
                <Canvas shadows dpr={[1, 2]}>
                    <PerspectiveCamera makeDefault position={[8, 8, 8]} fov={45} />
                    <OrbitControls makeDefault target={[0, 0, 0]} />
                    <BlueprintViewUpdated
                        cells={blueprintCells} 
                        onCellClick={handleArchCellClick}
                        currentType={archType}
                    />
                </Canvas>
            </div>

            <ArchitectControls 
                onClear={handleClear}
                onSetType={handleArchType}
                onGenerate={handleArchGenerate}
                onSpawn={handleSpawn}
                currentType={archType}
                cellCount={blueprintCells.length}
            />
          </>
      )}

    </div>
  );
}

export default App;

import { ShapeType, Organism, Node, Muscle, NeuralGenome, GridCoord } from './types';
import { VectorOps } from './math';
import { LatticeFactory, ILatticeStrategy } from './lattice/LatticeStrategy';
import { GeneticOperator } from './genetics/GeneticOperator';

export class BlueprintService {
  private cells: Map<string, boolean> = new Map();
  private type: ShapeType = ShapeType.CUBE;
  private readonly GRID_SIZE = 10; 
  private geneticOperator: GeneticOperator;

  constructor() {
    this.geneticOperator = new GeneticOperator();
    this.clear();
  }

  public setType(t: ShapeType) {
    this.type = t;
  }

  public clear() {
    this.cells.clear();
  }

  public getCells(): GridCoord[] {
    const res: GridCoord[] = [];
    this.cells.forEach((val, key) => {
        if (val) {
            const [x, y, z] = key.split(',').map(Number);
            res.push({ x, y, z });
        }
    });
    return res;
  }

  public setCell(x: number, y: number, z: number, active: boolean) {
    const key = `${Math.round(x)},${Math.round(y)},${Math.round(z)}`;
    if (active) {
        this.cells.set(key, true);
    } else {
        this.cells.delete(key);
    }
  }

  public hasCell(x: number, y: number, z: number): boolean {
      return this.cells.has(`${x},${y},${z}`);
  }

  // --- HEURISTICS ---

  public generateSmallCritter() {
      this.clear();
      const rng = () => Math.random();
      const length = 4 + Math.floor(rng() * 3);
      const wideStance = rng() > 0.4;
      const legX = wideStance ? 2 : 1;

      for(let z=0; z<length; z++) this.setCell(0, 1, z, true);

      const headZ = length - 1;
      this.setCell(0, 2, headZ, true);
      if (rng() > 0.5) this.setCell(0, 3, headZ, true);

      const frontLegZ = Math.max(0, headZ - 1);
      const backLegZ = 0;

      const addLeg = (z: number) => {
          this.setCell(legX, 0, z, true);
          this.setCell(1, 1, z, true);
          if (legX === 2) this.setCell(1, 0, z, true);
      };

      addLeg(backLegZ);
      addLeg(frontLegZ);

      for(let z=1; z < length - 1; z++) {
           if (rng() > 0.6) this.setCell(1, 1, z, true);
      }
      this.applyMirrorX();
  }

  public generateLargeBeast() {
    this.clear();
    const rng = () => Math.random();
    const range = (min: number, max: number) => Math.floor(Math.random() * (max - min + 1)) + min;

    const bodyLength = range(5, 8);
    const bodyHeight = range(2, 4); 
    const zOffset = -Math.floor(bodyLength / 2);

    for (let z = 0; z < bodyLength; z++) {
        const absZ = z + zOffset;
        this.setCell(0, bodyHeight, absZ, true);
        if (rng() > 0.4) this.setCell(0, bodyHeight + 1, absZ, true);
        if (rng() > 0.4 && bodyHeight > 1) this.setCell(0, bodyHeight - 1, absZ, true);
    }

    const numLegPairs = range(2, 4); 
    const legSpacing = Math.floor(bodyLength / numLegPairs);

    for (let i = 0; i < numLegPairs; i++) {
        const zIndex = (i * legSpacing) + Math.floor(legSpacing/2);
        if (zIndex >= bodyLength) continue;

        const startZ = zIndex + zOffset;
        const startY = bodyHeight;
        const startX = 0;
        let cx = startX;
        let cy = startY;
        let cz = startZ;

        cx++;
        this.setCell(cx, cy, cz, true);

        let safety = 0;
        while (cy > 0 && safety++ < 10) {
            const moveDown = rng() > 0.3; 
            if (moveDown) cy--;
            else {
                if (rng() > 0.4) cx++; 
                else cz += (rng() > 0.5 ? 1 : -1); 
            }
            this.setCell(cx, cy, cz, true);
        }

        if (cy === 0) {
            this.setCell(cx + 1, 0, cz, true);
            this.setCell(cx - 1, 0, cz, true);
        }
    }

    const headZ = (bodyLength - 1) + zOffset + 1;
    this.setCell(0, bodyHeight + 1, headZ, true);
    this.setCell(0, bodyHeight, headZ, true);
    this.setCell(0, bodyHeight - 1, headZ, true);

    this.applyMirrorX();
  }

  public applyWorm(length: number) {
      let curr = { x: 0, y: 0, z: 0 };
      this.setCell(0, 0, 0, true);

      for(let i=0; i<length; i++) {
          const axis = Math.floor(Math.random() * 3);
          const dir = Math.random() > 0.5 ? 1 : -1;

          if (axis === 0) curr.x += dir;
          if (axis === 1) curr.y += dir;
          if (axis === 2) curr.z += dir;
          if (Math.abs(curr.x) > 4) curr.x -= dir;
          if (Math.abs(curr.y) > 4) curr.y -= dir;
          if (Math.abs(curr.z) > 4) curr.z -= dir;

          this.setCell(curr.x, curr.y, curr.z, true);
      }
  }

  public applyMirrorX() {
      const newCells = new Map<string, boolean>();
      this.cells.forEach((_, key) => {
          const [x, y, z] = key.split(',').map(Number);
          newCells.set(key, true);

          if (this.type === ShapeType.HEX) {
              const mq = -x;
              const mr = z + x; 
              newCells.set(`${mq},${y},${mr}`, true);
          } else {
             const mx = -x;
             newCells.set(`${mx},${y},${z}`, true);
          }
      });
      this.cells = newCells;
  }

  public applyFloorFill() {
      for(let x=-2; x<=2; x++) {
          for(let z=-2; z<=2; z++) {
              this.setCell(x, 0, z, true);
          }
      }
  }

  public importOrganism(org: Organism) {
      this.clear();
      this.type = org.shape || ShapeType.CUBE; 

      // If we have metadata, use it (Exact reconstruction)
      for (const node of org.nodes) {
          if (node.originalGridCoord) {
              this.setCell(node.originalGridCoord.x, node.originalGridCoord.y, node.originalGridCoord.z, true);
          }
      }
  }

  // --- EXPORT TO PHYSICS WITH BRAIN GRAFTING ---

  public generateOrganism(id: string, source?: Organism): Organism {
      const strategy: ILatticeStrategy = LatticeFactory.getStrategy(this.type);

      const nodes: Node[] = [];
      const muscles: Muscle[] = [];
      const coordToNodeId = new Map<string, string>();
      const createdMuscles = new Set<string>();

      const activeCoords = this.getCells();
      if (activeCoords.length === 0) {
          this.setCell(0,0,0, true);
          this.setCell(0,1,0, true);
          activeCoords.push({x:0,y:0,z:0}, {x:0,y:1,z:0});
      }

      // --- HEIGHT NORMALIZATION ---
      // Ensure the creature sits on the floor regardless of editor position
      let minY = Infinity;
      activeCoords.forEach(c => { 
          const w = strategy.gridToWorld(c, 0.8);
          if(w.y < minY) minY = w.y; 
      });
      const heightOffset = -minY + 0.1; // Slight float

      const scale = 0.8; 
      const mass = 1.0; 
      const friction = 0.8;

      // 1. Generate Nodes
      activeCoords.forEach((c) => {
          const nodeId = `n_${c.x}_${c.y}_${c.z}`;
          coordToNodeId.set(`${c.x},${c.y},${c.z}`, nodeId);

          const worldPos = strategy.gridToWorld(c, scale);
          worldPos.y += heightOffset;

          nodes.push({
              id: nodeId,
              pos: worldPos,
              oldPos: VectorOps.copy(worldPos),
              mass,
              friction,
              originalGridCoord: { x: c.x, y: c.y, z: c.z }
          });
      });

      // 2. Identify Head
      let maxZ = -Infinity;
      nodes.forEach(n => { if (n.pos.z > maxZ) maxZ = n.pos.z; });
      const candidatesZ = nodes.filter(n => Math.abs(n.pos.z - maxZ) < 0.1);
      let maxY = -Infinity;
      candidatesZ.forEach(n => { if (n.pos.y > maxY) maxY = n.pos.y; });
      let headNode = candidatesZ.find(n => Math.abs(n.pos.y - maxY) < 0.1);

      if (headNode) {
          // @ts-ignore
          headNode.isHead = true;
      }

      // Init Head Pos
      const initialHeadPos = headNode ? { ...headNode.pos } : { x: 0, y: 0, z: 0 };

      // 3. Connect Muscles using Strategy
      const addMuscle = (n1: string, n2: string, stiffness: number = 0.8) => {
          const k = [n1, n2].sort().join('-');
          if (createdMuscles.has(k)) return;

          const node1 = nodes.find(n => n.id === n1);
          const node2 = nodes.find(n => n.id === n2);
          if (!node1 || !node2) return;

          const dist = VectorOps.distance(node1.pos, node2.pos);
          muscles.push({
              id: `m_${k}`,
              nodeA: n1,
              nodeB: n2,
              baseLength: dist,
              stiffness: stiffness, 
              dnaIndex: muscles.length,
              phase: Math.random() * Math.PI * 2,
              freq: 1.0,
              amp: 0.0
          });
          createdMuscles.add(k);
      };

      activeCoords.forEach(c => {
          const myId = coordToNodeId.get(`${c.x},${c.y},${c.z}`);
          if (!myId) return;

          const neighbors = strategy.getNeighbors(c);
          neighbors.forEach(n => {
              const targetKey = `${n.coord.x},${n.coord.y},${n.coord.z}`;
              const targetId = coordToNodeId.get(targetKey);
              if (targetId) {
                  addMuscle(myId, targetId, n.distanceWeight);
              }
          });
      });

      // 5. Genome Init & Grafting
      const reservoirSize = 20;
      let genome = this.geneticOperator.createRandomGenome(muscles.length, nodes.length, reservoirSize);

      // GRAFTING: Preserve brain if shape is similar
      if (source && source.neuralGenome) {
          const oldGenome = source.neuralGenome;
          // Copy parameters
          genome = this.geneticOperator.cloneGenome(oldGenome);

          // Resize Arrays if needed (Topology change)
          const resizeWeights = (target: number[], source: number[]) => {
              for(let i=0; i<target.length; i++) {
                  if (i < source.length) target[i] = source[i];
              }
          };

          const newSyn = this.geneticOperator.createRandomGenome(muscles.length, nodes.length).synapseWeights;
          resizeWeights(newSyn, oldGenome.synapseWeights);
          genome.synapseWeights = newSyn;
      }

      return {
          id,
          shape: this.type,
          nodes,
          muscles,
          neuralGenome: genome,
          fitness: source ? source.fitness : 0,
          generation: source ? source.generation : 1,
          energy: 100,
          maxEnergy: 100,
          hungerTime: 0,
          isAlive: true,
          foodEaten: 0,
          visibleFood: [],
          initialHeadPos,
          distanceTraveled: 0
      };
  }
}

import { Organism, ShapeType, Node, Muscle, NeuralGenome } from './types';
import { VectorOps } from './math';
import { GeneticOperator } from './genetics/GeneticOperator';

export class ShapeFactory {

  static create(type: ShapeType, id: string): Organism {
    let nodes: Node[] = [];
    let muscles: Muscle[] = [];

    switch (type) {
      case ShapeType.CUBE:
        ({ nodes, muscles } = this.createCube());
        break;
      case ShapeType.WORM:
        ({ nodes, muscles } = this.createWorm(4));
        break;
      case ShapeType.TETRAHEDRON:
      default:
        ({ nodes, muscles } = this.createTetrahedron());
        break;
    }

    // Initialize Neural Genome
    const operator = new GeneticOperator();
    const genome = operator.createRandomGenome(muscles.length, nodes.length);

    muscles.forEach((m, i) => m.dnaIndex = i);

    // Identify Head (Furthest Forward, then Highest Up)
    let maxZ = -Infinity;
    nodes.forEach(n => { if (n.pos.z > maxZ) maxZ = n.pos.z; });

    let candidates: Node[] = [];
    nodes.forEach(n => {
        if (Math.abs(n.pos.z - maxZ) < 0.1) candidates.push(n);
    });

    let headNode: Node | null = null;
    let maxY = -Infinity;
    candidates.forEach(n => {
        if (n.pos.y > maxY) {
            maxY = n.pos.y;
            headNode = n;
        }
    });

    if (headNode) {
        // @ts-ignore
        headNode.isHead = true;
    }

    const initialHeadPos = headNode ? { ...headNode.pos } : { x: 0, y: 0, z: 0 };

    return {
      id,
      shape: type, // Store shape type for editor consistency
      nodes,
      muscles,
      neuralGenome: genome,
      fitness: 0,
      generation: 1,
      // Metabolism Defaults
      energy: 100,
      maxEnergy: 100,
      hungerTime: 0,
      isAlive: true,
      foodEaten: 0,
      visibleFood: [],
      // Distance Metrics (Replaces Posture)
      initialHeadPos,
      distanceTraveled: 0
    };
  }

  // HELPER: Factory for optimized Node creation
  // Initializes all fields to ensure stable V8 Hidden Class
  private static createNode(id: string, x: number, y: number, z: number, mass: number, friction: number): Node {
      return {
          id,
          pos: { x, y, z },
          oldPos: { x, y, z },
          mass,
          friction,
          // Explicitly init optional fields to avoid de-opt
          isHead: false,
          isFixed: false,
          isGripping: false,
          gripSignal: 0,
          activation: 0,
          originalGridCoord: undefined
      };
  }

  private static createTetrahedron() {
    const f = 0.95; 
    const m = 4.0;  

    const nodes: Node[] = [
      this.createNode('n1', 0, 0, 1, m, f),
      this.createNode('n2', 1, 0, -0.7, m, f),
      this.createNode('n3', -1, 0, -0.7, m, f),
      this.createNode('n4', 0, 1.5, 0, m, f)
    ];
    const muscles = this.connectAll(nodes);
    return { nodes, muscles };
  }

  private static createCube() {
    const nodes: Node[] = [];
    const size = 1.0;
    const startY = 0.5;
    const f = 0.95; 
    const m = 4.0; 

    for(let x=0; x<=1; x++) {
      for(let y=0; y<=1; y++) {
        for(let z=0; z<=1; z++) {
          const px = (x - 0.5) * size;
          const py = startY + y * size;
          const pz = (z - 0.5) * size;
          nodes.push(this.createNode(`n${x}${y}${z}`, px, py, pz, m, f));
        }
      }
    }
    const muscles = this.connectDistanceThreshold(nodes, size * 1.8);
    return { nodes, muscles };
  }

  private static createWorm(segments: number) {
    const nodes: Node[] = [];
    const size = 1.0;
    const bellyFriction = 0.5; 
    const footFriction = 0.98; 
    const m = 4.0; 

    for (let i = 0; i < segments; i++) {
        const offset = i * size;
        nodes.push(
            this.createNode(`n${i}_a`, -0.5, 0, offset, m, footFriction),
            this.createNode(`n${i}_b`, 0.5, 0, offset, m, footFriction),
            this.createNode(`n${i}_top`, 0, 1, offset + 0.5, m, bellyFriction)
        );
    }
    return { nodes, muscles: this.connectDistanceThreshold(nodes, size * 1.5) };
  }

  private static connectAll(nodes: Node[]): Muscle[] {
    const muscles: Muscle[] = [];
    let mCount = 0;
    for (let i = 0; i < nodes.length; i++) {
      for (let j = i + 1; j < nodes.length; j++) {
        const dist = VectorOps.distance(nodes[i].pos, nodes[j].pos);
        muscles.push({
          id: `m${mCount++}`,
          nodeA: nodes[i].id,
          nodeB: nodes[j].id,
          baseLength: dist,
          stiffness: 1.0, 
          dnaIndex: 0,
          phase: Math.random() * Math.PI * 2,
          freq: 1.0,
          amp: 0.0,
          // Explicit Init for Hidden Class optimization (Muscle)
          currentLength: dist,
          targetLength: dist,
          nodeRefA: undefined,
          nodeRefB: undefined
        });
      }
    }
    return muscles;
  }

    private static connectDistanceThreshold(nodes: Node[], threshold: number): Muscle[] {
      const muscles: Muscle[] = [];
      let mCount = 0;
      for (let i = 0; i < nodes.length; i++) {
        for (let j = i + 1; j < nodes.length; j++) {
          const dist = VectorOps.distance(nodes[i].pos, nodes[j].pos);
          if (dist <= threshold) {
            muscles.push({
              id: `m${mCount++}`,
              nodeA: nodes[i].id,
              nodeB: nodes[j].id,
              baseLength: dist,
              stiffness: 1.0,
              dnaIndex: 0,
              phase: Math.random() * Math.PI * 2,
              freq: 1.0,
              amp: 0.0,
              currentLength: dist,
              targetLength: dist,
              nodeRefA: undefined,
              nodeRefB: undefined
            });
          }
        }
      }
      return muscles;
    }
}

import { Node, Muscle, Organism, SimulationConfig } from './types';
import { BrainController } from './neural/BrainController';

export class BioPhysicsEngine {
  private config: SimulationConfig;
  private readonly MAX_VELOCITY = 12.0; 

  // SOLVER SETTINGS
  private readonly RELAXATION_FACTOR = 0.25; 
  private readonly ITERATIONS = 6; 

  // DAMPING SETTINGS
  private readonly BASE_MUSCLE_DAMPING = 0.08; 
  private readonly ADAPTIVE_DAMPING_FACTOR = 0.12; 
  private readonly ROTATIONAL_DRAG = 0.92; 

  // AIR RESISTANCE
  private readonly DRAG_COEFFICIENT = 0.08; 

  // --- SOLIDITY CONSTANTS ---
  private readonly NODE_RADIUS = 0.1; 
  private readonly HARD_CONTACT_LIMIT = 0.22; 

  constructor(config: Partial<SimulationConfig> = {}) {
    this.config = {
      gravity: -60.0, 
      friction: 0.98, // Global air friction
      groundDamping: 0.8, // Increased ground damping (less bounce = more grip)
      timeStep: 0.016,
      shapeMemoryStrength: 0.85, 
      globalStiffness: 0.8, // Updated Default: 80% stiffness
      globalContractility: 1.5, // Updated Default: 150% muscle power
      ...config
    };
  }

  public setConfig(config: Partial<SimulationConfig>) {
      this.config = { ...this.config, ...config };
  }

  // fastMode: If true, runs lower fidelity physics for rapid evolutionary calculation
  public updateOrganism(organism: Organism, totalTime: number, fastMode: boolean = false): void {

    // 1. PHYSICS INTEGRATION
    // Note: Brain update is now handled externally by EvolutionService

    // Handle Ragdoll state
    if (!organism.isAlive) {
        organism.muscles.forEach(m => {
            m.stiffness = 0.05; // Very loose
            m.amp = 0; // Stop oscillating
            m.targetLength = m.baseLength;
        });
        // Release all grips if dead
        organism.nodes.forEach(n => {
            n.gripSignal = 1.0; 
            n.isGripping = false;
        });
    }

    // ADAPTIVE SUBSTEPS
    const subSteps = fastMode ? 4 : 12; 
    const subDt = this.config.timeStep / subSteps;
    const gravityVec = { x: 0, y: this.config.gravity * subDt * subDt, z: 0 };

    for(let s=0; s < subSteps; s++) {
        this.integrate(organism, subDt, gravityVec);
        if (!fastMode) this.applyRotationalDrag(organism); 

        // ITERATIVE SOLVER
        // In Fast Mode, we reduce iterations slightly
        const loops = fastMode ? 4 : this.ITERATIONS;

        for (let i = 0; i < loops; i++) {
            this.resolveMuscles(organism);

            // CRITICAL OPTIMIZATION:
            // Self-Collision is O(N^2). We disable it during rapid evolution.
            if (!fastMode) {
                this.resolveSelfCollisions(organism); 
            }
        }

        this.resolveFloor(organism);
    }
  }

  private applyRotationalDrag(organism: Organism): void {
      let cx = 0, cz = 0;
      let count = 0;
      for (const n of organism.nodes) {
          cx += n.pos.x;
          cz += n.pos.z;
          count++;
      }
      if (count === 0) return;
      cx /= count;
      cz /= count;

      let angularMomentum = 0;
      let momentOfInertia = 0;

      for (const n of organism.nodes) {
          const rx = n.pos.x - cx;
          const rz = n.pos.z - cz;

          const vx = n.pos.x - n.oldPos.x;
          const vz = n.pos.z - n.oldPos.z;

          const orbitalComponent = rx * vz - rz * vx;

          angularMomentum += orbitalComponent;
          momentOfInertia += rx * rx + rz * rz;
      }

      if (momentOfInertia < 0.001) return;

      const angularVel = angularMomentum / momentOfInertia;

      for (const n of organism.nodes) {
          const rx = n.pos.x - cx;
          const rz = n.pos.z - cz;

          const dampX = -angularVel * rz * this.ROTATIONAL_DRAG;
          const dampZ =  angularVel * rx * this.ROTATIONAL_DRAG;

          n.oldPos.x += dampX;
          n.oldPos.z += dampZ;
      }
  }

  private integrate(organism: Organism, dt: number, gravityVec: {x:number, y:number, z:number}): void {
    const { friction } = this.config;
    const maxStepDist = this.MAX_VELOCITY * dt;
    const maxStepSq = maxStepDist * maxStepDist;

    for (const node of organism.nodes) {
      if (node.isFixed) continue;

      let velX = node.pos.x - node.oldPos.x;
      let velY = node.pos.y - node.oldPos.y;
      let velZ = node.pos.z - node.oldPos.z;

      // 1. QUADRATIC DRAG
      const vSq = velX*velX + velY*velY + velZ*velZ;
      if (vSq > 0.000001) {
          const vLen = Math.sqrt(vSq);
          const dragFactor = 1.0 / (1.0 + this.DRAG_COEFFICIENT * vLen);

          velX *= dragFactor;
          velY *= dragFactor;
          velZ *= dragFactor;
      }

      // 2. Base Friction (Air)
      velX *= friction;
      velY *= friction;
      velZ *= friction;

      // 3. Hard Cap (Safety Terminator)
      const distSq = velX*velX + velY*velY + velZ*velZ;
      if (distSq > maxStepSq) {
          const scale = maxStepDist / Math.sqrt(distSq);
          velX *= scale;
          velY *= scale;
          velZ *= scale;
      }

      // GC OPTIMIZATION: Update oldPos in place instead of creating new object
      node.oldPos.x = node.pos.x;
      node.oldPos.y = node.pos.y;
      node.oldPos.z = node.pos.z;

      node.pos.x += velX + gravityVec.x;
      node.pos.y += velY + gravityVec.y;
      node.pos.z += velZ + gravityVec.z;
    }
  }

  private resolveMuscles(organism: Organism): void {
    const GROUND_TOLERANCE = 0.02;
    const ANCHOR_MULTIPLIER = 0.1; 
    const MEMORY_STRENGTH = this.config.shapeMemoryStrength || 0.8;
    const GLOBAL_STIFFNESS = this.config.globalStiffness; 

    // CACHE REFERENCES (Lazy Load)
    if (!organism.muscles[0]?.nodeRefA) {
         const nodeMap = new Map<string, Node>();
         for (const n of organism.nodes) nodeMap.set(n.id, n);
         for (const m of organism.muscles) {
             m.nodeRefA = nodeMap.get(m.nodeA);
             m.nodeRefB = nodeMap.get(m.nodeB);
         }
    }

    for (const muscle of organism.muscles) {
        // O(1) Access
        const n1 = muscle.nodeRefA;
        const n2 = muscle.nodeRefB;

        if (!n1 || !n2) continue;

        const dx = n2.pos.x - n1.pos.x;
        const dy = n2.pos.y - n1.pos.y;
        const dz = n2.pos.z - n1.pos.z;

        // OPTIMIZATION: Check Squared Distance first to avoid sqrt
        const distSq = dx*dx + dy*dy + dz*dz;
        if (distSq < 0.0000001) continue; 

        const dist = Math.sqrt(distSq);

        // 1. ACTIVE MUSCLE COMPONENT
        let activeTarget = muscle.targetLength || muscle.baseLength;
        if (activeTarget < this.HARD_CONTACT_LIMIT) activeTarget = this.HARD_CONTACT_LIMIT;

        let stiffness = muscle.stiffness * 0.8 * GLOBAL_STIFFNESS; 

        const activeDiff = dist - activeTarget;

        // 2. PASSIVE MEMORY COMPONENT
        const deviation = Math.abs(dist - muscle.baseLength);
        const strain = deviation / muscle.baseLength;
        const strainBoost = 1.0 + (strain * 4.0); 

        const currentMemoryStrength = organism.isAlive 
            ? MEMORY_STRENGTH * strainBoost * GLOBAL_STIFFNESS
            : MEMORY_STRENGTH * 0.1 * GLOBAL_STIFFNESS;

        const baseDiff = dist - muscle.baseLength;

        // --- DUAL FORCE BLENDING ---
        const activeCorrection = activeDiff * stiffness;
        const memoryCorrection = baseDiff * currentMemoryStrength;
        let totalCorrection = (activeCorrection + memoryCorrection) * this.RELAXATION_FACTOR;

        // --- DAMPING ---
        const vx1 = n1.pos.x - n1.oldPos.x;
        const vy1 = n1.pos.y - n1.oldPos.y;
        const vz1 = n1.pos.z - n1.oldPos.z;
        const vx2 = n2.pos.x - n2.oldPos.x;
        const vy2 = n2.pos.y - n2.oldPos.y;
        const vz2 = n2.pos.z - n2.oldPos.z;

        const rvx = vx2 - vx1;
        const rvy = vy2 - vy1;
        const rvz = vz2 - vz1;

        const nx = dx / dist;
        const ny = dy / dist;
        const nz = dz / dist;

        const relVel = Math.sqrt(rvx*rvx + rvy*rvy + rvz*rvz);
        const dynamicDamping = this.BASE_MUSCLE_DAMPING + (relVel * this.ADAPTIVE_DAMPING_FACTOR);
        const vRelProj = rvx * nx + rvy * ny + rvz * nz;

        totalCorrection += vRelProj * dynamicDamping;

        // --- MOMENTUM PRESERVATION ---
        let im1 = (n1.isFixed || n1.isGripping) ? 0 : 1 / n1.mass;
        let im2 = (n2.isFixed || n2.isGripping) ? 0 : 1 / n2.mass;

        if (n1.pos.y <= GROUND_TOLERANCE) im1 *= ANCHOR_MULTIPLIER;
        if (n2.pos.y <= GROUND_TOLERANCE) im2 *= ANCHOR_MULTIPLIER;

        const totalInvMass = im1 + im2;
        if (totalInvMass === 0) continue;

        const w1 = im1 / totalInvMass;
        const w2 = im2 / totalInvMass;

        const offsetX = nx * totalCorrection;
        const offsetY = ny * totalCorrection;
        const offsetZ = nz * totalCorrection;

        if (!n1.isFixed && !n1.isGripping) {
            n1.pos.x += offsetX * w1;
            n1.pos.y += offsetY * w1;
            n1.pos.z += offsetZ * w1;
        }

        if (!n2.isFixed && !n2.isGripping) {
            n2.pos.x -= offsetX * w2;
            n2.pos.y -= offsetY * w2;
            n2.pos.z -= offsetZ * w2;
        }
    }
  }

  private resolveSelfCollisions(organism: Organism): void {
      const nodes = organism.nodes;
      const count = nodes.length;
      const minDistance = this.HARD_CONTACT_LIMIT; 
      const minDistanceSq = minDistance * minDistance;

      for (let i = 0; i < count; i++) {
          for (let j = i + 1; j < count; j++) {
              const n1 = nodes[i];
              const n2 = nodes[j];

              const dx = n1.pos.x - n2.pos.x;
              const dy = n1.pos.y - n2.pos.y;
              const dz = n1.pos.z - n2.pos.z;
              const distSq = dx*dx + dy*dy + dz*dz;

              if (distSq < minDistanceSq && distSq > 0.000001) {
                  const dist = Math.sqrt(distSq);
                  const overlap = minDistance - dist;

                  const fx = (dx / dist) * overlap * 0.2;
                  const fy = (dy / dist) * overlap * 0.2;
                  const fz = (dz / dist) * overlap * 0.2;

                  if (!n1.isFixed) { n1.pos.x += fx; n1.pos.y += fy; n1.pos.z += fz; }
                  if (!n2.isFixed) { n2.pos.x -= fx; n2.pos.y -= fy; n2.pos.z -= fz; }
              }
          }
      }
  }

  private resolveFloor(organism: Organism): void {
    const RADIUS = this.NODE_RADIUS;

    for (const node of organism.nodes) {
      if (node.pos.y < RADIUS) {
        node.pos.y = RADIUS;

        // STANDARD FRICTION (Replaces Sticky Suction)
        const vx = node.pos.x - node.oldPos.x;
        const vz = node.pos.z - node.oldPos.z;
        const frictionCoeff = 0.85; 

        node.oldPos.x = node.pos.x - vx * frictionCoeff;
        node.oldPos.z = node.pos.z - vz * frictionCoeff;

        node.isGripping = false; // Never stick
      } else {
          node.isGripping = false;
      }
    }
  }
}

import React, { useRef, useMemo, MutableRefObject } from 'react';
import { useFrame } from '@react-three/fiber';
import { Organism } from '../../domain/types';
import * as THREE from 'three';

interface FoodViewProps {
    leaderRef: MutableRefObject<Organism | null>;
}

export const FoodView: React.FC<FoodViewProps> = ({ leaderRef }) => {
    const meshRef = useRef<THREE.InstancedMesh>(null);
    const tempObj = useMemo(() => new THREE.Object3D(), []);

    // Geometry/Material
    const geo = useMemo(() => new THREE.IcosahedronGeometry(0.15, 0), []);
    const mat = useMemo(() => new THREE.MeshStandardMaterial({ 
        color: '#4ade80', 
        emissive: '#22c55e',
        emissiveIntensity: 0.6,
        roughness: 0.2
    }), []);

    useFrame((state) => {
        if (!meshRef.current) return;

        // Use the centralized leader
        const leader = leaderRef.current;

        if (!leader || !leader.visibleFood) {
            meshRef.current.count = 0;
            return;
        }

        const foodItems = leader.visibleFood;
        meshRef.current.count = foodItems.length;

        // Use clock from state instead of Date.now()
        const time = state.clock.elapsedTime;

        // Update Instances
        for (let i = 0; i < foodItems.length; i++) {
            const item = foodItems[i];

            // Position
            tempObj.position.set(item.pos.x, item.pos.y, item.pos.z);

            // Animation: Spin
            tempObj.rotation.y += 0.02;
            tempObj.rotation.z += 0.01;

            // Scale: Shrink if consumed, else pulse
            if (item.consumed) {
                tempObj.scale.setScalar(0); 
            } else {
                const pulse = 1.0 + Math.sin(time * 3 + i) * 0.1;
                tempObj.scale.setScalar(pulse);
            }

            tempObj.updateMatrix();
            meshRef.current.setMatrixAt(i, tempObj.matrix);
        }

        meshRef.current.instanceMatrix.needsUpdate = true;
    });

    return (
        <instancedMesh 
            ref={meshRef} 
            args={[geo, mat, 100]} // Max 100 food items buffer
            frustumCulled={false}
        />
    );
};

import { Organism, Node } from '../types';
import { NeuralNode } from './NeuralNode';
import { CentralPatternGenerator } from './CentralPatternGenerator';
import { VectorOps } from '../math';

// Optimization Structure
interface Synapse {
    nodeA: NeuralNode;
    nodeB: NeuralNode;
    weightIndex: number;
}

export class BrainController {
  private neuralNodes: Map<string, NeuralNode> = new Map();
  private cpg: CentralPatternGenerator;
  private organism: Organism;
  private isInitialized = false;

  // OPTIMIZATION: Flattened array for O(1) iteration
  private synapses: Synapse[] = []; 
  // OPTIMIZATION: Typed Array for weight access (faster than standard number[])
  private synapseWeightsCache: Float32Array = new Float32Array(0);

  // Simulation Time Tracker
  private internalTime = 0;

  // Spinal Wave Props
  private muscleRestDistances: Float32Array; // Flattened distance cache

  // Decision Timer
  private decisionTimer = 0;
  private readonly DECISION_INTERVAL_BASE = 0.08; 

  // --- LEARNING MEMORY ---
  private previousEnergy: number = 0;
  private previousDistanceToFood: number = Infinity;
  private readonly VISION_RADIUS = 4.0;
  private readonly HEBBIAN_RATE = 0.15; // Learning Rate

  constructor(organism: Organism) {
    this.organism = organism;
    this.cpg = new CentralPatternGenerator(20);
    this.previousEnergy = organism.energy;

    // Initialize Neural Nodes
    organism.nodes.forEach(node => {
      this.neuralNodes.set(node.id, new NeuralNode(node));
    });

    // Init Empty Cache
    this.muscleRestDistances = new Float32Array(organism.muscles.length);

    if (organism.neuralGenome) {
        this.cpg.initialize(organism.neuralGenome.reservoirWeights);
    }
  }

  private initializeNervousSystem() {
      if (this.organism.nodes.length === 0) return;

      // Identify Head
      let headNode = this.organism.nodes.find(n => n.isHead);
      if (!headNode) {
          headNode = this.organism.nodes[0];
          // @ts-ignore
          headNode.isHead = true; 
      }

      // 1. Build Distance Cache
      this.organism.muscles.forEach((m, i) => {
          const nA = this.organism.nodes.find(n => n.id === m.nodeA);
          const nB = this.organism.nodes.find(n => n.id === m.nodeB);
          if (nA && nB) {
              const midX = (nA.pos.x + nB.pos.x) / 2;
              const midY = (nA.pos.y + nB.pos.y) / 2;
              const midZ = (nA.pos.z + nB.pos.z) / 2;

              const dist = VectorOps.distance(
                  headNode!.pos, 
                  { x: midX, y: midY, z: midZ }
              );
              this.muscleRestDistances[i] = dist;
          }
      });

      // 2. Build Synapse Cache (Optimization)
      // We pre-calculate connections so we don't query the Map every frame
      this.synapses = [];
      const weightCount = this.organism.neuralGenome?.synapseWeights.length || 1;

      // Convert standard array to Float32Array for the hot path
      this.synapseWeightsCache = new Float32Array(this.organism.neuralGenome.synapseWeights);

      this.organism.muscles.forEach((muscle, i) => {
          const nnA = this.neuralNodes.get(muscle.nodeA);
          const nnB = this.neuralNodes.get(muscle.nodeB);
          if (nnA && nnB) {
              this.synapses.push({
                  nodeA: nnA,
                  nodeB: nnB,
                  weightIndex: i % weightCount
              });
          }
      });

      // 3. Reset Muscle Oscillators
      this.organism.muscles.forEach(m => {
          m.targetLength = m.baseLength;
          m.phase = Math.random() * Math.PI * 2; 
          m.freq = 1.0; 
          m.amp = 0.0;
      });

      this.isInitialized = true;
  }

  public update(dt: number, powerScale: number = 1.0): void {
    const genome = this.organism.neuralGenome;
    if (!genome) return;

    const brainDt = dt * (genome.internalClockSpeed || 1.0);

    if (!this.isInitialized) {
        this.initializeNervousSystem();
    }

    this.internalTime += brainDt;
    this.decisionTimer += brainDt;

    if (this.decisionTimer >= this.DECISION_INTERVAL_BASE) {
        this.think(brainDt);
        this.learn();
        this.decisionTimer = 0;
    }

    // --- SPINAL WAVE (Motor Control) ---
    const WAVE_FREQ = genome.waveFreq || 1.5; 
    const WAVE_SPEED = genome.waveSpeed || 1.0; 
    const FORCED_AMP = 0.15; 
    const MAX_DEFORMATION = 0.3; 
    const PI2 = Math.PI * 2;

    // Use loop index for cache access
    for(let i=0; i<this.organism.muscles.length; i++) {
        const m = this.organism.muscles[i];

        m.phase += m.freq * brainDt * PI2;
        if (m.phase > PI2) m.phase -= PI2;
        const brainSignal = Math.sin(m.phase) * m.amp;

        const dist = this.muscleRestDistances[i]; // Direct array access
        const nerveLag = dist * WAVE_SPEED;
        const spinalSignal = Math.sin(this.internalTime * WAVE_FREQ * PI2 - nerveLag) * FORCED_AMP;

        let totalSignal = (spinalSignal + brainSignal) * powerScale;

        // Clamp
        if (totalSignal > MAX_DEFORMATION) totalSignal = MAX_DEFORMATION;
        if (totalSignal < -MAX_DEFORMATION) totalSignal = -MAX_DEFORMATION;

        const desiredLength = m.baseLength * (1 + totalSignal);

        // Inertia
        m.targetLength = m.targetLength || m.baseLength;
        m.targetLength += (desiredLength - m.targetLength) * 0.05;
        m.currentLength = m.targetLength;
    }
  }

  private think(dt: number): void {
    const genome = this.organism.neuralGenome;

    // 1. GATHER PROPRIOCEPTION
    let globalSensoryInput = 0;
    for (const nn of this.neuralNodes.values()) {
        nn.sense(dt);
        globalSensoryInput += nn.inputSum;
    }

    // 2. VISION WITH GATED ATTENTION
    const head = this.organism.nodes.find(n => n.isHead);
    if (head) {
        // Optimized Vision Logic ...
        const stability = Math.min(1.0, Math.max(0, (head.pos.y - 0.2))); 
        let nearestDistSq = Infinity;
        let tX=0, tY=0, tZ=0;
        let foundFood = false;

        const vRadSq = this.VISION_RADIUS * this.VISION_RADIUS;

        for (const food of this.organism.visibleFood) {
            if (food.consumed) continue;

            const dx = food.pos.x - head.pos.x;
            const dy = food.pos.y - head.pos.y;
            const dz = food.pos.z - head.pos.z;
            const distSq = dx*dx + dy*dy + dz*dz;

            if (distSq < vRadSq) {
                if (distSq < nearestDistSq) {
                    nearestDistSq = distSq;
                    tX = dx; tY = dy; tZ = dz;
                    foundFood = true;
                }
            }
        }

        this.previousDistanceToFood = foundFood ? Math.sqrt(nearestDistSq) : Infinity;

        if (foundFood && stability > 0.1) {
            const dist = Math.sqrt(nearestDistSq);
            const headNeural = this.neuralNodes.get(head.id);
            if (headNeural) {
                const signalStrength = Math.max(0, 1.0 - (dist / this.VISION_RADIUS)) * stability;
                headNeural.inputSum += (tX / dist) * signalStrength * 3.0; 
                headNeural.inputSum += (tY / dist) * signalStrength * 3.0; 
                headNeural.inputSum += (tZ / dist) * signalStrength * 3.0; 
                globalSensoryInput += signalStrength * 2.0;
            }
        }
    }

    globalSensoryInput /= (this.neuralNodes.size || 1);

    // 3. SYNAPTIC PROPAGATION (OPTIMIZED)
    // We iterate the pre-compiled array and use the TypedArray cache
    for(let i=0; i<this.synapses.length; i++) {
        const s = this.synapses[i];
        // Read from Float32Array cache instead of the genome object's standard array
        const w = this.synapseWeightsCache[s.weightIndex]; 
        s.nodeB.inputSum += s.nodeA.activation * w;
        s.nodeA.inputSum += s.nodeB.activation * w;
    }

    for (const nn of this.neuralNodes.values()) {
        nn.updateActivation();
    }

    // 4. RESERVOIR COMPUTING
    this.cpg.tick(globalSensoryInput);

    // 5. MOTOR OUTPUT
    const mus = this.organism.muscles;
    const len = mus.length;
    for(let i=0; i<len; i++) {
        const muscle = mus[i];
        const rawAmp = this.cpg.getSignal(i, genome.outputWeights); 
        const rawFreq = this.cpg.getSignal(i + 1, genome.outputWeights); 

        const targetAmp = Math.abs(rawAmp) * 0.3; 
        const targetFreq = 0.5 + ((rawFreq + 1) / 2) * 2.5; // range 0.5 to 3.0

        muscle.amp += (targetAmp - muscle.amp) * 0.1;
        muscle.freq += (targetFreq - muscle.freq) * 0.1;
    }

    // 6. SUCTION OUTPUT
    if (genome.gripWeights && genome.gripWeights.length > 0) {
        const nodes = this.organism.nodes;
        for(let i=0; i<nodes.length; i++) {
            const rawSignal = this.cpg.getSignal(i, genome.gripWeights);
            const normalized = (rawSignal + 1) / 2;
            const node = nodes[i];
            const oldGrip = node.gripSignal || 0;
            node.gripSignal = oldGrip + (normalized - oldGrip) * 0.2;
        }
    }
  }

  private learn(): void {
      // NOTE: We do NOT write back to Float32Array here yet.
      // We write to the master genome (number[]), then sync the cache if needed.
      // Or we write to both. Writing to simple array is fast enough for sparse learning updates.
      const genome = this.organism.neuralGenome;
      let learningSignal = 0;

      // 1. METABOLIC REWARD
      const currentEnergy = this.organism.energy;
      const energyDelta = currentEnergy - this.previousEnergy;
      if (energyDelta > 0.5) learningSignal += 1.0;
      this.previousEnergy = currentEnergy;

      // 2. VESTIBULAR PAIN
      const head = this.organism.nodes.find(n => n.isHead);
      if (head && head.pos.y < 0.2) {
          learningSignal -= 0.5; 
      }

      // APPLY LEARNING (OPTIMIZED)
      if (Math.abs(learningSignal) > 0.1) {
          for(let i=0; i<this.synapses.length; i++) {
              const s = this.synapses[i];
              const coActivity = s.nodeA.activation * s.nodeB.activation;

              if (coActivity > 0.1) {
                  let w = this.synapseWeightsCache[s.weightIndex]; // Read from cache
                  w += this.HEBBIAN_RATE * learningSignal * coActivity;

                  // Clamp
                  if (w > 3.0) w = 3.0;
                  else if (w < -3.0) w = -3.0;

                  // Write to both for consistency
                  this.synapseWeightsCache[s.weightIndex] = w;
                  genome.synapseWeights[s.weightIndex] = w;
              }
          }
      }
  }
}

// Hexagonal Architecture: Domain Layer (Inner Core)
// Zero dependencies on UI or Rendering libraries.

export interface Vec3 {
  x: number;
  y: number;
  z: number;
}

export interface Node {
  id: string;
  pos: Vec3;
  oldPos: Vec3; // For Verlet integration
  mass: number;
  friction: number;
  isFixed?: boolean;
  isHead?: boolean; // NEW: The only node that can eat

  // SUCTION MECHANICS
  isGripping?: boolean; // Read-only physics state
  gripSignal?: number;  // 0.0 to 1.0 (Controlled by Brain). High = Release Suction.

  // EDITOR METADATA (Preserves shape upon reloading)
  originalGridCoord?: { x: number; y: number; z: number }; 

  // Neural State
  activation?: number; // 0.0 to 1.0 (Visualization Glow)
  // Physics State
}

export interface Muscle {
  id: string;
  nodeA: string; // ID reference
  nodeB: string; // ID reference
  baseLength: number;
  stiffness: number;
  dnaIndex: number; // Maps to a Gene (Index in genome arrays)

  // Runtime Physics State
  currentLength?: number; 
  targetLength?: number; 

  // --- RUNTIME OPTIMIZATION (O(1) Access) ---
  nodeRefA?: Node;
  nodeRefB?: Node;

  // --- OSCILLATOR STATE (The Anti-Vibration Core) ---
  // The brain controls these parameters, not the length directly.
  phase: number;      // Current position in the sine wave (0 to 2PI)
  freq: number;       // How fast it pulses (Hz). Clamped to prevent jitter.
  amp: number;        // How much it expands (0.0 to 0.4). 
}

// Replaced simple Sine Gene with Neural Genome
export interface NeuralGenome {
  // GNN Weights: How much signal flows through each muscle (Synapse)
  synapseWeights: number[]; 
  // LSM Weights: The chaotic reservoir weights (simplified as a float array)
  reservoirWeights: number[];
  // Output Weights: Mapping the reservoir state to muscle contraction
  outputWeights: number[]; 
  // NEW: Predictive World Model Weights (Reservoir -> Predicted Sensory Input)
  predictionWeights: number[];
  // NEW: Grip Control Weights (Reservoir -> Node Suction Release)
  gripWeights: number[]; 
  // Biases for neurons
  biases: number[];

  // --- EVOLVABLE BRAIN DYNAMICS ---
  internalClockSpeed: number; // Multiplier (0.5 to 2.0). How fast the brain thinks relative to physics.
  waveFreq: number;           // Hz (0.5 to 3.0). Base frequency of the spinal generator.
  waveSpeed: number;          // Propagation speed of the wave along the body.
}

export interface FoodItem {
    id: string;
    pos: Vec3;
    energyValue: number;
    consumed: boolean;
}

export enum ShapeType {
  CUBE = 'CUBE', // Cartesian Lattice
  TETRAHEDRON = 'TETRAHEDRON', // Offset Lattice
  WORM = 'WORM', // Legacy
  HEX = 'HEX', // 3D Hexagonal Prism Layout
}

export interface Organism {
  id: string;
  shape: ShapeType; // NEW: Tracks the lattice type for the Architect
  nodes: Node[];
  muscles: Muscle[];
  // The Blueprint
  neuralGenome: NeuralGenome;
  // The Runtime Brain (Controller instance, not serialized usually, but here for simplicity)
  brain?: any; 

  // Stats
  fitness: number; // Total Score
  generation: number;

  // NEW: Distance Metrics (Replacing Posture)
  initialHeadPos: Vec3; // BENCHMARK: Where the head started
  distanceTraveled: number; // Real-time distance from start

  // NEW: Metabolism & Survival
  energy: number;          // 0 to 100
  maxEnergy: number;       
  hungerTime: number;      // Time since last meal (drives exponential decay)
  isAlive: boolean;
  foodEaten: number;
  visibleFood: FoodItem[]; // Each creature has its own reality/food track

  // OPTIMIZATION: Cached reference
  headNode?: Node;
}

export interface SimulationConfig {
  gravity: number;
  friction: number;
  groundDamping: number;
  timeStep: number;
  // NEW: Structural Integrity
  shapeMemoryStrength: number;

  // NEW: Real-time Physics Tweaks
  globalStiffness: number;     // Multiplier for bone rigidity (0.1 to 2.0)
  globalContractility: number; // Multiplier for muscle power (0.0 to 2.0)
}

// --- ARCHITECT TYPES ---
export type GridCoord = { x: number; y: number; z: number };

export interface Blueprint {
    cells: Map<string, boolean>; // Key "x,y,z"
    type: ShapeType;
}

import { Organism, ShapeType, Node, Muscle, NeuralGenome } from './types';
import { VectorOps } from './math';
import { GeneticOperator } from './genetics/GeneticOperator';

export class ShapeFactory {

  static create(type: ShapeType, id: string): Organism {
    let nodes: Node[] = [];
    let muscles: Muscle[] = [];

    switch (type) {
      case ShapeType.CUBE:
        ({ nodes, muscles } = this.createCube());
        break;
      case ShapeType.WORM:
        ({ nodes, muscles } = this.createWorm(4));
        break;
      case ShapeType.TETRAHEDRON:
      default:
        ({ nodes, muscles } = this.createTetrahedron());
        break;
    }

    // Initialize Neural Genome
    const operator = new GeneticOperator();
    const genome = operator.createRandomGenome(muscles.length, nodes.length);

    muscles.forEach((m, i) => m.dnaIndex = i);

    // Identify Head (Furthest Forward, then Highest Up)
    let maxZ = -Infinity;
    nodes.forEach(n => { if (n.pos.z > maxZ) maxZ = n.pos.z; });

    let candidates: Node[] = [];
    nodes.forEach(n => {
        if (Math.abs(n.pos.z - maxZ) < 0.1) candidates.push(n);
    });

    let headNode: Node | undefined = undefined;
    let maxY = -Infinity;
    candidates.forEach(n => {
        if (n.pos.y > maxY) {
            maxY = n.pos.y;
            headNode = n;
        }
    });

    if (headNode) {
        // @ts-ignore
        headNode.isHead = true;
    }

    const initialHeadPos = headNode ? { ...headNode.pos } : { x: 0, y: 0, z: 0 };

    return {
      id,
      shape: type, // Store shape type for editor consistency
      nodes,
      muscles,
      neuralGenome: genome,
      fitness: 0,
      generation: 1,
      // Metabolism Defaults
      energy: 100,
      maxEnergy: 100,
      hungerTime: 0,
      isAlive: true,
      foodEaten: 0,
      visibleFood: [],
      // Distance Metrics (Replaces Posture)
      initialHeadPos,
      distanceTraveled: 0,
      headNode // OPTIMIZATION
    };
  }

  // HELPER: Factory for optimized Node creation
  // Initializes all fields to ensure stable V8 Hidden Class
  private static createNode(id: string, x: number, y: number, z: number, mass: number, friction: number): Node {
      return {
          id,
          pos: { x, y, z },
          oldPos: { x, y, z },
          mass,
          friction,
          // Explicitly init optional fields to avoid de-opt
          isHead: false,
          isFixed: false,
          isGripping: false,
          gripSignal: 0,
          activation: 0,
          originalGridCoord: undefined
      };
  }

  private static createTetrahedron() {
    const f = 0.95; 
    const m = 4.0;  

    const nodes: Node[] = [
      this.createNode('n1', 0, 0, 1, m, f),
      this.createNode('n2', 1, 0, -0.7, m, f),
      this.createNode('n3', -1, 0, -0.7, m, f),
      this.createNode('n4', 0, 1.5, 0, m, f)
    ];
    const muscles = this.connectAll(nodes);
    return { nodes, muscles };
  }

  private static createCube() {
    const nodes: Node[] = [];
    const size = 1.0;
    const startY = 0.5;
    const f = 0.95; 
    const m = 4.0; 

    for(let x=0; x<=1; x++) {
      for(let y=0; y<=1; y++) {
        for(let z=0; z<=1; z++) {
          const px = (x - 0.5) * size;
          const py = startY + y * size;
          const pz = (z - 0.5) * size;
          nodes.push(this.createNode(`n${x}${y}${z}`, px, py, pz, m, f));
        }
      }
    }
    const muscles = this.connectDistanceThreshold(nodes, size * 1.8);
    return { nodes, muscles };
  }

  private static createWorm(segments: number) {
    const nodes: Node[] = [];
    const size = 1.0;
    const bellyFriction = 0.5; 
    const footFriction = 0.98; 
    const m = 4.0; 

    for (let i = 0; i < segments; i++) {
        const offset = i * size;
        nodes.push(
            this.createNode(`n${i}_a`, -0.5, 0, offset, m, footFriction),
            this.createNode(`n${i}_b`, 0.5, 0, offset, m, footFriction),
            this.createNode(`n${i}_top`, 0, 1, offset + 0.5, m, bellyFriction)
        );
    }
    return { nodes, muscles: this.connectDistanceThreshold(nodes, size * 1.5) };
  }

  private static connectAll(nodes: Node[]): Muscle[] {
    const muscles: Muscle[] = [];
    let mCount = 0;
    for (let i = 0; i < nodes.length; i++) {
      for (let j = i + 1; j < nodes.length; j++) {
        const dist = VectorOps.distance(nodes[i].pos, nodes[j].pos);
        muscles.push({
          id: `m${mCount++}`,
          nodeA: nodes[i].id,
          nodeB: nodes[j].id,
          baseLength: dist,
          stiffness: 1.0, 
          dnaIndex: 0,
          phase: Math.random() * Math.PI * 2,
          freq: 1.0,
          amp: 0.0,
          // Explicit Init for Hidden Class optimization (Muscle)
          currentLength: dist,
          targetLength: dist,
          nodeRefA: undefined,
          nodeRefB: undefined
        });
      }
    }
    return muscles;
  }

    private static connectDistanceThreshold(nodes: Node[], threshold: number): Muscle[] {
      const muscles: Muscle[] = [];
      let mCount = 0;
      for (let i = 0; i < nodes.length; i++) {
        for (let j = i + 1; j < nodes.length; j++) {
          const dist = VectorOps.distance(nodes[i].pos, nodes[j].pos);
          if (dist <= threshold) {
            muscles.push({
              id: `m${mCount++}`,
              nodeA: nodes[i].id,
              nodeB: nodes[j].id,
              baseLength: dist,
              stiffness: 1.0,
              dnaIndex: 0,
              phase: Math.random() * Math.PI * 2,
              freq: 1.0,
              amp: 0.0,
              currentLength: dist,
              targetLength: dist,
              nodeRefA: undefined,
              nodeRefB: undefined
            });
          }
        }
      }
      return muscles;
    }
}

import { Organism, Node } from '../types';
import { NeuralNode } from './NeuralNode';
import { CentralPatternGenerator } from './CentralPatternGenerator';
import { VectorOps } from '../math';

// Optimization Structure
interface Synapse {
    nodeA: NeuralNode;
    nodeB: NeuralNode;
    weightIndex: number;
}

export class BrainController {
  private neuralNodes: Map<string, NeuralNode> = new Map();
  private cpg: CentralPatternGenerator;
  private organism: Organism;
  private isInitialized = false;

  // OPTIMIZATION: Flattened array for O(1) iteration
  private synapses: Synapse[] = []; 
  // OPTIMIZATION: Typed Array for weight access (faster than standard number[])
  private synapseWeightsCache: Float32Array = new Float32Array(0);

  // Simulation Time Tracker
  private internalTime = 0;

  // Spinal Wave Props
  private muscleRestDistances: Float32Array; // Flattened distance cache

  // Decision Timer
  private decisionTimer = 0;
  private readonly DECISION_INTERVAL_BASE = 0.08; 

  // --- LEARNING MEMORY ---
  private previousEnergy: number = 0;
  private previousDistanceToFood: number = Infinity;
  private readonly VISION_RADIUS = 4.0;
  private readonly HEBBIAN_RATE = 0.15; // Learning Rate

  constructor(organism: Organism) {
    this.organism = organism;
    this.cpg = new CentralPatternGenerator(20);
    this.previousEnergy = organism.energy;

    // Initialize Neural Nodes
    organism.nodes.forEach(node => {
      this.neuralNodes.set(node.id, new NeuralNode(node));
    });

    // Init Empty Cache
    this.muscleRestDistances = new Float32Array(organism.muscles.length);

    if (organism.neuralGenome) {
        this.cpg.initialize(organism.neuralGenome.reservoirWeights);
    }
  }

  private initializeNervousSystem() {
      if (this.organism.nodes.length === 0) return;

      // Identify Head (Use Cached)
      let headNode = this.organism.headNode;
      if (!headNode) {
          headNode = this.organism.nodes[0];
          // @ts-ignore
          headNode.isHead = true; 
      }

      // 1. Build Distance Cache
      this.organism.muscles.forEach((m, i) => {
          const nA = this.organism.nodes.find(n => n.id === m.nodeA);
          const nB = this.organism.nodes.find(n => n.id === m.nodeB);
          if (nA && nB) {
              const midX = (nA.pos.x + nB.pos.x) / 2;
              const midY = (nA.pos.y + nB.pos.y) / 2;
              const midZ = (nA.pos.z + nB.pos.z) / 2;

              const dist = VectorOps.distance(
                  headNode!.pos, 
                  { x: midX, y: midY, z: midZ }
              );
              this.muscleRestDistances[i] = dist;
          }
      });

      // 2. Build Synapse Cache (Optimization)
      // We pre-calculate connections so we don't query the Map every frame
      this.synapses = [];
      const weightCount = this.organism.neuralGenome?.synapseWeights.length || 1;

      // Convert standard array to Float32Array for the hot path
      this.synapseWeightsCache = new Float32Array(this.organism.neuralGenome.synapseWeights);

      this.organism.muscles.forEach((muscle, i) => {
          const nnA = this.neuralNodes.get(muscle.nodeA);
          const nnB = this.neuralNodes.get(muscle.nodeB);
          if (nnA && nnB) {
              this.synapses.push({
                  nodeA: nnA,
                  nodeB: nnB,
                  weightIndex: i % weightCount
              });
          }
      });

      // 3. Reset Muscle Oscillators
      this.organism.muscles.forEach(m => {
          m.targetLength = m.baseLength;
          m.phase = Math.random() * Math.PI * 2; 
          m.freq = 1.0; 
          m.amp = 0.0;
      });

      this.isInitialized = true;
  }

  public update(dt: number, powerScale: number = 1.0): void {
    const genome = this.organism.neuralGenome;
    if (!genome) return;

    const brainDt = dt * (genome.internalClockSpeed || 1.0);

    if (!this.isInitialized) {
        this.initializeNervousSystem();
    }

    this.internalTime += brainDt;
    this.decisionTimer += brainDt;

    if (this.decisionTimer >= this.DECISION_INTERVAL_BASE) {
        this.think(brainDt);
        this.learn();
        this.decisionTimer = 0;
    }

    // --- SPINAL WAVE (Motor Control) ---
    const WAVE_FREQ = genome.waveFreq || 1.5; 
    const WAVE_SPEED = genome.waveSpeed || 1.0; 
    const FORCED_AMP = 0.15; 
    const MAX_DEFORMATION = 0.3; 
    const PI2 = Math.PI * 2;

    // Use loop index for cache access
    for(let i=0; i<this.organism.muscles.length; i++) {
        const m = this.organism.muscles[i];

        m.phase += m.freq * brainDt * PI2;
        if (m.phase > PI2) m.phase -= PI2;
        const brainSignal = Math.sin(m.phase) * m.amp;

        const dist = this.muscleRestDistances[i]; // Direct array access
        const nerveLag = dist * WAVE_SPEED;
        const spinalSignal = Math.sin(this.internalTime * WAVE_FREQ * PI2 - nerveLag) * FORCED_AMP;

        let totalSignal = (spinalSignal + brainSignal) * powerScale;

        // Clamp
        if (totalSignal > MAX_DEFORMATION) totalSignal = MAX_DEFORMATION;
        if (totalSignal < -MAX_DEFORMATION) totalSignal = -MAX_DEFORMATION;

        const desiredLength = m.baseLength * (1 + totalSignal);

        // Inertia
        m.targetLength = m.targetLength || m.baseLength;
        m.targetLength += (desiredLength - m.targetLength) * 0.05;
        m.currentLength = m.targetLength;
    }
  }

  private think(dt: number): void {
    const genome = this.organism.neuralGenome;

    // 1. GATHER PROPRIOCEPTION
    let globalSensoryInput = 0;
    for (const nn of this.neuralNodes.values()) {
        nn.sense(dt);
        globalSensoryInput += nn.inputSum;
    }

    // 2. VISION WITH GATED ATTENTION
    // OPTIMIZATION: Use cached head reference
    const head = this.organism.headNode;
    if (head) {
        // Optimized Vision Logic ...
        const stability = Math.min(1.0, Math.max(0, (head.pos.y - 0.2))); 
        let nearestDistSq = Infinity;
        let tX=0, tY=0, tZ=0;
        let foundFood = false;

        const vRadSq = this.VISION_RADIUS * this.VISION_RADIUS;

        for (const food of this.organism.visibleFood) {
            if (food.consumed) continue;

            const dx = food.pos.x - head.pos.x;
            const dy = food.pos.y - head.pos.y;
            const dz = food.pos.z - head.pos.z;
            const distSq = dx*dx + dy*dy + dz*dz;

            if (distSq < vRadSq) {
                if (distSq < nearestDistSq) {
                    nearestDistSq = distSq;
                    tX = dx; tY = dy; tZ = dz;
                    foundFood = true;
                }
            }
        }

        this.previousDistanceToFood = foundFood ? Math.sqrt(nearestDistSq) : Infinity;

        if (foundFood && stability > 0.1) {
            const dist = Math.sqrt(nearestDistSq);
            const headNeural = this.neuralNodes.get(head.id);
            if (headNeural) {
                const signalStrength = Math.max(0, 1.0 - (dist / this.VISION_RADIUS)) * stability;
                headNeural.inputSum += (tX / dist) * signalStrength * 3.0; 
                headNeural.inputSum += (tY / dist) * signalStrength * 3.0; 
                headNeural.inputSum += (tZ / dist) * signalStrength * 3.0; 
                globalSensoryInput += signalStrength * 2.0;
            }
        }
    }

    globalSensoryInput /= (this.neuralNodes.size || 1);

    // 3. SYNAPTIC PROPAGATION (OPTIMIZED)
    // We iterate the pre-compiled array and use the TypedArray cache
    for(let i=0; i<this.synapses.length; i++) {
        const s = this.synapses[i];
        // Read from Float32Array cache instead of the genome object's standard array
        const w = this.synapseWeightsCache[s.weightIndex]; 
        s.nodeB.inputSum += s.nodeA.activation * w;
        s.nodeA.inputSum += s.nodeB.activation * w;
    }

    for (const nn of this.neuralNodes.values()) {
        nn.updateActivation();
    }

    // 4. RESERVOIR COMPUTING
    this.cpg.tick(globalSensoryInput);

    // 5. MOTOR OUTPUT
    const mus = this.organism.muscles;
    const len = mus.length;
    for(let i=0; i<len; i++) {
        const muscle = mus[i];
        const rawAmp = this.cpg.getSignal(i, genome.outputWeights); 
        const rawFreq = this.cpg.getSignal(i + 1, genome.outputWeights); 

        const targetAmp = Math.abs(rawAmp) * 0.3; 
        const targetFreq = 0.5 + ((rawFreq + 1) / 2) * 2.5; // range 0.5 to 3.0

        muscle.amp += (targetAmp - muscle.amp) * 0.1;
        muscle.freq += (targetFreq - muscle.freq) * 0.1;
    }

    // 6. SUCTION OUTPUT
    if (genome.gripWeights && genome.gripWeights.length > 0) {
        const nodes = this.organism.nodes;
        for(let i=0; i<nodes.length; i++) {
            const rawSignal = this.cpg.getSignal(i, genome.gripWeights);
            const normalized = (rawSignal + 1) / 2;
            const node = nodes[i];
            const oldGrip = node.gripSignal || 0;
            node.gripSignal = oldGrip + (normalized - oldGrip) * 0.2;
        }
    }
  }

  private learn(): void {
      // NOTE: We do NOT write back to Float32Array here yet.
      // We write to the master genome (number[]), then sync the cache if needed.
      // Or we write to both. Writing to simple array is fast enough for sparse learning updates.
      const genome = this.organism.neuralGenome;
      let learningSignal = 0;

      // 1. METABOLIC REWARD
      const currentEnergy = this.organism.energy;
      const energyDelta = currentEnergy - this.previousEnergy;
      if (energyDelta > 0.5) learningSignal += 1.0;
      this.previousEnergy = currentEnergy;

      // 2. VESTIBULAR PAIN
      const head = this.organism.headNode;
      if (head && head.pos.y < 0.2) {
          learningSignal -= 0.5; 
      }

      // APPLY LEARNING (OPTIMIZED)
      if (Math.abs(learningSignal) > 0.1) {
          for(let i=0; i<this.synapses.length; i++) {
              const s = this.synapses[i];
              const coActivity = s.nodeA.activation * s.nodeB.activation;

              if (coActivity > 0.1) {
                  let w = this.synapseWeightsCache[s.weightIndex]; // Read from cache
                  w += this.HEBBIAN_RATE * learningSignal * coActivity;

                  // Clamp
                  if (w > 3.0) w = 3.0;
                  else if (w < -3.0) w = -3.0;

                  // Write to both for consistency
                  this.synapseWeightsCache[s.weightIndex] = w;
                  genome.synapseWeights[s.weightIndex] = w;
              }
          }
      }
  }
}

import { BioPhysicsEngine } from '../domain/BioPhysicsEngine';
import { Organism, ShapeType, NeuralGenome, FoodItem, Node, Muscle } from '../domain/types';
import { ShapeFactory } from '../domain/ShapeFactory';
import { VectorOps } from '../domain/math';
import { GeneticOperator } from '../domain/genetics/GeneticOperator';
import { IFitnessEvaluator, StandardFitnessEvaluator } from '../domain/fitness/FitnessEvaluator';
import { BrainController } from '../domain/neural/BrainController';

export class EvolutionService {
  public population: Organism[] = [];
  public currentGeneration = 1;
  public simulationTime = 0;

  private engine: BioPhysicsEngine;
  private geneticOperator: GeneticOperator;
  private fitnessEvaluator: IFitnessEvaluator;

  private populationSize = 20;
  private template: Organism | null = null; 

  private readonly START_ENERGY = 100;
  private readonly BASE_DECAY = 4.0; 
  private readonly HUNGER_ACCEL = 1.15; 
  private readonly FOOD_ENERGY = 30;

  public readonly MAGNET_RADIUS = 1.5; 
  private readonly MAGNET_FORCE = 0.8;  
  private readonly EAT_RADIUS = 0.8;    

  public foodSpawnCount = 50;
  public foodSpawnRadius = 3.5;

  private updateListeners: ((pop: Organism[], time: number) => void)[] = [];
  private genCompleteListeners: ((best: Organism, gen: number) => void)[] = [];
  private newGenListeners: ((pop: Organism[]) => void)[] = [];

  constructor() {
    this.engine = new BioPhysicsEngine();
    this.geneticOperator = new GeneticOperator(0.05); // 5% mutation rate
    this.fitnessEvaluator = new StandardFitnessEvaluator();
  }

  public setGlobalStiffness(val: number) {
      this.engine.setConfig({ globalStiffness: val });
  }

  public setGlobalContractility(val: number) {
      this.engine.setConfig({ globalContractility: val });
  }

  public set foodWeight(val: number) {
      this.fitnessEvaluator.setWeights(val, (this.fitnessEvaluator as any).distanceWeight);
  }
  public get foodWeight(): number { return (this.fitnessEvaluator as any).foodWeight; }

  public set distanceWeight(val: number) {
       this.fitnessEvaluator.setWeights((this.fitnessEvaluator as any).foodWeight, val);
  }
  public get distanceWeight(): number { return (this.fitnessEvaluator as any).distanceWeight; }

  public updateFoodDistribution(): void {
      this.population.forEach(org => {
          org.visibleFood = this.generateFoodTrack(org);
      });
  }

  public initializePopulation(shape: ShapeType): void {
    this.template = ShapeFactory.create(shape, 'template');
    this.spawnGenerationFromTemplate(true);
  }

  public setTemplateAndReset(organism: Organism, startGeneration: number = 1): void {
      // Deep copy for the master template to ensure it's clean
      const safeJson = JSON.stringify(organism, (key, value) => {
          if (key === 'brain') return undefined;
          if (key === 'nodeRefA' || key === 'nodeRefB') return undefined;
          if (key === 'headNode') return undefined; // Avoid circular ref or re-finding
          return value;
      });
      this.template = JSON.parse(safeJson);

      // Re-bind headNode if missing from JSON
      if (!this.template!.headNode) {
          this.template!.headNode = this.template!.nodes.find(n => n.isHead);
      }

      this.currentGeneration = startGeneration;
      this.spawnGenerationFromTemplate(false); 
  }

  private spawnGenerationFromTemplate(resetGen: boolean): void {
      if (!this.template) return;

      this.population = [];
      if (resetGen) this.currentGeneration = 1;
      this.simulationTime = 0;

      for (let i = 0; i < this.populationSize; i++) {
          const child = this.createOrganismFromTemplate(this.template, `gen${this.currentGeneration}_${i}`);

          if (i > 0) {
              this.geneticOperator.mutateGenome(child.neuralGenome);
          }

          child.visibleFood = this.generateFoodTrack(child);
          this.fitnessEvaluator.evaluate(child, 0.016);

          this.population.push(child);
      }

      this.notifyNewGeneration(this.population);
  }

  private generateFoodTrack(organism: Organism): FoodItem[] {
      const food: FoodItem[] = [];
      const numFood = this.foodSpawnCount; 

      let centerX = 0;
      let centerZ = 0;

      // OPTIMIZATION: Use cached headNode
      const head = organism.headNode;

      if (head) {
          centerX = head.pos.x;
          centerZ = head.pos.z;
      }

      const spread = this.foodSpawnRadius; 

      for(let i=0; i<numFood; i++) {
          const theta = Math.random() * Math.PI * 2;
          const radius = 1.0 + Math.random() * spread; 
          const x = centerX + Math.cos(theta) * radius;
          const z = centerZ + Math.sin(theta) * radius;
          const y = 1.0 + Math.random() * 2.5;

          food.push({
              id: `f_${i}`,
              pos: { x, y, z },
              energyValue: this.FOOD_ENERGY,
              consumed: false
          });
      }
      return food;
  }

  public getBestOrganism(): Organism | null {
      if (this.population.length === 0) return null;
      const sorted = [...this.population].sort((a, b) => b.fitness - a.fitness);
      const best = sorted[0];

      const safeJson = JSON.stringify(best, (key, value) => {
          if (key === 'brain') return undefined;
          if (key === 'nodeRefA' || key === 'nodeRefB') return undefined;
          if (key === 'headNode') return undefined;
          return value;
      });
      const cleanCopy = JSON.parse(safeJson);
      cleanCopy.generation = this.currentGeneration;

      return cleanCopy;
  }

  public getLeader(): Organism | null {
      if (this.population.length === 0) return null;

      let bestAlive: Organism | null = null;
      let maxZAlive = -Infinity;

      let bestDead: Organism | null = null;
      let maxZDead = -Infinity;

      for (const org of this.population) {
          let cz = 0;
          for(const n of org.nodes) cz += n.pos.z;
          cz /= org.nodes.length;

          if (org.isAlive) {
              if (cz > maxZAlive) { maxZAlive = cz; bestAlive = org; }
          } else {
              if (cz > maxZDead) { maxZDead = cz; bestDead = org; }
          }
      }

      return bestAlive || bestDead || this.population[0];
  }

  public step(dt: number): void {
    this.simulationTime += dt;
    this.updatePhysics(dt, false);
    this.updateMetabolism(dt);

    if (Math.floor(this.simulationTime * 100) % 100 === 0) {
        this.applySocialLearning();
    }

    const allDead = !this.population.some(org => org.isAlive);
    if (allDead) {
        this.evolve();
    }

    this.notifyUpdate(this.population, this.simulationTime);
  }

  private applySocialLearning() {
      const sorted = [...this.population].sort((a, b) => b.fitness - a.fitness);
      if (sorted.length < 2) return;

      const leader = sorted[0];
      const bottomHalfStart = Math.floor(sorted.length / 2);

      for(let i=bottomHalfStart; i<sorted.length; i++) {
          const learner = sorted[i];
          if (!learner.isAlive) continue;

          const learningRate = 0.05; 
          const lg = learner.neuralGenome;
          const bg = leader.neuralGenome;

          for(let k=0; k<lg.synapseWeights.length; k++) {
              if (bg.synapseWeights[k] !== undefined) {
                  lg.synapseWeights[k] += (bg.synapseWeights[k] - lg.synapseWeights[k]) * learningRate;
              }
          }
      }
  }

  public async computeGenerationAsync(
    maxSafetyTime: number, 
    shouldStop: () => boolean, 
    onProgress?: (pct: number) => void
  ): Promise<void> {
      const dt = 0.016; 
      const BATCH_DURATION = 0.012; 
      let allDead = false;

      while (!allDead && this.simulationTime < maxSafetyTime) {
          if (shouldStop()) throw new Error("Evolution Aborted");

          let batchTime = 0;
          while (batchTime < BATCH_DURATION && !allDead && this.simulationTime < maxSafetyTime) {
              this.simulationTime += dt;
              batchTime += dt; 

              this.updatePhysics(dt, true);
              this.updateMetabolism(dt); 

              if (Math.abs(this.simulationTime % 1.0) < dt) {
                  this.applySocialLearning();
              }

              allDead = !this.population.some(org => org.isAlive);
          }

          const deadCount = this.population.filter(o => !o.isAlive).length;
          const pct = deadCount / this.populationSize;

          if (onProgress) onProgress(pct);
          await new Promise(resolve => setTimeout(resolve, 0));
      }

      this.finalizeFitness();
  }

  private updatePhysics(dt: number, fastMode: boolean): void {
    this.population.forEach(org => {
      // ORCHESTRATION: Update Brain THEN Physics
      if (org.isAlive) {
         if (!org.brain) {
             org.brain = new BrainController(org);
         }
         const contractility = (this.engine as any).config.globalContractility;
         org.brain.update(dt, contractility);
      }

      this.engine.updateOrganism(org, this.simulationTime, fastMode);
    });
  }

  private updateMetabolism(dt: number): void {
      this.population.forEach(org => {
          // 1. Calculate Fitness
          this.fitnessEvaluator.evaluate(org, dt);

          if (!org.isAlive) return;

          org.hungerTime += dt;
          const hungerMultiplier = Math.pow(this.HUNGER_ACCEL, org.hungerTime);
          const loss = this.BASE_DECAY * hungerMultiplier * dt;
          org.energy -= loss;

          if (org.energy <= 0) {
              org.energy = 0;
              org.isAlive = false;
              return; 
          }

          // OPTIMIZATION: Use Cached Head
          let head = org.headNode;

          // Self-heal just in case
          if (!head && org.nodes.length > 0) {
              head = org.nodes.find(n => n.isHead);
              if (!head) head = org.nodes[0];
              org.headNode = head;
          }

          if (head) {
            for (const food of org.visibleFood) {
                if (food.consumed) continue;

                // INLINED MATH (Optimized)
                // Avoid VectorOps.distance and VectorOps.sub object creation
                const dx = head.pos.x - food.pos.x;
                const dy = head.pos.y - food.pos.y;
                const dz = head.pos.z - food.pos.z;
                const distSq = dx*dx + dy*dy + dz*dz;

                // Fast reject check (Squared)
                if (distSq < this.MAGNET_RADIUS * this.MAGNET_RADIUS) {
                    const dist = Math.sqrt(distSq);

                    // Pull Force
                    const strength = 1.0 - (dist / this.MAGNET_RADIUS);
                    const force = this.MAGNET_FORCE * (1.0 + strength);

                    // Apply directly (Pull vector is -diff vector)
                    // pull = head - food. so dx = head.x - food.x
                    food.pos.x += dx * force * 0.1;
                    food.pos.y += dy * force * 0.1;
                    food.pos.z += dz * force * 0.1;

                    // Recheck Distance (Cheap approximation: assume it moved closer)
                    // But to be exact for eating:
                    const ndx = head.pos.x - food.pos.x;
                    const ndy = head.pos.y - food.pos.y;
                    const ndz = head.pos.z - food.pos.z;
                    const nDistSq = ndx*ndx + ndy*ndy + ndz*ndz;

                    if (nDistSq < this.EAT_RADIUS * this.EAT_RADIUS) {
                        food.consumed = true;
                        org.energy += food.energyValue;
                        if (org.energy > org.maxEnergy) org.energy = org.maxEnergy;
                        org.hungerTime = 0;
                        org.foodEaten++;
                    }
                }
            }
          }
      });
  }

  private finalizeFitness() {
      this.population.forEach(org => this.fitnessEvaluator.finalize(org));
  }

  public evolve(): void {
    if (!this.template) return;

    this.finalizeFitness(); 

    // 1. Selection
    this.population.sort((a, b) => b.fitness - a.fitness);
    const survivorsCount = Math.floor(this.populationSize * 0.25);
    const survivors = this.population.slice(0, survivorsCount);
    const bestOrganism = survivors[0];

    this.notifyGenComplete(bestOrganism, this.currentGeneration);

    // 2. Reproduction
    this.currentGeneration++;
    const nextGen: Organism[] = [];

    // Elitism
    const champion = this.createOrganismFromTemplate(this.template, `gen${this.currentGeneration}_champ`);
    champion.neuralGenome = this.geneticOperator.cloneGenome(bestOrganism.neuralGenome);
    champion.visibleFood = this.generateFoodTrack(champion);
    this.fitnessEvaluator.evaluate(champion, 0.016);
    nextGen.push(champion);

    // Fill
    while (nextGen.length < this.populationSize) {
      const parent = survivors[Math.floor(Math.random() * survivors.length)];
      const child = this.createOrganismFromTemplate(this.template, `gen${this.currentGeneration}_${nextGen.length}`);
      child.neuralGenome = this.geneticOperator.cloneGenome(parent.neuralGenome);
      this.geneticOperator.mutateGenome(child.neuralGenome);
      child.visibleFood = this.generateFoodTrack(child);
      this.fitnessEvaluator.evaluate(child, 0.016);
      nextGen.push(child);
    }

    this.population = nextGen;
    this.simulationTime = 0;

    this.notifyNewGeneration(this.population);
  }

  private createOrganismFromTemplate(template: Organism, newId: string): Organism {
      // 1. Clone Nodes
      const newNodes: Node[] = template.nodes.map(n => ({
          ...n,
          pos: { ...n.pos },
          oldPos: { ...n.pos }, 
          activation: 0,
          gripSignal: 0,
          isGripping: false
      }));

      // 2. Clone Muscles
      const newMuscles: Muscle[] = template.muscles.map(m => ({
          ...m,
          currentLength: undefined,
          targetLength: undefined,
          phase: Math.random() * Math.PI * 2,
          nodeRefA: undefined,
          nodeRefB: undefined
      }));

      // 3. Clone Genome 
      const newGenome = this.geneticOperator.cloneGenome(template.neuralGenome);

      // 4. Construct
      const clone: Organism = {
          id: newId,
          shape: template.shape,
          nodes: newNodes,
          muscles: newMuscles,
          neuralGenome: newGenome,
          fitness: 0,
          generation: 1,
          brain: undefined,

          energy: this.START_ENERGY,
          maxEnergy: this.START_ENERGY,
          hungerTime: 0,
          isAlive: true,
          foodEaten: 0,
          visibleFood: [],

          // Distance Stats
          initialHeadPos: template.initialHeadPos ? { ...template.initialHeadPos } : {x:0,y:0,z:0},
          distanceTraveled: 0
      };

      // Safety check for starting pos if template was malformed
      if (!clone.initialHeadPos) {
           const head = clone.nodes.find(n => n.isHead);
           clone.initialHeadPos = head ? { ...head.pos } : { x: 0, y: 0, z: 0 };
      }

      // OPTIMIZATION: Cache Head
      const head = clone.nodes.find(n => n.isHead);
      if (head) clone.headNode = head;

      return clone;
  }

  public subscribe(type: 'update', cb: (pop: Organism[], time: number) => void): () => void;
  public subscribe(type: 'genComplete', cb: (best: Organism, gen: number) => void): () => void;
  public subscribe(type: 'newGen', cb: (pop: Organism[]) => void): () => void;
  public subscribe(type: string, cb: any): () => void {
      if (type === 'update') {
          this.updateListeners.push(cb);
          return () => this.updateListeners = this.updateListeners.filter(l => l !== cb);
      }
      if (type === 'genComplete') {
          this.genCompleteListeners.push(cb);
          return () => this.genCompleteListeners = this.genCompleteListeners.filter(l => l !== cb);
      }
      if (type === 'newGen') {
          this.newGenListeners.push(cb);
          return () => this.newGenListeners = this.newGenListeners.filter(l => l !== cb);
      }
      return () => {};
  }

  public onUpdate(cb: (pop: Organism[], time: number) => void) { this.subscribe('update', cb); }
  public onGenComplete(cb: (best: Organism, gen: number) => void) { this.subscribe('genComplete', cb); }
  public onNewGeneration(cb: (pop: Organism[]) => void) { this.subscribe('newGen', cb); }

  private notifyUpdate(pop: Organism[], time: number) { this.updateListeners.forEach(l => l(pop, time)); }
  private notifyGenComplete(best: Organism, gen: number) { this.genCompleteListeners.forEach(l => l(best, gen)); }
  private notifyNewGeneration(pop: Organism[]) { this.newGenListeners.forEach(l => l(pop)); }
}

import React, { useRef, useMemo, MutableRefObject, useEffect } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { Organism, Node, Muscle } from '../../domain/types';

interface CreatureViewProps {
  organism: Organism;
  leaderRef: MutableRefObject<Organism | null>;
  showBestOnly: boolean;
}

// CACHED OBJECTS
const _tempObj = new THREE.Object3D();
const _color = new THREE.Color();
const _vecA = new THREE.Vector3();
const _vecB = new THREE.Vector3();
const _mid = new THREE.Vector3();

// COLORS
const COL_RED = new THREE.Color(0xff3333);
const COL_BLUE = new THREE.Color(0x3333ff);
const COL_WHITE = new THREE.Color(0xffffff);
const COL_YELLOW = new THREE.Color(0xffff00);
const COL_HEAD = new THREE.Color(0x1a1a1a);
const COL_DEAD = new THREE.Color(0x52525b);
const COL_GRIP = new THREE.Color(0x22c55e);

export const CreatureView: React.FC<CreatureViewProps> = ({ organism, leaderRef, showBestOnly }) => {
  const groupRef = useRef<THREE.Group>(null);

  // Instanced Meshes
  const nodesMeshRef = useRef<THREE.InstancedMesh>(null);
  const musclesMeshRef = useRef<THREE.InstancedMesh>(null);

  // Singular items (Head indicators)
  const visionRef = useRef<THREE.Mesh>(null);
  const magnetRef = useRef<THREE.Mesh>(null);

  // Geometries
  const nodeGeo = useMemo(() => new THREE.SphereGeometry(0.08, 6, 6), []); // Low Poly
  const muscleGeo = useMemo(() => new THREE.CylinderGeometry(0.03, 0.03, 1, 4), []); // Low Poly, Height=1 for easy scaling
  const visionGeo = useMemo(() => new THREE.SphereGeometry(1, 16, 16), []); 
  const magnetGeo = useMemo(() => new THREE.RingGeometry(1.45, 1.5, 32), []);

  // Materials
  const nodeMat = useMemo(() => new THREE.MeshStandardMaterial({ color: 0xffffff, roughness: 0.5 }), []);
  const muscleMat = useMemo(() => new THREE.MeshStandardMaterial({ color: 0xffffff, roughness: 0.5 }), []);
  const visionMat = useMemo(() => new THREE.MeshBasicMaterial({ 
      color: 0x00ffff, transparent: true, opacity: 0.05, wireframe: true 
  }), []);
  const magnetMat = useMemo(() => new THREE.MeshBasicMaterial({
      color: 0xffff00, transparent: true, opacity: 0.3, side: THREE.DoubleSide
  }), []);

  // Set initial counts
  useEffect(() => {
      if (nodesMeshRef.current) nodesMeshRef.current.count = organism.nodes.length;
      if (musclesMeshRef.current) musclesMeshRef.current.count = organism.muscles.length;
  }, [organism.nodes.length, organism.muscles.length]);

  // Optimization: Pre-map node IDs to indices for fast lookup during muscle update
  const nodeIndexMap = useMemo(() => {
      const map = new Map<string, number>();
      organism.nodes.forEach((n, i) => map.set(n.id, i));
      return map;
  }, [organism.nodes]);


  useFrame((state) => {
    if (!groupRef.current) return;

    // Visibility Check
    if (showBestOnly) {
        const isLeader = leaderRef.current?.id === organism.id;
        groupRef.current.visible = isLeader;
    } else {
        groupRef.current.visible = true;
    }

    if (!groupRef.current.visible) return;

    let headPos: THREE.Vector3 | null = null;
    const isAlive = organism.isAlive;

    // --- UPDATE NODES ---
    if (nodesMeshRef.current) {
        for (let i = 0; i < organism.nodes.length; i++) {
            const node = organism.nodes[i];

            // Transform
            _tempObj.position.set(node.pos.x, node.pos.y, node.pos.z);
            _tempObj.scale.setScalar(1);
            _tempObj.rotation.set(0,0,0);
            _tempObj.updateMatrix();
            nodesMeshRef.current.setMatrixAt(i, _tempObj.matrix);

            // Color
            if (!isAlive) {
                nodesMeshRef.current.setColorAt(i, COL_DEAD);
            } else if (node.isHead) {
                headPos = _tempObj.position; // Capture for singulars
                nodesMeshRef.current.setColorAt(i, COL_HEAD);
            } else {
                if (node.isGripping) {
                    nodesMeshRef.current.setColorAt(i, COL_GRIP);
                } else {
                    const act = node.activation || 0;
                    _color.copy(COL_WHITE).lerp(COL_YELLOW, act);
                    nodesMeshRef.current.setColorAt(i, _color);
                }
            }
        }
        nodesMeshRef.current.instanceMatrix.needsUpdate = true;
        if (nodesMeshRef.current.instanceColor) nodesMeshRef.current.instanceColor.needsUpdate = true;
    }

    // --- UPDATE MUSCLES ---
    if (musclesMeshRef.current) {
        for (let i = 0; i < organism.muscles.length; i++) {
            const m = organism.muscles[i];
            // Lookup indices
            // We use direct array access if possible, but map is safer for partial updates
            const idxA = nodeIndexMap.get(m.nodeA);
            const idxB = nodeIndexMap.get(m.nodeB);

            if (idxA !== undefined && idxB !== undefined) {
                const nA = organism.nodes[idxA];
                const nB = organism.nodes[idxB];

                _vecA.set(nA.pos.x, nA.pos.y, nA.pos.z);
                _vecB.set(nB.pos.x, nB.pos.y, nB.pos.z);

                // Math to orient cylinder
                _mid.copy(_vecA).add(_vecB).multiplyScalar(0.5);
                const len = _vecA.distanceTo(_vecB);

                _tempObj.position.copy(_mid);
                _tempObj.lookAt(_vecB);
                _tempObj.rotateX(Math.PI / 2); // Align cylinder Y-axis to LookAt Z-axis
                _tempObj.scale.set(1, len, 1);
                _tempObj.updateMatrix();

                musclesMeshRef.current.setMatrixAt(i, _tempObj.matrix);

                // Color
                if (!isAlive) {
                    musclesMeshRef.current.setColorAt(i, COL_DEAD);
                } else {
                    const target = m.targetLength || m.baseLength;
                    const ratio = target / m.baseLength;
                    if (ratio < 0.98) {
                        _color.copy(COL_WHITE).lerp(COL_RED, Math.min(1, (1 - ratio) * 5));
                    } else if (ratio > 1.02) {
                        _color.copy(COL_WHITE).lerp(COL_BLUE, Math.min(1, (ratio - 1) * 5));
                    } else {
                        _color.copy(COL_WHITE);
                    }
                    musclesMeshRef.current.setColorAt(i, _color);
                }
            }
        }
        musclesMeshRef.current.instanceMatrix.needsUpdate = true;
        if (musclesMeshRef.current.instanceColor) musclesMeshRef.current.instanceColor.needsUpdate = true;
    }

    // --- UPDATE SINGULAR MESHES ---
    if (headPos && isAlive) {
        if (visionRef.current) {
            visionRef.current.position.copy(headPos);
            const pulse = 4.0 + Math.sin(state.clock.elapsedTime * 4) * 0.2; 
            visionRef.current.scale.setScalar(pulse);
            visionRef.current.visible = true;
        }
        if (magnetRef.current) {
            magnetRef.current.position.copy(headPos);
            magnetRef.current.rotation.x = -Math.PI / 2;
            magnetRef.current.visible = true;
        }
    } else {
        if (visionRef.current) visionRef.current.visible = false;
        if (magnetRef.current) magnetRef.current.visible = false;
    }
  });

  return (
    <group ref={groupRef}>
      <mesh ref={visionRef} geometry={visionGeo} material={visionMat} />
      <mesh ref={magnetRef} geometry={magnetGeo} material={magnetMat} />

      {/* INSTANCED NODES */}
      <instancedMesh 
        ref={nodesMeshRef} 
        args={[nodeGeo, nodeMat, organism.nodes.length]}
        frustumCulled={false}
      />

      {/* INSTANCED MUSCLES */}
      <instancedMesh 
        ref={musclesMeshRef} 
        args={[muscleGeo, muscleMat, organism.muscles.length]}
        frustumCulled={false}
      />
    </group>
  );
};

import { Node, Muscle, Organism, SimulationConfig } from './types';
import { BrainController } from './neural/BrainController';

export class BioPhysicsEngine {
  private config: SimulationConfig;
  private readonly MAX_VELOCITY = 12.0; 

  // SOLVER SETTINGS
  private readonly RELAXATION_FACTOR = 0.25; 
  private readonly ITERATIONS = 6; 

  // DAMPING SETTINGS
  private readonly BASE_MUSCLE_DAMPING = 0.08; 
  private readonly ADAPTIVE_DAMPING_FACTOR = 0.12; 
  private readonly ROTATIONAL_DRAG = 0.92; 

  // AIR RESISTANCE
  private readonly DRAG_COEFFICIENT = 0.08; 

  // --- SOLIDITY CONSTANTS ---
  private readonly NODE_RADIUS = 0.1; 
  private readonly HARD_CONTACT_LIMIT = 0.22; 

  constructor(config: Partial<SimulationConfig> = {}) {
    this.config = {
      gravity: -60.0, 
      friction: 0.98, // Global air friction
      groundDamping: 0.8, 
      timeStep: 0.016,
      shapeMemoryStrength: 0.85, 
      globalStiffness: 0.8, 
      globalContractility: 1.5, 
      ...config
    };
  }

  public setConfig(config: Partial<SimulationConfig>) {
      this.config = { ...this.config, ...config };
  }

  // fastMode: If true, runs lower fidelity physics for rapid evolutionary calculation
  public updateOrganism(organism: Organism, totalTime: number, fastMode: boolean = false): void {

    // 1. PHYSICS INTEGRATION

    // Handle Ragdoll state
    if (!organism.isAlive) {
        organism.muscles.forEach(m => {
            m.stiffness = 0.05; // Very loose
            m.amp = 0; // Stop oscillating
            m.targetLength = m.baseLength;
        });
        // Release all grips if dead
        organism.nodes.forEach(n => {
            n.gripSignal = 1.0; 
            n.isGripping = false;
        });
    }

    // ADAPTIVE SUBSTEPS
    const subSteps = fastMode ? 4 : 12; 
    const subDt = this.config.timeStep / subSteps;
    const gravityVec = { x: 0, y: this.config.gravity * subDt * subDt, z: 0 };

    for(let s=0; s < subSteps; s++) {
        this.integrate(organism, subDt, gravityVec);
        if (!fastMode) this.applyRotationalDrag(organism); 

        // ITERATIVE SOLVER
        const loops = fastMode ? 4 : this.ITERATIONS;

        for (let i = 0; i < loops; i++) {
            this.resolveMuscles(organism);

            if (!fastMode) {
                this.resolveSelfCollisions(organism); 
            }
        }

        this.resolveFloor(organism);
    }
  }

  private applyRotationalDrag(organism: Organism): void {
      let cx = 0, cz = 0;
      let count = 0;
      for (const n of organism.nodes) {
          cx += n.pos.x;
          cz += n.pos.z;
          count++;
      }
      if (count === 0) return;
      cx /= count;
      cz /= count;

      let angularMomentum = 0;
      let momentOfInertia = 0;

      for (const n of organism.nodes) {
          const rx = n.pos.x - cx;
          const rz = n.pos.z - cz;

          const vx = n.pos.x - n.oldPos.x;
          const vz = n.pos.z - n.oldPos.z;

          const orbitalComponent = rx * vz - rz * vx;

          angularMomentum += orbitalComponent;
          momentOfInertia += rx * rx + rz * rz;
      }

      if (momentOfInertia < 0.001) return;

      const angularVel = angularMomentum / momentOfInertia;

      for (const n of organism.nodes) {
          const rx = n.pos.x - cx;
          const rz = n.pos.z - cz;

          const dampX = -angularVel * rz * this.ROTATIONAL_DRAG;
          const dampZ =  angularVel * rx * this.ROTATIONAL_DRAG;

          n.oldPos.x += dampX;
          n.oldPos.z += dampZ;
      }
  }

  private integrate(organism: Organism, dt: number, gravityVec: {x:number, y:number, z:number}): void {
    const { friction } = this.config;
    const maxStepDist = this.MAX_VELOCITY * dt;
    const maxStepSq = maxStepDist * maxStepDist;

    for (const node of organism.nodes) {
      if (node.isFixed) continue;

      let velX = node.pos.x - node.oldPos.x;
      let velY = node.pos.y - node.oldPos.y;
      let velZ = node.pos.z - node.oldPos.z;

      // 1. QUADRATIC DRAG
      const vSq = velX*velX + velY*velY + velZ*velZ;
      if (vSq > 0.000001) {
          const vLen = Math.sqrt(vSq);
          const dragFactor = 1.0 / (1.0 + this.DRAG_COEFFICIENT * vLen);

          velX *= dragFactor;
          velY *= dragFactor;
          velZ *= dragFactor;
      }

      // 2. Base Friction (Air)
      velX *= friction;
      velY *= friction;
      velZ *= friction;

      // 3. Hard Cap (Safety Terminator)
      const distSq = velX*velX + velY*velY + velZ*velZ;
      if (distSq > maxStepSq) {
          const scale = maxStepDist / Math.sqrt(distSq);
          velX *= scale;
          velY *= scale;
          velZ *= scale;
      }

      // GC OPTIMIZATION: Update oldPos in place instead of creating new object
      node.oldPos.x = node.pos.x;
      node.oldPos.y = node.pos.y;
      node.oldPos.z = node.pos.z;

      node.pos.x += velX + gravityVec.x;
      node.pos.y += velY + gravityVec.y;
      node.pos.z += velZ + gravityVec.z;
    }
  }

  private resolveMuscles(organism: Organism): void {
    const GROUND_TOLERANCE = 0.02;
    // AUTO-GRIP: Make feet extremely heavy relative to body so body moves instead of feet sliding
    const ANCHOR_MULTIPLIER = 0.05; 
    const MEMORY_STRENGTH = this.config.shapeMemoryStrength || 0.8;
    const GLOBAL_STIFFNESS = this.config.globalStiffness; 

    // CACHE REFERENCES (Lazy Load)
    if (!organism.muscles[0]?.nodeRefA) {
         const nodeMap = new Map<string, Node>();
         for (const n of organism.nodes) nodeMap.set(n.id, n);
         for (const m of organism.muscles) {
             m.nodeRefA = nodeMap.get(m.nodeA);
             m.nodeRefB = nodeMap.get(m.nodeB);
         }
    }

    for (const muscle of organism.muscles) {
        const n1 = muscle.nodeRefA;
        const n2 = muscle.nodeRefB;

        if (!n1 || !n2) continue;

        const dx = n2.pos.x - n1.pos.x;
        const dy = n2.pos.y - n1.pos.y;
        const dz = n2.pos.z - n1.pos.z;

        const distSq = dx*dx + dy*dy + dz*dz;
        if (distSq < 0.0000001) continue; 

        const dist = Math.sqrt(distSq);

        // 1. ACTIVE MUSCLE COMPONENT
        let activeTarget = muscle.targetLength || muscle.baseLength;
        if (activeTarget < this.HARD_CONTACT_LIMIT) activeTarget = this.HARD_CONTACT_LIMIT;

        let stiffness = muscle.stiffness * 0.8 * GLOBAL_STIFFNESS; 

        const activeDiff = dist - activeTarget;

        // 2. PASSIVE MEMORY COMPONENT
        const deviation = Math.abs(dist - muscle.baseLength);
        const strain = deviation / muscle.baseLength;
        const strainBoost = 1.0 + (strain * 4.0); 

        const currentMemoryStrength = organism.isAlive 
            ? MEMORY_STRENGTH * strainBoost * GLOBAL_STIFFNESS
            : MEMORY_STRENGTH * 0.1 * GLOBAL_STIFFNESS;

        const baseDiff = dist - muscle.baseLength;

        // --- DUAL FORCE BLENDING ---
        const activeCorrection = activeDiff * stiffness;
        const memoryCorrection = baseDiff * currentMemoryStrength;
        let totalCorrection = (activeCorrection + memoryCorrection) * this.RELAXATION_FACTOR;

        // --- DAMPING ---
        const vx1 = n1.pos.x - n1.oldPos.x;
        const vy1 = n1.pos.y - n1.oldPos.y;
        const vz1 = n1.pos.z - n1.oldPos.z;
        const vx2 = n2.pos.x - n2.oldPos.x;
        const vy2 = n2.pos.y - n2.oldPos.y;
        const vz2 = n2.pos.z - n2.oldPos.z;

        const rvx = vx2 - vx1;
        const rvy = vy2 - vy1;
        const rvz = vz2 - vz1;

        const nx = dx / dist;
        const ny = dy / dist;
        const nz = dz / dist;

        const relVel = Math.sqrt(rvx*rvx + rvy*rvy + rvz*rvz);
        const dynamicDamping = this.BASE_MUSCLE_DAMPING + (relVel * this.ADAPTIVE_DAMPING_FACTOR);
        const vRelProj = rvx * nx + rvy * ny + rvz * nz;

        totalCorrection += vRelProj * dynamicDamping;

        // --- MOMENTUM PRESERVATION ---
        let im1 = (n1.isFixed || n1.isGripping) ? 0 : 1 / n1.mass;
        let im2 = (n2.isFixed || n2.isGripping) ? 0 : 1 / n2.mass;

        if (n1.pos.y <= GROUND_TOLERANCE) im1 *= ANCHOR_MULTIPLIER;
        if (n2.pos.y <= GROUND_TOLERANCE) im2 *= ANCHOR_MULTIPLIER;

        const totalInvMass = im1 + im2;
        if (totalInvMass === 0) continue;

        const w1 = im1 / totalInvMass;
        const w2 = im2 / totalInvMass;

        const offsetX = nx * totalCorrection;
        const offsetY = ny * totalCorrection;
        const offsetZ = nz * totalCorrection;

        if (!n1.isFixed && !n1.isGripping) {
            n1.pos.x += offsetX * w1;
            n1.pos.y += offsetY * w1;
            n1.pos.z += offsetZ * w1;
        }

        if (!n2.isFixed && !n2.isGripping) {
            n2.pos.x -= offsetX * w2;
            n2.pos.y -= offsetY * w2;
            n2.pos.z -= offsetZ * w2;
        }
    }
  }

  private resolveSelfCollisions(organism: Organism): void {
      const nodes = organism.nodes;
      const count = nodes.length;
      const minDistance = this.HARD_CONTACT_LIMIT; 
      const minDistanceSq = minDistance * minDistance;

      for (let i = 0; i < count; i++) {
          for (let j = i + 1; j < count; j++) {
              const n1 = nodes[i];
              const n2 = nodes[j];

              const dx = n1.pos.x - n2.pos.x;
              const dy = n1.pos.y - n2.pos.y;
              const dz = n1.pos.z - n2.pos.z;
              const distSq = dx*dx + dy*dy + dz*dz;

              if (distSq < minDistanceSq && distSq > 0.000001) {
                  const dist = Math.sqrt(distSq);
                  const overlap = minDistance - dist;

                  const fx = (dx / dist) * overlap * 0.2;
                  const fy = (dy / dist) * overlap * 0.2;
                  const fz = (dz / dist) * overlap * 0.2;

                  if (!n1.isFixed) { n1.pos.x += fx; n1.pos.y += fy; n1.pos.z += fz; }
                  if (!n2.isFixed) { n2.pos.x -= fx; n2.pos.y -= fy; n2.pos.z -= fz; }
              }
          }
      }
  }

  private resolveFloor(organism: Organism): void {
    const RADIUS = this.NODE_RADIUS;

    for (const node of organism.nodes) {
      if (node.pos.y < RADIUS) {
        node.pos.y = RADIUS;

        const vx = node.pos.x - node.oldPos.x;
        const vz = node.pos.z - node.oldPos.z;

        // AUTO-GRIP: HIGH FRICTION
        // If we set this too low (e.g. 0.85), they slide on ice.
        // We set it to 0.2 to kill 80% of momentum per frame, acting like 'Sticky Mud'.
        const frictionCoeff = 0.2; 

        node.oldPos.x = node.pos.x - vx * frictionCoeff;
        node.oldPos.z = node.pos.z - vz * frictionCoeff;

        node.isGripping = false; // We don't use absolute lock, just heavy friction
      } else {
          node.isGripping = false;
      }
    }
  }
}

