import React, { useState, useMemo, useEffect, useRef } from 'react';
import { useThree } from '@react-three/fiber';
import { GridCoord, ShapeType } from '../../domain/types';
import * as THREE from 'three';
import { EditorTool } from '../../App';

// Helper to convert axial to pixel (for rendering hexes)
const hexToPixel = (q: number, r: number, size: number = 0.5) => {
    const x = size * 1.5 * q;
    const z = size * Math.sqrt(3) * (r + q/2);
    return { x, z };
};

// Neighbor directions for Hexagons (Axial)
const HEX_NEIGHBORS = [
    {q: 1, r: 0}, {q: 1, r: -1}, {q: 0, r: -1},
    {q: -1, r: 0}, {q: -1, r: 1}, {q: 0, r: 1}
];

export const BlueprintViewUpdated: React.FC<{
    cells: GridCoord[]; 
    onCellClick: (x: number, y: number, z: number, isRight: boolean) => void;
    currentType: ShapeType;
    editorTool: EditorTool;
}> = ({ cells, onCellClick, currentType, editorTool }) => {

  const { camera, raycaster, pointer, scene } = useThree();
  const [hoverCoord, setHoverCoord] = useState<GridCoord | null>(null);

  // INSTANCING REFS
  const meshRef = useRef<THREE.InstancedMesh>(null);
  const tempMat = useMemo(() => new THREE.Matrix4(), []);

  const boxGeo = useMemo(() => new THREE.BoxGeometry(0.8, 0.8, 0.8), []);
  const hexGeo = useMemo(() => new THREE.CylinderGeometry(0.45, 0.45, 0.5, 6), []);
  const hexRotation = useMemo(() => new THREE.Euler(0, Math.PI/6, 0), []);
  const hexQuaternion = useMemo(() => new THREE.Quaternion().setFromEuler(hexRotation), []);

  const material = useMemo(() => new THREE.MeshStandardMaterial({ color: '#3b82f6', roughness: 0.3 }), []);
  const materialHex = useMemo(() => new THREE.MeshStandardMaterial({ color: '#8b5cf6', roughness: 0.3 }), []);

  const hoverMaterial = useMemo(() => new THREE.MeshStandardMaterial({ color: '#facc15', transparent: true, opacity: 0.5 }), []);
  const eraseMaterial = useMemo(() => new THREE.MeshStandardMaterial({ color: '#ef4444', transparent: true, opacity: 0.5 }), []);

  // UPDATE INSTANCES
  useEffect(() => {
      if (!meshRef.current) return;

      meshRef.current.count = cells.length;

      cells.forEach((c, i) => {
          tempMat.identity();
          if (currentType === ShapeType.HEX) {
             const {x, z} = hexToPixel(c.x, c.z, 0.6);
             const hexHeight = 0.5;
             const yPos = c.y * hexHeight + (hexHeight/2);
             tempMat.makeRotationFromQuaternion(hexQuaternion);
             tempMat.setPosition(x, yPos, z);
          } else {
             tempMat.setPosition(c.x, c.y, c.z);
          }
          meshRef.current!.setMatrixAt(i, tempMat);
      });
      meshRef.current.instanceMatrix.needsUpdate = true;

  }, [cells, currentType, tempMat, hexQuaternion]);


  const handlePointerMove = (e: any) => {
      // If View mode, disable raycasting
      if (editorTool === 'VIEW') {
          if (hoverCoord) setHoverCoord(null);
          return;
      }

      raycaster.setFromCamera(pointer, camera);
      const intersects = raycaster.intersectObjects(scene.children, true);

      let hitPoint: THREE.Vector3 | null = null;
      let hitNormal: THREE.Vector3 | null = null;
      let hitObject: THREE.Object3D | null = null;
      let hitInstanceId: number | undefined = undefined;

      for (const hit of intersects) {
          if (hit.object === meshRef.current || hit.object.name === 'base_plane') {
              hitPoint = hit.point;
              hitNormal = hit.face?.normal || new THREE.Vector3(0,1,0);
              hitObject = hit.object;
              hitInstanceId = hit.instanceId;
              break;
          }
      }

      if (hitPoint) {
          // ERASE MODE: Highlight existing voxel
          if (editorTool === 'ERASE') {
              if (hitObject === meshRef.current && hitInstanceId !== undefined) {
                  const c = cells[hitInstanceId];
                  if (c) setHoverCoord(c);
              } else {
                  setHoverCoord(null);
              }
              return;
          }

          // BUILD MODE: Highlight neighbor space
          // CASE 1: HOVERING EXISTING VOXEL (Add to side)
          if (hitObject === meshRef.current && hitInstanceId !== undefined) {
             const c = cells[hitInstanceId];
             if (!c) return;

             if (currentType === ShapeType.HEX) {
                  // --- HEX LOGIC ---
                  const {x: cx, z: cz} = hexToPixel(c.x, c.z, 0.6);
                  const hexHeight = 0.5;
                  const cy = c.y * hexHeight + (hexHeight/2);

                  const relY = hitPoint.y - cy;

                  // Top/Bottom
                  if (relY > 0.23) {
                      setHoverCoord({ x: c.x, y: c.y + 1, z: c.z });
                      return;
                  }
                  if (relY < -0.23) {
                       setHoverCoord({ x: c.x, y: c.y - 1, z: c.z });
                       return;
                  }

                  // Side Neighbors
                  let bestNeigh = null;
                  let minD = Infinity;

                  HEX_NEIGHBORS.forEach(n => {
                       const pos = hexToPixel(c.x + n.q, c.z + n.r, 0.6);
                       const dx = pos.x - hitPoint!.x;
                       const dz = pos.z - hitPoint!.z;
                       const d = dx*dx + dz*dz;
                       if (d < minD) {
                           minD = d;
                           bestNeigh = n;
                       }
                  });

                  if (bestNeigh) {
                      setHoverCoord({ x: c.x + bestNeigh.q, y: c.y, z: c.z + bestNeigh.r });
                  }
             } else {
                 // --- CUBE LOGIC ---
                 const nx = hitNormal!.x;
                 const ny = hitNormal!.y;
                 const nz = hitNormal!.z;

                 setHoverCoord({
                     x: c.x + Math.round(nx),
                     y: c.y + Math.round(ny),
                     z: c.z + Math.round(nz)
                 });
             }
          } 
          // CASE 2: HOVERING FLOOR
          else if (hitObject?.name === 'base_plane') {
             if (currentType === ShapeType.HEX) {
                  const size = 0.6;
                  const q = (2./3 * hitPoint.x) / size;
                  const r = (-1./3 * hitPoint.x + Math.sqrt(3)/3 * hitPoint.z) / size;

                  let rx = Math.round(q);
                  let rz = Math.round(r);
                  let ry = Math.round(-q-r);

                  const x_diff = Math.abs(rx - q);
                  const y_diff = Math.abs(ry - (-q-r));
                  const z_diff = Math.abs(rz - r);

                  if (x_diff > y_diff && x_diff > z_diff) {
                      rx = -ry-rz;
                  } else {
                      rz = -rx-ry;
                  }
                  setHoverCoord({ x: rx, y: 0, z: rz });
             } else {
                 setHoverCoord({
                     x: Math.round(hitPoint.x),
                     y: 0,
                     z: Math.round(hitPoint.z)
                 });
             }
          }
      } else {
          setHoverCoord(null);
      }
  };

  const handleClick = (e: any) => {
      e.stopPropagation();
      if (editorTool === 'VIEW') return;

      if (editorTool === 'ERASE') {
          // Explicit raycast to find the object clicked
          if (e.object === meshRef.current && e.instanceId !== undefined) {
             const c = cells[e.instanceId];
             if(c) onCellClick(c.x, c.y, c.z, true); // true = right click (remove)
          }
          return;
      }

      if (editorTool === 'BUILD') {
          if (hoverCoord) {
              onCellClick(hoverCoord.x, hoverCoord.y, hoverCoord.z, false);
          }
      }
  };

  return (
    <group 
        onPointerMove={handlePointerMove} 
        onClick={handleClick}
        onContextMenu={handleClick}
    >
      <ambientLight intensity={0.8} />
      <directionalLight position={[5, 10, 5]} intensity={1.5} />

      <instancedMesh 
          ref={meshRef} 
          args={[undefined, undefined, 2000]} // Capacity 2000
          onPointerMove={handlePointerMove}
      >
          {currentType === ShapeType.HEX 
            ? <cylinderGeometry args={[0.45, 0.45, 0.5, 6]} /> 
            : <boxGeometry args={[0.8, 0.8, 0.8]} />
          }
          {currentType === ShapeType.HEX 
            ? <primitive object={materialHex} attach="material" />
            : <primitive object={material} attach="material" />
          }
      </instancedMesh>

      {hoverCoord && (
         <group>
             {currentType === ShapeType.HEX ? (
                 <mesh 
                    position={[
                        hexToPixel(hoverCoord.x, hoverCoord.z, 0.6).x, 
                        hoverCoord.y * 0.5 + 0.25, 
                        hexToPixel(hoverCoord.x, hoverCoord.z, 0.6).z
                    ]} 
                    geometry={hexGeo} 
                    material={editorTool === 'ERASE' ? eraseMaterial : hoverMaterial}
                    rotation={[0, Math.PI/6, 0]}
                 />
             ) : (
                 <mesh 
                    position={[hoverCoord.x, hoverCoord.y, hoverCoord.z]} 
                    geometry={boxGeo} 
                    material={editorTool === 'ERASE' ? eraseMaterial : hoverMaterial} 
                 />
             )}
         </group>
      )}

      <mesh rotation={[-Math.PI / 2, 0, 0]} position={[0, -0.5, 0]} name="base_plane" visible={false}>
          <planeGeometry args={[60, 60]} />
      </mesh>

      {currentType === ShapeType.HEX ? (
           <gridHelper args={[30, 30, 0x444444, 0x111111]} position={[0, -2.5, 0]} />
      ) : (
           <gridHelper args={[30, 30, 0x444444, 0x222222]} position={[0, -2.5, 0]} />
      )}

    </group>
  );
};

import React, { useRef, useMemo, MutableRefObject, useEffect } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { Organism, Node, Muscle } from '../../domain/types';

// Fix for missing R3F types in JSX.IntrinsicElements
declare global {
  namespace JSX {
    interface IntrinsicElements {
      group: any;
      mesh: any;
      instancedMesh: any;
      primitive: any;
      ambientLight: any;
      directionalLight: any;
      pointLight: any;
      planeGeometry: any;
      boxGeometry: any;
      cylinderGeometry: any;
      sphereGeometry: any;
      icosahedronGeometry: any;
      meshStandardMaterial: any;
      meshBasicMaterial: any;
      gridHelper: any;
    }
  }
}

interface CreatureViewProps {
  organism: Organism;
  leaderRef: MutableRefObject<Organism | null>;
  showBestOnly: boolean;
}

// CACHED OBJECTS
const _tempObj = new THREE.Object3D();
const _color = new THREE.Color();
const _vecA = new THREE.Vector3();
const _vecB = new THREE.Vector3();
const _mid = new THREE.Vector3();

// COLORS
const COL_RED = new THREE.Color(0xff3333);
const COL_BLUE = new THREE.Color(0x3333ff);
const COL_WHITE = new THREE.Color(0xffffff);
const COL_YELLOW = new THREE.Color(0xffff00);
const COL_HEAD = new THREE.Color(0x1a1a1a);
const COL_DEAD = new THREE.Color(0x52525b);
const COL_GRIP = new THREE.Color(0x22c55e);

export const CreatureView: React.FC<CreatureViewProps> = ({ organism, leaderRef, showBestOnly }) => {
  const groupRef = useRef<THREE.Group>(null);

  // Instanced Meshes
  const nodesMeshRef = useRef<THREE.InstancedMesh>(null);
  const musclesMeshRef = useRef<THREE.InstancedMesh>(null);

  // Singular items (Head indicators)
  const visionRef = useRef<THREE.Mesh>(null);
  const magnetRef = useRef<THREE.Mesh>(null);

  // Geometries
  const nodeGeo = useMemo(() => new THREE.SphereGeometry(0.08, 6, 6), []); // Low Poly
  const muscleGeo = useMemo(() => new THREE.CylinderGeometry(0.03, 0.03, 1, 4), []); // Low Poly, Height=1 for easy scaling
  const visionGeo = useMemo(() => new THREE.SphereGeometry(1, 16, 16), []); 
  const magnetGeo = useMemo(() => new THREE.RingGeometry(1.45, 1.5, 32), []);

  // Materials
  const nodeMat = useMemo(() => new THREE.MeshStandardMaterial({ color: 0xffffff, roughness: 0.5 }), []);
  const muscleMat = useMemo(() => new THREE.MeshStandardMaterial({ color: 0xffffff, roughness: 0.5 }), []);
  const visionMat = useMemo(() => new THREE.MeshBasicMaterial({ 
      color: 0x00ffff, transparent: true, opacity: 0.05, wireframe: true 
  }), []);
  const magnetMat = useMemo(() => new THREE.MeshBasicMaterial({
      color: 0xffff00, transparent: true, opacity: 0.3, side: THREE.DoubleSide
  }), []);

  // Set initial counts
  useEffect(() => {
      if (nodesMeshRef.current) nodesMeshRef.current.count = organism.nodes.length;
      if (musclesMeshRef.current) musclesMeshRef.current.count = organism.muscles.length;
  }, [organism.nodes.length, organism.muscles.length]);

  // Optimization: Pre-map node IDs to indices for fast lookup during muscle update
  const nodeIndexMap = useMemo(() => {
      const map = new Map<string, number>();
      organism.nodes.forEach((n, i) => map.set(n.id, i));
      return map;
  }, [organism.nodes]);


  useFrame((state) => {
    if (!groupRef.current) return;

    // Visibility Check
    if (showBestOnly) {
        const isLeader = leaderRef.current?.id === organism.id;
        groupRef.current.visible = isLeader;
    } else {
        groupRef.current.visible = true;
    }

    if (!groupRef.current.visible) return;

    let headPos: THREE.Vector3 | null = null;
    const isAlive = organism.isAlive;

    // --- UPDATE NODES ---
    if (nodesMeshRef.current) {
        for (let i = 0; i < organism.nodes.length; i++) {
            const node = organism.nodes[i];

            // Transform
            _tempObj.position.set(node.pos.x, node.pos.y, node.pos.z);
            _tempObj.scale.setScalar(1);
            _tempObj.rotation.set(0,0,0);
            _tempObj.updateMatrix();
            nodesMeshRef.current.setMatrixAt(i, _tempObj.matrix);

            // Color
            if (!isAlive) {
                nodesMeshRef.current.setColorAt(i, COL_DEAD);
            } else if (node.isHead) {
                headPos = _tempObj.position; // Capture for singulars
                nodesMeshRef.current.setColorAt(i, COL_HEAD);
            } else {
                if (node.isGripping) {
                    nodesMeshRef.current.setColorAt(i, COL_GRIP);
                } else {
                    const act = node.activation || 0;
                    _color.copy(COL_WHITE).lerp(COL_YELLOW, act);
                    nodesMeshRef.current.setColorAt(i, _color);
                }
            }
        }
        nodesMeshRef.current.instanceMatrix.needsUpdate = true;
        if (nodesMeshRef.current.instanceColor) nodesMeshRef.current.instanceColor.needsUpdate = true;
    }

    // --- UPDATE MUSCLES ---
    if (musclesMeshRef.current) {
        for (let i = 0; i < organism.muscles.length; i++) {
            const m = organism.muscles[i];
            // Lookup indices
            // We use direct array access if possible, but map is safer for partial updates
            const idxA = nodeIndexMap.get(m.nodeA);
            const idxB = nodeIndexMap.get(m.nodeB);

            if (idxA !== undefined && idxB !== undefined) {
                const nA = organism.nodes[idxA];
                const nB = organism.nodes[idxB];

                _vecA.set(nA.pos.x, nA.pos.y, nA.pos.z);
                _vecB.set(nB.pos.x, nB.pos.y, nB.pos.z);

                // Math to orient cylinder
                _mid.copy(_vecA).add(_vecB).multiplyScalar(0.5);
                const len = _vecA.distanceTo(_vecB);

                _tempObj.position.copy(_mid);
                _tempObj.lookAt(_vecB);
                _tempObj.rotateX(Math.PI / 2); // Align cylinder Y-axis to LookAt Z-axis
                _tempObj.scale.set(1, len, 1);
                _tempObj.updateMatrix();

                musclesMeshRef.current.setMatrixAt(i, _tempObj.matrix);

                // Color
                if (!isAlive) {
                    musclesMeshRef.current.setColorAt(i, COL_DEAD);
                } else {
                    const target = m.targetLength || m.baseLength;
                    const ratio = target / m.baseLength;
                    if (ratio < 0.98) {
                        _color.copy(COL_WHITE).lerp(COL_RED, Math.min(1, (1 - ratio) * 5));
                    } else if (ratio > 1.02) {
                        _color.copy(COL_WHITE).lerp(COL_BLUE, Math.min(1, (ratio - 1) * 5));
                    } else {
                        _color.copy(COL_WHITE);
                    }
                    musclesMeshRef.current.setColorAt(i, _color);
                }
            }
        }
        musclesMeshRef.current.instanceMatrix.needsUpdate = true;
        if (musclesMeshRef.current.instanceColor) musclesMeshRef.current.instanceColor.needsUpdate = true;
    }

    // --- UPDATE SINGULAR MESHES ---
    if (headPos && isAlive) {
        if (visionRef.current) {
            visionRef.current.position.copy(headPos);
            const pulse = 4.0 + Math.sin(state.clock.elapsedTime * 4) * 0.2; 
            visionRef.current.scale.setScalar(pulse);
            visionRef.current.visible = true;
        }
        if (magnetRef.current) {
            magnetRef.current.position.copy(headPos);
            magnetRef.current.rotation.x = -Math.PI / 2;
            magnetRef.current.visible = true;
        }
    } else {
        if (visionRef.current) visionRef.current.visible = false;
        if (magnetRef.current) magnetRef.current.visible = false;
    }
  });

  return (
    <group ref={groupRef}>
      <mesh ref={visionRef} geometry={visionGeo} material={visionMat} />
      <mesh ref={magnetRef} geometry={magnetGeo} material={magnetMat} />

      {/* INSTANCED NODES */}
      <instancedMesh 
        ref={nodesMeshRef} 
        args={[nodeGeo, nodeMat, organism.nodes.length]}
        frustumCulled={false}
      />

      {/* INSTANCED MUSCLES */}
      <instancedMesh 
        ref={musclesMeshRef} 
        args={[muscleGeo, muscleMat, organism.muscles.length]}
        frustumCulled={false}
      />
    </group>
  );
};

