import React, { useRef, useMemo, MutableRefObject } from 'react';
import { useFrame } from '@react-three/fiber';
import { Organism } from '../../domain/types';
import * as THREE from 'three';

// Fix for missing R3F types in JSX.IntrinsicElements
declare global {
  namespace JSX {
    interface IntrinsicElements {
      [elemName: string]: any;
    }
  }
}

interface FoodViewProps {
    leaderRef: MutableRefObject<Organism | null>;
}

export const FoodView: React.FC<FoodViewProps> = ({ leaderRef }) => {
    const meshRef = useRef<THREE.InstancedMesh>(null);
    const tempObj = useMemo(() => new THREE.Object3D(), []);

    // Geometry/Material
    const geo = useMemo(() => new THREE.IcosahedronGeometry(0.15, 0), []);
    const mat = useMemo(() => new THREE.MeshStandardMaterial({ 
        color: '#4ade80', 
        emissive: '#22c55e',
        emissiveIntensity: 0.6,
        roughness: 0.2
    }), []);

    useFrame((state) => {
        if (!meshRef.current) return;

        // Use the centralized leader
        const leader = leaderRef.current;

        if (!leader || !leader.visibleFood) {
            meshRef.current.count = 0;
            return;
        }

        const foodItems = leader.visibleFood;
        meshRef.current.count = foodItems.length;

        // Use clock from state instead of Date.now()
        const time = state.clock.elapsedTime;

        // Update Instances
        for (let i = 0; i < foodItems.length; i++) {
            const item = foodItems[i];

            // Position
            tempObj.position.set(item.pos.x, item.pos.y, item.pos.z);

            // Animation: Spin
            tempObj.rotation.y += 0.02;
            tempObj.rotation.z += 0.01;

            // Scale: Shrink if consumed, else pulse
            if (item.consumed) {
                tempObj.scale.setScalar(0); 
            } else {
                const pulse = 1.0 + Math.sin(time * 3 + i) * 0.1;
                tempObj.scale.setScalar(pulse);
            }

            tempObj.updateMatrix();
            meshRef.current.setMatrixAt(i, tempObj.matrix);
        }

        meshRef.current.instanceMatrix.needsUpdate = true;
    });

    return (
        <instancedMesh 
            ref={meshRef} 
            args={[geo, mat, 100]} // Max 100 food items buffer
            frustumCulled={false}
        />
    );
};

import React, { useState, useMemo } from 'react';
import { useThree } from '@react-three/fiber';
import { GridCoord, ShapeType } from '../../domain/types';
import * as THREE from 'three';

// Fix for missing R3F types in JSX.IntrinsicElements
declare global {
  namespace JSX {
    interface IntrinsicElements {
      [elemName: string]: any;
    }
  }
}

// Helper to convert axial to pixel (for rendering hexes)
const hexToPixel = (q: number, r: number, size: number = 0.5) => {
    const x = size * 1.5 * q;
    const z = size * Math.sqrt(3) * (r + q/2);
    return { x, z };
};

// Neighbor directions for Hexagons (Axial)
const HEX_NEIGHBORS = [
    {q: 1, r: 0}, {q: 1, r: -1}, {q: 0, r: -1},
    {q: -1, r: 0}, {q: -1, r: 1}, {q: 0, r: 1}
];

export const BlueprintViewUpdated: React.FC<{
    cells: GridCoord[]; 
    onCellClick: (x: number, y: number, z: number, isRight: boolean) => void;
    currentType: ShapeType;
}> = ({ cells, onCellClick, currentType }) => {

  const { camera, raycaster, pointer, scene } = useThree();
  const [hoverCoord, setHoverCoord] = useState<GridCoord | null>(null);

  const boxGeo = useMemo(() => new THREE.BoxGeometry(0.8, 0.8, 0.8), []);
  const hexGeo = useMemo(() => new THREE.CylinderGeometry(0.45, 0.45, 0.5, 6), []); // Taller prism

  const material = useMemo(() => new THREE.MeshStandardMaterial({ color: '#3b82f6', roughness: 0.3 }), []);
  const materialHex = useMemo(() => new THREE.MeshStandardMaterial({ color: '#8b5cf6', roughness: 0.3 }), []);

  const hoverMaterial = useMemo(() => new THREE.MeshStandardMaterial({ color: '#facc15', transparent: true, opacity: 0.5 }), []);

  const handlePointerMove = (e: any) => {
      raycaster.setFromCamera(pointer, camera);
      const intersects = raycaster.intersectObjects(scene.children, true);

      let hitPoint: THREE.Vector3 | null = null;
      let hitNormal: THREE.Vector3 | null = null;
      let hitObject: THREE.Object3D | null = null;

      for (const hit of intersects) {
          if (hit.object.name.startsWith('voxel') || hit.object.name === 'base_plane') {
              hitPoint = hit.point;
              hitNormal = hit.face?.normal || new THREE.Vector3(0,1,0);
              hitObject = hit.object;
              break;
          }
      }

      if (hitPoint) {
          if (currentType === ShapeType.HEX) {
              // --- HEX LOGIC ---
              if (hitObject?.name === 'voxel_hex') {
                  const data = hitObject.userData as GridCoord;

                  // Transform world normal to local rotation of the hex mesh?
                  // Our hex meshes are rotated 30 deg (PI/6) on Y usually, or not.
                  // Simpler: Check Up/Down first.

                  // Convert normal to world space if needed (usually face normal is local to geometry, but raycaster returns world? No, raycaster face.normal is local?)
                  // THREE.Raycaster returns face normal in object space (usually). 
                  // But we need to be careful. Let's rely on hitPoint relative to object center.

                  const relX = hitPoint.x - hitObject.position.x;
                  const relY = hitPoint.y - hitObject.position.y;
                  const relZ = hitPoint.z - hitObject.position.z;

                  // 1. Vertical Stacking (Top/Bottom Faces)
                  // The Cylinder is 0.5 high. So Top is ~0.25, Bottom ~ -0.25
                  if (relY > 0.23) {
                      setHoverCoord({ x: data.x, y: data.y + 1, z: data.z });
                      return;
                  }
                  if (relY < -0.23) {
                       setHoverCoord({ x: data.x, y: data.y - 1, z: data.z });
                       return;
                  }

                  // 2. Horizontal Neighbors (Side Faces)
                  // We need to map the hit vector angle to the 6 neighbor directions.
                  // Angle in X/Z plane.
                  const angle = Math.atan2(relZ, relX); // -PI to PI
                  // Convert to degrees for easier debugging mental model: -180 to 180
                  // Hex flat sides are at 0, 60, 120... or 30, 90, 150 depending on rotation.
                  // Our mesh has rotation [0, Math.PI/6, 0].

                  // Simple brute force: Find which neighbor center is closest to hitPoint (projected to plane)
                  const size = 0.6;
                  let bestNeigh = null;
                  let minD = Infinity;

                  HEX_NEIGHBORS.forEach(n => {
                       const pos = hexToPixel(data.x + n.q, data.z + n.r, size);
                       // We compare world positions
                       const wx = pos.x; 
                       const wz = pos.z; 

                       const dx = wx - hitPoint!.x;
                       const dz = wz - hitPoint!.z;
                       const d = dx*dx + dz*dz;
                       if (d < minD) {
                           minD = d;
                           bestNeigh = n;
                       }
                  });

                  if (bestNeigh) {
                      setHoverCoord({ x: data.x + bestNeigh.q, y: data.y, z: data.z + bestNeigh.r });
                  }

              } else {
                  // Hit Floor (Y=0 plane)
                  // Map X/Z to Hex Grid
                  // We need to invert the hexToPixel math.
                  const size = 0.6;
                  const q = (2./3 * hitPoint.x) / size;
                  const r = (-1./3 * hitPoint.x + Math.sqrt(3)/3 * hitPoint.z) / size;

                  // Round to nearest Hex
                  let rx = Math.round(q);
                  let rz = Math.round(r);
                  let ry = Math.round(-q-r);

                  const x_diff = Math.abs(rx - q);
                  const y_diff = Math.abs(ry - (-q-r));
                  const z_diff = Math.abs(rz - r);

                  if (x_diff > y_diff && x_diff > z_diff) {
                      rx = -ry-rz;
                  } else if (y_diff > z_diff) {
                      // ry = -rx-rz; 
                  } else {
                      rz = -rx-ry;
                  }

                  setHoverCoord({ x: rx, y: 0, z: rz });
              }

          } else {
              // --- CUBE/TETRA LOGIC ---
              if (hitObject?.name.startsWith('voxel')) {
                 const nx = hitNormal!.x;
                 const ny = hitNormal!.y;
                 const nz = hitNormal!.z;
                 const p = hitObject.position;
                 setHoverCoord({
                     x: Math.round(p.x + nx),
                     y: Math.round(p.y + ny),
                     z: Math.round(p.z + nz)
                 });
              } else {
                 // Hit floor
                 setHoverCoord({
                     x: Math.round(hitPoint.x),
                     y: 0,
                     z: Math.round(hitPoint.z)
                 });
              }
          }
      } else {
          setHoverCoord(null);
      }
  };

  const handleClick = (e: any) => {
      e.stopPropagation();
      // If Right click on existing voxel
      // We need to raycast specifically for existing objects to get the one to delete
      if (e.button === 2) {
         raycaster.setFromCamera(pointer, camera);
         const intersects = raycaster.intersectObjects(scene.children, true);
         for(const hit of intersects) {
             if (hit.object.name.startsWith('voxel')) {
                 const userData = hit.object.userData as GridCoord;
                 onCellClick(userData.x, userData.y, userData.z, true);
                 return;
             }
         }
      }

      if (hoverCoord) {
          onCellClick(hoverCoord.x, hoverCoord.y, hoverCoord.z, false);
      }
  };

  return (
    <group 
        onPointerMove={handlePointerMove} 
        onClick={handleClick}
        onContextMenu={handleClick}
    >
      <ambientLight intensity={0.8} />
      <directionalLight position={[5, 10, 5]} intensity={1.5} />

      {cells.map(c => {
          if (currentType === ShapeType.HEX) {
              const {x, z} = hexToPixel(c.x, c.z, 0.6);
              // Vertical Spacing for Cylinders (Height 0.5)
              // Gap is small or zero. Let's say 0.5 height, positioned at y * 0.5 + 0.25
              const hexHeight = 0.5;
              const yPos = c.y * hexHeight + (hexHeight/2);

              return (
                  <mesh 
                    key={`${c.x},${c.y},${c.z}`}
                    position={[x, yPos, z]}
                    geometry={hexGeo}
                    material={materialHex}
                    name="voxel_hex"
                    userData={c}
                    rotation={[0, Math.PI/6, 0]} // Pointy top orientation
                  />
              );
          } else {
              return (
                <mesh 
                    key={`${c.x},${c.y},${c.z}`}
                    position={[c.x, c.y, c.z]} 
                    geometry={boxGeo} 
                    material={material}
                    name="voxel_cube"
                    userData={c}
                />
              );
          }
      })}

      {hoverCoord && (
         <group>
             {currentType === ShapeType.HEX ? (
                 <mesh 
                    position={[
                        hexToPixel(hoverCoord.x, hoverCoord.z, 0.6).x, 
                        hoverCoord.y * 0.5 + 0.25, 
                        hexToPixel(hoverCoord.x, hoverCoord.z, 0.6).z
                    ]} 
                    geometry={hexGeo} 
                    material={hoverMaterial}
                    rotation={[0, Math.PI/6, 0]}
                 />
             ) : (
                 <mesh position={[hoverCoord.x, hoverCoord.y, hoverCoord.z]} geometry={boxGeo} material={hoverMaterial} />
             )}
         </group>
      )}

      {/* Base Plane for Raycasting */}
      <mesh rotation={[-Math.PI / 2, 0, 0]} position={[0, -0.5, 0]} name="base_plane" visible={false}>
          <planeGeometry args={[40, 40]} />
      </mesh>

      {currentType === ShapeType.HEX ? (
           <gridHelper args={[20, 20, 0x444444, 0x111111]} position={[0, -0.01, 0]} />
      ) : (
           <gridHelper args={[20, 20, 0x444444, 0x222222]} position={[0, -0.5, 0]} />
      )}

    </group>
  );
};

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { useThree } from '@react-three/fiber';
import { GridCoord, ShapeType } from '../../domain/types';
import * as THREE from 'three';
import { EditorTool } from '../../App';

// Fix for missing R3F types in JSX.IntrinsicElements
declare global {
  namespace JSX {
    interface IntrinsicElements {
      [elemName: string]: any;
    }
  }
}

// Helper to convert axial to pixel (for rendering hexes)
const hexToPixel = (q: number, r: number, size: number = 0.5) => {
    const x = size * 1.5 * q;
    const z = size * Math.sqrt(3) * (r + q/2);
    return { x, z };
};

// Neighbor directions for Hexagons (Axial)
const HEX_NEIGHBORS = [
    {q: 1, r: 0}, {q: 1, r: -1}, {q: 0, r: -1},
    {q: -1, r: 0}, {q: -1, r: 1}, {q: 0, r: 1}
];

export const BlueprintViewUpdated: React.FC<{
    cells: GridCoord[]; 
    onCellClick: (x: number, y: number, z: number, isRight: boolean) => void;
    currentType: ShapeType;
    editorTool: EditorTool;
}> = ({ cells, onCellClick, currentType, editorTool }) => {

  const { camera, raycaster, pointer, scene } = useThree();
  const [hoverCoord, setHoverCoord] = useState<GridCoord | null>(null);

  // INSTANCING REFS
  const meshRef = useRef<THREE.InstancedMesh>(null);
  const tempMat = useMemo(() => new THREE.Matrix4(), []);

  const boxGeo = useMemo(() => new THREE.BoxGeometry(0.8, 0.8, 0.8), []);
  const hexGeo = useMemo(() => new THREE.CylinderGeometry(0.45, 0.45, 0.5, 6), []);
  const hexRotation = useMemo(() => new THREE.Euler(0, Math.PI/6, 0), []);
  const hexQuaternion = useMemo(() => new THREE.Quaternion().setFromEuler(hexRotation), []);

  const material = useMemo(() => new THREE.MeshStandardMaterial({ color: '#3b82f6', roughness: 0.3 }), []);
  const materialHex = useMemo(() => new THREE.MeshStandardMaterial({ color: '#8b5cf6', roughness: 0.3 }), []);

  const hoverMaterial = useMemo(() => new THREE.MeshStandardMaterial({ color: '#facc15', transparent: true, opacity: 0.5 }), []);
  const eraseMaterial = useMemo(() => new THREE.MeshStandardMaterial({ color: '#ef4444', transparent: true, opacity: 0.5 }), []);

  // UPDATE INSTANCES
  useEffect(() => {
      if (!meshRef.current) return;

      meshRef.current.count = cells.length;

      cells.forEach((c, i) => {
          tempMat.identity();
          if (currentType === ShapeType.HEX) {
             const {x, z} = hexToPixel(c.x, c.z, 0.6);
             const hexHeight = 0.5;
             const yPos = c.y * hexHeight + (hexHeight/2);
             tempMat.makeRotationFromQuaternion(hexQuaternion);
             tempMat.setPosition(x, yPos, z);
          } else {
             tempMat.setPosition(c.x, c.y, c.z);
          }
          meshRef.current!.setMatrixAt(i, tempMat);
      });
      meshRef.current.instanceMatrix.needsUpdate = true;

  }, [cells, currentType, tempMat, hexQuaternion]);


  const handlePointerMove = (e: any) => {
      // If View mode, disable raycasting
      if (editorTool === 'VIEW') {
          if (hoverCoord) setHoverCoord(null);
          return;
      }

      raycaster.setFromCamera(pointer, camera);
      const intersects = raycaster.intersectObjects(scene.children, true);

      let hitPoint: THREE.Vector3 | null = null;
      let hitNormal: THREE.Vector3 | null = null;
      let hitObject: THREE.Object3D | null = null;
      let hitInstanceId: number | undefined = undefined;

      for (const hit of intersects) {
          if (hit.object === meshRef.current || hit.object.name === 'base_plane') {
              hitPoint = hit.point;
              hitNormal = hit.face?.normal || new THREE.Vector3(0,1,0);
              hitObject = hit.object;
              hitInstanceId = hit.instanceId;
              break;
          }
      }

      if (hitPoint) {
          // ERASE MODE: Highlight existing voxel
          if (editorTool === 'ERASE') {
              if (hitObject === meshRef.current && hitInstanceId !== undefined) {
                  const c = cells[hitInstanceId];
                  if (c) setHoverCoord(c);
              } else {
                  setHoverCoord(null);
              }
              return;
          }

          // BUILD MODE: Highlight neighbor space
          // CASE 1: HOVERING EXISTING VOXEL (Add to side)
          if (hitObject === meshRef.current && hitInstanceId !== undefined) {
             const c = cells[hitInstanceId];
             if (!c) return;

             if (currentType === ShapeType.HEX) {
                  // --- HEX LOGIC ---
                  const {x: cx, z: cz} = hexToPixel(c.x, c.z, 0.6);
                  const hexHeight = 0.5;
                  const cy = c.y * hexHeight + (hexHeight/2);

                  const relY = hitPoint.y - cy;

                  // Top/Bottom
                  if (relY > 0.23) {
                      setHoverCoord({ x: c.x, y: c.y + 1, z: c.z });
                      return;
                  }
                  if (relY < -0.23) {
                       setHoverCoord({ x: c.x, y: c.y - 1, z: c.z });
                       return;
                  }

                  // Side Neighbors
                  let bestNeigh = null;
                  let minD = Infinity;

                  HEX_NEIGHBORS.forEach(n => {
                       const pos = hexToPixel(c.x + n.q, c.z + n.r, 0.6);
                       const dx = pos.x - hitPoint!.x;
                       const dz = pos.z - hitPoint!.z;
                       const d = dx*dx + dz*dz;
                       if (d < minD) {
                           minD = d;
                           bestNeigh = n;
                       }
                  });

                  if (bestNeigh) {
                      setHoverCoord({ x: c.x + bestNeigh.q, y: c.y, z: c.z + bestNeigh.r });
                  }
             } else {
                 // --- CUBE LOGIC ---
                 const nx = hitNormal!.x;
                 const ny = hitNormal!.y;
                 const nz = hitNormal!.z;

                 setHoverCoord({
                     x: c.x + Math.round(nx),
                     y: c.y + Math.round(ny),
                     z: c.z + Math.round(nz)
                 });
             }
          } 
          // CASE 2: HOVERING FLOOR
          else if (hitObject?.name === 'base_plane') {
             if (currentType === ShapeType.HEX) {
                  const size = 0.6;
                  const q = (2./3 * hitPoint.x) / size;
                  const r = (-1./3 * hitPoint.x + Math.sqrt(3)/3 * hitPoint.z) / size;

                  let rx = Math.round(q);
                  let rz = Math.round(r);
                  let ry = Math.round(-q-r);

                  const x_diff = Math.abs(rx - q);
                  const y_diff = Math.abs(ry - (-q-r));
                  const z_diff = Math.abs(rz - r);

                  if (x_diff > y_diff && x_diff > z_diff) {
                      rx = -ry-rz;
                  } else {
                      rz = -rx-ry;
                  }
                  setHoverCoord({ x: rx, y: 0, z: rz });
             } else {
                 setHoverCoord({
                     x: Math.round(hitPoint.x),
                     y: 0,
                     z: Math.round(hitPoint.z)
                 });
             }
          }
      } else {
          setHoverCoord(null);
      }
  };

  const handleClick = (e: any) => {
      e.stopPropagation();
      if (editorTool === 'VIEW') return;

      if (editorTool === 'ERASE') {
          // Explicit raycast to find the object clicked
          if (e.object === meshRef.current && e.instanceId !== undefined) {
             const c = cells[e.instanceId];
             if(c) onCellClick(c.x, c.y, c.z, true); // true = right click (remove)
          }
          return;
      }

      if (editorTool === 'BUILD') {
          if (hoverCoord) {
              onCellClick(hoverCoord.x, hoverCoord.y, hoverCoord.z, false);
          }
      }
  };

  return (
    <group 
        onPointerMove={handlePointerMove} 
        onClick={handleClick}
        onContextMenu={handleClick}
    >
      <ambientLight intensity={0.8} />
      <directionalLight position={[5, 10, 5]} intensity={1.5} />

      <instancedMesh 
          ref={meshRef} 
          args={[undefined, undefined, 2000]} // Capacity 2000
          onPointerMove={handlePointerMove}
      >
          {currentType === ShapeType.HEX 
            ? <cylinderGeometry args={[0.45, 0.45, 0.5, 6]} /> 
            : <boxGeometry args={[0.8, 0.8, 0.8]} />
          }
          {currentType === ShapeType.HEX 
            ? <primitive object={materialHex} attach="material" />
            : <primitive object={material} attach="material" />
          }
      </instancedMesh>

      {hoverCoord && (
         <group>
             {currentType === ShapeType.HEX ? (
                 <mesh 
                    position={[
                        hexToPixel(hoverCoord.x, hoverCoord.z, 0.6).x, 
                        hoverCoord.y * 0.5 + 0.25, 
                        hexToPixel(hoverCoord.x, hoverCoord.z, 0.6).z
                    ]} 
                    geometry={hexGeo} 
                    material={editorTool === 'ERASE' ? eraseMaterial : hoverMaterial}
                    rotation={[0, Math.PI/6, 0]}
                 />
             ) : (
                 <mesh 
                    position={[hoverCoord.x, hoverCoord.y, hoverCoord.z]} 
                    geometry={boxGeo} 
                    material={editorTool === 'ERASE' ? eraseMaterial : hoverMaterial} 
                 />
             )}
         </group>
      )}

      <mesh rotation={[-Math.PI / 2, 0, 0]} position={[0, -0.5, 0]} name="base_plane" visible={false}>
          <planeGeometry args={[60, 60]} />
      </mesh>

      {currentType === ShapeType.HEX ? (
           <gridHelper args={[30, 30, 0x444444, 0x111111]} position={[0, -2.5, 0]} />
      ) : (
           <gridHelper args={[30, 30, 0x444444, 0x222222]} position={[0, -2.5, 0]} />
      )}

    </group>
  );
};

// Hexagonal Architecture: Domain Layer (Inner Core)
// Zero dependencies on UI or Rendering libraries.

export interface Vec3 {
  x: number;
  y: number;
  z: number;
}

export interface Node {
  id: string;
  pos: Vec3;
  oldPos: Vec3; // For Verlet integration
  mass: number;
  friction: number;
  isFixed?: boolean;
  isHead?: boolean; // NEW: The only node that can eat

  // SUCTION MECHANICS (Rhythmic Anchor)
  isGripping?: boolean; 
  gripTimer?: number;     // Frames remaining in current grip
  gripCooldown?: number;  // Frames until next grip is allowed
  gripSignal?: number;    // Deprecated for manual, but kept for compatibility

  // EDITOR METADATA (Preserves shape upon reloading)
  originalGridCoord?: { x: number; y: number; z: number }; 

  // Neural State
  activation?: number; // 0.0 to 1.0 (Visualization Glow)
  // Physics State
}

export interface Muscle {
  id: string;
  nodeA: string; // ID reference
  nodeB: string; // ID reference
  baseLength: number;
  stiffness: number;
  dnaIndex: number; // Maps to a Gene (Index in genome arrays)

  // Runtime Physics State
  currentLength?: number; 
  targetLength?: number; 

  // --- RUNTIME OPTIMIZATION (O(1) Access) ---
  nodeRefA?: Node;
  nodeRefB?: Node;

  // --- OSCILLATOR STATE (The Anti-Vibration Core) ---
  // The brain controls these parameters, not the length directly.
  phase: number;      // Current position in the sine wave (0 to 2PI)
  freq: number;       // How fast it pulses (Hz). Clamped to prevent jitter.
  amp: number;        // How much it expands (0.0 to 0.4). 
}

// Replaced simple Sine Gene with Neural Genome
export interface NeuralGenome {
  // GNN Weights: How much signal flows through each muscle (Synapse)
  synapseWeights: number[]; 
  // LSM Weights: The chaotic reservoir weights (simplified as a float array)
  reservoirWeights: number[];
  // Output Weights: Mapping the reservoir state to muscle contraction
  outputWeights: number[]; 
  // NEW: Predictive World Model Weights (Reservoir -> Predicted Sensory Input)
  predictionWeights: number[];
  // NEW: Grip Control Weights (Reservoir -> Node Suction Release)
  gripWeights: number[]; 
  // Biases for neurons
  biases: number[];

  // --- EVOLVABLE BRAIN DYNAMICS ---
  internalClockSpeed: number; // Multiplier (0.5 to 2.0). How fast the brain thinks relative to physics.
  waveFreq: number;           // Hz (0.5 to 3.0). Base frequency of the spinal generator.
  waveSpeed: number;          // Propagation speed of the wave along the body.
}

export interface FoodItem {
    id: string;
    pos: Vec3;
    energyValue: number;
    consumed: boolean;
}

export enum ShapeType {
  CUBE = 'CUBE', // Cartesian Lattice
  TETRAHEDRON = 'TETRAHEDRON', // Offset Lattice
  WORM = 'WORM', // Legacy
  HEX = 'HEX', // 3D Hexagonal Prism Layout
}

export interface Organism {
  id: string;
  shape: ShapeType; // NEW: Tracks the lattice type for the Architect
  nodes: Node[];
  muscles: Muscle[];
  // The Blueprint
  neuralGenome: NeuralGenome;
  // The Runtime Brain (Controller instance, not serialized usually, but here for simplicity)
  brain?: any; 

  // Stats
  fitness: number; // Total Score
  generation: number;

  // NEW: Distance Metrics (Replacing Posture)
  initialHeadPos: Vec3; // BENCHMARK: Where the head started
  distanceTraveled: number; // Real-time distance from start

  // NEW: Metabolism & Survival
  energy: number;          // 0 to 100
  maxEnergy: number;       
  hungerTime: number;      // Time since last meal (drives exponential decay)
  isAlive: boolean;
  foodEaten: number;
  visibleFood: FoodItem[]; // Each creature has its own reality/food track

  // OPTIMIZATION: Cached reference
  headNode?: Node;
}

export interface SimulationConfig {
  gravity: number;
  friction: number;
  groundDamping: number;
  timeStep: number;
  // NEW: Structural Integrity
  shapeMemoryStrength: number;

  // NEW: Real-time Physics Tweaks
  globalStiffness: number;     // Multiplier for bone rigidity (0.1 to 2.0)
  globalContractility: number; // Multiplier for muscle power (0.0 to 2.0)
}

// --- ARCHITECT TYPES ---
export type GridCoord = { x: number; y: number; z: number };

export interface Blueprint {
    cells: Map<string, boolean>; // Key "x,y,z"
    type: ShapeType;
}

import { Node, Muscle, Organism, SimulationConfig } from './types';
import { BrainController } from './neural/BrainController';

export class BioPhysicsEngine {
  private config: SimulationConfig;
  private readonly MAX_VELOCITY = 12.0; 

  // SOLVER SETTINGS
  private readonly RELAXATION_FACTOR = 0.25; 
  private readonly ITERATIONS = 6; 

  // DAMPING SETTINGS
  private readonly BASE_MUSCLE_DAMPING = 0.08; 
  private readonly ADAPTIVE_DAMPING_FACTOR = 0.12; 
  private readonly ROTATIONAL_DRAG = 0.92; 

  // AIR RESISTANCE
  private readonly DRAG_COEFFICIENT = 0.08; 

  // --- SOLIDITY CONSTANTS ---
  private readonly NODE_RADIUS = 0.1; 
  private readonly HARD_CONTACT_LIMIT = 0.22; 

  // --- GRIP CONSTANTS ---
  private readonly GRIP_DURATION = 45; // Frames (approx 0.75s) to hold
  private readonly GRIP_COOLDOWN = 20; // Frames (approx 0.33s) to release/slide

  constructor(config: Partial<SimulationConfig> = {}) {
    this.config = {
      gravity: -60.0, 
      friction: 0.98, // Global air friction
      groundDamping: 0.8, 
      timeStep: 0.016,
      shapeMemoryStrength: 0.85, 
      globalStiffness: 0.8, 
      globalContractility: 1.5, 
      ...config
    };
  }

  public setConfig(config: Partial<SimulationConfig>) {
      this.config = { ...this.config, ...config };
  }

  // fastMode: If true, runs lower fidelity physics for rapid evolutionary calculation
  public updateOrganism(organism: Organism, totalTime: number, fastMode: boolean = false): void {

    // 1. PHYSICS INTEGRATION

    // Handle Ragdoll state
    if (!organism.isAlive) {
        organism.muscles.forEach(m => {
            m.stiffness = 0.05; // Very loose
            m.amp = 0; // Stop oscillating
            m.targetLength = m.baseLength;
        });
        // Release all grips if dead
        organism.nodes.forEach(n => {
            n.isGripping = false;
        });
    }

    // ADAPTIVE SUBSTEPS
    const subSteps = fastMode ? 4 : 12; 
    const subDt = this.config.timeStep / subSteps;
    const gravityVec = { x: 0, y: this.config.gravity * subDt * subDt, z: 0 };

    for(let s=0; s < subSteps; s++) {
        this.integrate(organism, subDt, gravityVec);
        if (!fastMode) this.applyRotationalDrag(organism); 

        // ITERATIVE SOLVER
        const loops = fastMode ? 4 : this.ITERATIONS;

        for (let i = 0; i < loops; i++) {
            this.resolveMuscles(organism);

            if (!fastMode) {
                this.resolveSelfCollisions(organism); 
            }
        }

        this.resolveFloor(organism);
    }
  }

  private applyRotationalDrag(organism: Organism): void {
      let cx = 0, cz = 0;
      let count = 0;
      for (const n of organism.nodes) {
          cx += n.pos.x;
          cz += n.pos.z;
          count++;
      }
      if (count === 0) return;
      cx /= count;
      cz /= count;

      let angularMomentum = 0;
      let momentOfInertia = 0;

      for (const n of organism.nodes) {
          const rx = n.pos.x - cx;
          const rz = n.pos.z - cz;

          const vx = n.pos.x - n.oldPos.x;
          const vz = n.pos.z - n.oldPos.z;

          const orbitalComponent = rx * vz - rz * vx;

          angularMomentum += orbitalComponent;
          momentOfInertia += rx * rx + rz * rz;
      }

      if (momentOfInertia < 0.001) return;

      const angularVel = angularMomentum / momentOfInertia;

      for (const n of organism.nodes) {
          const rx = n.pos.x - cx;
          const rz = n.pos.z - cz;

          const dampX = -angularVel * rz * this.ROTATIONAL_DRAG;
          const dampZ =  angularVel * rx * this.ROTATIONAL_DRAG;

          n.oldPos.x += dampX;
          n.oldPos.z += dampZ;
      }
  }

  private integrate(organism: Organism, dt: number, gravityVec: {x:number, y:number, z:number}): void {
    const { friction } = this.config;
    const maxStepDist = this.MAX_VELOCITY * dt;
    const maxStepSq = maxStepDist * maxStepDist;

    for (const node of organism.nodes) {
      if (node.isFixed) continue;

      // AUTO-GRIP MECHANIC: FREEZE MOMENTUM IF GRIPPING
      // If gripping, we ignore velocity integration essentially, or rely on resolveFloor to enforce lock.
      // But clearing velocity here helps stability.
      if (node.isGripping) {
          node.oldPos.x = node.pos.x;
          node.oldPos.z = node.pos.z;
          // We allow Y movement slightly (gravity will push it down, resolveFloor will push it up)
          // but mainly we want horizontal anchor.
      }

      let velX = node.pos.x - node.oldPos.x;
      let velY = node.pos.y - node.oldPos.y;
      let velZ = node.pos.z - node.oldPos.z;

      // 1. QUADRATIC DRAG
      const vSq = velX*velX + velY*velY + velZ*velZ;
      if (vSq > 0.000001) {
          const vLen = Math.sqrt(vSq);
          const dragFactor = 1.0 / (1.0 + this.DRAG_COEFFICIENT * vLen);

          velX *= dragFactor;
          velY *= dragFactor;
          velZ *= dragFactor;
      }

      // 2. Base Friction (Air)
      velX *= friction;
      velY *= friction;
      velZ *= friction;

      // 3. Hard Cap (Safety Terminator)
      const distSq = velX*velX + velY*velY + velZ*velZ;
      if (distSq > maxStepSq) {
          const scale = maxStepDist / Math.sqrt(distSq);
          velX *= scale;
          velY *= scale;
          velZ *= scale;
      }

      // GC OPTIMIZATION: Update oldPos in place instead of creating new object
      node.oldPos.x = node.pos.x;
      node.oldPos.y = node.pos.y;
      node.oldPos.z = node.pos.z;

      node.pos.x += velX + gravityVec.x;
      node.pos.y += velY + gravityVec.y;
      node.pos.z += velZ + gravityVec.z;
    }
  }

  private resolveMuscles(organism: Organism): void {
    const GROUND_TOLERANCE = 0.02;
    // When gripping, node acts as infinite mass anchor (almost)
    const ANCHOR_MULTIPLIER = 0.001; 
    const MEMORY_STRENGTH = this.config.shapeMemoryStrength || 0.8;
    const GLOBAL_STIFFNESS = this.config.globalStiffness; 

    // CACHE REFERENCES (Lazy Load)
    if (!organism.muscles[0]?.nodeRefA) {
         const nodeMap = new Map<string, Node>();
         for (const n of organism.nodes) nodeMap.set(n.id, n);
         for (const m of organism.muscles) {
             m.nodeRefA = nodeMap.get(m.nodeA);
             m.nodeRefB = nodeMap.get(m.nodeB);
         }
    }

    for (const muscle of organism.muscles) {
        const n1 = muscle.nodeRefA;
        const n2 = muscle.nodeRefB;

        if (!n1 || !n2) continue;

        const dx = n2.pos.x - n1.pos.x;
        const dy = n2.pos.y - n1.pos.y;
        const dz = n2.pos.z - n1.pos.z;

        const distSq = dx*dx + dy*dy + dz*dz;
        if (distSq < 0.0000001) continue; 

        const dist = Math.sqrt(distSq);

        // 1. ACTIVE MUSCLE COMPONENT
        let activeTarget = muscle.targetLength || muscle.baseLength;
        if (activeTarget < this.HARD_CONTACT_LIMIT) activeTarget = this.HARD_CONTACT_LIMIT;

        let stiffness = muscle.stiffness * 0.8 * GLOBAL_STIFFNESS; 

        const activeDiff = dist - activeTarget;

        // 2. PASSIVE MEMORY COMPONENT
        const deviation = Math.abs(dist - muscle.baseLength);
        const strain = deviation / muscle.baseLength;
        const strainBoost = 1.0 + (strain * 4.0); 

        const currentMemoryStrength = organism.isAlive 
            ? MEMORY_STRENGTH * strainBoost * GLOBAL_STIFFNESS
            : MEMORY_STRENGTH * 0.1 * GLOBAL_STIFFNESS;

        const baseDiff = dist - muscle.baseLength;

        // --- DUAL FORCE BLENDING ---
        const activeCorrection = activeDiff * stiffness;
        const memoryCorrection = baseDiff * currentMemoryStrength;
        let totalCorrection = (activeCorrection + memoryCorrection) * this.RELAXATION_FACTOR;

        // --- DAMPING ---
        const vx1 = n1.pos.x - n1.oldPos.x;
        const vy1 = n1.pos.y - n1.oldPos.y;
        const vz1 = n1.pos.z - n1.oldPos.z;
        const vx2 = n2.pos.x - n2.oldPos.x;
        const vy2 = n2.pos.y - n2.oldPos.y;
        const vz2 = n2.pos.z - n2.oldPos.z;

        const rvx = vx2 - vx1;
        const rvy = vy2 - vy1;
        const rvz = vz2 - vz1;

        const nx = dx / dist;
        const ny = dy / dist;
        const nz = dz / dist;

        const relVel = Math.sqrt(rvx*rvx + rvy*rvy + rvz*rvz);
        const dynamicDamping = this.BASE_MUSCLE_DAMPING + (relVel * this.ADAPTIVE_DAMPING_FACTOR);
        const vRelProj = rvx * nx + rvy * ny + rvz * nz;

        totalCorrection += vRelProj * dynamicDamping;

        // --- MOMENTUM PRESERVATION & ANCHORING ---
        let im1 = n1.isFixed ? 0 : 1 / n1.mass;
        let im2 = n2.isFixed ? 0 : 1 / n2.mass;

        // If Gripping, effective mass is infinite (invMass = 0)
        // This forces the other node to do all the moving
        if (n1.isGripping) im1 *= ANCHOR_MULTIPLIER;
        if (n2.isGripping) im2 *= ANCHOR_MULTIPLIER;

        const totalInvMass = im1 + im2;
        if (totalInvMass === 0) continue;

        const w1 = im1 / totalInvMass;
        const w2 = im2 / totalInvMass;

        const offsetX = nx * totalCorrection;
        const offsetY = ny * totalCorrection;
        const offsetZ = nz * totalCorrection;

        // Apply Move (if not absolutely fixed)
        if (!n1.isFixed) {
            n1.pos.x += offsetX * w1;
            n1.pos.y += offsetY * w1;
            n1.pos.z += offsetZ * w1;
        }

        if (!n2.isFixed) {
            n2.pos.x -= offsetX * w2;
            n2.pos.y -= offsetY * w2;
            n2.pos.z -= offsetZ * w2;
        }
    }
  }

  private resolveSelfCollisions(organism: Organism): void {
      const nodes = organism.nodes;
      const count = nodes.length;
      const minDistance = this.HARD_CONTACT_LIMIT; 
      const minDistanceSq = minDistance * minDistance;

      for (let i = 0; i < count; i++) {
          for (let j = i + 1; j < count; j++) {
              const n1 = nodes[i];
              const n2 = nodes[j];

              const dx = n1.pos.x - n2.pos.x;
              const dy = n1.pos.y - n2.pos.y;
              const dz = n1.pos.z - n2.pos.z;
              const distSq = dx*dx + dy*dy + dz*dz;

              if (distSq < minDistanceSq && distSq > 0.000001) {
                  const dist = Math.sqrt(distSq);
                  const overlap = minDistance - dist;

                  const fx = (dx / dist) * overlap * 0.2;
                  const fy = (dy / dist) * overlap * 0.2;
                  const fz = (dz / dist) * overlap * 0.2;

                  if (!n1.isFixed) { n1.pos.x += fx; n1.pos.y += fy; n1.pos.z += fz; }
                  if (!n2.isFixed) { n2.pos.x -= fx; n2.pos.y -= fy; n2.pos.z -= fz; }
              }
          }
      }
  }

  private resolveFloor(organism: Organism): void {
    const RADIUS = this.NODE_RADIUS;

    for (const node of organism.nodes) {
      if (node.pos.y < RADIUS) {
        node.pos.y = RADIUS;

        // --- AUTO-GRIP LOGIC ---
        // Initialize State if missing
        if (node.gripTimer === undefined) node.gripTimer = 0;
        if (node.gripCooldown === undefined) node.gripCooldown = 0;

        if (node.isGripping) {
            // HOLD
            node.gripTimer--;

            // Absolute Lock in X/Z (Anchor)
            // We revert position to old position to kill any slide
            // But we allow external forces to have moved 'pos', so we just
            // snap 'pos' back to 'oldPos' horizontally? 
            // Better: Update oldPos to match pos so velocity is 0 next frame, 
            // AND reset pos to oldPos to stop this frame's slide.

            // Actually, we want it to stay where it WAS.
            // So we restore the position it had before integration/forces moved it?
            // Simpler approach: Heavy Damping.

            // FORCE VELOCITY ZERO
            node.oldPos.x = node.pos.x;
            node.oldPos.z = node.pos.z;

            if (node.gripTimer <= 0) {
                // RELEASE
                node.isGripping = false;
                node.gripCooldown = this.GRIP_COOLDOWN;
            }
        } else {
            // NOT GRIPPING
            if (node.gripCooldown > 0) {
                // COOLDOWN (Sliding phase)
                node.gripCooldown--;
                // Standard friction
                const vx = node.pos.x - node.oldPos.x;
                const vz = node.pos.z - node.oldPos.z;
                node.oldPos.x = node.pos.x - vx * 0.85; // Slide
                node.oldPos.z = node.pos.z - vz * 0.85;
            } else {
                // READY TO GRIP
                node.isGripping = true;
                node.gripTimer = this.GRIP_DURATION;
            }
        }
      } else {
          // IN AIR
          node.isGripping = false;
          // Tick down cooldown even in air so they can grip immediately upon landing
          if (node.gripCooldown && node.gripCooldown > 0) node.gripCooldown--;
      }
    }
  }
}

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { useThree, ThreeEvent } from '@react-three/fiber';
import { GridCoord, ShapeType } from '../../domain/types';
import * as THREE from 'three';
import { EditorTool } from '../../App';

// Helper to convert axial to pixel (for rendering hexes)
const hexToPixel = (q: number, r: number, size: number = 0.5) => {
    const x = size * 1.5 * q;
    const z = size * Math.sqrt(3) * (r + q/2);
    return { x, z };
};

// Neighbor directions for Hexagons (Axial)
const HEX_NEIGHBORS = [
    {q: 1, r: 0}, {q: 1, r: -1}, {q: 0, r: -1},
    {q: -1, r: 0}, {q: -1, r: 1}, {q: 0, r: 1}
];

export const BlueprintViewUpdated: React.FC<{
    cells: GridCoord[]; 
    onCellClick: (x: number, y: number, z: number, isRight: boolean) => void;
    currentType: ShapeType;
    editorTool: EditorTool;
}> = ({ cells, onCellClick, currentType, editorTool }) => {

  const { camera, raycaster, pointer, scene } = useThree();
  const [hoverCoord, setHoverCoord] = useState<GridCoord | null>(null);

  // INSTANCING REFS
  const meshRef = useRef<THREE.InstancedMesh>(null);
  const tempMat = useMemo(() => new THREE.Matrix4(), []);

  const boxGeo = useMemo(() => new THREE.BoxGeometry(0.8, 0.8, 0.8), []);
  const hexGeo = useMemo(() => new THREE.CylinderGeometry(0.45, 0.45, 0.5, 6), []);
  const hexRotation = useMemo(() => new THREE.Euler(0, Math.PI/6, 0), []);
  const hexQuaternion = useMemo(() => new THREE.Quaternion().setFromEuler(hexRotation), []);

  const material = useMemo(() => new THREE.MeshStandardMaterial({ color: '#3b82f6', roughness: 0.3 }), []);
  const materialHex = useMemo(() => new THREE.MeshStandardMaterial({ color: '#8b5cf6', roughness: 0.3 }), []);

  const hoverMaterial = useMemo(() => new THREE.MeshStandardMaterial({ color: '#facc15', transparent: true, opacity: 0.5 }), []);
  const eraseMaterial = useMemo(() => new THREE.MeshStandardMaterial({ color: '#ef4444', transparent: true, opacity: 0.5 }), []);

  // UPDATE INSTANCES
  useEffect(() => {
      if (!meshRef.current) return;

      meshRef.current.count = cells.length;

      cells.forEach((c, i) => {
          tempMat.identity();
          if (currentType === ShapeType.HEX) {
             const {x, z} = hexToPixel(c.x, c.z, 0.6);
             const hexHeight = 0.5;
             const yPos = c.y * hexHeight + (hexHeight/2);
             tempMat.makeRotationFromQuaternion(hexQuaternion);
             tempMat.setPosition(x, yPos, z);
          } else {
             tempMat.setPosition(c.x, c.y, c.z);
          }
          meshRef.current!.setMatrixAt(i, tempMat);
      });
      meshRef.current.instanceMatrix.needsUpdate = true;

      // Update bounding sphere for raycasting
      if (meshRef.current.geometry) {
          meshRef.current.computeBoundingSphere();
      }

  }, [cells, currentType, tempMat, hexQuaternion]);

  // --- EVENTS ON MESH (More Reliable) ---

  const handleMeshMove = (e: ThreeEvent<PointerEvent>) => {
      e.stopPropagation();
      if (editorTool === 'VIEW') return;

      const instanceId = e.instanceId;
      if (instanceId === undefined) return;

      const c = cells[instanceId];
      if (!c) return;

      if (editorTool === 'ERASE') {
          setHoverCoord(c);
      } 
      else if (editorTool === 'BUILD') {
          // Calculate neighbor based on face normal or hit point
          const hitPoint = e.point;
          // Localize hit point relative to the instance center
          // This is hard with InstancedMesh without matrix inversion.
          // Easier: Just use face normal from intersection.

          if (currentType === ShapeType.HEX) {
             // HEX LOGIC using world hit point relative to calculated instance pos
             const {x: cx, z: cz} = hexToPixel(c.x, c.z, 0.6);
             const hexHeight = 0.5;
             const cy = c.y * hexHeight + (hexHeight/2);

             const relY = hitPoint.y - cy;

             // Top/Bottom
             if (relY > 0.23) {
                 setHoverCoord({ x: c.x, y: c.y + 1, z: c.z });
                 return;
             }
             if (relY < -0.23) {
                  setHoverCoord({ x: c.x, y: c.y - 1, z: c.z });
                  return;
             }

             // Side Neighbors
             let bestNeigh = null;
             let minD = Infinity;

             HEX_NEIGHBORS.forEach(n => {
                  const pos = hexToPixel(c.x + n.q, c.z + n.r, 0.6);
                  // Approximate y center for distance check
                  const dy = 0; 
                  const dx = pos.x - hitPoint.x;
                  const dz = pos.z - hitPoint.z;
                  const d = dx*dx + dz*dz;
                  if (d < minD) {
                      minD = d;
                      bestNeigh = n;
                  }
             });

             if (bestNeigh) {
                 setHoverCoord({ x: c.x + bestNeigh.q, y: c.y, z: c.z + bestNeigh.r });
             }
          } else {
             // CUBE LOGIC (Using Normals)
             if (e.face) {
                 const n = e.face.normal;
                 // Face normals in InstancedMesh are usually in local space of geometry? 
                 // Or world space? R3F/Three usually provides world space normal in intersections if updated?
                 // Actually, standard Raycaster returns face normal.
                 // For axis-aligned cubes, simpler:
                 // Just map normal to int

                 // Transform normal by instance rotation if needed (not for cubes usually)
                 // But wait, if we rotated the camera, face normal is still geometry normal.
                 // Let's assume standard orientation.

                 setHoverCoord({
                     x: c.x + Math.round(n.x),
                     y: c.y + Math.round(n.y),
                     z: c.z + Math.round(n.z)
                 });
             }
          }
      }
  };

  const handleMeshClick = (e: ThreeEvent<MouseEvent>) => {
      e.stopPropagation();
      if (editorTool === 'VIEW') return;

      const instanceId = e.instanceId;
      if (instanceId === undefined) return;

      if (editorTool === 'ERASE') {
          const c = cells[instanceId];
          if (c) onCellClick(c.x, c.y, c.z, true); // remove
      }
      else if (editorTool === 'BUILD') {
          if (hoverCoord) {
              onCellClick(hoverCoord.x, hoverCoord.y, hoverCoord.z, false); // add
          }
      }
  };

  const handleFloorMove = (e: ThreeEvent<PointerEvent>) => {
      if (editorTool !== 'BUILD') {
          if (editorTool !== 'ERASE') setHoverCoord(null); // Don't clear if erasing valid block
          return;
      }
      e.stopPropagation();

      const hitPoint = e.point;

      if (currentType === ShapeType.HEX) {
          const size = 0.6;
          const q = (2./3 * hitPoint.x) / size;
          const r = (-1./3 * hitPoint.x + Math.sqrt(3)/3 * hitPoint.z) / size;

          let rx = Math.round(q);
          let rz = Math.round(r);
          let ry = Math.round(-q-r);

          const x_diff = Math.abs(rx - q);
          const y_diff = Math.abs(ry - (-q-r));
          const z_diff = Math.abs(rz - r);

          if (x_diff > y_diff && x_diff > z_diff) {
              rx = -ry-rz;
          } else {
              rz = -rx-ry;
          }
          setHoverCoord({ x: rx, y: 0, z: rz });
      } else {
          setHoverCoord({
              x: Math.round(hitPoint.x),
              y: 0,
              z: Math.round(hitPoint.z)
          });
      }
  };

  const handleFloorClick = (e: ThreeEvent<MouseEvent>) => {
       if (editorTool !== 'BUILD') return;
       e.stopPropagation();
       if (hoverCoord) {
           onCellClick(hoverCoord.x, hoverCoord.y, hoverCoord.z, false);
       }
  };

  const handleMiss = () => {
     setHoverCoord(null);
  };

  return (
    <group 
        onPointerMissed={handleMiss}
    >
      <ambientLight intensity={0.8} />
      <directionalLight position={[5, 10, 5]} intensity={1.5} />

      <instancedMesh 
          ref={meshRef} 
          args={[undefined, undefined, 2000]} 
          onPointerMove={handleMeshMove}
          onClick={handleMeshClick}
          onContextMenu={handleMeshClick} // Handle right click naturally
      >
          {currentType === ShapeType.HEX 
            ? <cylinderGeometry args={[0.45, 0.45, 0.5, 6]} /> 
            : <boxGeometry args={[0.8, 0.8, 0.8]} />
          }
          {currentType === ShapeType.HEX 
            ? <primitive object={materialHex} attach="material" />
            : <primitive object={material} attach="material" />
          }
      </instancedMesh>

      {hoverCoord && (
         <group>
             {currentType === ShapeType.HEX ? (
                 <mesh 
                    position={[
                        hexToPixel(hoverCoord.x, hoverCoord.z, 0.6).x, 
                        hoverCoord.y * 0.5 + 0.25, 
                        hexToPixel(hoverCoord.x, hoverCoord.z, 0.6).z
                    ]} 
                    geometry={hexGeo} 
                    material={editorTool === 'ERASE' ? eraseMaterial : hoverMaterial}
                    rotation={[0, Math.PI/6, 0]}
                    pointerEvents="none" // Ghost should not block raycast
                 />
             ) : (
                 <mesh 
                    position={[hoverCoord.x, hoverCoord.y, hoverCoord.z]} 
                    geometry={boxGeo} 
                    material={editorTool === 'ERASE' ? eraseMaterial : hoverMaterial} 
                    pointerEvents="none" 
                 />
             )}
         </group>
      )}

      {/* Invisible Plane for Floor Building */}
      <mesh 
          rotation={[-Math.PI / 2, 0, 0]} 
          position={[0, -0.5, 0]} 
          name="base_plane" 
          visible={false}
          onPointerMove={handleFloorMove}
          onClick={handleFloorClick}
      >
          <planeGeometry args={[60, 60]} />
      </mesh>

      {currentType === ShapeType.HEX ? (
           <gridHelper args={[30, 30, 0x444444, 0x111111]} position={[0, -2.5, 0]} />
      ) : (
           <gridHelper args={[30, 30, 0x444444, 0x222222]} position={[0, -2.5, 0]} />
      )}

    </group>
  );
};

import { ShapeType, Organism, Node, Muscle, NeuralGenome, GridCoord } from './types';
import { VectorOps } from './math';
import { LatticeFactory, ILatticeStrategy } from './lattice/LatticeStrategy';
import { GeneticOperator } from './genetics/GeneticOperator';

export class BlueprintService {
  private cells: Map<string, boolean> = new Map();
  private type: ShapeType = ShapeType.CUBE;
  private readonly GRID_SIZE = 10; 
  private geneticOperator: GeneticOperator;

  constructor() {
    this.geneticOperator = new GeneticOperator();
    this.clear();
  }

  public setType(t: ShapeType) {
    this.type = t;
  }

  public clear() {
    this.cells.clear();
  }

  public getCells(): GridCoord[] {
    const res: GridCoord[] = [];
    this.cells.forEach((val, key) => {
        if (val) {
            const [x, y, z] = key.split(',').map(Number);
            res.push({ x, y, z });
        }
    });
    return res;
  }

  public setCell(x: number, y: number, z: number, active: boolean) {
    const key = `${Math.round(x)},${Math.round(y)},${Math.round(z)}`;
    if (active) {
        this.cells.set(key, true);
    } else {
        this.cells.delete(key);
    }
  }

  public hasCell(x: number, y: number, z: number): boolean {
      return this.cells.has(`${x},${y},${z}`);
  }

  // --- HEURISTICS ---

  public generateSmallCritter() {
      this.clear();
      const rng = () => Math.random();
      const length = 4 + Math.floor(rng() * 3);
      const wideStance = rng() > 0.4;
      const legX = wideStance ? 2 : 1;

      for(let z=0; z<length; z++) this.setCell(0, 1, z, true);

      const headZ = length - 1;
      this.setCell(0, 2, headZ, true);
      if (rng() > 0.5) this.setCell(0, 3, headZ, true);

      const frontLegZ = Math.max(0, headZ - 1);
      const backLegZ = 0;

      const addLeg = (z: number) => {
          this.setCell(legX, 0, z, true);
          this.setCell(1, 1, z, true);
          if (legX === 2) this.setCell(1, 0, z, true);
      };

      addLeg(backLegZ);
      addLeg(frontLegZ);

      for(let z=1; z < length - 1; z++) {
           if (rng() > 0.6) this.setCell(1, 1, z, true);
      }
      this.applyMirrorX();
  }

  public generateLargeBeast() {
    this.clear();
    const rng = () => Math.random();
    const range = (min: number, max: number) => Math.floor(Math.random() * (max - min + 1)) + min;

    const bodyLength = range(5, 8);
    const bodyHeight = range(2, 4); 
    const zOffset = -Math.floor(bodyLength / 2);

    for (let z = 0; z < bodyLength; z++) {
        const absZ = z + zOffset;
        this.setCell(0, bodyHeight, absZ, true);
        if (rng() > 0.4) this.setCell(0, bodyHeight + 1, absZ, true);
        if (rng() > 0.4 && bodyHeight > 1) this.setCell(0, bodyHeight - 1, absZ, true);
    }

    const numLegPairs = range(2, 4); 
    const legSpacing = Math.floor(bodyLength / numLegPairs);

    for (let i = 0; i < numLegPairs; i++) {
        const zIndex = (i * legSpacing) + Math.floor(legSpacing/2);
        if (zIndex >= bodyLength) continue;

        const startZ = zIndex + zOffset;
        const startY = bodyHeight;
        const startX = 0;
        let cx = startX;
        let cy = startY;
        let cz = startZ;

        cx++;
        this.setCell(cx, cy, cz, true);

        let safety = 0;
        while (cy > 0 && safety++ < 10) {
            const moveDown = rng() > 0.3; 
            if (moveDown) cy--;
            else {
                if (rng() > 0.4) cx++; 
                else cz += (rng() > 0.5 ? 1 : -1); 
            }
            this.setCell(cx, cy, cz, true);
        }

        if (cy === 0) {
            this.setCell(cx + 1, 0, cz, true);
            this.setCell(cx - 1, 0, cz, true);
        }
    }

    const headZ = (bodyLength - 1) + zOffset + 1;
    this.setCell(0, bodyHeight + 1, headZ, true);
    this.setCell(0, bodyHeight, headZ, true);
    this.setCell(0, bodyHeight - 1, headZ, true);

    this.applyMirrorX();
  }

  public applyWorm(length: number) {
      let curr = { x: 0, y: 0, z: 0 };
      this.setCell(0, 0, 0, true);

      for(let i=0; i<length; i++) {
          const axis = Math.floor(Math.random() * 3);
          const dir = Math.random() > 0.5 ? 1 : -1;

          if (axis === 0) curr.x += dir;
          if (axis === 1) curr.y += dir;
          if (axis === 2) curr.z += dir;
          if (Math.abs(curr.x) > 4) curr.x -= dir;
          if (Math.abs(curr.y) > 4) curr.y -= dir;
          if (Math.abs(curr.z) > 4) curr.z -= dir;

          this.setCell(curr.x, curr.y, curr.z, true);
      }
  }

  public applyMirrorX() {
      const newCells = new Map<string, boolean>();
      this.cells.forEach((_, key) => {
          const [x, y, z] = key.split(',').map(Number);
          newCells.set(key, true);

          if (this.type === ShapeType.HEX) {
              const mq = -x;
              const mr = z + x; 
              newCells.set(`${mq},${y},${mr}`, true);
          } else {
             const mx = -x;
             newCells.set(`${mx},${y},${z}`, true);
          }
      });
      this.cells = newCells;
  }

  public applyFloorFill() {
      for(let x=-2; x<=2; x++) {
          for(let z=-2; z<=2; z++) {
              this.setCell(x, 0, z, true);
          }
      }
  }

  public importOrganism(org: Organism) {
      this.clear();
      this.type = org.shape || ShapeType.CUBE; 

      let needsVoxelization = false;
      for (const node of org.nodes) {
          if (node.originalGridCoord) {
              this.setCell(node.originalGridCoord.x, node.originalGridCoord.y, node.originalGridCoord.z, true);
          } else {
              needsVoxelization = true;
          }
      }

      // Fallback: If no metadata (legacy creature), try to voxelize based on position
      if (needsVoxelization) {
          org.nodes.forEach(n => {
             // Simple quantization fallback
             const x = Math.round(n.pos.x);
             const y = Math.round(n.pos.y);
             const z = Math.round(n.pos.z);
             this.setCell(x, y, z, true);
          });
      }
  }

  // --- EXPORT TO PHYSICS WITH BRAIN GRAFTING ---

  public generateOrganism(id: string, source?: Organism): Organism {
      const strategy: ILatticeStrategy = LatticeFactory.getStrategy(this.type);

      const nodes: Node[] = [];
      const muscles: Muscle[] = [];
      const coordToNodeId = new Map<string, string>();
      const createdMuscles = new Set<string>();

      const activeCoords = this.getCells();
      if (activeCoords.length === 0) {
          this.setCell(0,0,0, true);
          this.setCell(0,1,0, true);
          activeCoords.push({x:0,y:0,z:0}, {x:0,y:1,z:0});
      }

      // --- HEIGHT NORMALIZATION ---
      // Ensure the creature sits on the floor regardless of editor position
      let minY = Infinity;
      activeCoords.forEach(c => { 
          const w = strategy.gridToWorld(c, 0.8);
          if(w.y < minY) minY = w.y; 
      });
      const heightOffset = -minY + 0.1; // Slight float

      const scale = 0.8; 
      const mass = 1.0; 
      const friction = 0.8;

      // 1. Generate Nodes
      activeCoords.forEach((c) => {
          const nodeId = `n_${c.x}_${c.y}_${c.z}`;
          coordToNodeId.set(`${c.x},${c.y},${c.z}`, nodeId);

          const worldPos = strategy.gridToWorld(c, scale);
          worldPos.y += heightOffset;

          nodes.push({
              id: nodeId,
              pos: worldPos,
              oldPos: VectorOps.copy(worldPos),
              mass,
              friction,
              originalGridCoord: { x: c.x, y: c.y, z: c.z }
          });
      });

      // 2. Identify Head
      let maxZ = -Infinity;
      nodes.forEach(n => { if (n.pos.z > maxZ) maxZ = n.pos.z; });
      const candidatesZ = nodes.filter(n => Math.abs(n.pos.z - maxZ) < 0.1);
      let maxY = -Infinity;
      candidatesZ.forEach(n => { if (n.pos.y > maxY) maxY = n.pos.y; });
      let headNode = candidatesZ.find(n => Math.abs(n.pos.y - maxY) < 0.1);

      if (headNode) {
          // @ts-ignore
          headNode.isHead = true;
      }

      // Init Head Pos
      const initialHeadPos = headNode ? { ...headNode.pos } : { x: 0, y: 0, z: 0 };

      // 3. Connect Muscles using Strategy
      const addMuscle = (n1: string, n2: string, stiffness: number = 0.8) => {
          const k = [n1, n2].sort().join('-');
          if (createdMuscles.has(k)) return;

          const node1 = nodes.find(n => n.id === n1);
          const node2 = nodes.find(n => n.id === n2);
          if (!node1 || !node2) return;

          const dist = VectorOps.distance(node1.pos, node2.pos);
          muscles.push({
              id: `m_${k}`,
              nodeA: n1,
              nodeB: n2,
              baseLength: dist,
              stiffness: stiffness, 
              dnaIndex: muscles.length,
              phase: Math.random() * Math.PI * 2,
              freq: 1.0,
              amp: 0.0
          });
          createdMuscles.add(k);
      };

      activeCoords.forEach(c => {
          const myId = coordToNodeId.get(`${c.x},${c.y},${c.z}`);
          if (!myId) return;

          const neighbors = strategy.getNeighbors(c);
          neighbors.forEach(n => {
              const targetKey = `${n.coord.x},${n.coord.y},${n.coord.z}`;
              const targetId = coordToNodeId.get(targetKey);
              if (targetId) {
                  addMuscle(myId, targetId, n.distanceWeight);
              }
          });
      });

      // 5. Genome Init & Grafting
      const reservoirSize = 20;
      let genome = this.geneticOperator.createRandomGenome(muscles.length, nodes.length, reservoirSize);

      // GRAFTING: Preserve brain if shape is similar
      if (source && source.neuralGenome) {
          const oldGenome = source.neuralGenome;
          // Copy parameters
          genome = this.geneticOperator.cloneGenome(oldGenome);

          // Resize Arrays if needed (Topology change)
          const resizeWeights = (target: number[], source: number[]) => {
              for(let i=0; i<target.length; i++) {
                  if (i < source.length) target[i] = source[i];
              }
          };

          const newSyn = this.geneticOperator.createRandomGenome(muscles.length, nodes.length).synapseWeights;
          resizeWeights(newSyn, oldGenome.synapseWeights);
          genome.synapseWeights = newSyn;
      }

      return {
          id,
          shape: this.type,
          nodes,
          muscles,
          neuralGenome: genome,
          fitness: source ? source.fitness : 0,
          generation: source ? source.generation : 1,
          energy: 100,
          maxEnergy: 100,
          hungerTime: 0,
          isAlive: true,
          foodEaten: 0,
          visibleFood: [],
          initialHeadPos,
          distanceTraveled: 0
      };
  }
}

