import React, { useRef, useMemo, MutableRefObject, useEffect } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { Organism, Node, Muscle } from '../../domain/types';

// Fix for missing R3F types in JSX.IntrinsicElements
declare global {
  namespace JSX {
    interface IntrinsicElements {
      [elemName: string]: any;
    }
  }
}

interface CreatureViewProps {
  organism: Organism;
  leaderRef: MutableRefObject<Organism | null>;
  showBestOnly: boolean;
  visionRadius: number;
}

// CACHED OBJECTS
const _tempObj = new THREE.Object3D();
const _color = new THREE.Color();
const _vecA = new THREE.Vector3();
const _vecB = new THREE.Vector3();
const _mid = new THREE.Vector3();

// COLORS
const COL_RED = new THREE.Color(0xff3333);
const COL_BLUE = new THREE.Color(0x3333ff);
const COL_WHITE = new THREE.Color(0xffffff);
const COL_YELLOW = new THREE.Color(0xffff00);
const COL_HEAD = new THREE.Color(0x1a1a1a);
const COL_DEAD = new THREE.Color(0x52525b);
const COL_GRIP = new THREE.Color(0x22c55e);

export const CreatureView: React.FC<CreatureViewProps> = ({ organism, leaderRef, showBestOnly, visionRadius }) => {
  const groupRef = useRef<THREE.Group>(null);

  // Instanced Meshes
  const nodesMeshRef = useRef<THREE.InstancedMesh>(null);
  const musclesMeshRef = useRef<THREE.InstancedMesh>(null);

  // Singular items (Head indicators)
  const visionRef = useRef<THREE.Mesh>(null);
  const magnetRef = useRef<THREE.Mesh>(null);

  // Cache vector to store head position without allocations
  const headPosCache = useMemo(() => new THREE.Vector3(), []);

  // Geometries
  const nodeGeo = useMemo(() => new THREE.SphereGeometry(0.08, 6, 6), []); // Low Poly
  const muscleGeo = useMemo(() => new THREE.CylinderGeometry(0.03, 0.03, 1, 4), []); // Low Poly, Height=1 for easy scaling
  const visionGeo = useMemo(() => new THREE.SphereGeometry(1, 16, 16), []); 
  // Changed magnet to 3D Sphere for better visibility
  const magnetGeo = useMemo(() => new THREE.SphereGeometry(1.5, 16, 16), []);

  // Materials
  const nodeMat = useMemo(() => new THREE.MeshStandardMaterial({ color: 0xffffff, roughness: 0.5 }), []);
  const muscleMat = useMemo(() => new THREE.MeshStandardMaterial({ color: 0xffffff, roughness: 0.5 }), []);
  const visionMat = useMemo(() => new THREE.MeshBasicMaterial({ 
      color: 0x00ffff, transparent: true, opacity: 0.05, wireframe: true 
  }), []);
  // 3D Magnet Field Visualization
  const magnetMat = useMemo(() => new THREE.MeshBasicMaterial({
      color: 0xffff00, transparent: true, opacity: 0.1, wireframe: true
  }), []);

  // Set initial counts
  useEffect(() => {
      if (nodesMeshRef.current) nodesMeshRef.current.count = organism.nodes.length;
      if (musclesMeshRef.current) musclesMeshRef.current.count = organism.muscles.length;
  }, [organism.nodes.length, organism.muscles.length]);

  // Optimization: Pre-map node IDs to indices for fast lookup during muscle update
  const nodeIndexMap = useMemo(() => {
      const map = new Map<string, number>();
      organism.nodes.forEach((n, i) => map.set(n.id, i));
      return map;
  }, [organism.nodes]);


  useFrame((state) => {
    if (!groupRef.current) return;

    // Visibility Check
    if (showBestOnly) {
        const isLeader = leaderRef.current?.id === organism.id;
        groupRef.current.visible = isLeader;
    } else {
        groupRef.current.visible = true;
    }

    if (!groupRef.current.visible) return;

    let foundHead = false;
    const isAlive = organism.isAlive;

    // --- UPDATE NODES ---
    if (nodesMeshRef.current) {
        for (let i = 0; i < organism.nodes.length; i++) {
            const node = organism.nodes[i];

            // Transform
            _tempObj.position.set(node.pos.x, node.pos.y, node.pos.z);
            _tempObj.scale.setScalar(1);
            _tempObj.rotation.set(0,0,0);
            _tempObj.updateMatrix();
            nodesMeshRef.current.setMatrixAt(i, _tempObj.matrix);

            // Color
            if (!isAlive) {
                nodesMeshRef.current.setColorAt(i, COL_DEAD);
            } else if (node.isHead) {
                headPosCache.copy(_tempObj.position); // Store copy of position
                foundHead = true;
                nodesMeshRef.current.setColorAt(i, COL_HEAD);
            } else {
                if (node.isGripping) {
                    nodesMeshRef.current.setColorAt(i, COL_GRIP);
                } else {
                    const act = node.activation || 0;
                    _color.copy(COL_WHITE).lerp(COL_YELLOW, act);
                    nodesMeshRef.current.setColorAt(i, _color);
                }
            }
        }
        nodesMeshRef.current.instanceMatrix.needsUpdate = true;
        if (nodesMeshRef.current.instanceColor) nodesMeshRef.current.instanceColor.needsUpdate = true;
    }

    // --- UPDATE MUSCLES ---
    if (musclesMeshRef.current) {
        for (let i = 0; i < organism.muscles.length; i++) {
            const m = organism.muscles[i];
            // Lookup indices
            // We use direct array access if possible, but map is safer for partial updates
            const idxA = nodeIndexMap.get(m.nodeA);
            const idxB = nodeIndexMap.get(m.nodeB);

            if (idxA !== undefined && idxB !== undefined) {
                const nA = organism.nodes[idxA];
                const nB = organism.nodes[idxB];

                _vecA.set(nA.pos.x, nA.pos.y, nA.pos.z);
                _vecB.set(nB.pos.x, nB.pos.y, nB.pos.z);

                // Math to orient cylinder
                _mid.copy(_vecA).add(_vecB).multiplyScalar(0.5);
                const len = _vecA.distanceTo(_vecB);

                _tempObj.position.copy(_mid);
                _tempObj.lookAt(_vecB);
                _tempObj.rotateX(Math.PI / 2); // Align cylinder Y-axis to LookAt Z-axis
                _tempObj.scale.set(1, len, 1);
                _tempObj.updateMatrix();

                musclesMeshRef.current.setMatrixAt(i, _tempObj.matrix);

                // Color
                if (!isAlive) {
                    musclesMeshRef.current.setColorAt(i, COL_DEAD);
                } else {
                    const target = m.targetLength || m.baseLength;
                    const ratio = target / m.baseLength;
                    if (ratio < 0.98) {
                        _color.copy(COL_WHITE).lerp(COL_RED, Math.min(1, (1 - ratio) * 5));
                    } else if (ratio > 1.02) {
                        _color.copy(COL_WHITE).lerp(COL_BLUE, Math.min(1, (ratio - 1) * 5));
                    } else {
                        _color.copy(COL_WHITE);
                    }
                    musclesMeshRef.current.setColorAt(i, _color);
                }
            }
        }
        musclesMeshRef.current.instanceMatrix.needsUpdate = true;
        if (musclesMeshRef.current.instanceColor) musclesMeshRef.current.instanceColor.needsUpdate = true;
    }

    // --- UPDATE SINGULAR MESHES ---
    if (foundHead && isAlive) {
        if (visionRef.current) {
            visionRef.current.position.copy(headPosCache);
            // No more pulsation, strict radius
            visionRef.current.scale.setScalar(visionRadius);
            visionRef.current.visible = true;
        }
        if (magnetRef.current) {
            magnetRef.current.position.copy(headPosCache);
            magnetRef.current.visible = true;
            // 3D sphere doesn't need specific rotation, but keeps position
        }
    } else {
        if (visionRef.current) visionRef.current.visible = false;
        if (magnetRef.current) magnetRef.current.visible = false;
    }
  });

  return (
    <group ref={groupRef}>
      <mesh ref={visionRef} geometry={visionGeo} material={visionMat} />
      <mesh ref={magnetRef} geometry={magnetGeo} material={magnetMat} />

      {/* INSTANCED NODES */}
      <instancedMesh 
        ref={nodesMeshRef} 
        args={[nodeGeo, nodeMat, organism.nodes.length]}
        frustumCulled={false}
      />

      {/* INSTANCED MUSCLES */}
      <instancedMesh 
        ref={musclesMeshRef} 
        args={[muscleGeo, muscleMat, organism.muscles.length]}
        frustumCulled={false}
      />
    </group>
  );
};

import React, { useRef, MutableRefObject } from 'react';
import { Canvas, useFrame, useThree } from '@react-three/fiber';
import { OrbitControls, Grid, PerspectiveCamera } from '@react-three/drei';
import { Organism } from '../../domain/types';
import { CreatureView } from './CreatureView';
import { FoodView } from './FoodView';
import * as THREE from 'three';
import { OrbitControls as OrbitControlsImpl } from 'three-stdlib';

// Fix for missing R3F types in JSX.IntrinsicElements
declare global {
  namespace JSX {
    interface IntrinsicElements {
      [elemName: string]: any;
    }
  }
}

interface LabSceneProps {
  population: Organism[];
  showBestOnly: boolean;
  visionRadius: number;
}

// COMPONENT: LeaderTracker
// Calculates the current "Leader" (Alive + Furthest Z) every frame and updates the ref.
// This ensures Camera, Food, and Visibility all use the exact same target.
const LeaderTracker: React.FC<{ 
    population: Organism[], 
    leaderRef: MutableRefObject<Organism | null> 
}> = ({ population, leaderRef }) => {
    useFrame(() => {
        if (!population.length) return;

        // Strategy: 
        // 1. Find Best Alive
        // 2. If no Alive, Find Best Dead

        let bestAlive: Organism | null = null;
        let maxZAlive = -Infinity;

        let bestDead: Organism | null = null;
        let maxZDead = -Infinity;

        for (const org of population) {
            let cz = 0;
            for(const n of org.nodes) cz += n.pos.z;
            cz /= org.nodes.length;

            if (org.isAlive) {
                if (cz > maxZAlive) { maxZAlive = cz; bestAlive = org; }
            } else {
                if (cz > maxZDead) { maxZDead = cz; bestDead = org; }
            }
        }

        leaderRef.current = bestAlive || bestDead || population[0];
    });
    return null;
};

// COMPONENT: CameraDirector
// Follows the Organism inside leaderRef
const CameraDirector: React.FC<{ leaderRef: MutableRefObject<Organism | null> }> = ({ leaderRef }) => {
    const { camera } = useThree();
    const controlsRef = useRef<OrbitControlsImpl>(null);
    const targetRef = useRef(new THREE.Vector3(0, 0, 0));

    useFrame(() => {
        const leader = leaderRef.current;
        if (!leader) return;

        // Calculate Target Position
        let cx = 0, cy = 0, cz = 0;
        const len = leader.nodes.length;
        for (const n of leader.nodes) {
            cx += n.pos.x;
            cy += n.pos.y;
            cz += n.pos.z;
        }
        const center = new THREE.Vector3(cx/len, cy/len, cz/len);

        // Smoothly Interpolate Camera & Target
        targetRef.current.lerp(center, 0.1);

        if (controlsRef.current) {
            const offset = camera.position.clone().sub(controlsRef.current.target);
            controlsRef.current.target.copy(targetRef.current);
            camera.position.copy(targetRef.current).add(offset);
            controlsRef.current.update();
        }
    });

    return <OrbitControls ref={controlsRef} makeDefault maxPolarAngle={Math.PI / 2 - 0.1} />;
};

export const LabScene: React.FC<LabSceneProps> = ({ population, showBestOnly, visionRadius }) => {
  const leaderRef = useRef<Organism | null>(null);

  return (
    <div className="w-full h-full bg-slate-900">
      <Canvas shadows dpr={[1, 2]}>
        <PerspectiveCamera makeDefault position={[10, 8, 10]} fov={45} />

        <LeaderTracker population={population} leaderRef={leaderRef} />
        <CameraDirector leaderRef={leaderRef} />

        <ambientLight intensity={0.6} />
        <directionalLight 
          position={[20, 30, 10]} 
          intensity={1.5} 
          castShadow 
          shadow-mapSize={[2048, 2048]} 
        />

        <group>
            {population.map((org) => {
                return (
                  <CreatureView 
                    key={org.id} 
                    organism={org} 
                    leaderRef={leaderRef}
                    showBestOnly={showBestOnly}
                    visionRadius={visionRadius}
                  />
                );
            })}
        </group>

        <FoodView leaderRef={leaderRef} />

        {/* Floor Grid */}
        <Grid 
            position={[0, -0.01, 0]} 
            args={[200, 200]} 
            cellColor="#5c4d3c" 
            sectionColor="#7f675b" 
            fadeDistance={60}
            infiniteGrid
        />
        <mesh rotation={[-Math.PI / 2, 0, 0]} position={[0, -0.05, 0]} receiveShadow>
          <planeGeometry args={[1000, 1000]} />
          <meshStandardMaterial color="#3f2e22" roughness={0.9} metalness={0.1} />
        </mesh>

      </Canvas>
    </div>
  );
};

import React, { useState, useRef, useMemo } from 'react';
import { Canvas } from '@react-three/fiber';
import { OrbitControls, Grid, PerspectiveCamera } from '@react-three/drei';
import { LabScene } from './src/infrastructure/visuals/LabScene';
import { Dashboard } from './src/ui/Dashboard';
import { useEvolutionLoop } from './src/application/useEvolutionLoop';
import { BlueprintViewUpdated } from './src/infrastructure/visuals/BlueprintViewUpdated';
import { ArchitectControls } from './src/ui/ArchitectControls';
import { BlueprintService } from './src/domain/BlueprintService';
import { ShapeType, Organism } from './src/domain/types';

export type EditorTool = 'VIEW' | 'BUILD' | 'ERASE';

function App() {
  const {
    population,
    generation,
    currentStats,
    isRunning,
    isAutoEvolving,
    isProcessing,
    progress,
    currentShape,
    globalStiffness,
    globalContractility,
    setGlobalStiffness,
    setGlobalContractility,
    foodWeight,
    distanceWeight,
    setFoodWeight,
    setDistanceWeight,
    foodSpawnCount,
    setFoodSpawnCount,
    foodSpawnRadius,
    setFoodSpawnRadius,
    visionRadius,
    setVisionRadius,
    setIsRunning,
    toggleAutoEvolve, 
    reset,
    evolve,
    spawnCustom,
    saveCreature,
    loadCreature
  } = useEvolutionLoop();

  const [mode, setMode] = useState<'LAB' | 'ARCHITECT'>('LAB');
  const [showBestOnly, setShowBestOnly] = useState(false);

  // Architect State
  const blueprintService = useMemo(() => new BlueprintService(), []);
  const [blueprintCells, setBlueprintCells] = useState(blueprintService.getCells());
  const [archType, setArchType] = useState(ShapeType.CUBE);
  const [editorTool, setEditorTool] = useState<EditorTool>('VIEW');

  // TRACKING FOR EDITING
  const [editingOrganism, setEditingOrganism] = useState<Organism | undefined>(undefined);

  // --- HANDLERS ---

  const handleLoad = (file: File) => {
      loadCreature(file, (org) => {
          // Sync Architect State
          blueprintService.importOrganism(org);
          setBlueprintCells(blueprintService.getCells());
          setArchType(org.shape || ShapeType.CUBE);

          // Store for potential editing
          setEditingOrganism(org);
      });
  };

  const handleArchCellClick = (x: number, y: number, z: number, isRight: boolean) => {
      // Logic handled in view, but we update state here
      if (isRight) {
          blueprintService.setCell(x, y, z, false);
      } else {
          blueprintService.setCell(x, y, z, true);
      }
      setBlueprintCells(blueprintService.getCells());
  };

  const handleArchGenerate = (type: string) => {
      // If we generate a new random template, we clear the "editing" link
      setEditingOrganism(undefined);

      if (type === 'small') blueprintService.generateSmallCritter();
      if (type === 'large') blueprintService.generateLargeBeast();
      if (type === 'procedural') blueprintService.generateLargeBeast(); 

      if (type === 'floor') blueprintService.applyFloorFill();
      if (type === 'worm') blueprintService.applyWorm(8);
      if (type === 'mirror') blueprintService.applyMirrorX();

      setBlueprintCells(blueprintService.getCells());
  };

  const handleArchType = (t: ShapeType) => {
      setArchType(t);
      blueprintService.setType(t);
      setBlueprintCells([...blueprintService.getCells()]);
  };

  const handleSpawn = () => {
      // Pass editingOrganism as source to preserve brain
      const organism = blueprintService.generateOrganism('custom_proto', editingOrganism);
      spawnCustom(organism);
      setMode('LAB');
  };

  const handleClear = () => {
      blueprintService.clear();
      setBlueprintCells([]);
      setEditingOrganism(undefined);
  };

  return (
    <div className="relative w-full h-full bg-slate-900">

      {/* MODE TOGGLE */}
      <div className="absolute top-4 right-1/2 translate-x-1/2 z-10 flex bg-slate-800 rounded-full p-1 border border-slate-700">
          <button 
            onClick={() => setMode('LAB')}
            className={`px-4 py-1 rounded-full text-xs font-bold transition-all ${mode === 'LAB' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-white'}`}
          >
              LAB
          </button>
          <button 
            onClick={() => setMode('ARCHITECT')}
            className={`px-4 py-1 rounded-full text-xs font-bold transition-all ${mode === 'ARCHITECT' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-white'}`}
          >
              ARCHITECT
          </button>
      </div>

      {mode === 'LAB' ? (
          <>
            <LabScene 
                population={population} 
                showBestOnly={showBestOnly}
                visionRadius={visionRadius}
            />
            <Dashboard 
                generation={generation}
                currentStats={currentStats}
                isRunning={isRunning}
                isAutoEvolving={isAutoEvolving}
                isProcessing={isProcessing}
                progress={progress}
                currentShape={currentShape}
                onReset={reset}
                onToggleRun={() => setIsRunning(!isRunning)}
                onToggleAutoEvolve={toggleAutoEvolve} 
                showBestOnly={showBestOnly}
                setShowBestOnly={setShowBestOnly}
                // New Controls
                globalStiffness={globalStiffness}
                setGlobalStiffness={setGlobalStiffness}
                globalContractility={globalContractility}
                setGlobalContractility={setGlobalContractility}
                // Fitness Controls
                foodWeight={foodWeight}
                setFoodWeight={setFoodWeight}
                distanceWeight={distanceWeight}
                setDistanceWeight={setDistanceWeight}
                // Scarcity Controls
                foodSpawnCount={foodSpawnCount}
                setFoodSpawnCount={setFoodSpawnCount}
                foodSpawnRadius={foodSpawnRadius}
                setFoodSpawnRadius={setFoodSpawnRadius}
                // Vision Controls
                visionRadius={visionRadius}
                setVisionRadius={setVisionRadius}
                // IO
                onSave={saveCreature}
                onLoad={handleLoad}
            />
            {/* Instruction Toast */}
            {!isRunning && generation === 1 && !isAutoEvolving && (
                <div className="absolute bottom-10 left-1/2 -translate-x-1/2 bg-black/50 text-white px-4 py-2 rounded-full backdrop-blur text-sm pointer-events-none animate-pulse">
                    Press RESUME to start the simulation
                </div>
            )}
          </>
      ) : (
          <>
            {/* ARCHITECT 3D VIEW */}
            <div className={`w-full h-full ${editorTool === 'VIEW' ? 'cursor-move' : 'cursor-crosshair'}`}>
                <Canvas shadows dpr={[1, 2]}>
                    <PerspectiveCamera makeDefault position={[8, 8, 8]} fov={45} />
                    <OrbitControls makeDefault target={[0, 0, 0]} enabled={true} />
                    <BlueprintViewUpdated
                        cells={blueprintCells} 
                        onCellClick={handleArchCellClick}
                        currentType={archType}
                        editorTool={editorTool}
                    />
                </Canvas>
            </div>

            <ArchitectControls 
                onClear={handleClear}
                onSetType={handleArchType}
                onGenerate={handleArchGenerate}
                onSpawn={handleSpawn}
                currentType={archType}
                cellCount={blueprintCells.length}
                editorTool={editorTool}
                setEditorTool={setEditorTool}
            />
          </>
      )}

    </div>
  );
}

export default App;

import React, { useRef, useMemo, MutableRefObject, useEffect } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { Organism, Node, Muscle } from '../../domain/types';

interface CreatureViewProps {
  organism: Organism;
  leaderRef: MutableRefObject<Organism | null>;
  showBestOnly: boolean;
  visionRadius: number;
}

// CACHED OBJECTS
const _tempObj = new THREE.Object3D();
const _color = new THREE.Color();
const _vecA = new THREE.Vector3();
const _vecB = new THREE.Vector3();
const _mid = new THREE.Vector3();

// COLORS
const COL_RED = new THREE.Color(0xff3333);
const COL_BLUE = new THREE.Color(0x3333ff);
const COL_WHITE = new THREE.Color(0xffffff);
const COL_YELLOW = new THREE.Color(0xffff00);
const COL_HEAD = new THREE.Color(0x1a1a1a);
const COL_DEAD = new THREE.Color(0x52525b);
const COL_GRIP = new THREE.Color(0x22c55e);

export const CreatureView: React.FC<CreatureViewProps> = ({ organism, leaderRef, showBestOnly, visionRadius }) => {
  const groupRef = useRef<THREE.Group>(null);

  // Instanced Meshes
  const nodesMeshRef = useRef<THREE.InstancedMesh>(null);
  const musclesMeshRef = useRef<THREE.InstancedMesh>(null);

  // Singular items (Head indicators)
  const visionRef = useRef<THREE.Mesh>(null);
  const magnetRef = useRef<THREE.Mesh>(null);

  // Cache vector to store head position without allocations
  const headPosCache = useMemo(() => new THREE.Vector3(), []);

  // Geometries
  const nodeGeo = useMemo(() => new THREE.SphereGeometry(0.08, 6, 6), []); // Low Poly
  const muscleGeo = useMemo(() => new THREE.CylinderGeometry(0.03, 0.03, 1, 4), []); // Low Poly, Height=1 for easy scaling
  const visionGeo = useMemo(() => new THREE.SphereGeometry(1, 16, 16), []); 
  // Changed magnet to 3D Sphere for better visibility
  const magnetGeo = useMemo(() => new THREE.SphereGeometry(1.5, 16, 16), []);

  // Materials
  const nodeMat = useMemo(() => new THREE.MeshStandardMaterial({ color: 0xffffff, roughness: 0.5 }), []);
  const muscleMat = useMemo(() => new THREE.MeshStandardMaterial({ color: 0xffffff, roughness: 0.5 }), []);
  const visionMat = useMemo(() => new THREE.MeshBasicMaterial({ 
      color: 0x00ffff, transparent: true, opacity: 0.05, wireframe: true 
  }), []);
  // 3D Magnet Field Visualization
  const magnetMat = useMemo(() => new THREE.MeshBasicMaterial({
      color: 0xffff00, transparent: true, opacity: 0.1, wireframe: true
  }), []);

  // Set initial counts
  useEffect(() => {
      if (nodesMeshRef.current) nodesMeshRef.current.count = organism.nodes.length;
      if (musclesMeshRef.current) musclesMeshRef.current.count = organism.muscles.length;
  }, [organism.nodes.length, organism.muscles.length]);

  // Optimization: Pre-map node IDs to indices for fast lookup during muscle update
  const nodeIndexMap = useMemo(() => {
      const map = new Map<string, number>();
      organism.nodes.forEach((n, i) => map.set(n.id, i));
      return map;
  }, [organism.nodes]);


  useFrame((state) => {
    if (!groupRef.current) return;

    // Visibility Check
    if (showBestOnly) {
        const isLeader = leaderRef.current?.id === organism.id;
        groupRef.current.visible = isLeader;
    } else {
        groupRef.current.visible = true;
    }

    if (!groupRef.current.visible) return;

    let foundHead = false;
    const isAlive = organism.isAlive;

    // --- UPDATE NODES ---
    if (nodesMeshRef.current) {
        for (let i = 0; i < organism.nodes.length; i++) {
            const node = organism.nodes[i];

            // Transform
            _tempObj.position.set(node.pos.x, node.pos.y, node.pos.z);
            _tempObj.scale.setScalar(1);
            _tempObj.rotation.set(0,0,0);
            _tempObj.updateMatrix();
            nodesMeshRef.current.setMatrixAt(i, _tempObj.matrix);

            // Color
            if (!isAlive) {
                nodesMeshRef.current.setColorAt(i, COL_DEAD);
            } else if (node.isHead) {
                headPosCache.copy(_tempObj.position); // Store copy of position
                foundHead = true;
                nodesMeshRef.current.setColorAt(i, COL_HEAD);
            } else {
                if (node.isGripping) {
                    nodesMeshRef.current.setColorAt(i, COL_GRIP);
                } else {
                    const act = node.activation || 0;
                    _color.copy(COL_WHITE).lerp(COL_YELLOW, act);
                    nodesMeshRef.current.setColorAt(i, _color);
                }
            }
        }
        nodesMeshRef.current.instanceMatrix.needsUpdate = true;
        if (nodesMeshRef.current.instanceColor) nodesMeshRef.current.instanceColor.needsUpdate = true;
    }

    // --- UPDATE MUSCLES ---
    if (musclesMeshRef.current) {
        for (let i = 0; i < organism.muscles.length; i++) {
            const m = organism.muscles[i];
            // Lookup indices
            // We use direct array access if possible, but map is safer for partial updates
            const idxA = nodeIndexMap.get(m.nodeA);
            const idxB = nodeIndexMap.get(m.nodeB);

            if (idxA !== undefined && idxB !== undefined) {
                const nA = organism.nodes[idxA];
                const nB = organism.nodes[idxB];

                _vecA.set(nA.pos.x, nA.pos.y, nA.pos.z);
                _vecB.set(nB.pos.x, nB.pos.y, nB.pos.z);

                // Math to orient cylinder
                _mid.copy(_vecA).add(_vecB).multiplyScalar(0.5);
                const len = _vecA.distanceTo(_vecB);

                _tempObj.position.copy(_mid);
                _tempObj.lookAt(_vecB);
                _tempObj.rotateX(Math.PI / 2); // Align cylinder Y-axis to LookAt Z-axis
                _tempObj.scale.set(1, len, 1);
                _tempObj.updateMatrix();

                musclesMeshRef.current.setMatrixAt(i, _tempObj.matrix);

                // Color
                if (!isAlive) {
                    musclesMeshRef.current.setColorAt(i, COL_DEAD);
                } else {
                    const target = m.targetLength || m.baseLength;
                    const ratio = target / m.baseLength;
                    if (ratio < 0.98) {
                        _color.copy(COL_WHITE).lerp(COL_RED, Math.min(1, (1 - ratio) * 5));
                    } else if (ratio > 1.02) {
                        _color.copy(COL_WHITE).lerp(COL_BLUE, Math.min(1, (ratio - 1) * 5));
                    } else {
                        _color.copy(COL_WHITE);
                    }
                    musclesMeshRef.current.setColorAt(i, _color);
                }
            }
        }
        musclesMeshRef.current.instanceMatrix.needsUpdate = true;
        if (musclesMeshRef.current.instanceColor) musclesMeshRef.current.instanceColor.needsUpdate = true;
    }

    // --- UPDATE SINGULAR MESHES ---
    if (foundHead && isAlive) {
        if (visionRef.current) {
            visionRef.current.position.copy(headPosCache);
            // No more pulsation, strict radius
            visionRef.current.scale.setScalar(visionRadius);
            visionRef.current.visible = true;
        }
        if (magnetRef.current) {
            magnetRef.current.position.copy(headPosCache);
            magnetRef.current.visible = true;
            // 3D sphere doesn't need specific rotation, but keeps position
        }
    } else {
        if (visionRef.current) visionRef.current.visible = false;
        if (magnetRef.current) magnetRef.current.visible = false;
    }
  });

  return (
    <group ref={groupRef}>
      <mesh ref={visionRef} geometry={visionGeo} material={visionMat} />
      <mesh ref={magnetRef} geometry={magnetGeo} material={magnetMat} />

      {/* INSTANCED NODES */}
      <instancedMesh 
        ref={nodesMeshRef} 
        args={[nodeGeo, nodeMat, organism.nodes.length]}
        frustumCulled={false}
      />

      {/* INSTANCED MUSCLES */}
      <instancedMesh 
        ref={musclesMeshRef} 
        args={[muscleGeo, muscleMat, organism.muscles.length]}
        frustumCulled={false}
      />
    </group>
  );
};

import React, { useRef, MutableRefObject } from 'react';
import { Canvas, useFrame, useThree } from '@react-three/fiber';
import { OrbitControls, Grid, PerspectiveCamera } from '@react-three/drei';
import { Organism } from '../../domain/types';
import { CreatureView } from './CreatureView';
import { FoodView } from './FoodView';
import * as THREE from 'three';
import { OrbitControls as OrbitControlsImpl } from 'three-stdlib';

interface LabSceneProps {
  population: Organism[];
  showBestOnly: boolean;
  visionRadius: number;
}

// COMPONENT: LeaderTracker
// Calculates the current "Leader" (Alive + Furthest Z) every frame and updates the ref.
// This ensures Camera, Food, and Visibility all use the exact same target.
const LeaderTracker: React.FC<{ 
    population: Organism[], 
    leaderRef: MutableRefObject<Organism | null> 
}> = ({ population, leaderRef }) => {
    useFrame(() => {
        if (!population.length) return;

        // Strategy: 
        // 1. Find Best Alive
        // 2. If no Alive, Find Best Dead

        let bestAlive: Organism | null = null;
        let maxZAlive = -Infinity;

        let bestDead: Organism | null = null;
        let maxZDead = -Infinity;

        for (const org of population) {
            let cz = 0;
            for(const n of org.nodes) cz += n.pos.z;
            cz /= org.nodes.length;

            if (org.isAlive) {
                if (cz > maxZAlive) { maxZAlive = cz; bestAlive = org; }
            } else {
                if (cz > maxZDead) { maxZDead = cz; bestDead = org; }
            }
        }

        leaderRef.current = bestAlive || bestDead || population[0];
    });
    return null;
};

// COMPONENT: CameraDirector
// Follows the Organism inside leaderRef
const CameraDirector: React.FC<{ leaderRef: MutableRefObject<Organism | null> }> = ({ leaderRef }) => {
    const { camera } = useThree();
    const controlsRef = useRef<OrbitControlsImpl>(null);
    const targetRef = useRef(new THREE.Vector3(0, 0, 0));

    useFrame(() => {
        const leader = leaderRef.current;
        if (!leader) return;

        // Calculate Target Position
        let cx = 0, cy = 0, cz = 0;
        const len = leader.nodes.length;
        for (const n of leader.nodes) {
            cx += n.pos.x;
            cy += n.pos.y;
            cz += n.pos.z;
        }
        const center = new THREE.Vector3(cx/len, cy/len, cz/len);

        // Smoothly Interpolate Camera & Target
        targetRef.current.lerp(center, 0.1);

        if (controlsRef.current) {
            const offset = camera.position.clone().sub(controlsRef.current.target);
            controlsRef.current.target.copy(targetRef.current);
            camera.position.copy(targetRef.current).add(offset);
            controlsRef.current.update();
        }
    });

    return <OrbitControls ref={controlsRef} makeDefault maxPolarAngle={Math.PI / 2 - 0.1} />;
};

export const LabScene: React.FC<LabSceneProps> = ({ population, showBestOnly, visionRadius }) => {
  const leaderRef = useRef<Organism | null>(null);

  return (
    <div className="w-full h-full bg-slate-900">
      <Canvas shadows dpr={[1, 2]}>
        <PerspectiveCamera makeDefault position={[10, 8, 10]} fov={45} />

        <LeaderTracker population={population} leaderRef={leaderRef} />
        <CameraDirector leaderRef={leaderRef} />

        <ambientLight intensity={0.6} />
        <directionalLight 
          position={[20, 30, 10]} 
          intensity={1.5} 
          castShadow 
          shadow-mapSize={[2048, 2048]} 
        />

        <group>
            {population.map((org) => {
                return (
                  <CreatureView 
                    key={org.id} 
                    organism={org} 
                    leaderRef={leaderRef}
                    showBestOnly={showBestOnly}
                    visionRadius={visionRadius}
                  />
                );
            })}
        </group>

        <FoodView leaderRef={leaderRef} />

        {/* Floor Grid */}
        <Grid 
            position={[0, -0.01, 0]} 
            args={[200, 200]} 
            cellColor="#5c4d3c" 
            sectionColor="#7f675b" 
            fadeDistance={60}
            infiniteGrid
        />
        <mesh rotation={[-Math.PI / 2, 0, 0]} position={[0, -0.05, 0]} receiveShadow>
          <planeGeometry args={[1000, 1000]} />
          <meshStandardMaterial color="#3f2e22" roughness={0.9} metalness={0.1} />
        </mesh>

      </Canvas>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { useThree } from '@react-three/fiber';
import { GridCoord, ShapeType } from '../../domain/types';
import * as THREE from 'three';

// Helper to convert axial to pixel (for rendering hexes)
const hexToPixel = (q: number, r: number, size: number = 0.5) => {
    const x = size * 1.5 * q;
    const z = size * Math.sqrt(3) * (r + q/2);
    return { x, z };
};

// Neighbor directions for Hexagons (Axial)
const HEX_NEIGHBORS = [
    {q: 1, r: 0}, {q: 1, r: -1}, {q: 0, r: -1},
    {q: -1, r: 0}, {q: -1, r: 1}, {q: 0, r: 1}
];

export const BlueprintViewUpdated: React.FC<{
    cells: GridCoord[]; 
    onCellClick: (x: number, y: number, z: number, isRight: boolean) => void;
    currentType: ShapeType;
}> = ({ cells, onCellClick, currentType }) => {

  const { camera, raycaster, pointer, scene } = useThree();
  const [hoverCoord, setHoverCoord] = useState<GridCoord | null>(null);

  const boxGeo = useMemo(() => new THREE.BoxGeometry(0.8, 0.8, 0.8), []);
  const hexGeo = useMemo(() => new THREE.CylinderGeometry(0.45, 0.45, 0.5, 6), []); // Taller prism

  const material = useMemo(() => new THREE.MeshStandardMaterial({ color: '#3b82f6', roughness: 0.3 }), []);
  const materialHex = useMemo(() => new THREE.MeshStandardMaterial({ color: '#8b5cf6', roughness: 0.3 }), []);

  const hoverMaterial = useMemo(() => new THREE.MeshStandardMaterial({ color: '#facc15', transparent: true, opacity: 0.5 }), []);

  const handlePointerMove = (e: any) => {
      raycaster.setFromCamera(pointer, camera);
      const intersects = raycaster.intersectObjects(scene.children, true);

      let hitPoint: THREE.Vector3 | null = null;
      let hitNormal: THREE.Vector3 | null = null;
      let hitObject: THREE.Object3D | null = null;

      for (const hit of intersects) {
          if (hit.object.name.startsWith('voxel') || hit.object.name === 'base_plane') {
              hitPoint = hit.point;
              hitNormal = hit.face?.normal || new THREE.Vector3(0,1,0);
              hitObject = hit.object;
              break;
          }
      }

      if (hitPoint) {
          if (currentType === ShapeType.HEX) {
              // --- HEX LOGIC ---
              if (hitObject?.name === 'voxel_hex') {
                  const data = hitObject.userData as GridCoord;

                  // Transform world normal to local rotation of the hex mesh?
                  // Our hex meshes are rotated 30 deg (PI/6) on Y usually, or not.
                  // Simpler: Check Up/Down first.

                  // Convert normal to world space if needed (usually face normal is local to geometry, but raycaster returns world? No, raycaster face.normal is local?)
                  // THREE.Raycaster returns face normal in object space (usually). 
                  // But we need to be careful. Let's rely on hitPoint relative to object center.

                  const relX = hitPoint.x - hitObject.position.x;
                  const relY = hitPoint.y - hitObject.position.y;
                  const relZ = hitPoint.z - hitObject.position.z;

                  // 1. Vertical Stacking (Top/Bottom Faces)
                  // The Cylinder is 0.5 high. So Top is ~0.25, Bottom ~ -0.25
                  if (relY > 0.23) {
                      setHoverCoord({ x: data.x, y: data.y + 1, z: data.z });
                      return;
                  }
                  if (relY < -0.23) {
                       setHoverCoord({ x: data.x, y: data.y - 1, z: data.z });
                       return;
                  }

                  // 2. Horizontal Neighbors (Side Faces)
                  // We need to map the hit vector angle to the 6 neighbor directions.
                  // Angle in X/Z plane.
                  const angle = Math.atan2(relZ, relX); // -PI to PI
                  // Convert to degrees for easier debugging mental model: -180 to 180
                  // Hex flat sides are at 0, 60, 120... or 30, 90, 150 depending on rotation.
                  // Our mesh has rotation [0, Math.PI/6, 0].

                  // Simple brute force: Find which neighbor center is closest to hitPoint (projected to plane)
                  const size = 0.6;
                  let bestNeigh = null;
                  let minD = Infinity;

                  HEX_NEIGHBORS.forEach(n => {
                       const pos = hexToPixel(data.x + n.q, data.z + n.r, size);
                       // We compare world positions
                       const wx = pos.x; 
                       const wz = pos.z; 

                       const dx = wx - hitPoint!.x;
                       const dz = wz - hitPoint!.z;
                       const d = dx*dx + dz*dz;
                       if (d < minD) {
                           minD = d;
                           bestNeigh = n;
                       }
                  });

                  if (bestNeigh) {
                      setHoverCoord({ x: data.x + bestNeigh.q, y: data.y, z: data.z + bestNeigh.r });
                  }

              } else {
                  // Hit Floor (Y=0 plane)
                  // Map X/Z to Hex Grid
                  // We need to invert the hexToPixel math.
                  const size = 0.6;
                  const q = (2./3 * hitPoint.x) / size;
                  const r = (-1./3 * hitPoint.x + Math.sqrt(3)/3 * hitPoint.z) / size;

                  // Round to nearest Hex
                  let rx = Math.round(q);
                  let rz = Math.round(r);
                  let ry = Math.round(-q-r);

                  const x_diff = Math.abs(rx - q);
                  const y_diff = Math.abs(ry - (-q-r));
                  const z_diff = Math.abs(rz - r);

                  if (x_diff > y_diff && x_diff > z_diff) {
                      rx = -ry-rz;
                  } else if (y_diff > z_diff) {
                      // ry = -rx-rz; 
                  } else {
                      rz = -rx-ry;
                  }

                  setHoverCoord({ x: rx, y: 0, z: rz });
              }

          } else {
              // --- CUBE/TETRA LOGIC ---
              if (hitObject?.name.startsWith('voxel')) {
                 const nx = hitNormal!.x;
                 const ny = hitNormal!.y;
                 const nz = hitNormal!.z;
                 const p = hitObject.position;
                 setHoverCoord({
                     x: Math.round(p.x + nx),
                     y: Math.round(p.y + ny),
                     z: Math.round(p.z + nz)
                 });
              } else {
                 // Hit floor
                 setHoverCoord({
                     x: Math.round(hitPoint.x),
                     y: 0,
                     z: Math.round(hitPoint.z)
                 });
              }
          }
      } else {
          setHoverCoord(null);
      }
  };

  const handleClick = (e: any) => {
      e.stopPropagation();
      // If Right click on existing voxel
      // We need to raycast specifically for existing objects to get the one to delete
      if (e.button === 2) {
         raycaster.setFromCamera(pointer, camera);
         const intersects = raycaster.intersectObjects(scene.children, true);
         for(const hit of intersects) {
             if (hit.object.name.startsWith('voxel')) {
                 const userData = hit.object.userData as GridCoord;
                 onCellClick(userData.x, userData.y, userData.z, true);
                 return;
             }
         }
      }

      if (hoverCoord) {
          onCellClick(hoverCoord.x, hoverCoord.y, hoverCoord.z, false);
      }
  };

  return (
    <group 
        onPointerMove={handlePointerMove} 
        onClick={handleClick}
        onContextMenu={handleClick}
    >
      <ambientLight intensity={0.8} />
      <directionalLight position={[5, 10, 5]} intensity={1.5} />

      {cells.map(c => {
          if (currentType === ShapeType.HEX) {
              const {x, z} = hexToPixel(c.x, c.z, 0.6);
              // Vertical Spacing for Cylinders (Height 0.5)
              // Gap is small or zero. Let's say 0.5 height, positioned at y * 0.5 + 0.25
              const hexHeight = 0.5;
              const yPos = c.y * hexHeight + (hexHeight/2);

              return (
                  <mesh 
                    key={`${c.x},${c.y},${c.z}`}
                    position={[x, yPos, z]}
                    geometry={hexGeo}
                    material={materialHex}
                    name="voxel_hex"
                    userData={c}
                    rotation={[0, Math.PI/6, 0]} // Pointy top orientation
                  />
              );
          } else {
              return (
                <mesh 
                    key={`${c.x},${c.y},${c.z}`}
                    position={[c.x, c.y, c.z]} 
                    geometry={boxGeo} 
                    material={material}
                    name="voxel_cube"
                    userData={c}
                />
              );
          }
      })}

      {hoverCoord && (
         <group>
             {currentType === ShapeType.HEX ? (
                 <mesh 
                    position={[
                        hexToPixel(hoverCoord.x, hoverCoord.z, 0.6).x, 
                        hoverCoord.y * 0.5 + 0.25, 
                        hexToPixel(hoverCoord.x, hoverCoord.z, 0.6).z
                    ]} 
                    geometry={hexGeo} 
                    material={hoverMaterial}
                    rotation={[0, Math.PI/6, 0]}
                 />
             ) : (
                 <mesh 
                    position={[hoverCoord.x, hoverCoord.y, hoverCoord.z]} 
                    geometry={boxGeo} 
                    material={hoverMaterial} 
                    pointerEvents="none" 
                 />
             )}
         </group>
      )}

      {/* Base Plane for Raycasting */}
      <mesh rotation={[-Math.PI / 2, 0, 0]} position={[0, -0.5, 0]} name="base_plane" visible={false}>
          <planeGeometry args={[40, 40]} />
      </mesh>

      {currentType === ShapeType.HEX ? (
           <gridHelper args={[20, 20, 0x444444, 0x111111]} position={[0, -0.01, 0]} />
      ) : (
           <gridHelper args={[20, 20, 0x444444, 0x222222]} position={[0, -0.5, 0]} />
      )}

    </group>
  );
};

import React, { useRef, useMemo, MutableRefObject } from 'react';
import { useFrame } from '@react-three/fiber';
import { Organism } from '../../domain/types';
import * as THREE from 'three';

interface FoodViewProps {
    leaderRef: MutableRefObject<Organism | null>;
}

export const FoodView: React.FC<FoodViewProps> = ({ leaderRef }) => {
    const meshRef = useRef<THREE.InstancedMesh>(null);
    const tempObj = useMemo(() => new THREE.Object3D(), []);

    // Geometry/Material
    const geo = useMemo(() => new THREE.IcosahedronGeometry(0.15, 0), []);
    const mat = useMemo(() => new THREE.MeshStandardMaterial({ 
        color: '#4ade80', 
        emissive: '#22c55e',
        emissiveIntensity: 0.6,
        roughness: 0.2
    }), []);

    useFrame((state) => {
        if (!meshRef.current) return;

        // Use the centralized leader
        const leader = leaderRef.current;

        if (!leader || !leader.visibleFood) {
            meshRef.current.count = 0;
            return;
        }

        const foodItems = leader.visibleFood;
        meshRef.current.count = foodItems.length;

        // Use clock from state instead of Date.now()
        const time = state.clock.elapsedTime;

        // Update Instances
        for (let i = 0; i < foodItems.length; i++) {
            const item = foodItems[i];

            // Position
            tempObj.position.set(item.pos.x, item.pos.y, item.pos.z);

            // Animation: Spin
            tempObj.rotation.y += 0.02;
            tempObj.rotation.z += 0.01;

            // Scale: Shrink if consumed, else pulse
            if (item.consumed) {
                tempObj.scale.setScalar(0); 
            } else {
                const pulse = 1.0 + Math.sin(time * 3 + i) * 0.1;
                tempObj.scale.setScalar(pulse);
            }

            tempObj.updateMatrix();
            meshRef.current.setMatrixAt(i, tempObj.matrix);
        }

        meshRef.current.instanceMatrix.needsUpdate = true;
    });

    return (
        <instancedMesh 
            ref={meshRef} 
            args={[geo, mat, 100]} // Max 100 food items buffer
            frustumCulled={false}
        />
    );
};

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { useThree, ThreeEvent } from '@react-three/fiber';
import { GridCoord, ShapeType } from '../../domain/types';
import * as THREE from 'three';
import { EditorTool } from '../../App';

// Helper to convert axial to pixel (for rendering hexes)
const hexToPixel = (q: number, r: number, size: number = 0.5) => {
    const x = size * 1.5 * q;
    const z = size * Math.sqrt(3) * (r + q/2);
    return { x, z };
};

// Neighbor directions for Hexagons (Axial)
const HEX_NEIGHBORS = [
    {q: 1, r: 0}, {q: 1, r: -1}, {q: 0, r: -1},
    {q: -1, r: 0}, {q: -1, r: 1}, {q: 0, r: 1}
];

export const BlueprintViewUpdated: React.FC<{
    cells: GridCoord[]; 
    onCellClick: (x: number, y: number, z: number, isRight: boolean) => void;
    currentType: ShapeType;
    editorTool: EditorTool;
}> = ({ cells, onCellClick, currentType, editorTool }) => {

  const { camera, raycaster, pointer, scene } = useThree();
  const [hoverCoord, setHoverCoord] = useState<GridCoord | null>(null);

  // INSTANCING REFS
  const meshRef = useRef<THREE.InstancedMesh>(null);
  const tempMat = useMemo(() => new THREE.Matrix4(), []);

  const boxGeo = useMemo(() => new THREE.BoxGeometry(0.8, 0.8, 0.8), []);
  const hexGeo = useMemo(() => new THREE.CylinderGeometry(0.45, 0.45, 0.5, 6), []);
  const hexRotation = useMemo(() => new THREE.Euler(0, Math.PI/6, 0), []);
  const hexQuaternion = useMemo(() => new THREE.Quaternion().setFromEuler(hexRotation), []);

  const material = useMemo(() => new THREE.MeshStandardMaterial({ color: '#3b82f6', roughness: 0.3 }), []);
  const materialHex = useMemo(() => new THREE.MeshStandardMaterial({ color: '#8b5cf6', roughness: 0.3 }), []);

  const hoverMaterial = useMemo(() => new THREE.MeshStandardMaterial({ color: '#facc15', transparent: true, opacity: 0.5 }), []);
  const eraseMaterial = useMemo(() => new THREE.MeshStandardMaterial({ color: '#ef4444', transparent: true, opacity: 0.5 }), []);

  // UPDATE INSTANCES
  useEffect(() => {
      if (!meshRef.current) return;

      meshRef.current.count = cells.length;

      cells.forEach((c, i) => {
          tempMat.identity();
          if (currentType === ShapeType.HEX) {
             const {x, z} = hexToPixel(c.x, c.z, 0.6);
             const hexHeight = 0.5;
             const yPos = c.y * hexHeight + (hexHeight/2);
             tempMat.makeRotationFromQuaternion(hexQuaternion);
             tempMat.setPosition(x, yPos, z);
          } else {
             tempMat.setPosition(c.x, c.y, c.z);
          }
          meshRef.current!.setMatrixAt(i, tempMat);
      });
      meshRef.current.instanceMatrix.needsUpdate = true;

      // Update bounding sphere for raycasting
      if (meshRef.current.geometry) {
          meshRef.current.computeBoundingSphere();
      }

  }, [cells, currentType, tempMat, hexQuaternion]);

  // --- EVENTS ON MESH (More Reliable) ---

  const handleMeshMove = (e: ThreeEvent<PointerEvent>) => {
      e.stopPropagation();
      if (editorTool === 'VIEW') return;

      const instanceId = e.instanceId;
      if (instanceId === undefined) return;

      const c = cells[instanceId];
      if (!c) return;

      if (editorTool === 'ERASE') {
          setHoverCoord(c);
      } 
      else if (editorTool === 'BUILD') {
          // Calculate neighbor based on face normal or hit point
          const hitPoint = e.point;
          // Localize hit point relative to the instance center
          // This is hard with InstancedMesh without matrix inversion.
          // Easier: Just use face normal from intersection.

          if (currentType === ShapeType.HEX) {
             // HEX LOGIC using world hit point relative to calculated instance pos
             const {x: cx, z: cz} = hexToPixel(c.x, c.z, 0.6);
             const hexHeight = 0.5;
             const cy = c.y * hexHeight + (hexHeight/2);

             const relY = hitPoint.y - cy;

             // Top/Bottom
             if (relY > 0.23) {
                 setHoverCoord({ x: c.x, y: c.y + 1, z: c.z });
                 return;
             }
             if (relY < -0.23) {
                  setHoverCoord({ x: c.x, y: c.y - 1, z: c.z });
                  return;
             }

             // Side Neighbors
             let bestNeigh = null;
             let minD = Infinity;

             HEX_NEIGHBORS.forEach(n => {
                  const pos = hexToPixel(c.x + n.q, c.z + n.r, 0.6);
                  // Approximate y center for distance check
                  const dy = 0; 
                  const dx = pos.x - hitPoint.x;
                  const dz = pos.z - hitPoint.z;
                  const d = dx*dx + dz*dz;
                  if (d < minD) {
                      minD = d;
                      bestNeigh = n;
                  }
             });

             if (bestNeigh) {
                 setHoverCoord({ x: c.x + bestNeigh.q, y: c.y, z: c.z + bestNeigh.r });
             }
          } else {
             // CUBE LOGIC (Using Normals)
             if (e.face) {
                 const n = e.face.normal;
                 // Face normals in InstancedMesh are usually in local space of geometry? 
                 // Or world space? R3F/Three usually provides world space normal in intersections if updated?
                 // Actually, standard Raycaster returns face normal.
                 // For axis-aligned cubes, simpler:
                 // Just map normal to int

                 // Transform normal by instance rotation if needed (not for cubes usually)
                 // But wait, if we rotated the camera, face normal is still geometry normal.
                 // Let's assume standard orientation.

                 setHoverCoord({
                     x: c.x + Math.round(n.x),
                     y: c.y + Math.round(n.y),
                     z: c.z + Math.round(n.z)
                 });
             }
          }
      }
  };

  const handleMeshClick = (e: ThreeEvent<MouseEvent>) => {
      e.stopPropagation();
      if (editorTool === 'VIEW') return;

      const instanceId = e.instanceId;
      if (instanceId === undefined) return;

      if (editorTool === 'ERASE') {
          const c = cells[instanceId];
          if (c) onCellClick(c.x, c.y, c.z, true); // remove
      }
      else if (editorTool === 'BUILD') {
          if (hoverCoord) {
              onCellClick(hoverCoord.x, hoverCoord.y, hoverCoord.z, false); // add
          }
      }
  };

  const handleFloorMove = (e: ThreeEvent<PointerEvent>) => {
      if (editorTool !== 'BUILD') {
          if (editorTool !== 'ERASE') setHoverCoord(null); // Don't clear if erasing valid block
          return;
      }
      e.stopPropagation();

      const hitPoint = e.point;

      if (currentType === ShapeType.HEX) {
          const size = 0.6;
          const q = (2./3 * hitPoint.x) / size;
          const r = (-1./3 * hitPoint.x + Math.sqrt(3)/3 * hitPoint.z) / size;

          let rx = Math.round(q);
          let rz = Math.round(r);
          let ry = Math.round(-q-r);

          const x_diff = Math.abs(rx - q);
          const y_diff = Math.abs(ry - (-q-r));
          const z_diff = Math.abs(rz - r);

          if (x_diff > y_diff && x_diff > z_diff) {
              rx = -ry-rz;
          } else {
              rz = -rx-ry;
          }
          setHoverCoord({ x: rx, y: 0, z: rz });
      } else {
          setHoverCoord({
              x: Math.round(hitPoint.x),
              y: 0,
              z: Math.round(hitPoint.z)
          });
      }
  };

  const handleFloorClick = (e: ThreeEvent<MouseEvent>) => {
       if (editorTool !== 'BUILD') return;
       e.stopPropagation();
       if (hoverCoord) {
           onCellClick(hoverCoord.x, hoverCoord.y, hoverCoord.z, false);
       }
  };

  const handleMiss = () => {
     setHoverCoord(null);
  };

  return (
    <group 
        onPointerMissed={handleMiss}
    >
      <ambientLight intensity={0.8} />
      <directionalLight position={[5, 10, 5]} intensity={1.5} />

      <instancedMesh 
          ref={meshRef} 
          args={[undefined, undefined, 2000]} 
          onPointerMove={handleMeshMove}
          onClick={handleMeshClick}
          onContextMenu={handleMeshClick} // Handle right click naturally
      >
          {currentType === ShapeType.HEX 
            ? <cylinderGeometry args={[0.45, 0.45, 0.5, 6]} /> 
            : <boxGeometry args={[0.8, 0.8, 0.8]} />
          }
          {currentType === ShapeType.HEX 
            ? <primitive object={materialHex} attach="material" />
            : <primitive object={material} attach="material" />
          }
      </instancedMesh>

      {hoverCoord && (
         <group>
             {currentType === ShapeType.HEX ? (
                 <mesh 
                    position={[
                        hexToPixel(hoverCoord.x, hoverCoord.z, 0.6).x, 
                        hoverCoord.y * 0.5 + 0.25, 
                        hexToPixel(hoverCoord.x, hoverCoord.z, 0.6).z
                    ]} 
                    geometry={hexGeo} 
                    material={editorTool === 'ERASE' ? eraseMaterial : hoverMaterial}
                    rotation={[0, Math.PI/6, 0]}
                    pointerEvents="none" // Ghost should not block raycast
                 />
             ) : (
                 <mesh 
                    position={[hoverCoord.x, hoverCoord.y, hoverCoord.z]} 
                    geometry={boxGeo} 
                    material={editorTool === 'ERASE' ? eraseMaterial : hoverMaterial} 
                    pointerEvents="none" 
                 />
             )}
         </group>
      )}

      {/* Invisible Plane for Floor Building */}
      <mesh 
          rotation={[-Math.PI / 2, 0, 0]} 
          position={[0, -0.5, 0]} 
          name="base_plane" 
          visible={false}
          onPointerMove={handleFloorMove}
          onClick={handleFloorClick}
      >
          <planeGeometry args={[60, 60]} />
      </mesh>

      {currentType === ShapeType.HEX ? (
           <gridHelper args={[30, 30, 0x444444, 0x111111]} position={[0, -2.5, 0]} />
      ) : (
           <gridHelper args={[30, 30, 0x444444, 0x222222]} position={[0, -2.5, 0]} />
      )}

    </group>
  );
};

// Hexagonal Architecture: Domain Layer (Inner Core)
// Zero dependencies on UI or Rendering libraries.

export interface Vec3 {
  x: number;
  y: number;
  z: number;
}

export interface Node {
  id: string;
  pos: Vec3;
  oldPos: Vec3; // For Verlet integration
  mass: number;
  friction: number;
  isFixed?: boolean;
  isHead?: boolean; // NEW: The only node that can eat

  // SUCTION MECHANICS (Rhythmic Anchor)
  isGripping?: boolean; 
  gripTimer?: number;     // Frames remaining in current grip
  gripCooldown?: number;  // Frames until next grip is allowed
  gripSignal?: number;    // Deprecated for manual, but kept for compatibility

  // EDITOR METADATA (Preserves shape upon reloading)
  originalGridCoord?: { x: number; y: number; z: number }; 

  // Neural State
  activation?: number; // 0.0 to 1.0 (Visualization Glow)
  // Physics State
}

export interface Muscle {
  id: string;
  nodeA: string; // ID reference
  nodeB: string; // ID reference
  baseLength: number;
  stiffness: number;
  dnaIndex: number; // Maps to a Gene (Index in genome arrays)

  // Runtime Physics State
  currentLength?: number; 
  targetLength?: number; 

  // --- RUNTIME OPTIMIZATION (O(1) Access) ---
  nodeRefA?: Node;
  nodeRefB?: Node;

  // --- OSCILLATOR STATE (The Anti-Vibration Core) ---
  // The brain controls these parameters, not the length directly.
  phase: number;      // Current position in the sine wave (0 to 2PI)
  freq: number;       // How fast it pulses (Hz). Clamped to prevent jitter.
  amp: number;        // How much it expands (0.0 to 0.4). 
}

// Replaced simple Sine Gene with Neural Genome
export interface NeuralGenome {
  // GNN Weights: How much signal flows through each muscle (Synapse)
  synapseWeights: number[]; 
  // LSM Weights: The chaotic reservoir weights (simplified as a float array)
  reservoirWeights: number[];
  // Output Weights: Mapping the reservoir state to muscle contraction
  outputWeights: number[]; 
  // NEW: Predictive World Model Weights (Reservoir -> Predicted Sensory Input)
  predictionWeights: number[];
  // NEW: Grip Control Weights (Reservoir -> Node Suction Release)
  gripWeights: number[]; 
  // Biases for neurons
  biases: number[];

  // --- EVOLVABLE BRAIN DYNAMICS ---
  internalClockSpeed: number; // Multiplier (0.5 to 2.0). How fast the brain thinks relative to physics.
  waveFreq: number;           // Hz (0.5 to 3.0). Base frequency of the spinal generator.
  waveSpeed: number;          // Propagation speed of the wave along the body.
}

export interface FoodItem {
    id: string;
    pos: Vec3;
    energyValue: number;
    consumed: boolean;
}

export enum ShapeType {
  CUBE = 'CUBE', 
  TETRAHEDRON = 'TETRAHEDRON',
  OCTAHEDRON = 'OCTAHEDRON',
  DODECAHEDRON = 'DODECAHEDRON',
  ICOSAHEDRON = 'ICOSAHEDRON',
  WORM = 'WORM', // Legacy
