}

export interface SimulationConfig {
  gravity: number;
  friction: number;
  groundDamping: number;
  timeStep: number;
  // NEW: Structural Integrity
  shapeMemoryStrength: number;

  // NEW: Real-time Physics Tweaks
  globalStiffness: number;     // Multiplier for bone rigidity (0.1 to 2.0)
  globalContractility: number; // Multiplier for muscle power (0.0 to 2.0)
}

// --- ARCHITECT TYPES ---
export type GridCoord = { x: number; y: number; z: number };

export interface Blueprint {
    cells: Map<string, boolean>; // Key "x,y,z"
    type: ShapeType;
}

import { ShapeType, Organism, Node, Muscle, NeuralGenome, GridCoord, Vec3 } from './types';
import { VectorOps } from './math';
import { GeneticOperator } from './genetics/GeneticOperator';

export class BlueprintService {
  private cells: Map<string, boolean> = new Map();
  private type: ShapeType = ShapeType.CUBE;
  private geneticOperator: GeneticOperator;

  constructor() {
    this.geneticOperator = new GeneticOperator();
    this.clear();
  }

  public setType(t: ShapeType) {
    this.type = t;
  }

  public clear() {
    this.cells.clear();
  }

  public getCells(): GridCoord[] {
    const res: GridCoord[] = [];
    this.cells.forEach((val, key) => {
        if (val) {
            const [x, y, z] = key.split(',').map(Number);
            res.push({ x, y, z });
        }
    });
    return res;
  }

  public setCell(x: number, y: number, z: number, active: boolean) {
    const key = `${Math.round(x)},${Math.round(y)},${Math.round(z)}`;
    if (active) {
        this.cells.set(key, true);
    } else {
        this.cells.delete(key);
    }
  }

  public hasCell(x: number, y: number, z: number): boolean {
      return this.cells.has(`${x},${y},${z}`);
  }

  // --- GEOMETRY LIBRARY (PLATONIC SOLIDS) ---
  // Returns normalized vertices centered at 0,0,0
  private getAtomicStructure(type: ShapeType): Vec3[] {
      const t = (1 + Math.sqrt(5)) / 2; // Golden Ratio

      switch (type) {
          case ShapeType.TETRAHEDRON:
              return [
                  { x: 1, y: 1, z: 1 },
                  { x: -1, y: -1, z: 1 },
                  { x: -1, y: 1, z: -1 },
                  { x: 1, y: -1, z: -1 }
              ].map(v => VectorOps.mul(v, 0.5)); // Scale down slightly

          case ShapeType.OCTAHEDRON:
              return [
                  { x: 1, y: 0, z: 0 }, { x: -1, y: 0, z: 0 },
                  { x: 0, y: 1, z: 0 }, { x: 0, y: -1, z: 0 },
                  { x: 0, y: 0, z: 1 }, { x: 0, y: 0, z: -1 }
              ].map(v => VectorOps.mul(v, 0.7));

          case ShapeType.ICOSAHEDRON:
              // 12 Vertices
              const ico: Vec3[] = [];
              // XY plane
              ico.push({x: -1, y: t, z: 0}, {x: 1, y: t, z: 0}, {x: -1, y: -t, z: 0}, {x: 1, y: -t, z: 0});
              // YZ plane
              ico.push({x: 0, y: -1, z: t}, {x: 0, y: 1, z: t}, {x: 0, y: -1, z: -t}, {x: 0, y: 1, z: -t});
              // ZX plane
              ico.push({x: t, y: 0, z: -1}, {x: t, y: 0, z: 1}, {x: -t, y: 0, z: -1}, {x: -t, y: 0, z: 1});
              return ico.map(v => VectorOps.mul(v, 0.5));

          case ShapeType.DODECAHEDRON:
              // 20 Vertices
              const dodeca: Vec3[] = [];
              // Cube vertices
              for(let x=-1; x<=1; x+=2) for(let y=-1; y<=1; y+=2) for(let z=-1; z<=1; z+=2)
                  dodeca.push({x, y, z});
              // Green vertices (on axes)
              dodeca.push(
                  {x:0, y: 1/t, z: t}, {x:0, y: -1/t, z: t}, {x:0, y: 1/t, z: -t}, {x:0, y: -1/t, z: -t},
                  {x: 1/t, y: t, z: 0}, {x: -1/t, y: t, z: 0}, {x: 1/t, y: -t, z: 0}, {x: -1/t, y: -t, z: 0},
                  {x: t, y: 0, z: 1/t}, {x: t, y: 0, z: -1/t}, {x: -t, y: 0, z: 1/t}, {x: -t, y: 0, z: -1/t}
              );
              return dodeca.map(v => VectorOps.mul(v, 0.45));

          case ShapeType.CUBE:
          case ShapeType.HEX:
          default:
             // Standard Cube Corners
             const cube: Vec3[] = [];
             for(let x=-1; x<=1; x+=2) for(let y=-1; y<=1; y+=2) for(let z=-1; z<=1; z+=2)
                cube.push({x: x*0.5, y: y*0.5, z: z*0.5});
             return cube;
      }
  }

  // --- HEURISTICS ---

  public generateSmallCritter() {
      this.clear();
      // Heuristics act on Voxels (which are now Macro-Atoms)
      this.setCell(0,0,0, true);
      this.setCell(0,0,1, true);
      this.setCell(1,0,1, true);
      this.setCell(-1,0,1, true);
      this.setCell(0,1,1, true);
  }

  public generateLargeBeast() {
    this.clear();
    const len = 4;
    for(let z=0; z<len; z++) {
        this.setCell(0, 1, z, true);
        this.setCell(1, 0, z, true);
        this.setCell(-1, 0, z, true);
    }
    this.setCell(0, 2, len-1, true);
  }

  public applyWorm(length: number) {
      let curr = { x: 0, y: 0, z: 0 };
      this.setCell(0, 0, 0, true);
      for(let i=0; i<length; i++) {
          curr.z += 1;
          this.setCell(curr.x, curr.y, curr.z, true);
      }
  }

  public applyMirrorX() {
      const newCells = new Map<string, boolean>();
      this.cells.forEach((_, key) => {
          const [x, y, z] = key.split(',').map(Number);
          newCells.set(key, true);
          const mx = -x;
          newCells.set(`${mx},${y},${z}`, true);
      });
      this.cells = newCells;
  }

  public applyFloorFill() {
      for(let x=-1; x<=1; x++) {
          for(let z=-1; z<=1; z++) {
              this.setCell(x, 0, z, true);
          }
      }
  }

  public importOrganism(org: Organism) {
      this.clear();
      this.type = org.shape || ShapeType.CUBE; 
      // Simple re-mapping of existing structure if we stored coordinates
      for (const node of org.nodes) {
          if (node.originalGridCoord) {
              this.setCell(node.originalGridCoord.x, node.originalGridCoord.y, node.originalGridCoord.z, true);
          }
      }
      if (this.getCells().length === 0) {
          // Fallback if no metadata
          this.setCell(0,0,0, true);
      }
  }

  // --- UNIVERSAL PLATONIC GENERATOR ---

  public generateOrganism(id: string, source?: Organism): Organism {
      const nodes: Node[] = [];
      const muscles: Muscle[] = [];

      const activeCoords = this.getCells();
      if (activeCoords.length === 0) {
          this.setCell(0,0,0, true);
          activeCoords.push({x:0,y:0,z:0});
      }

      const gridScale = 1.0; 
      const atomStruct = this.getAtomicStructure(this.type);

      // 1. EXPAND MACRO-ATOMS
      // For every active voxel, we spawn the entire platonic solid's vertices
      // transformed to the voxel's world position.

      let tempNodes: { pos: Vec3, gridId: string }[] = [];

      activeCoords.forEach(c => {
          const cx = c.x * gridScale;
          const cy = c.y * gridScale;
          const cz = c.z * gridScale;

          atomStruct.forEach(v => {
              tempNodes.push({
                  pos: { x: cx + v.x, y: cy + v.y, z: cz + v.z },
                  gridId: `${c.x},${c.y},${c.z}` // Keep track of origin for coloring/logic?
              });
          });
      });

      // 2. MERGE DUPLICATES (Fusing)
      // If two nodes are very close (epsilon), merge them into one.
      // This creates the "Shared Facets" architecture automatically.

      const mergeThreshold = 0.1; // Fusion distance
      const mergedNodes: { pos: Vec3, id: string, originGrid: string }[] = [];

      tempNodes.forEach((t, i) => {
          let found = false;
          for (const m of mergedNodes) {
              const dist = VectorOps.distance(t.pos, m.pos);
              if (dist < mergeThreshold) {
                  found = true;
                  break;
              }
          }

          if (!found) {
              mergedNodes.push({
                  pos: t.pos,
                  id: `n_${i}`,
                  originGrid: t.gridId
              });
          }
      });

      // 3. NORMALIZE HEIGHT
      let minY = Infinity;
      mergedNodes.forEach(n => { if (n.pos.y < minY) minY = n.pos.y; });
      const heightOffset = -minY + 0.15; // Float slightly

      mergedNodes.forEach(n => {
          nodes.push({
              id: n.id,
              pos: { x: n.pos.x, y: n.pos.y + heightOffset, z: n.pos.z },
              oldPos: { x: n.pos.x, y: n.pos.y + heightOffset, z: n.pos.z },
              mass: 1.0,
              friction: 0.8,
              // Map back to origin grid for editor restoring
              originalGridCoord: (() => {
                  const [x,y,z] = n.originGrid.split(',').map(Number);
                  return {x,y,z};
              })()
          });
      });

      // 4. PROXIMITY BONDING (Universal Muscle Generation)
      // We ignore grid neighbors logic. We just check distances.
      // Connection Range depends on shape type density.
      let bondRange = 1.2; 
      if (this.type === ShapeType.DODECAHEDRON) bondRange = 0.6; // Closer vertices
      if (this.type === ShapeType.ICOSAHEDRON) bondRange = 0.7;
      if (this.type === ShapeType.OCTAHEDRON) bondRange = 1.2;

      const createdMuscles = new Set<string>();

      for(let i=0; i<nodes.length; i++) {
          for(let j=i+1; j<nodes.length; j++) {
              const n1 = nodes[i];
              const n2 = nodes[j];
              const dist = VectorOps.distance(n1.pos, n2.pos);

              if (dist < bondRange) {
                  const k = `${n1.id}-${n2.id}`;
                  if (!createdMuscles.has(k)) {
                      muscles.push({
                          id: `m_${k}`,
                          nodeA: n1.id,
                          nodeB: n2.id,
                          baseLength: dist,
                          stiffness: 1.0,
                          dnaIndex: 0, // Assigned later
                          phase: Math.random() * Math.PI * 2,
                          freq: 1.0,
                          amp: 0.0
                      });
                      createdMuscles.add(k);
                  }
              }
          }
      }

      // 5. POST-PROCESS: ASSIGN GENES & HEAD
      muscles.forEach((m, i) => m.dnaIndex = i);

      let maxZ = -Infinity;
      nodes.forEach(n => { if (n.pos.z > maxZ) maxZ = n.pos.z; });
      let headNode = nodes.find(n => Math.abs(n.pos.z - maxZ) < 0.1);
      if (headNode) {
          // @ts-ignore
          headNode.isHead = true;
      }
      const initialHeadPos = headNode ? { ...headNode.pos } : { x: 0, y: 0, z: 0 };

      // 6. GENOME GRAFTING
      const reservoirSize = 20;
      let genome = this.geneticOperator.createRandomGenome(muscles.length, nodes.length, reservoirSize);

      if (source && source.neuralGenome) {
          const oldGenome = source.neuralGenome;
          genome = this.geneticOperator.cloneGenome(oldGenome);

          // Simple resize if topology changed drastically
          if (genome.synapseWeights.length !== muscles.length * 2) {
             const newSyn = this.geneticOperator.createRandomGenome(muscles.length, nodes.length).synapseWeights;
             for(let i=0; i<newSyn.length && i<oldGenome.synapseWeights.length; i++) {
                 newSyn[i] = oldGenome.synapseWeights[i];
             }
             genome.synapseWeights = newSyn;
          }
      }

      return {
          id,
          shape: this.type,
          nodes,
          muscles,
          neuralGenome: genome,
          fitness: source ? source.fitness : 0,
          generation: source ? source.generation : 1,
          energy: 100,
          maxEnergy: 100,
          hungerTime: 0,
          isAlive: true,
          foodEaten: 0,
          visibleFood: [],
          initialHeadPos,
          distanceTraveled: 0
      };
  }
}

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { useThree, ThreeEvent } from '@react-three/fiber';
import { GridCoord, ShapeType } from '../../domain/types';
import * as THREE from 'three';
import { EditorTool } from '../../App';

// Fix for missing R3F types in JSX.IntrinsicElements
declare global {
  namespace JSX {
    interface IntrinsicElements {
      [elemName: string]: any;
    }
  }
}

export const BlueprintViewUpdated: React.FC<{
    cells: GridCoord[]; 
    onCellClick: (x: number, y: number, z: number, isRight: boolean) => void;
    currentType: ShapeType;
    editorTool: EditorTool;
}> = ({ cells, onCellClick, currentType, editorTool }) => {

  const { camera, raycaster, pointer, scene } = useThree();
  const [hoverCoord, setHoverCoord] = useState<GridCoord | null>(null);

  // INSTANCING REFS
  const meshRef = useRef<THREE.InstancedMesh>(null);
  const tempMat = useMemo(() => new THREE.Matrix4(), []);

  // GEOMETRIES FOR PLATONIC SOLIDS
  const boxGeo = useMemo(() => new THREE.BoxGeometry(0.8, 0.8, 0.8), []);
  const tetraGeo = useMemo(() => new THREE.TetrahedronGeometry(0.5), []);
  const octaGeo = useMemo(() => new THREE.OctahedronGeometry(0.5), []);
  const dodecaGeo = useMemo(() => new THREE.DodecahedronGeometry(0.45), []);
  const icosaGeo = useMemo(() => new THREE.IcosahedronGeometry(0.45), []);

  const currentGeo = useMemo(() => {
      switch(currentType) {
          case ShapeType.TETRAHEDRON: return tetraGeo;
          case ShapeType.OCTAHEDRON: return octaGeo;
          case ShapeType.DODECAHEDRON: return dodecaGeo;
          case ShapeType.ICOSAHEDRON: return icosaGeo;
          case ShapeType.CUBE:
          default: return boxGeo;
      }
  }, [currentType, boxGeo, tetraGeo, octaGeo, dodecaGeo, icosaGeo]);

  const material = useMemo(() => new THREE.MeshStandardMaterial({ color: '#3b82f6', roughness: 0.3 }), []);
  const hoverMaterial = useMemo(() => new THREE.MeshStandardMaterial({ color: '#facc15', transparent: true, opacity: 0.5 }), []);
  const eraseMaterial = useMemo(() => new THREE.MeshStandardMaterial({ color: '#ef4444', transparent: true, opacity: 0.5 }), []);

  // UPDATE INSTANCES
  useEffect(() => {
      if (!meshRef.current) return;
      meshRef.current.count = cells.length;

      cells.forEach((c, i) => {
          tempMat.identity();
          tempMat.setPosition(c.x, c.y, c.z);
          meshRef.current!.setMatrixAt(i, tempMat);
      });
      meshRef.current.instanceMatrix.needsUpdate = true;

      // Update bounding sphere for raycasting
      if (meshRef.current.geometry) {
          meshRef.current.computeBoundingSphere();
      }

  }, [cells, currentType, tempMat]);

  // --- EVENTS ---

  const handleMeshMove = (e: ThreeEvent<PointerEvent>) => {
      e.stopPropagation();
      if (editorTool === 'VIEW') return;

      const instanceId = e.instanceId;
      if (instanceId === undefined) return;

      const c = cells[instanceId];
      if (!c) return;

      if (editorTool === 'ERASE') {
          setHoverCoord(c);
      } 
      else if (editorTool === 'BUILD') {
          if (e.face) {
             const n = e.face.normal;
             // Simple normal mapping works because we align solids to grid center
             setHoverCoord({
                 x: c.x + Math.round(n.x),
                 y: c.y + Math.round(n.y),
                 z: c.z + Math.round(n.z)
             });
          }
      }
  };

  const handleMeshClick = (e: ThreeEvent<MouseEvent>) => {
      e.stopPropagation();
      if (editorTool === 'VIEW') return;

      const instanceId = e.instanceId;
      if (instanceId === undefined) return;

      if (editorTool === 'ERASE') {
          const c = cells[instanceId];
          if (c) onCellClick(c.x, c.y, c.z, true); // remove
      }
      else if (editorTool === 'BUILD') {
          if (hoverCoord) {
              onCellClick(hoverCoord.x, hoverCoord.y, hoverCoord.z, false); // add
          }
      }
  };

  const handleFloorMove = (e: ThreeEvent<PointerEvent>) => {
      if (editorTool !== 'BUILD') {
          if (editorTool !== 'ERASE') setHoverCoord(null);
          return;
      }
      e.stopPropagation();
      const hitPoint = e.point;
      setHoverCoord({
          x: Math.round(hitPoint.x),
          y: 0,
          z: Math.round(hitPoint.z)
      });
  };

  const handleFloorClick = (e: ThreeEvent<MouseEvent>) => {
       if (editorTool !== 'BUILD') return;
       e.stopPropagation();
       if (hoverCoord) {
           onCellClick(hoverCoord.x, hoverCoord.y, hoverCoord.z, false);
       }
  };

  const handleMiss = () => {
     setHoverCoord(null);
  };

  return (
    <group 
        onPointerMissed={handleMiss}
    >
      <ambientLight intensity={0.8} />
      <directionalLight position={[5, 10, 5]} intensity={1.5} />

      <instancedMesh 
          ref={meshRef} 
          args={[undefined, undefined, 2000]} 
          onPointerMove={handleMeshMove}
          onClick={handleMeshClick}
          onContextMenu={handleMeshClick} 
      >
          <primitive object={currentGeo} attach="geometry" />
          <primitive object={material} attach="material" />
      </instancedMesh>

      {hoverCoord && (
         <mesh 
            position={[hoverCoord.x, hoverCoord.y, hoverCoord.z]} 
            geometry={currentGeo} 
            material={editorTool === 'ERASE' ? eraseMaterial : hoverMaterial} 
            pointerEvents="none" 
         />
      )}

      {/* Invisible Plane for Floor Building */}
      <mesh 
          rotation={[-Math.PI / 2, 0, 0]} 
          position={[0, -0.5, 0]} 
          name="base_plane" 
          visible={false}
          onPointerMove={handleFloorMove}
          onClick={handleFloorClick}
      >
          <planeGeometry args={[60, 60]} />
      </mesh>

      <gridHelper args={[30, 30, 0x444444, 0x222222]} position={[0, -0.5, 0]} />
    </group>
  );
};

