interface LabSceneProps {
  population: Organism[];
  showBestOnly: boolean;
  visionRadius: number;
}

// COMPONENT: LeaderTracker
// Calculates the current "Leader" (Alive + Furthest Z) every frame and updates the ref.
// This ensures Camera, Food, and Visibility all use the exact same target.
const LeaderTracker: React.FC<{ 
    population: Organism[], 
    leaderRef: MutableRefObject<Organism | null> 
}> = ({ population, leaderRef }) => {
    useFrame(() => {
        if (!population.length) return;

        // Strategy: 
        // 1. Find Best Alive
        // 2. If no Alive, Find Best Dead

        let bestAlive: Organism | null = null;
        let maxZAlive = -Infinity;

        let bestDead: Organism | null = null;
        let maxZDead = -Infinity;

        for (const org of population) {
            let cz = 0;
            for(const n of org.nodes) cz += n.pos.z;
            cz /= org.nodes.length;

            if (org.isAlive) {
                if (cz > maxZAlive) { maxZAlive = cz; bestAlive = org; }
            } else {
                if (cz > maxZDead) { maxZDead = cz; bestDead = org; }
            }
        }

        leaderRef.current = bestAlive || bestDead || population[0];
    });
    return null;
};

// COMPONENT: CameraDirector
// Follows the Organism inside leaderRef
const CameraDirector: React.FC<{ leaderRef: MutableRefObject<Organism | null> }> = ({ leaderRef }) => {
    const { camera } = useThree();
    const controlsRef = useRef<OrbitControlsImpl>(null);
    const targetRef = useRef(new THREE.Vector3(0, 0, 0));

    useFrame(() => {
        const leader = leaderRef.current;
        if (!leader) return;

        // Calculate Target Position
        let cx = 0, cy = 0, cz = 0;
        const len = leader.nodes.length;
        for (const n of leader.nodes) {
            cx += n.pos.x;
            cy += n.pos.y;
            cz += n.pos.z;
        }
        const center = new THREE.Vector3(cx/len, cy/len, cz/len);

        // Smoothly Interpolate Camera & Target
        targetRef.current.lerp(center, 0.1);

        if (controlsRef.current) {
            const offset = camera.position.clone().sub(controlsRef.current.target);
            controlsRef.current.target.copy(targetRef.current);
            camera.position.copy(targetRef.current).add(offset);
            controlsRef.current.update();
        }
    });

    return <OrbitControls ref={controlsRef} makeDefault maxPolarAngle={Math.PI / 2 - 0.1} />;
};

