// --- ARCHITECT TYPES ---
export type GridCoord = { x: number; y: number; z: number };

export interface Blueprint {
    cells: Map<string, boolean>; // Key "x,y,z"
    type: ShapeType;
}

import { ShapeType, Organism, Node, Muscle, NeuralGenome, GridCoord, Vec3 } from './types';
import { VectorOps } from './math';
import { GeneticOperator } from './genetics/GeneticOperator';
import { LatticeFactory } from './lattice/LatticeStrategy';

export class BlueprintService {
  private cells: Map<string, boolean> = new Map();
  private type: ShapeType = ShapeType.CUBE;
  private geneticOperator: GeneticOperator;

  constructor() {
    this.geneticOperator = new GeneticOperator();
    this.clear();
  }

  public setType(t: ShapeType) {
    this.type = t;
  }

  public clear() {
    this.cells.clear();
  }

  public getCells(): GridCoord[] {
    const res: GridCoord[] = [];
    this.cells.forEach((val, key) => {
        if (val) {
            const [x, y, z] = key.split(',').map(Number);
            res.push({ x, y, z });
        }
    });
    return res;
  }

  public setCell(x: number, y: number, z: number, active: boolean) {
    const key = `${Math.round(x)},${Math.round(y)},${Math.round(z)}`;
    if (active) {
        this.cells.set(key, true);
    } else {
        this.cells.delete(key);
    }
  }

  public hasCell(x: number, y: number, z: number): boolean {
      return this.cells.has(`${x},${y},${z}`);
  }

  // --- PRESETS / HEURISTICS ---

  public generateSmallCritter() {
      this.clear();
      this.setCell(0,0,0, true);
      this.setCell(0,0,1, true);
      this.setCell(0,1,0, true);
      this.setCell(1,0,0, true);
      this.setCell(-1,0,0, true);
  }

  public generateLargeBeast() {
    this.clear();
    const len = 4;
    for(let z=0; z<len; z++) {
        this.setCell(0, 0, z, true);
        this.setCell(1, 0, z, true);
        this.setCell(-1, 0, z, true);

        // Spine
        this.setCell(0, 1, z, true);
    }
    // Head
    this.setCell(0, 2, len-1, true);
  }

  public applyWorm(length: number) {
      this.clear();
      for(let i=0; i<length; i++) {
          this.setCell(0, 0, i, true);
      }
  }

  public applyMirrorX() {
      const newCells = new Map<string, boolean>();
      this.cells.forEach((_, key) => {
          const [x, y, z] = key.split(',').map(Number);
          newCells.set(key, true);
          const mx = -x;
          newCells.set(`${mx},${y},${z}`, true);
      });
      this.cells = newCells;
  }

  public applyFloorFill() {
      for(let x=-2; x<=2; x++) {
          for(let z=-2; z<=2; z++) {
              this.setCell(x, 0, z, true);
          }
      }
  }

  public importOrganism(org: Organism) {
      this.clear();
      this.type = org.shape || ShapeType.CUBE; 
      // Re-map from stored metadata
      let foundMeta = false;
      for (const node of org.nodes) {
          if (node.originalGridCoord) {
              this.setCell(node.originalGridCoord.x, node.originalGridCoord.y, node.originalGridCoord.z, true);
              foundMeta = true;
          }
      }

      // Fallback: If no metadata, we can't perfectly reconstruct the grid, 
      // but we can try to snap positions. For now, just reset if unknown.
      if (!foundMeta) {
          this.generateSmallCritter();
      }
  }

  // --- LATTICE GENERATOR ---

  public generateOrganism(id: string, source?: Organism): Organism {
      const nodes: Node[] = [];
      const muscles: Muscle[] = [];

      const activeCoords = this.getCells();
      if (activeCoords.length === 0) {
          this.setCell(0,0,0, true);
          activeCoords.push({x:0,y:0,z:0});
      }

      // 1. SELECT STRATEGY
      const strategy = LatticeFactory.getStrategy(this.type);
      const scale = 1.0; 

      // 2. CREATE NODES (1 Cell = 1 Node)
      const coordToNodeId = new Map<string, string>();

      activeCoords.forEach((c, i) => {
          const worldPos = strategy.gridToWorld(c, scale);
          const nodeId = `n_${c.x}_${c.y}_${c.z}`;

          nodes.push({
              id: nodeId,
              pos: { ...worldPos },
              oldPos: { ...worldPos },
              mass: 1.0,
              friction: 0.8,
              originalGridCoord: c
          });

          coordToNodeId.set(`${c.x},${c.y},${c.z}`, nodeId);
      });

      // 3. CREATE MUSCLES (Using Lattice Connectivity)
      // This ensures rigid structures (Trusses) unlike proximity bonding
      const createdMuscles = new Set<string>();

      activeCoords.forEach(c => {
          const myId = coordToNodeId.get(`${c.x},${c.y},${c.z}`);
          if (!myId) return;

          const myNode = nodes.find(n => n.id === myId);
          if (!myNode) return;

          const neighbors = strategy.getNeighbors(c);

          neighbors.forEach(neigh => {
              const nKey = `${neigh.coord.x},${neigh.coord.y},${neigh.coord.z}`;
              const targetId = coordToNodeId.get(nKey);

              if (targetId) {
                  // Sort IDs to ensure unique key for A-B vs B-A
                  const [id1, id2] = [myId, targetId].sort(); 
                  const muscleKey = `${id1}-${id2}`;

                  if (!createdMuscles.has(muscleKey)) {
                      const targetNode = nodes.find(n => n.id === targetId);
                      if (targetNode) {
                          const dist = VectorOps.distance(myNode.pos, targetNode.pos);

                          muscles.push({
                              id: `m_${muscleKey}`,
                              nodeA: id1,
                              nodeB: id2,
                              baseLength: dist,
                              stiffness: 1.0, // Default stiffness
                              dnaIndex: 0,
                              phase: Math.random() * Math.PI * 2,
                              freq: 1.0,
                              amp: 0.0
                          });
                          createdMuscles.add(muscleKey);
                      }
                  }
              }
          });
      });

      // 4. POST-PROCESS
      muscles.forEach((m, i) => m.dnaIndex = i);

      // Identify Head (Highest Z then Highest Y)
      let maxZ = -Infinity;
      nodes.forEach(n => { if (n.pos.z > maxZ) maxZ = n.pos.z; });
      let candidates = nodes.filter(n => Math.abs(n.pos.z - maxZ) < 0.1);

      let maxY = -Infinity;
      let headNode = candidates[0];
      candidates.forEach(n => {
          if (n.pos.y > maxY) {
              maxY = n.pos.y;
              headNode = n;
          }
      });

      if (headNode) {
          // @ts-ignore
          headNode.isHead = true;
      }
      const initialHeadPos = headNode ? { ...headNode.pos } : { x: 0, y: 0, z: 0 };

      // 5. GENOME
      const reservoirSize = 20;
      let genome = this.geneticOperator.createRandomGenome(muscles.length, nodes.length, reservoirSize);

      if (source && source.neuralGenome) {
          const oldGenome = source.neuralGenome;
          genome = this.geneticOperator.cloneGenome(oldGenome);

          // Resize logic if topology changed
          if (genome.synapseWeights.length !== muscles.length * 2) {
             const newSyn = this.geneticOperator.createRandomGenome(muscles.length, nodes.length).synapseWeights;
             // Try to preserve what we can
             for(let i=0; i<newSyn.length && i<oldGenome.synapseWeights.length; i++) {
                 newSyn[i] = oldGenome.synapseWeights[i];
             }
             genome.synapseWeights = newSyn;
          }
      }

      return {
          id,
          shape: this.type,
          nodes,
          muscles,
          neuralGenome: genome,
          fitness: source ? source.fitness : 0,
          generation: source ? source.generation : 1,
          energy: 100,
          maxEnergy: 100,
          hungerTime: 0,
          isAlive: true,
          foodEaten: 0,
          visibleFood: [],
          initialHeadPos,
          distanceTraveled: 0
      };
  }
}

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { useThree, ThreeEvent } from '@react-three/fiber';
import { GridCoord, ShapeType } from '../../domain/types';
import { LatticeFactory } from '../../domain/lattice/LatticeStrategy';
import * as THREE from 'three';
import { EditorTool } from '../../App';

// Fix for missing R3F types in JSX.IntrinsicElements
declare global {
  namespace JSX {
    interface IntrinsicElements {
      group: any;
      ambientLight: any;
      directionalLight: any;
      instancedMesh: any;
      primitive: any;
      mesh: any;
      planeGeometry: any;
      gridHelper: any;
      boxGeometry: any;
      sphereGeometry: any;
      meshStandardMaterial: any;
      lineSegments: any;
    }
  }
}

export const BlueprintViewUpdated: React.FC<{
    cells: GridCoord[]; 
    onCellClick: (x: number, y: number, z: number, isRight: boolean) => void;
    currentType: ShapeType;
    editorTool: EditorTool;
}> = ({ cells, onCellClick, currentType, editorTool }) => {

  const { camera, raycaster, pointer, scene } = useThree();
  const [hoverCoord, setHoverCoord] = useState<GridCoord | null>(null);

  // INSTANCING REFS
  const meshRef = useRef<THREE.InstancedMesh>(null);
  const tempMat = useMemo(() => new THREE.Matrix4(), []);

  // GEOMETRIES
  // We use simple Box for everything to ensure easy clicking/building.
  // The position will reflect the Lattice Strategy (Tetra/Hex), but the visual handle is a box.
  const boxGeo = useMemo(() => new THREE.BoxGeometry(0.5, 0.5, 0.5), []);
  const sphereGeo = useMemo(() => new THREE.SphereGeometry(0.3, 8, 8), []);

  const material = useMemo(() => new THREE.MeshStandardMaterial({ color: '#3b82f6', roughness: 0.3 }), []);
  const hoverMaterial = useMemo(() => new THREE.MeshStandardMaterial({ color: '#facc15', transparent: true, opacity: 0.5 }), []);
  const eraseMaterial = useMemo(() => new THREE.MeshStandardMaterial({ color: '#ef4444', transparent: true, opacity: 0.5 }), []);

  const latticeStrategy = useMemo(() => LatticeFactory.getStrategy(currentType), [currentType]);

  // UPDATE INSTANCES
  useEffect(() => {
      if (!meshRef.current) return;
      meshRef.current.count = cells.length;

      cells.forEach((c, i) => {
          tempMat.identity();
          // Vital: Use the SAME strategy as the physics engine to position the visual blocks
          const pos = latticeStrategy.gridToWorld(c, 1.0);
          tempMat.setPosition(pos.x, pos.y, pos.z);
          meshRef.current!.setMatrixAt(i, tempMat);
      });
      meshRef.current.instanceMatrix.needsUpdate = true;

      if (meshRef.current.geometry) {
          meshRef.current.computeBoundingSphere();
      }

  }, [cells, latticeStrategy, tempMat]);

  // --- EVENTS ---

  const getGridCoordFromHit = (instanceId: number): GridCoord | null => {
      return cells[instanceId] || null;
  };

  const handleMeshMove = (e: ThreeEvent<PointerEvent>) => {
      e.stopPropagation();
      if (editorTool === 'VIEW') return;

      const instanceId = e.instanceId;
      if (instanceId === undefined) return;

      const c = getGridCoordFromHit(instanceId);
      if (!c) return;

      if (editorTool === 'ERASE') {
          setHoverCoord(c);
      } 
      else if (editorTool === 'BUILD') {
          if (e.face) {
             // FOR BUILD: We need to know which neighbor slot is being pointed at.
             // Since we might be in Tetra/Hex mode, simple normal addition might be wrong
             // if the lattice axes aren't orthogonal.
             // BUT, for Cube and Tetra (as implemented), adding normal to grid coord usually works 
             // because the neighbors are logically adjacent.

             // However, for Tetra/Hex, let's try a smarter approach:
             // 1. Get world hit point.
             // 2. Add a small offset along the normal.
             // 3. Reverse map World -> Grid? (Hard without inverse function)
             // 4. Fallback: Check standard 6 neighbors + diagonals, pick closest center to (hit + normal*0.5)

             const n = e.face.normal;
             const proposed: GridCoord = {
                 x: c.x + Math.round(n.x),
                 y: c.y + Math.round(n.y),
                 z: c.z + Math.round(n.z)
             };

             // Verify this matches a valid neighbor in the strategy?
             // Actually, simplest is usually best for the user:
             setHoverCoord(proposed);
          }
      }
  };

  const handleMeshClick = (e: ThreeEvent<MouseEvent>) => {
      e.stopPropagation();
      if (editorTool === 'VIEW') return;

      const instanceId = e.instanceId;
      if (instanceId === undefined) return;

      if (editorTool === 'ERASE') {
          const c = cells[instanceId];
          if (c) onCellClick(c.x, c.y, c.z, true); 
      }
      else if (editorTool === 'BUILD') {
          if (hoverCoord) {
              onCellClick(hoverCoord.x, hoverCoord.y, hoverCoord.z, false); 
          }
      }
  };

  const handleFloorMove = (e: ThreeEvent<PointerEvent>) => {
      if (editorTool !== 'BUILD') {
          if (editorTool !== 'ERASE') setHoverCoord(null);
          return;
      }
      e.stopPropagation();
      const hitPoint = e.point;

      // For floor, we just round to nearest int, 
      // but for Tetra strategy, we might need to adjust y=0 coords.
      // Let's assume ground layer is y=0
      setHoverCoord({
          x: Math.round(hitPoint.x),
          y: 0,
          z: Math.round(hitPoint.z)
      });
  };

  const handleFloorClick = (e: ThreeEvent<MouseEvent>) => {
       if (editorTool !== 'BUILD') return;
       e.stopPropagation();
       if (hoverCoord) {
           onCellClick(hoverCoord.x, hoverCoord.y, hoverCoord.z, false);
       }
  };

  const handleMiss = () => {
     setHoverCoord(null);
  };

  // Determine hover position visually
  const hoverPos = useMemo(() => {
      if (!hoverCoord) return new THREE.Vector3(0,-100,0);
      return latticeStrategy.gridToWorld(hoverCoord, 1.0);
  }, [hoverCoord, latticeStrategy]);

  return (
    <group 
        onPointerMissed={handleMiss}
    >
      <ambientLight intensity={0.8} />
      <directionalLight position={[5, 10, 5]} intensity={1.5} />

      <instancedMesh 
          ref={meshRef} 
          args={[undefined, undefined, 2000]} 
          onPointerMove={handleMeshMove}
          onClick={handleMeshClick}
          onContextMenu={handleMeshClick} 
      >
          <primitive object={currentType === ShapeType.CUBE ? boxGeo : sphereGeo} attach="geometry" />
          <primitive object={material} attach="material" />
      </instancedMesh>

      {hoverCoord && (
         <mesh 
            position={[hoverPos.x, hoverPos.y, hoverPos.z]} 
            geometry={currentType === ShapeType.CUBE ? boxGeo : sphereGeo} 
            material={editorTool === 'ERASE' ? eraseMaterial : hoverMaterial} 
            pointerEvents="none" 
         />
      )}

      {/* Invisible Plane for Floor Building */}
      <mesh 
          rotation={[-Math.PI / 2, 0, 0]} 
          position={[0, -0.5, 0]} 
          name="base_plane" 
          visible={false}
          onPointerMove={handleFloorMove}
          onClick={handleFloorClick}
      >
          <planeGeometry args={[60, 60]} />
      </mesh>

      <gridHelper args={[30, 30, 0x444444, 0x222222]} position={[0, -0.5, 0]} />
    </group>
  );
};

