                onClick={() => onGenerate('floor')}
                className="w-full py-1 bg-slate-800 hover:bg-slate-700 border border-slate-600 rounded text-xs"
            >
                Add Floor Base
            </button>
            <button 
                onClick={() => onGenerate('mirror')}
                className="w-full py-1 bg-purple-900/50 hover:bg-purple-800/50 border border-purple-700 rounded text-xs text-purple-200"
            >
                Apply Symmetry (X)
            </button>
        </div>

        {/* Actions */}
        <div className="flex gap-2 pt-2 border-t border-slate-700">
            <button 
                onClick={onClear}
                className="flex-1 py-2 bg-red-900/30 hover:bg-red-900/50 text-red-300 border border-red-800/50 rounded text-xs font-bold"
            >
                CLEAR
            </button>
            <button 
                onClick={onSpawn}
                className="flex-[2] py-2 bg-green-600 hover:bg-green-500 text-white border border-green-500 rounded text-xs font-bold shadow-lg shadow-green-900/50"
            >
                SPAWN
            </button>
        </div>
      </div>
    </div>
  );
};

